function paperDaemonMemoryTickFromState(state: Web3TradingState, recordedAt: string): PaperDaemonMemoryTick {
  return {
    id: `daemon-${Date.parse(recordedAt)}-${state.paper_daemon.current_cycle}-${state.paper_daemon.action}`,
    recorded_at: recordedAt,
    cycle: state.paper_daemon.current_cycle,
    action: state.paper_daemon.action,
    status: state.paper_daemon.status,
    advanced: state.paper_daemon.advanced,
    filled_count: state.paper_daemon.filled_count,
    blocked_count: state.paper_daemon.blocked_count,
    observed_count: state.paper_daemon.observed_count,
    equity_usd: roundMetric(state.portfolio.equity_usd),
    cash_usd: roundMetric(state.portfolio.cash_usd),
    exposure_usd: roundMetric(state.portfolio.exposure_usd),
    realized_pnl_usd: roundMetric(state.portfolio.realized_pnl_usd),
    drawdown_pct: roundMetric(state.portfolio.max_drawdown_pct),
    interval_seconds: state.paper_daemon.interval_seconds,
    reason: state.paper_daemon.reason,
  };
}

function buildPaperDaemonMemory(
  ticks: PaperDaemonMemoryTick[],
  currentTick: PaperDaemonTick | undefined,
  portfolio: TradingPortfolio,
): PaperDaemonMemory {
  const ordered = ticks
    .filter(isPaperDaemonMemoryTick)
    .sort((a, b) => Date.parse(a.recorded_at) - Date.parse(b.recorded_at))
    .slice(-12);
  const latestFirst = [...ordered].reverse();
  const firstEquity = ordered[0]?.equity_usd ?? portfolio.equity_usd;
  const lastEquity = ordered[ordered.length - 1]?.equity_usd ?? portfolio.equity_usd;
  const windowPnl = roundMetric(lastEquity - firstEquity);
  const windowPnlPct = firstEquity > 0 ? roundMetric((windowPnl / firstEquity) * 100) : 0;
  const fillCount = ordered.reduce((sum, tick) => sum + tick.filled_count, 0);
  const blockedCount = ordered.reduce((sum, tick) => sum + tick.blocked_count, 0);
  const advanceCount = ordered.filter((tick) => tick.action === "advance").length;
  const observeCount = ordered.filter((tick) => tick.action === "observe").length;
  const standDownCount = ordered.filter((tick) => tick.action === "stand-down").length;
  const consecutiveObserveCount = countFromEnd(ordered, (tick) => tick.action === "observe");
  const consecutiveLossCount = consecutiveLossTicks(ordered);
  const pauseNewEntries = standDownCount > 0 ||
    consecutiveLossCount >= 3 ||
    (ordered.length >= 4 && blockedCount > Math.max(6, fillCount * 3));
  const status: PaperDaemonMemory["status"] = ordered.length === 0
    ? "idle"
    : pauseNewEntries
      ? standDownCount > 0 ? "halted" : "cooldown"
      : windowPnl > 25 && fillCount > 0
        ? "compounding"
        : "learning";

  return {
    mode: "paper-daemon-memory",
    status,
    summary: paperDaemonMemorySummary(status, ordered.length, windowPnl, fillCount, blockedCount, currentTick),
    tick_count: ticks.filter(isPaperDaemonMemoryTick).length,
    window_size: ordered.length,
    window_pnl_usd: windowPnl,
    window_pnl_pct: windowPnlPct,
    fill_count: fillCount,
    blocked_count: blockedCount,
    advance_count: advanceCount,
    observe_count: observeCount,
    stand_down_count: standDownCount,
    consecutive_observe_count: consecutiveObserveCount,
    consecutive_loss_count: consecutiveLossCount,
    pause_new_entries: pauseNewEntries,
    recommended_action: paperDaemonMemoryAction(status, pauseNewEntries, consecutiveObserveCount, consecutiveLossCount),
    last_tick_at: ordered[ordered.length - 1]?.recorded_at ?? null,
    ticks: latestFirst,
  };
}

function buildAutonomousWalletTelemetry({
  asOf,
  portfolio,
  daemonMemory,
  performance,
  churnEfficiency,
  tradeTape,
}: {
  asOf: string;
  portfolio: TradingPortfolio;
  daemonMemory: PaperDaemonMemory;
  performance: PerformanceScorecard;
  churnEfficiency: ChurnEfficiencyAuditor;
  tradeTape: AutonomousTrade[];
}): AutonomousWalletTelemetry {
  const orderedTicks = [...daemonMemory.ticks].reverse();
  const currentPoint: AutonomousWalletTelemetryPoint = {
    id: `wallet-current-${Date.parse(asOf)}`,
    label: `Cycle ${orderedTicks[orderedTicks.length - 1]?.cycle ?? tradeTape.length}`,
    recorded_at: asOf,
    cycle: orderedTicks[orderedTicks.length - 1]?.cycle ?? tradeTape.length,
    action: "current",
    equity_usd: roundMetric(portfolio.equity_usd),
    cash_usd: roundMetric(portfolio.cash_usd),
    exposure_usd: roundMetric(portfolio.exposure_usd),
    realized_pnl_usd: roundMetric(portfolio.realized_pnl_usd),
    unrealized_pnl_usd: roundMetric(portfolio.unrealized_pnl_usd),
    drawdown_pct: roundMetric(portfolio.max_drawdown_pct),
    filled_count: 0,
    blocked_count: 0,
  };
  const curveSeed = orderedTicks.map((tick): AutonomousWalletTelemetryPoint => ({
    id: `wallet-${tick.id}`,
    label: `Cycle ${tick.cycle}`,
    recorded_at: tick.recorded_at,
    cycle: tick.cycle,
    action: tick.action,
    equity_usd: roundMetric(tick.equity_usd),
    cash_usd: roundMetric(tick.cash_usd),
    exposure_usd: roundMetric(tick.exposure_usd),
    realized_pnl_usd: roundMetric(tick.realized_pnl_usd),
    unrealized_pnl_usd: roundMetric(tick.equity_usd - tick.cash_usd - tick.exposure_usd),
    drawdown_pct: roundMetric(tick.drawdown_pct),
    filled_count: tick.filled_count,
    blocked_count: tick.blocked_count,
  }));
  const startPoint: AutonomousWalletTelemetryPoint = {
    id: "wallet-start",
    label: "Start",
    recorded_at: isoAfterSeconds(asOf, -60),
    cycle: 0,
    action: "current",
    equity_usd: roundMetric(portfolio.starting_cash_usd),
    cash_usd: roundMetric(portfolio.starting_cash_usd),
    exposure_usd: 0,
    realized_pnl_usd: 0,
    unrealized_pnl_usd: 0,
    drawdown_pct: 0,
    filled_count: 0,
    blocked_count: 0,
  };
  const curve = autonomousWalletTelemetryCurve(curveSeed.length > 0 ? [...curveSeed, currentPoint] : [startPoint, currentPoint]);
  const firstEquity = curve[0]?.equity_usd ?? portfolio.starting_cash_usd;
  const lastEquity = curve[curve.length - 1]?.equity_usd ?? portfolio.equity_usd;
  const highWatermark = roundMetric(Math.max(portfolio.starting_cash_usd, ...curve.map((point) => point.equity_usd)));
  const netPnl = roundMetric(portfolio.equity_usd - portfolio.starting_cash_usd);
  const netPnlPct = portfolio.starting_cash_usd > 0 ? roundMetric((netPnl / portfolio.starting_cash_usd) * 100) : 0;
  const windowPnl = roundMetric(lastEquity - firstEquity);
  const windowPnlPct = firstEquity > 0 ? roundMetric((windowPnl / firstEquity) * 100) : 0;
  const slope = curve.length > 1 ? roundMetric((lastEquity - firstEquity) / (curve.length - 1)) : 0;
  const allocationBase = Math.max(1, portfolio.cash_usd + portfolio.exposure_usd);
  const fillCount = curve.reduce((sum, point) => sum + point.filled_count, 0);
  const blockedCount = curve.reduce((sum, point) => sum + point.blocked_count, 0);
  const riskNotes = autonomousWalletRiskNotes({ performance, churnEfficiency, daemonMemory, portfolio, slope, blockedCount });
  const status = autonomousWalletTelemetryStatus({
    performance,
    churnEfficiency,
    daemonMemory,
    portfolio,
    netPnl,
    windowPnl,
    slope,
  });

  return {
    mode: "autonomous-wallet-telemetry",
    status,
    summary: autonomousWalletTelemetrySummary(status, netPnl, windowPnl, slope, portfolio.open_positions.length),
    starting_cash_usd: roundMetric(portfolio.starting_cash_usd),
    equity_usd: roundMetric(portfolio.equity_usd),
    high_watermark_usd: highWatermark,
    cash_usd: roundMetric(portfolio.cash_usd),
    exposure_usd: roundMetric(portfolio.exposure_usd),
    cash_pct: roundMetric((portfolio.cash_usd / allocationBase) * 100),
    exposure_pct: roundMetric((portfolio.exposure_usd / allocationBase) * 100),
    realized_pnl_usd: roundMetric(portfolio.realized_pnl_usd),
    unrealized_pnl_usd: roundMetric(portfolio.unrealized_pnl_usd),
    net_pnl_usd: netPnl,
    net_pnl_pct: netPnlPct,
    window_pnl_usd: windowPnl,
    window_pnl_pct: windowPnlPct,
    slope_usd_per_tick: slope,
    max_drawdown_pct: roundMetric(Math.max(portfolio.max_drawdown_pct, performance.max_drawdown_pct)),
    open_position_count: portfolio.open_positions.length,
    trade_count: tradeTape.length,
    fill_count: fillCount,
    blocked_count: blockedCount,
    last_tick_at: daemonMemory.last_tick_at,
    next_action: autonomousWalletTelemetryNextAction(status, riskNotes, churnEfficiency, performance),
    risk_notes: riskNotes,
    curve,
  };
}

function autonomousWalletTelemetryCurve(points: AutonomousWalletTelemetryPoint[]) {
  return points
    .filter((point, index, list) =>
      index === 0 ||
      point.recorded_at !== list[index - 1].recorded_at ||
      point.equity_usd !== list[index - 1].equity_usd ||
      point.cash_usd !== list[index - 1].cash_usd ||
      point.exposure_usd !== list[index - 1].exposure_usd
    )
    .slice(-16);
}

function autonomousWalletTelemetryStatus({
  performance,
  churnEfficiency,
  daemonMemory,
  portfolio,
  netPnl,
  windowPnl,
  slope,
}: {
  performance: PerformanceScorecard;
  churnEfficiency: ChurnEfficiencyAuditor;
  daemonMemory: PaperDaemonMemory;
  portfolio: TradingPortfolio;
  netPnl: number;
  windowPnl: number;
  slope: number;
}): AutonomousWalletTelemetry["status"] {
  if (performance.status === "protect" || portfolio.max_drawdown_pct >= 4 || daemonMemory.status === "halted") return "protect";
  if (churnEfficiency.status === "stop" || churnEfficiency.status === "cooldown" || daemonMemory.pause_new_entries) return "cooldown";
  if (netPnl > 0 && windowPnl > 0 && slope > 0 && portfolio.exposure_usd > portfolio.cash_usd * 0.65) return "harvest";
  if (netPnl > 0 && windowPnl > 0 && slope > 0) return "compounding";
  if (netPnl < 0 || windowPnl < 0 || slope < 0) return "recover";
  return "flat";
}

function autonomousWalletRiskNotes({
  performance,
  churnEfficiency,
  daemonMemory,
  portfolio,
  slope,
  blockedCount,
}: {
  performance: PerformanceScorecard;
  churnEfficiency: ChurnEfficiencyAuditor;
  daemonMemory: PaperDaemonMemory;
  portfolio: TradingPortfolio;
  slope: number;
  blockedCount: number;
}) {
  const notes: string[] = [];
  if (performance.max_drawdown_pct >= 3) notes.push(`Drawdown is ${performance.max_drawdown_pct}% across the current window.`);
  if (churnEfficiency.status === "stop" || churnEfficiency.status === "cooldown") notes.push(churnEfficiency.next_action);
  if (daemonMemory.consecutive_loss_count > 0) notes.push(`${daemonMemory.consecutive_loss_count} consecutive losing tick${daemonMemory.consecutive_loss_count === 1 ? "" : "s"} detected.`);
  if (blockedCount > Math.max(3, daemonMemory.fill_count * 2)) notes.push(`${blockedCount} blocker events are crowding recent fills.`);
  if (portfolio.exposure_usd > portfolio.cash_usd * 1.25) notes.push("Exposure is heavier than cash; harvest or protect winners before pressing fresh buys.");
  if (slope < 0) notes.push("Equity slope is negative; recover capital before increasing frequency.");
  if (notes.length === 0) notes.push("No wallet-level telemetry blocker is active.");
  return notes.slice(0, 5);
}

function autonomousWalletTelemetrySummary(
  status: AutonomousWalletTelemetry["status"],
  netPnl: number,
  windowPnl: number,
  slope: number,
  openPositions: number,
) {
  if (status === "compounding") return `Wallet is compounding: ${formatSignedCompactValue(netPnl)} net, ${formatSignedCompactValue(windowPnl)} window, ${formatSignedCompactValue(slope)} per tick.`;
  if (status === "harvest") return `Wallet is profitable but exposure is high; harvest gains across ${openPositions} open position${openPositions === 1 ? "" : "s"}.`;
  if (status === "recover") return `Wallet telemetry is negative: ${formatSignedCompactValue(netPnl)} net and ${formatSignedCompactValue(slope)} per tick.`;
  if (status === "cooldown") return "Wallet telemetry says to slow the loop before adding more churn.";
  if (status === "protect") return "Wallet telemetry is in protect mode because drawdown or daemon memory is too risky.";
  return "Wallet telemetry is flat; wait for high-signal entries or protective exits.";
}

function autonomousWalletTelemetryNextAction(
  status: AutonomousWalletTelemetry["status"],
  riskNotes: string[],
  churnEfficiency: ChurnEfficiencyAuditor,
  performance: PerformanceScorecard,
) {
  if (status === "compounding") return "Keep pressing only high-signal entries while preserving route-profit and churn gates.";
  if (status === "harvest") return "Prefer trims, exits, and profit-lock releases before opening more exposure.";
  if (status === "recover") return "Prioritize protective sells, avoid fresh buys, and wait for positive equity slope.";
  if (status === "cooldown") return churnEfficiency.next_action;
  if (status === "protect") return performance.summary;
  return riskNotes[0] ?? "Wait for the next high-signal opportunity.";
}

function isPaperDaemonMemoryTick(value: unknown): value is PaperDaemonMemoryTick {
  if (!value || typeof value !== "object") return false;
  const row = value as Partial<PaperDaemonMemoryTick>;
  return typeof row.id === "string" &&
    typeof row.recorded_at === "string" &&
    typeof row.cycle === "number" &&
    (row.action === "advance" || row.action === "observe" || row.action === "stand-down") &&
    (row.status === "advanced" || row.status === "observed" || row.status === "stand-down") &&
    typeof row.equity_usd === "number" &&
    typeof row.filled_count === "number" &&
    typeof row.blocked_count === "number";
}

function countFromEnd<T>(items: T[], predicate: (item: T) => boolean) {
  let count = 0;
  for (let index = items.length - 1; index >= 0; index -= 1) {
    if (!predicate(items[index])) break;
    count += 1;
  }
  return count;
}

function consecutiveLossTicks(ticks: PaperDaemonMemoryTick[]) {
  let losses = 0;
  for (let index = ticks.length - 1; index > 0; index -= 1) {
    if (ticks[index].equity_usd >= ticks[index - 1].equity_usd) break;
    losses += 1;
  }
  return losses;
}

function paperDaemonMemorySummary(
  status: PaperDaemonMemory["status"],
  windowSize: number,
  windowPnl: number,
  fillCount: number,
  blockedCount: number,
  currentTick: PaperDaemonTick | undefined,
) {
  if (status === "idle") return "No autonomous daemon ticks have been recorded yet.";
  if (status === "halted") return "Recent daemon memory includes stand-down behavior; fresh entries stay under review.";
  if (status === "cooldown") return "Recent daemon memory says to cool down before pressing more entries.";
  if (status === "compounding") return `${windowSize} recorded tick${windowSize === 1 ? "" : "s"} show ${formatSignedCompactValue(windowPnl)} with ${fillCount} fill${fillCount === 1 ? "" : "s"}.`;
  return `${windowSize} recorded tick${windowSize === 1 ? "" : "s"} are being learned from; ${blockedCount} blocker${blockedCount === 1 ? "" : "s"} remain visible. ${currentTick?.action === "advance" ? "The latest tick advanced." : "The latest tick observed."}`;
}

function paperDaemonMemoryAction(
  status: PaperDaemonMemory["status"],
  pauseNewEntries: boolean,
  consecutiveObserveCount: number,
  consecutiveLossCount: number,
) {
  if (pauseNewEntries && consecutiveLossCount >= 3) return "Pause fresh entries and let exits or stops reduce risk.";
  if (pauseNewEntries) return "Keep observing until blockers or stand-down memory clears.";
  if (status === "compounding") return "Allow measured redeploys while profit and governor gates stay green.";
  if (consecutiveObserveCount >= 3) return "Refresh market data before the next paper advance.";
  return "Keep the daemon armed and record the next wake.";
}

function buildPostTradeReview({
  daemonMemory,
  performance,
  paperExecutionQuality,
  signalAlpha,
  riskGovernor,
  profitLoop,
  executionCost,
}: {
  daemonMemory: PaperDaemonMemory;
  performance: PerformanceScorecard;
  paperExecutionQuality: PaperExecutionQuality;
  signalAlpha: SignalAlphaAttribution;
  riskGovernor: AutonomyRiskGovernor;
  profitLoop: ProfitLoopController;
  executionCost: ExecutionCostMonitor;
}): PostTradeReview {
  const executionFriction = Math.round(
    paperExecutionQuality.implementation_shortfall_usd +
      performance.cost_drag_usd +
      executionCost.fee_drag_usd,
  );
  const lessons = postTradeLessons({
    daemonMemory,
    performance,
    paperExecutionQuality,
    signalAlpha,
    riskGovernor,
    profitLoop,
    executionFriction,
  });
  const failCount = lessons.filter((lesson) => lesson.status === "fail").length;
  const watchCount = lessons.filter((lesson) => lesson.status === "watch").length;
  const positiveCount = lessons.filter((lesson) => lesson.impact === "positive").length;
  const reviewScore = clamp(Math.round(
    54 +
      Math.max(-24, Math.min(24, performance.net_pnl_usd * 0.09)) +
      Math.max(-18, Math.min(18, daemonMemory.window_pnl_usd * 0.12)) +
      Math.max(-16, Math.min(14, signalAlpha.net_alpha_usd * 0.08)) -
      paperExecutionQuality.implementation_shortfall_usd * 0.04 -
      executionCost.average_total_cost_bps * 0.08 -
      performance.max_drawdown_pct * 4 -
      failCount * 18 -
      watchCount * 7 +
      positiveCount * 4,
  ), 0, 100);
  const status = postTradeReviewStatus(reviewScore, failCount, watchCount, daemonMemory, riskGovernor, performance);
  const decision = postTradeReviewDecision(status, performance, daemonMemory, profitLoop);
  const recommendedSize = postTradeSizeMultiplier(status, reviewScore, signalAlpha, paperExecutionQuality, daemonMemory);
  const recommendedCadence = postTradeCadenceSeconds(status, riskGovernor, profitLoop, paperExecutionQuality);
  const pauseNewEntries = decision === "pause-entries" ||
    decision === "exit-only" ||
    daemonMemory.pause_new_entries ||
    riskGovernor.allow_new_entries === false;

  return {
    mode: "post-trade-review",
    status,
    decision,
    summary: postTradeReviewSummary(status, decision, reviewScore, performance, daemonMemory, executionFriction),
    reviewed_tick_count: daemonMemory.window_size,
    reviewed_trade_count: performance.trade_count,
    paper_window_pnl_usd: daemonMemory.window_pnl_usd,
    paper_window_pnl_pct: daemonMemory.window_pnl_pct,
    execution_friction_usd: executionFriction,
    quality_status: paperExecutionQuality.status,
    win_rate_pct: performance.win_rate_pct,
    profit_factor: performance.profit_factor,
    recommended_size_multiplier: recommendedSize,
    recommended_cadence_seconds: recommendedCadence,
    pause_new_entries: pauseNewEntries,
    next_action: postTradeReviewNextAction(decision, lessons, profitLoop, riskGovernor),
    lessons,
  };
}

function postTradeLessons({
  daemonMemory,
  performance,
  paperExecutionQuality,
  signalAlpha,
  riskGovernor,
  profitLoop,
  executionFriction,
}: {
  daemonMemory: PaperDaemonMemory;
  performance: PerformanceScorecard;
  paperExecutionQuality: PaperExecutionQuality;
  signalAlpha: SignalAlphaAttribution;
  riskGovernor: AutonomyRiskGovernor;
  profitLoop: ProfitLoopController;
  executionFriction: number;
}): PostTradeReviewLesson[] {
  const pnlStatus: PostTradeReviewLesson["status"] = performance.net_pnl_usd > 40 && daemonMemory.window_pnl_usd >= 0
    ? "pass"
    : performance.net_pnl_usd < -25 || daemonMemory.consecutive_loss_count >= 2
      ? "fail"
      : "watch";
  const executionStatus: PostTradeReviewLesson["status"] = paperExecutionQuality.status === "poor"
    ? "fail"
    : paperExecutionQuality.status === "degraded" || executionFriction > Math.max(40, Math.abs(performance.net_pnl_usd) * 0.45)
      ? "watch"
      : "pass";
  const alphaStatus: PostTradeReviewLesson["status"] = signalAlpha.status === "scale-up"
    ? "pass"
    : signalAlpha.status === "protect" || signalAlpha.recommended_size_multiplier < 0.55
      ? "fail"
      : "watch";
  const drawdownStatus: PostTradeReviewLesson["status"] = riskGovernor.status === "halted" || performance.max_drawdown_pct >= riskGovernor.max_drawdown_pct
    ? "fail"
    : riskGovernor.status === "cooldown" || riskGovernor.status === "tighten" || performance.max_drawdown_pct >= 2.8
      ? "watch"
      : "pass";
  const disciplineStatus: PostTradeReviewLesson["status"] = daemonMemory.pause_new_entries || profitLoop.status === "stand-down"
    ? "fail"
    : performance.status === "overtrading" || profitLoop.status === "cooldown"
      ? "watch"
      : "pass";

  return [
    {
      id: "pnl",
      label: "PnL memory",
      status: pnlStatus,
      impact: pnlStatus === "pass" ? "positive" : pnlStatus === "fail" ? "negative" : "neutral",
      detail: `${formatSignedCompactValue(performance.net_pnl_usd)} net PnL with ${formatSignedCompactValue(daemonMemory.window_pnl_usd)} over the daemon window.`,
      adjustment: pnlStatus === "pass" ? "Allow measured compounding if route and governor gates stay green." : pnlStatus === "fail" ? "Cut fresh entries until the loss streak clears." : "Keep size steady while the paper edge proves itself.",
    },
    {
      id: "execution",
      label: "Execution friction",
      status: executionStatus,
      impact: executionStatus === "pass" ? "positive" : executionStatus === "fail" ? "negative" : "neutral",
      detail: `${paperExecutionQuality.status} paper fills with ${formatCompactValue(executionFriction)} combined friction.`,
      adjustment: executionStatus === "pass" ? "Keep the current route cadence." : executionStatus === "fail" ? "Require smaller or exit-only orders until fills improve." : "Requote or resize before pressing the next entry.",
    },
    {
      id: "alpha",
      label: "Alpha attribution",
      status: alphaStatus,
      impact: alphaStatus === "pass" ? "positive" : alphaStatus === "fail" ? "negative" : "neutral",
      detail: `${signalAlpha.status.replace("-", " ")} with ${signalAlpha.recommended_size_multiplier}x signal-size guidance.`,
      adjustment: alphaStatus === "pass" ? `Favor ${signalAlpha.best_driver?.replace("-", " ") ?? "best"} signals.` : alphaStatus === "fail" ? `Disable weak ${signalAlpha.worst_driver?.replace("-", " ") ?? "driver"} sizing for the next review.` : "Keep collecting attribution before increasing size.",
    },
    {
      id: "drawdown",
      label: "Drawdown",
      status: drawdownStatus,
      impact: drawdownStatus === "pass" ? "positive" : drawdownStatus === "fail" ? "negative" : "neutral",
      detail: `${performance.max_drawdown_pct}% drawdown against ${riskGovernor.max_drawdown_pct}% autonomous stop.`,
      adjustment: drawdownStatus === "pass" ? "Risk budget can stay available." : drawdownStatus === "fail" ? "Move to exit-only review until drawdown recovers." : "Tighten size and shorten review cadence.",
    },
    {
      id: "discipline",
      label: "Trade discipline",
      status: disciplineStatus,
      impact: disciplineStatus === "pass" ? "positive" : disciplineStatus === "fail" ? "negative" : "neutral",
      detail: `${daemonMemory.advance_count} advances, ${daemonMemory.observe_count} observes, and ${daemonMemory.blocked_count} blockers in memory.`,
      adjustment: disciplineStatus === "pass" ? "Let the daemon keep advancing only when preflight is clean." : disciplineStatus === "fail" ? "Pause entries and keep exits, stops, and monitoring active." : "Slow the loop until churn pays for itself.",
    },
  ];
}

function postTradeReviewStatus(
  reviewScore: number,
  failCount: number,
  watchCount: number,
  daemonMemory: PaperDaemonMemory,
  riskGovernor: AutonomyRiskGovernor,
  performance: PerformanceScorecard,
): PostTradeReview["status"] {
  if (riskGovernor.status === "halted" || daemonMemory.status === "halted" || failCount >= 2) return "halted";
  if (failCount > 0 || daemonMemory.pause_new_entries || riskGovernor.status === "cooldown") return "cooldown";
  if (performance.status === "overtrading" || watchCount >= 3) return "tighten";
  if (reviewScore >= 74 && performance.status === "compounding" && daemonMemory.status === "compounding") return "scale";
  if (reviewScore >= 54) return "steady";
  return "learning";
}

function postTradeReviewDecision(
  status: PostTradeReview["status"],
  performance: PerformanceScorecard,
  daemonMemory: PaperDaemonMemory,
  profitLoop: ProfitLoopController,
): PostTradeReviewDecision {
  if (status === "halted") return "exit-only";
  if (status === "cooldown" || daemonMemory.pause_new_entries) return "pause-entries";
  if (status === "tighten" || performance.status === "overtrading" || profitLoop.status === "cooldown") return "reduce-size";
  if (status === "scale" && profitLoop.status === "compound") return "increase-size";
  return "hold-size";
}

function postTradeSizeMultiplier(
  status: PostTradeReview["status"],
  reviewScore: number,
  signalAlpha: SignalAlphaAttribution,
  paperExecutionQuality: PaperExecutionQuality,
  daemonMemory: PaperDaemonMemory,
) {
  if (status === "halted") return 0;
  if (status === "cooldown") return 0.22;
  if (status === "tighten") return 0.48;
  if (status === "learning") return 0.62;
  const qualityTrim = paperExecutionQuality.status === "degraded" ? 0.12 : paperExecutionQuality.status === "poor" ? 0.35 : 0;
  const memoryBoost = daemonMemory.status === "compounding" ? 0.08 : 0;
  const alpha = clamp(signalAlpha.recommended_size_multiplier, 0.45, 1.18);
  return roundMetric(clamp(alpha + memoryBoost + Math.max(0, reviewScore - 70) / 260 - qualityTrim, 0.55, status === "scale" ? 1.18 : 1));
}

function postTradeCadenceSeconds(
  status: PostTradeReview["status"],
  riskGovernor: AutonomyRiskGovernor,
  profitLoop: ProfitLoopController,
  paperExecutionQuality: PaperExecutionQuality,
) {
  if (status === "halted") return 30;
  if (status === "cooldown") return 18;
  if (status === "tighten") return 12;
  if (paperExecutionQuality.status === "poor") return 20;
  if (profitLoop.status === "compound" || profitLoop.status === "attack") return riskGovernor.status === "clear" ? 5 : 8;
  return 10;
}

function postTradeReviewSummary(
  status: PostTradeReview["status"],
  decision: PostTradeReviewDecision,
  reviewScore: number,
  performance: PerformanceScorecard,
  daemonMemory: PaperDaemonMemory,
  executionFriction: number,
) {
  if (status === "halted") return `Post-trade review halts fresh entries: ${decision.replace("-", " ")} after ${formatSignedCompactValue(performance.net_pnl_usd)} net PnL and ${formatCompactValue(executionFriction)} friction.`;
  if (status === "cooldown") return `Post-trade review pauses entries until losses, blockers, or friction clear from ${daemonMemory.window_size} remembered tick${daemonMemory.window_size === 1 ? "" : "s"}.`;
  if (status === "tighten") return `Post-trade review tightens size at ${reviewScore}/100 because churn or drawdown is ahead of edge.`;
  if (status === "scale") return `Post-trade review allows cautious scale: ${formatSignedCompactValue(daemonMemory.window_pnl_usd)} window PnL supports measured compounding.`;
  if (status === "steady") return `Post-trade review holds size at ${reviewScore}/100 while the next route proves edge after costs.`;
  return "Post-trade review is still learning; keep entries small until more paper outcomes are recorded.";
}

function postTradeReviewNextAction(
  decision: PostTradeReviewDecision,
  lessons: PostTradeReviewLesson[],
  profitLoop: ProfitLoopController,
  riskGovernor: AutonomyRiskGovernor,
) {
  const issue = lessons.find((lesson) => lesson.status === "fail") ?? lessons.find((lesson) => lesson.status === "watch");
  if (decision === "exit-only") return issue?.adjustment ?? "Run exits and stops only until the governor clears.";
  if (decision === "pause-entries") return issue?.adjustment ?? "Pause entries and keep monitoring the open book.";
  if (decision === "reduce-size") return issue?.adjustment ?? "Reduce order size and wait for cleaner post-trade evidence.";
  if (decision === "increase-size") return profitLoop.next_action;
  return riskGovernor.allow_paper_advance ? profitLoop.next_action : riskGovernor.summary;
}

function buildAutonomousSessionSupervisor({
  asOf,
  monitor,
  paperDaemon,
  daemonMemory,
  postTradeReview,
  profitLoop,
  capitalAllocator,
  riskGovernor,
  orderHandoff,
  custodyMandate,
  liveArming,
  executionGate,
}: {
  asOf: string;
  monitor: AutonomousMonitorSchedule;
  paperDaemon: PaperDaemonTick;
  daemonMemory: PaperDaemonMemory;
  postTradeReview: PostTradeReview;
  profitLoop: ProfitLoopController;
  capitalAllocator?: AutonomousCapitalAllocator;
  riskGovernor: AutonomyRiskGovernor;
  orderHandoff: AutonomousOrderHandoff;
  custodyMandate: AutonomousCustodyMandate;
  liveArming: LiveExecutionArming;
  executionGate: ExecutionGate;
}): AutonomousSessionSupervisor {
  const canAdvancePaper = monitor.should_advance_paper &&
    riskGovernor.allow_paper_advance &&
    capitalAllocator?.status !== "blocked" &&
    !postTradeReview.pause_new_entries &&
    daemonMemory.pause_new_entries !== true;
  const canRequestOrder = orderHandoff.ready_count > 0 && riskGovernor.status !== "halted";
  const canRequestSignature = orderHandoff.signature_count > 0 &&
    custodyMandate.status === "armed" &&
    liveArming.submit_ready;
  const canSubmitSignedPayload = orderHandoff.status === "ready-to-submit" &&
    custodyMandate.status === "armed" &&
    liveArming.submit_ready;
  const liveExecutionPermitted = executionGate.live_execution_enabled && liveArming.submit_ready && custodyMandate.status === "armed";
  const items = autonomousSessionItems({
    monitor,
    paperDaemon,
    daemonMemory,
    postTradeReview,
    profitLoop,
    capitalAllocator,
    riskGovernor,
    orderHandoff,
    custodyMandate,
    liveArming,
  });
  const blockers = items
    .filter((item) => item.status === "fail")
    .map((item) => item.blocker ?? item.reason)
    .filter(Boolean)
    .slice(0, 6);
  const status = autonomousSessionStatus({
    monitor,
    daemonMemory,
    postTradeReview,
    profitLoop,
    riskGovernor,
    orderHandoff,
    blockers,
    canAdvancePaper,
    canSubmitSignedPayload,
  });
  const runLevel: AutonomousSessionSupervisor["run_level"] = liveExecutionPermitted
    ? "live-ready"
    : liveArming.status === "dry-run-ready" || liveArming.submit_ready || orderHandoff.signature_count > 0
      ? "dry-run"
      : "paper";
  const shouldKeepRunning = status !== "stand-down" &&
    status !== "blocked" &&
    monitor.status !== "stand-down" &&
    riskGovernor.status !== "halted";
  const riskScore = clamp(Math.round(
    100 -
      riskGovernor.current_drawdown_pct * 12 -
      Math.max(0, riskGovernor.current_turnover_pct - riskGovernor.max_turnover_pct * 0.65) * 0.35 -
      (daemonMemory.pause_new_entries ? 24 : 0) -
      (postTradeReview.pause_new_entries ? 18 : 0),
  ), 0, 100);

  return {
    mode: "autonomous-session-supervisor",
    status,
    summary: autonomousSessionSummary(status, profitLoop, monitor, daemonMemory, orderHandoff, capitalAllocator),
    session_id: autonomousSessionId(asOf, monitor, riskGovernor, orderHandoff),
    heartbeat_status: monitor.heartbeat_status,
    cadence_seconds: Math.min(monitor.recommended_interval_seconds, postTradeReview.recommended_cadence_seconds),
    next_wake_at: monitor.next_wake_at,
    should_keep_running: shouldKeepRunning,
    can_advance_paper: canAdvancePaper,
    can_request_order: canRequestOrder,
    can_request_signature: canRequestSignature,
    can_submit_signed_payload: canSubmitSignedPayload,
    live_execution_permitted: liveExecutionPermitted,
    run_level: runLevel,
    loop_score: profitLoop.loop_score,
    urgency_score: monitor.urgency_score,
    risk_score: riskScore,
    expected_next_profit_usd: capitalAllocator?.expected_net_profit_usd ?? profitLoop.expected_next_profit_usd,
    deploy_cap_usd: capitalAllocator?.deploy_budget_usd ?? profitLoop.max_cycle_deploy_usd,
    release_cap_usd: capitalAllocator?.release_budget_usd ?? profitLoop.max_cycle_release_usd,
    message_budget_remaining: riskGovernor.message_budget_remaining,
    tick_memory_window: daemonMemory.window_size,
    watch_symbols: monitor.watch_symbols.slice(0, 8),
    next_action: autonomousSessionNextAction(status, items, profitLoop, monitor, postTradeReview, orderHandoff),
    blockers,
    controls: [
      "Heartbeat, capital allocation, risk governor, pre-trade checks, and post-trade review must all clear before autonomous advance.",
      "Paper advance can run without live signing; live signing still requires custody mandate, operator, RPC/Jupiter, and kill-switch gates.",
      "Message budget, drawdown, turnover, fill quality, and daemon memory can force cooldown or stand-down.",
      "Session supervisor records why the loop should attack, harvest, observe, cool down, or stop.",
    ],
    items,
  };
}

function autonomousSessionItems({
  monitor,
  paperDaemon,
  daemonMemory,
  postTradeReview,
  profitLoop,
  capitalAllocator,
  riskGovernor,
  orderHandoff,
  custodyMandate,
  liveArming,
}: {
  monitor: AutonomousMonitorSchedule;
  paperDaemon: PaperDaemonTick;
  daemonMemory: PaperDaemonMemory;
  postTradeReview: PostTradeReview;
  profitLoop: ProfitLoopController;
  capitalAllocator?: AutonomousCapitalAllocator;
  riskGovernor: AutonomyRiskGovernor;
  orderHandoff: AutonomousOrderHandoff;
  custodyMandate: AutonomousCustodyMandate;
  liveArming: LiveExecutionArming;
}): AutonomousSessionSupervisorItem[] {
  const heartbeatFail = monitor.heartbeat_status === "stale" || monitor.status === "stand-down";
  const riskFail = riskGovernor.status === "halted" || riskGovernor.allow_paper_advance === false;
  const capitalFail = capitalAllocator?.status === "blocked";
  const postTradeFail = postTradeReview.decision === "exit-only" || postTradeReview.pause_new_entries;
  const executionFail = orderHandoff.status === "blocked";
  const custodyFail = custodyMandate.status === "blocked" || (orderHandoff.signature_count > 0 && custodyMandate.status !== "armed");
  const items: AutonomousSessionSupervisorItem[] = [
    {
      id: "session-heartbeat",
      lane: "heartbeat",
      action: heartbeatFail ? "stand-down" : monitor.should_advance_paper ? "advance" : "observe",
      status: heartbeatFail ? "fail" : monitor.status === "cooldown" ? "watch" : "pass",
      symbol: monitor.watch_symbols[0] ?? null,
      score: monitor.urgency_score,
      reason: monitor.summary,
      next_review_seconds: monitor.recommended_interval_seconds,
      blocker: heartbeatFail ? "Monitor heartbeat is stale or stood down." : null,
    },
    {
      id: "session-capital",
      lane: "capital",
      action: capitalFail
        ? "blocked"
        : capitalAllocator?.status === "deploy"
          ? "attack"
          : capitalAllocator?.status === "harvest" || capitalAllocator?.status === "rebalance"
            ? "harvest"
            : capitalAllocator?.status === "cooldown"
              ? "cooldown"
              : "observe",
      status: capitalFail ? "fail" : capitalAllocator?.status === "deploy" || capitalAllocator?.status === "harvest" || capitalAllocator?.status === "rebalance" ? "pass" : "watch",
      symbol: capitalAllocator?.items.find((item) => item.symbol)?.symbol ?? null,
      score: capitalAllocator?.allocation_score ?? 0,
      reason: capitalAllocator?.summary ?? "Capital allocator has not produced a budget yet.",
      next_review_seconds: Math.min(monitor.recommended_interval_seconds, profitLoop.review_after_seconds),
      blocker: capitalFail ? capitalAllocator?.next_action ?? "Capital allocator blocks the next cycle." : null,
    },
    {
      id: "session-profit-loop",
      lane: "profit-loop",
      action: profitLoop.status === "compound" || profitLoop.status === "attack"
        ? "attack"
        : profitLoop.status === "harvest"
          ? "harvest"
          : profitLoop.status === "protect"
            ? "protect"
            : profitLoop.status === "cooldown"
              ? "cooldown"
              : profitLoop.status === "stand-down"
                ? "stand-down"
                : "observe",
      status: profitLoop.status === "stand-down" ? "fail" : profitLoop.status === "cooldown" || profitLoop.status === "protect" ? "watch" : "pass",
      symbol: profitLoop.items.find((item) => item.symbol)?.symbol ?? null,
      score: profitLoop.loop_score,
      reason: profitLoop.summary,
      next_review_seconds: profitLoop.review_after_seconds,
      blocker: profitLoop.status === "stand-down" ? profitLoop.next_action : null,
    },
    {
      id: "session-risk",
      lane: "risk",
      action: riskFail ? "stand-down" : riskGovernor.status === "cooldown" || riskGovernor.status === "tighten" ? "cooldown" : "advance",
      status: riskFail ? "fail" : riskGovernor.status === "cooldown" || riskGovernor.status === "tighten" ? "watch" : "pass",
      symbol: null,
      score: riskGovernor.status === "clear" ? 100 : riskGovernor.status === "tighten" ? 70 : riskGovernor.status === "cooldown" ? 42 : 0,
      reason: riskGovernor.summary,
      next_review_seconds: monitor.recommended_interval_seconds,
      blocker: riskFail ? riskGovernor.actions[0] ?? riskGovernor.summary : null,
    },
    {
      id: "session-execution",
      lane: "execution",
      action: orderHandoff.status === "ready-to-submit"
        ? "advance"
        : orderHandoff.status === "needs-signature" || orderHandoff.status === "build-order"
          ? "observe"
          : executionFail
            ? "blocked"
            : "observe",
      status: executionFail ? "fail" : orderHandoff.status === "paper" || orderHandoff.status === "idle" ? "watch" : "pass",
      symbol: orderHandoff.items.find((item) => item.symbol)?.symbol ?? null,
      score: orderHandoff.status === "ready-to-submit" ? 92 : orderHandoff.status === "needs-signature" ? 74 : orderHandoff.status === "build-order" ? 62 : orderHandoff.status === "paper" ? 45 : 20,
      reason: orderHandoff.summary,
      next_review_seconds: orderHandoff.fastest_ttl_seconds > 0 ? orderHandoff.fastest_ttl_seconds : monitor.recommended_interval_seconds,
      blocker: executionFail ? orderHandoff.next_action : null,
    },
    {
      id: "session-custody",
      lane: "custody",
      action: custodyMandate.status === "armed" ? "advance" : custodyMandate.status === "bounded-ready" || custodyMandate.status === "setup-required" ? "observe" : custodyMandate.status === "blocked" ? "blocked" : "observe",
      status: custodyFail ? "fail" : custodyMandate.status === "armed" ? "pass" : "watch",
      symbol: custodyMandate.allowed_symbols[0] ?? null,
      score: custodyMandate.status === "armed" ? 92 : custodyMandate.status === "bounded-ready" ? 70 : custodyMandate.status === "setup-required" ? 48 : 18,
      reason: custodyMandate.summary,
      next_review_seconds: custodyMandate.revoke_after_seconds,
      blocker: custodyFail ? custodyMandate.next_action : null,
    },
    {
      id: "session-post-trade",
      lane: "post-trade",
      action: postTradeFail ? "cooldown" : postTradeReview.decision === "increase-size" ? "attack" : postTradeReview.decision === "reduce-size" ? "cooldown" : "observe",
      status: postTradeFail ? "fail" : postTradeReview.status === "tighten" || postTradeReview.status === "cooldown" ? "watch" : "pass",
      symbol: null,
      score: postTradeReview.status === "scale" ? 90 : postTradeReview.status === "steady" ? 74 : postTradeReview.status === "learning" ? 54 : postTradeReview.status === "tighten" ? 45 : postTradeReview.status === "cooldown" ? 32 : 0,
      reason: postTradeReview.summary,
      next_review_seconds: postTradeReview.recommended_cadence_seconds,
      blocker: postTradeFail ? postTradeReview.next_action : null,
    },
    {
      id: "session-daemon-memory",
      lane: "heartbeat",
      action: daemonMemory.pause_new_entries ? "cooldown" : paperDaemon.action,
      status: daemonMemory.pause_new_entries ? "fail" : daemonMemory.status === "idle" || daemonMemory.status === "learning" ? "watch" : "pass",
      symbol: null,
      score: daemonMemory.status === "compounding" ? 82 : daemonMemory.status === "learning" ? 58 : daemonMemory.status === "idle" ? 38 : daemonMemory.status === "cooldown" ? 26 : 0,
      reason: daemonMemory.summary,
      next_review_seconds: paperDaemon.interval_seconds,
      blocker: daemonMemory.pause_new_entries ? daemonMemory.recommended_action : null,
    },
    {
      id: "session-live-arming",
      lane: "execution",
      action: liveArming.submit_ready ? "advance" : "observe",
      status: liveArming.submit_ready ? "pass" : liveArming.status === "dry-run-ready" ? "watch" : "fail",
      symbol: null,
      score: liveArming.submit_ready ? 96 : liveArming.status === "dry-run-ready" ? 62 : 28,
      reason: liveArming.summary,
      next_review_seconds: monitor.recommended_interval_seconds,
      blocker: liveArming.submit_ready ? null : liveArming.next_action,
    },
  ];
  return items.sort((a, b) => autonomousSessionItemRank(b) - autonomousSessionItemRank(a)).slice(0, 8);
}

function autonomousSessionStatus({
  monitor,
  daemonMemory,
  postTradeReview,
  profitLoop,
  riskGovernor,
  orderHandoff,
  blockers,
  canAdvancePaper,
  canSubmitSignedPayload,
}: {
  monitor: AutonomousMonitorSchedule;
  daemonMemory: PaperDaemonMemory;
  postTradeReview: PostTradeReview;
  profitLoop: ProfitLoopController;
  riskGovernor: AutonomyRiskGovernor;
  orderHandoff: AutonomousOrderHandoff;
  blockers: string[];
  canAdvancePaper: boolean;
  canSubmitSignedPayload: boolean;
}): AutonomousSessionSupervisor["status"] {
  if (riskGovernor.status === "halted" || monitor.status === "stand-down" || postTradeReview.decision === "exit-only") return "stand-down";
  if (blockers.length > 0 && orderHandoff.status === "blocked" && monitor.status !== "accelerate") return "blocked";
  if (daemonMemory.pause_new_entries || postTradeReview.pause_new_entries || riskGovernor.status === "cooldown" || profitLoop.status === "cooldown") return "cooldown";
  if (profitLoop.status === "harvest" || profitLoop.status === "protect") return "harvest";
  if (canSubmitSignedPayload || (canAdvancePaper && (profitLoop.status === "compound" || profitLoop.status === "attack" || monitor.status === "accelerate"))) return "attack";
  return "observe";
}

function autonomousSessionSummary(
  status: AutonomousSessionSupervisor["status"],
  profitLoop: ProfitLoopController,
  monitor: AutonomousMonitorSchedule,
  daemonMemory: PaperDaemonMemory,
  orderHandoff: AutonomousOrderHandoff,
  capitalAllocator?: AutonomousCapitalAllocator,
) {
  if (status === "attack") return `Session can press the loop: ${formatSignedCompactValue(capitalAllocator?.expected_net_profit_usd ?? profitLoop.expected_next_profit_usd)} expected next profit with ${formatCompactValue(capitalAllocator?.deploy_budget_usd ?? profitLoop.max_cycle_deploy_usd)} deploy budget.`;
  if (status === "harvest") return `Session prioritizes exits or profit capture before new buys: ${formatCompactValue(capitalAllocator?.release_budget_usd ?? profitLoop.max_cycle_release_usd)} release cap is visible.`;
  if (status === "cooldown") return `Session cools down while ${daemonMemory.window_size} remembered tick${daemonMemory.window_size === 1 ? "" : "s"} and post-trade review settle.`;
  if (status === "stand-down") return "Session is stood down; keep monitoring exits and risk only.";
  if (status === "blocked") return `Session is blocked before autonomous advance: ${orderHandoff.next_action}`;
  return `Session observes the tape and wakes in ${monitor.recommended_interval_seconds}s before the next advance decision.`;
}

function autonomousSessionNextAction(
  status: AutonomousSessionSupervisor["status"],
  items: AutonomousSessionSupervisorItem[],
  profitLoop: ProfitLoopController,
  monitor: AutonomousMonitorSchedule,
  postTradeReview: PostTradeReview,
  orderHandoff: AutonomousOrderHandoff,
) {
  const failed = items.find((item) => item.status === "fail");
  if (status === "attack") return profitLoop.next_action;
  if (status === "harvest") return profitLoop.next_action;
  if (status === "cooldown") return postTradeReview.next_action;
  if (status === "stand-down") return failed?.blocker ?? "Keep exits and risk monitoring active.";
  if (status === "blocked") return failed?.blocker ?? orderHandoff.next_action;
  return monitor.summary;
}

function autonomousSessionItemRank(item: AutonomousSessionSupervisorItem) {
  const status = item.status === "fail" ? 3 : item.status === "watch" ? 2 : 1;
  const action = item.action === "attack" || item.action === "harvest" || item.action === "stand-down" || item.action === "blocked" ? 2 : 0;
  return status * 100 + action * 10 + item.score;
}

function autonomousSessionId(
  asOf: string,
  monitor: AutonomousMonitorSchedule,
  riskGovernor: AutonomyRiskGovernor,
  orderHandoff: AutonomousOrderHandoff,
) {
  return `session-${createHash("sha256").update(`${asOf}:${monitor.next_wake_at}:${riskGovernor.status}:${orderHandoff.status}`).digest("hex").slice(0, 12)}`;
}

function buildAutonomousLoopDirector({
  asOf,
  marketSource,
  monitor,
  daemonMemory,
  sessionSupervisor,
  capitalAllocator,
  tradeBatch,
  tradeReadinessGate,
  setupMemory,
  routeQuoteSampler,
  routeRefreshQueue,
  marketStream,
  feedIntegrity,
  riskGovernor,
  postTradeReview,
}: {
  asOf: string;
  marketSource: Web3TradingState["market_source"];
  monitor: AutonomousMonitorSchedule;
  daemonMemory: PaperDaemonMemory;
  sessionSupervisor: AutonomousSessionSupervisor;
  capitalAllocator: AutonomousCapitalAllocator;
  tradeBatch?: AutonomousTradeBatch;
  tradeReadinessGate?: AutonomousTradeReadinessGate;
  setupMemory?: AutonomousSetupMemory;
  routeQuoteSampler?: RouteQuoteSampler;
  routeRefreshQueue?: RouteRefreshQueue;
  marketStream?: MarketStreamSupervisor;
  feedIntegrity?: MarketFeedIntegrity;
  riskGovernor: AutonomyRiskGovernor;
  postTradeReview: PostTradeReview;
}): AutonomousLoopDirector {
  const blockers = autonomousLoopDirectorBlockers(sessionSupervisor, capitalAllocator, riskGovernor, postTradeReview, daemonMemory, tradeReadinessGate);
  const status = autonomousLoopDirectorStatus(sessionSupervisor, capitalAllocator, riskGovernor, postTradeReview, daemonMemory, blockers, tradeReadinessGate, routeRefreshQueue);
  const pressure = autonomousLoopPressure({ tradeBatch, setupMemory, routeQuoteSampler, routeRefreshQueue, marketStream, feedIntegrity, monitor, sessionSupervisor });
  const intensity = autonomousLoopIntensity(status, pressure, sessionSupervisor, tradeBatch, monitor);
  const tickSeconds = autonomousLoopRouteRefreshTickSeconds(
    autonomousLoopTickSeconds(status, intensity, sessionSupervisor, capitalAllocator, monitor, postTradeReview, daemonMemory),
    routeRefreshQueue,
  );
  const clientShouldRun = status !== "halted" && status !== "blocked" && status !== "paused";
  const shouldIssueDaemonTick = clientShouldRun &&
    status !== "cooldown" &&
    intensity !== "cooldown" &&
    (tradeReadinessGate?.can_apply_batch ?? true);
  const repeatedExecutionLimit = Math.max(1, Math.min(6, Math.floor(riskGovernor.max_messages_per_minute / 2)));
  const burstTicks = autonomousLoopBurstTicks(intensity, tradeBatch, sessionSupervisor, repeatedExecutionLimit);
  const ticksRemaining = Math.max(0, burstTicks - Math.max(0, daemonMemory.advance_count));
  const marketWatchMode = autonomousLoopMarketWatchMode(marketSource, marketStream, feedIntegrity, intensity);

  return {
    mode: "autonomous-loop-director",
    status,
    intensity,
    market_watch_mode: marketWatchMode,
    summary: autonomousLoopDirectorSummary(status, intensity, tickSeconds, sessionSupervisor, capitalAllocator, tradeBatch, pressure, blockers),
    client_should_run: clientShouldRun,
    should_issue_daemon_tick: shouldIssueDaemonTick,
    next_tick_seconds: tickSeconds,
    next_tick_at: new Date(Date.parse(asOf) + tickSeconds * 1_000).toISOString(),
    client_interval_seconds: tickSeconds,
    max_ticks_per_minute: Math.max(1, Math.min(12, Math.floor(60 / Math.max(1, tickSeconds)))),
    repeated_execution_limit: repeatedExecutionLimit,
    ticks_remaining_before_pause: ticksRemaining,
    recommended_burst_ticks: burstTicks,
    batch_pressure_score: pressure.batch,
    feed_pressure_score: pressure.feed,
    route_pressure_score: pressure.route,
    route_refresh_status: routeRefreshQueue?.status ?? "idle",
    should_refresh_route_quotes: routeRefreshQueue?.status === "refresh-now" || routeRefreshQueue?.status === "queued" || monitor.should_refresh_route_quotes,
    route_refresh_next_action: routeRefreshQueue?.next_action ?? "No route refresh work is queued.",
    setup_pressure_score: pressure.setup,
    request: {
      endpoint: "/api/web3-trading",
      method: "POST",
      account: "persistent",
      source: marketSource.mode,
      daemon: true,
      advance: false,
      reset: false,
    },
    stop_reason: clientShouldRun ? null : blockers[0] ?? autonomousLoopStopReason(status, sessionSupervisor, postTradeReview, daemonMemory),
    tick_reason: autonomousLoopTickReason(status, intensity, sessionSupervisor, capitalAllocator, monitor, tradeBatch, pressure, routeRefreshQueue),
    blockers,
    controls: [
      "Client loop follows the director intensity instead of a fixed timer.",
      "Burst mode is reserved for ready paper batches, exits, hot setup memory, or urgent monitor pressure.",
      "Watch mode keeps market refresh/backfill moving when the desk needs fresher DEX evidence before trading.",
      "Repeated autonomous advances are throttled by remembered daemon ticks and message budget.",
      "A blocked allocator, halted governor, stale heartbeat, or exit-only review pauses the local loop.",
      "The director can request local daemon ticks only; signing and submission remain separately gated.",
    ],
  };
}

function buildAutonomousBurstScheduler({
  asOf,
  signalNoise,
  arbiter,
  tradeBatch,
  walletTelemetry,
  loopDirector,
  tradeReadinessGate,
  routeRefreshQueue,
  marketStream,
  churnEfficiency,
  performance,
}: {
  asOf: string;
  signalNoise: SignalNoiseScanner;
  arbiter: AutonomousTradeArbiter;
  tradeBatch: AutonomousTradeBatch;
  walletTelemetry: AutonomousWalletTelemetry;
  loopDirector: AutonomousLoopDirector;
  tradeReadinessGate: AutonomousTradeReadinessGate;
  routeRefreshQueue: RouteRefreshQueue;
  marketStream: MarketStreamSupervisor;
  churnEfficiency: ChurnEfficiencyAuditor;
  performance: PerformanceScorecard;
}): AutonomousBurstScheduler {
  const leader = signalNoise.items[0];
  const blockers = autonomousBurstBlockers({ signalNoise, walletTelemetry, loopDirector, tradeReadinessGate, churnEfficiency, performance });
  const expectedProfit = Math.round(
    Math.max(0, arbiter.total_expected_profit_usd) +
      Math.max(0, tradeBatch.expected_profit_usd) +
      Math.max(0, walletTelemetry.slope_usd_per_tick),
  );
  const riskBudget = Math.round(
    Math.max(0, arbiter.total_risk_usd) +
      Math.max(0, tradeBatch.max_loss_usd) +
      Math.max(0, walletTelemetry.exposure_usd * 0.04),
  );
  const items = autonomousBurstItems({
    leader,
    signalNoise,
    arbiter,
    tradeBatch,
    routeRefreshQueue,
    marketStream,
    walletTelemetry,
    loopDirector,
    blockers,
  });
  const status = autonomousBurstStatus({ blockers, signalNoise, walletTelemetry, loopDirector, tradeReadinessGate, tradeBatch, churnEfficiency });
  const tickSeconds = autonomousBurstTickSeconds(status, loopDirector, signalNoise, walletTelemetry, churnEfficiency, routeRefreshQueue);
  const maxTrades = autonomousBurstMaxTrades(status, tradeBatch, churnEfficiency, signalNoise, tradeReadinessGate);
  const clientShouldRun = status !== "stand-down" && status !== "idle" && loopDirector.client_should_run;
  const shouldIssueDaemonTick = clientShouldRun &&
    status !== "cooldown" &&
    (status === "burst" || status === "active" || status === "selective" || status === "protect") &&
    loopDirector.should_issue_daemon_tick;

  return {
    mode: "autonomous-burst-scheduler",
    status,
    summary: autonomousBurstSummary(status, leader, expectedProfit, tickSeconds, maxTrades, blockers),
    next_tick_seconds: tickSeconds,
    ticks_per_minute: tickSeconds > 0 ? Math.max(1, Math.min(30, Math.floor(60 / tickSeconds))) : 0,
    max_trades_next_tick: maxTrades,
    expected_profit_next_tick_usd: expectedProfit,
    risk_budget_next_tick_usd: riskBudget,
    dex_discovery_budget_per_minute: autonomousBurstDexDiscoveryBudget(status, marketStream),
    dex_pair_budget_per_minute: autonomousBurstDexPairBudget(status, marketStream),
    route_quote_budget_per_minute: autonomousBurstRouteBudget(status, routeRefreshQueue),
    signal_to_noise_ratio: leader?.signal_to_noise_ratio ?? signalNoise.average_signal_to_noise_ratio,
    client_should_run: clientShouldRun,
    should_issue_daemon_tick: shouldIssueDaemonTick,
    next_action: autonomousBurstNextAction(status, items, blockers, loopDirector, signalNoise),
    controls: [
      "Schedules only local paper daemon bursts; live signing, transaction submission, and confirmation remain separate gates.",
      "Respects DEX Screener-style discovery and pair polling budgets before increasing market refresh pressure.",
      "Keeps Jupiter/Solana route work bounded because transaction submission success is not the same as confirmation.",
      "Cuts cadence or trade count when wallet telemetry, churn efficiency, post-trade review, or readiness gates deteriorate.",
    ],
    items,
  };
}

function buildAutonomousTickPlan({
  loopDirector,
  burstScheduler,
  tradeMission,
  edgeStackExecution,
	  policyOptimizer,
	  commandCenterExecution,
	  highFrequencyRaceExecution,
	  opportunityRace,
	  opportunityRaceExecution,
	  trendChaseExecution,
	  scoutLifecycle,
	  positionRiskExecution,
	  tradeReadinessGate,
  routeRefreshQueue,
  marketStream,
}: {
  loopDirector: AutonomousLoopDirector;
  burstScheduler: AutonomousBurstScheduler;
  tradeMission: AutonomousTradeMission;
  edgeStackExecution?: AutonomousEdgeStackExecution;
	  policyOptimizer: AutonomousPolicyOptimizer;
	  highFrequencyRaceExecution: HighFrequencyProfitRaceExecution;
	  commandCenterExecution?: AutonomousCommandCenterExecution;
	  opportunityRace: AutonomousOpportunityRace;
	  opportunityRaceExecution: AutonomousOpportunityRaceExecution;
	  trendChaseExecution: TrendChaseExecution;
	  scoutLifecycle?: ScoutLifecycleController;
	  positionRiskExecution: AutonomousPositionRiskExecution;
  tradeReadinessGate: AutonomousTradeReadinessGate;
  routeRefreshQueue: RouteRefreshQueue;
  marketStream: MarketStreamSupervisor;
}): AutonomousTickPlan {
  const items: AutonomousTickPlanItem[] = [];
  const globalBlocker = loopDirector.stop_reason ?? tradeReadinessGate.blockers[0] ?? policyOptimizer.blockers[0] ?? null;

  if (edgeStackExecution && edgeStackExecution.status !== "idle") {
    items.push(autonomousTickPlanEdgeItem(edgeStackExecution, loopDirector));
  }

  if (commandCenterExecution && (commandCenterExecution.status === "queued" || commandCenterExecution.status === "applied" || commandCenterExecution.status === "blocked")) {
    const trade = commandCenterExecution.paper_trade;
    const sideIsSell = commandCenterExecution.selected_side === "sell" || trade?.side === "sell";
    const sideIsBuy = commandCenterExecution.selected_side === "buy" || trade?.side === "buy";
    items.push({
      id: "tick-plan-command-center",
      lane: sideIsSell ? "protect" : sideIsBuy ? "entry" : commandCenterExecution.status === "blocked" ? "blocked" : "observe",
      action: sideIsSell ? "protect-now" : sideIsBuy ? "trade-now" : commandCenterExecution.status === "blocked" ? "stand-down" : "observe",
      symbol: commandCenterExecution.selected_symbol ?? trade?.symbol ?? null,
      priority: sideIsSell ? "critical" : commandCenterExecution.status === "queued" ? "high" : "normal",
      status: commandCenterExecution.status === "queued" ? "ready" : commandCenterExecution.status === "applied" ? "watch" : "blocked",
      urgency_seconds: Math.max(2, Math.min(commandCenterExecution.review_after_seconds, loopDirector.next_tick_seconds || 12)),
      paper_budget_usd: Math.round(trade?.size_usd ?? 0),
      expected_edge_usd: Math.round(Math.max(0, commandCenterExecution.projected_pnl_usd)),
      risk_usd: Math.round(Math.max(0, commandCenterExecution.projected_drawdown_pct)),
      confidence_score: clamp(commandCenterExecution.rehearsal_score, 20, 98),
      reason: commandCenterExecution.summary,
      blocker: commandCenterExecution.blockers[0] ?? null,
    });
  }

  if (positionRiskExecution.status === "queued" || positionRiskExecution.status === "applied") {
    items.push({
      id: "tick-plan-position-risk",
      lane: "protect",
      action: "protect-now",
      symbol: positionRiskExecution.selected_symbol,
      priority: "critical",
      status: positionRiskExecution.status === "queued" ? "ready" : "watch",
      urgency_seconds: Math.max(2, Math.min(positionRiskExecution.review_after_seconds, loopDirector.next_tick_seconds || 12)),
      paper_budget_usd: Math.round(positionRiskExecution.release_usd),
      expected_edge_usd: Math.round(Math.max(0, positionRiskExecution.protected_profit_usd)),
      risk_usd: Math.round(Math.max(0, positionRiskExecution.release_usd - positionRiskExecution.protected_profit_usd)),
      confidence_score: clamp(100 - positionRiskExecution.risk_score + (positionRiskExecution.status === "queued" ? 20 : 0), 30, 96),
      reason: positionRiskExecution.summary,
      blocker: positionRiskExecution.blockers[0] ?? null,
    });
  }

	  if (highFrequencyRaceExecution.status === "queued" || highFrequencyRaceExecution.status === "applied" || highFrequencyRaceExecution.status === "blocked") {
	    const trade = highFrequencyRaceExecution.paper_trade;
	    const sideIsSell = trade?.side === "sell";
	    items.push({
	      id: "tick-plan-high-frequency",
	      lane: sideIsSell ? "protect" : highFrequencyRaceExecution.status === "blocked" ? "blocked" : "entry",
	      action: sideIsSell ? "protect-now" : highFrequencyRaceExecution.status === "blocked" ? "stand-down" : "trade-now",
	      symbol: highFrequencyRaceExecution.selected_symbol,
	      priority: sideIsSell ? "critical" : highFrequencyRaceExecution.status === "queued" ? "high" : "normal",
	      status: highFrequencyRaceExecution.status === "queued" ? "ready" : highFrequencyRaceExecution.status === "applied" ? "watch" : "blocked",
	      urgency_seconds: Math.max(2, Math.min(highFrequencyRaceExecution.review_after_seconds, loopDirector.next_tick_seconds || 12)),
	      paper_budget_usd: Math.round(trade?.size_usd ?? 0),
	      expected_edge_usd: Math.round(Math.max(0, highFrequencyRaceExecution.expected_profit_usd)),
	      risk_usd: Math.round(Math.max(0, (trade?.size_usd ?? 0) - highFrequencyRaceExecution.expected_profit_usd)),
	      confidence_score: clamp(
	        48 +
	          Math.max(0, highFrequencyRaceExecution.expected_profit_per_minute_usd) * 2 -
	          highFrequencyRaceExecution.churn_cost_bps * 0.08 +
	          (highFrequencyRaceExecution.status === "queued" ? 22 : highFrequencyRaceExecution.status === "applied" ? 8 : -12),
	        18,
	        96,
	      ),
	      reason: highFrequencyRaceExecution.summary,
	      blocker: highFrequencyRaceExecution.blockers[0] ?? null,
	    });
	  }

	  if (opportunityRaceExecution.status === "queued" || opportunityRaceExecution.status === "applied") {
	    const trade = opportunityRaceExecution.paper_trade;
	    const sideIsSell = trade?.side === "sell";
    items.push({
      id: "tick-plan-race-execution",
      lane: sideIsSell ? "protect" : "entry",
      action: sideIsSell ? "protect-now" : "trade-now",
      symbol: opportunityRaceExecution.selected_symbol,
      priority: sideIsSell ? "critical" : "high",
      status: opportunityRaceExecution.status === "queued" ? "ready" : "watch",
      urgency_seconds: Math.max(2, Math.min(opportunityRaceExecution.review_after_seconds, loopDirector.next_tick_seconds || 12)),
      paper_budget_usd: Math.round(trade?.size_usd ?? 0),
      expected_edge_usd: Math.round(Math.max(0, opportunityRaceExecution.expected_edge_usd)),
      risk_usd: Math.round(Math.max(0, opportunityRaceExecution.risk_usd)),
      confidence_score: clamp(opportunityRace.winner_action === "attack" ? 82 : opportunityRace.winner_action === "protect" || opportunityRace.winner_action === "harvest" ? 74 : 58, 0, 100),
      reason: opportunityRaceExecution.summary,
      blocker: opportunityRaceExecution.blockers[0] ?? null,
	    });
	  }

	  if (scoutLifecycle && scoutLifecycle.status !== "idle") {
	    const trade = scoutLifecycle.paper_trade;
	    const actionIsReady = scoutLifecycle.paper_trade_ready && !!trade;
	    items.push({
	      id: "tick-plan-scout-lifecycle",
	      lane: actionIsReady ? "protect" : "observe",
	      action: actionIsReady ? "protect-now" : "observe",
	      symbol: scoutLifecycle.selected_symbol,
	      priority: scoutLifecycle.status === "stop" ? "critical" : scoutLifecycle.status === "harvest" || scoutLifecycle.status === "trim" ? "high" : "normal",
	      status: actionIsReady ? "ready" : scoutLifecycle.status === "watch" || scoutLifecycle.status === "tighten" ? "watch" : "blocked",
	      urgency_seconds: Math.max(2, Math.min(scoutLifecycle.review_after_seconds, loopDirector.next_tick_seconds || 12)),
	      paper_budget_usd: Math.round(scoutLifecycle.release_usd),
	      expected_edge_usd: Math.round(Math.max(0, scoutLifecycle.protected_profit_usd)),
	      risk_usd: Math.round(Math.max(0, scoutLifecycle.risk_usd)),
	      confidence_score: clamp(
	        58 +
	          (scoutLifecycle.status === "stop" ? 24 : scoutLifecycle.status === "harvest" ? 20 : scoutLifecycle.status === "trim" ? 12 : 0) +
	          Math.round(Math.max(0, scoutLifecycle.protected_profit_usd) / 8) -
	          Math.round(Math.max(0, scoutLifecycle.risk_usd) / 12),
	        24,
	        94,
	      ),
	      reason: scoutLifecycle.summary,
	      blocker: actionIsReady ? null : scoutLifecycle.items[0]?.blockers[0] ?? null,
	    });
	  }

	  if (trendChaseExecution.status === "queued" || trendChaseExecution.status === "applied" || trendChaseExecution.status === "blocked") {
	    items.push({
	      id: "tick-plan-trend-chase",
	      lane: "entry",
	      action: "trade-now",
	      symbol: trendChaseExecution.selected_symbol,
	      priority: trendChaseExecution.status === "queued" ? "high" : "normal",
	      status: trendChaseExecution.status === "queued" ? "ready" : trendChaseExecution.status === "applied" ? "watch" : "blocked",
	      urgency_seconds: Math.max(2, Math.min(trendChaseExecution.review_after_seconds, loopDirector.next_tick_seconds || 12)),
	      paper_budget_usd: Math.round(trendChaseExecution.paper_size_usd),
	      expected_edge_usd: Math.round(Math.max(0, trendChaseExecution.expected_edge_usd)),
	      risk_usd: Math.round(Math.max(0, trendChaseExecution.risk_usd)),
	      confidence_score: clamp(
	        52 +
	          Math.max(0, trendChaseExecution.expected_edge_usd) -
	          Math.max(0, trendChaseExecution.risk_usd) +
	          (trendChaseExecution.selected_action === "chase" ? 20 : trendChaseExecution.selected_action === "probe" ? 10 : 0),
	        20,
	        92,
	      ),
	      reason: trendChaseExecution.summary,
	      blocker: trendChaseExecution.blockers[0] ?? null,
	    });
	  }

  for (const item of routeRefreshQueue.items.slice(0, 2)) {
    if (item.action !== "requote-now" && item.action !== "refresh-soon") continue;
    items.push({
      id: `tick-plan-route-${item.id}`,
      lane: "route",
      action: "refresh-routes",
      symbol: item.symbol,
      priority: item.priority === "critical" || item.action === "requote-now" ? "critical" : "high",
      status: item.blockers.length > 0 ? "blocked" : "ready",
      urgency_seconds: Math.max(2, Math.min(item.due_in_seconds, item.max_quote_age_seconds)),
      paper_budget_usd: 0,
      expected_edge_usd: 0,
      risk_usd: 0,
      confidence_score: clamp(item.route_confidence_score - Math.round(item.impact_drift_bps / 10), 20, 92),
      reason: item.reason,
      blocker: item.blockers[0] ?? null,
    });
  }

  if (marketStream.status === "backfill" || marketStream.status === "reconnect") {
    items.push({
      id: "tick-plan-market-refresh",
      lane: "market",
      action: "refresh-market",
      symbol: marketStream.watch_symbols[0] ?? tradeMission.target_symbol,
      priority: marketStream.status === "reconnect" ? "critical" : "high",
      status: "ready",
      urgency_seconds: Math.max(3, Math.min(marketStream.reconnect_after_seconds || 12, loopDirector.next_tick_seconds || 12)),
      paper_budget_usd: 0,
      expected_edge_usd: 0,
      risk_usd: 0,
      confidence_score: clamp(100 - marketStream.gap_risk_score, 20, 92),
      reason: marketStream.summary,
      blocker: null,
    });
  }

  if (burstScheduler.should_issue_daemon_tick && tradeMission.status !== "blocked") {
    const tradeAction: AutonomousTickPlanAction = tradeMission.target_side === "sell" ? "protect-now" : "trade-now";
    items.push({
      id: "tick-plan-burst",
      lane: tradeMission.target_side === "sell" ? "protect" : "entry",
      action: tradeAction,
      symbol: tradeMission.target_symbol,
      priority: burstScheduler.status === "burst" ? "high" : "normal",
      status: tradeReadinessGate.can_apply_batch ? "ready" : "blocked",
      urgency_seconds: Math.max(2, burstScheduler.next_tick_seconds || loopDirector.next_tick_seconds || 12),
      paper_budget_usd: tradeMission.target_side === "sell" ? Math.round(tradeMission.release_budget_usd) : Math.round(Math.min(tradeMission.deploy_budget_usd, policyOptimizer.deploy_budget_usd || tradeMission.deploy_budget_usd)),
      expected_edge_usd: Math.round(Math.max(0, tradeMission.expected_profit_usd, burstScheduler.expected_profit_next_tick_usd)),
      risk_usd: Math.round(Math.max(0, tradeMission.max_risk_usd, burstScheduler.risk_budget_next_tick_usd)),
      confidence_score: tradeMission.confidence_score,
      reason: tradeMission.next_action,
      blocker: tradeReadinessGate.can_apply_batch ? null : tradeReadinessGate.next_action,
    });
  }

  if (items.length === 0) {
    items.push({
      id: globalBlocker ? "tick-plan-blocked" : "tick-plan-observe",
      lane: globalBlocker ? "blocked" : "observe",
      action: globalBlocker ? "stand-down" : "observe",
      symbol: tradeMission.target_symbol,
      priority: globalBlocker ? "critical" : "low",
      status: globalBlocker ? "blocked" : "watch",
      urgency_seconds: Math.max(5, loopDirector.next_tick_seconds || burstScheduler.next_tick_seconds || 30),
      paper_budget_usd: 0,
      expected_edge_usd: 0,
      risk_usd: 0,
      confidence_score: globalBlocker ? 20 : 48,
      reason: globalBlocker ?? loopDirector.tick_reason,
      blocker: globalBlocker,
    });
  }

  const sortedItems = items
    .map((item) => ({
      ...item,
      blocker: item.status === "blocked" ? item.blocker ?? globalBlocker ?? "Blocked before the next autonomous tick." : item.blocker,
    }))
    .sort((a, b) => autonomousTickPlanItemRank(b) - autonomousTickPlanItemRank(a));
  const edgePlanItem = sortedItems.find((item) => item.id === "tick-plan-edge-action");
  const rankedItems = edgePlanItem && !sortedItems.slice(0, 6).some((item) => item.id === edgePlanItem.id)
    ? [...sortedItems.slice(0, 5), edgePlanItem]
    : sortedItems.slice(0, 6);
  const ready = rankedItems.filter((item) => item.status === "ready");
  const executeCount = ready.filter((item) => item.action === "trade-now" || item.action === "protect-now").length;
  const refreshCount = ready.filter((item) => item.action === "refresh-routes" || item.action === "refresh-market").length;
  const blockedCount = rankedItems.filter((item) => item.status === "blocked").length;
	  const leader = ready[0] ?? rankedItems[0];
	  const status = autonomousTickPlanStatus(leader, executeCount, refreshCount, blockedCount);
	  const throughput = autonomousTickPlanThroughput({
	    status,
	    ready,
	    executeCount,
	    refreshCount,
	    blockedCount,
	    loopDirector,
	    burstScheduler,
	    tradeReadinessGate,
	    policyOptimizer,
	  });
	  const bundleItems = autonomousTickPlanBundleItems(ready, throughput.maxActionsNextMinute);
	  const bundleTradeItems = bundleItems.filter((item) => item.action === "trade-now" || item.action === "protect-now");
	  const bundleRefreshItems = bundleItems.filter((item) => item.action === "refresh-routes" || item.action === "refresh-market");
	  const bundleSymbols = Array.from(new Set(bundleItems.map((item) => item.symbol).filter((symbol): symbol is string => Boolean(symbol)))).slice(0, 5);
	  const bundleTradeBudgetUsd = Math.round(bundleTradeItems.reduce((sum, item) => sum + Math.max(0, item.paper_budget_usd), 0));
	  const bundleExpectedEdgeUsd = Math.round(bundleItems.reduce((sum, item) => sum + Math.max(0, item.expected_edge_usd), 0));

	  return {
	    mode: "autonomous-tick-plan",
	    status,
	    throughput_mode: throughput.mode,
	    summary: autonomousTickPlanSummary(status, leader, executeCount, refreshCount),
	    next_action: leader.blocker ?? leader.reason,
	    tick_seconds: Math.max(2, Math.min(...rankedItems.map((item) => item.urgency_seconds))),
	    max_actions_next_minute: throughput.maxActionsNextMinute,
	    execution_slots_remaining: throughput.executionSlotsRemaining,
	    bundle_action_count: bundleItems.length,
	    bundle_trade_count: bundleTradeItems.length,
	    bundle_refresh_count: bundleRefreshItems.length,
	    bundle_symbols: bundleSymbols,
	    bundle_expected_edge_usd: bundleExpectedEdgeUsd,
	    bundle_trade_budget_usd: bundleTradeBudgetUsd,
	    bundle_summary: autonomousTickPlanBundleSummary(bundleItems, bundleTradeItems.length, bundleRefreshItems.length, throughput.mode, throughput.throttleReason),
	    next_minute_trade_budget_usd: throughput.nextMinuteTradeBudgetUsd,
	    throttle_reason: throughput.throttleReason,
	    execute_count: executeCount,
    refresh_count: refreshCount,
    blocked_count: blockedCount,
    paper_budget_usd: Math.round(ready.reduce((sum, item) => sum + item.paper_budget_usd, 0)),
    expected_edge_usd: Math.round(ready.reduce((sum, item) => sum + Math.max(0, item.expected_edge_usd), 0)),
    risk_usd: Math.round(ready.reduce((sum, item) => sum + Math.max(0, item.risk_usd), 0)),
		    controls: [
		      "Orders the next local paper tick from fused edge action, position protection, scout lifecycle exits, race execution, trend chase, route refresh, market refresh, and mission pressure.",
          "The fused edge action can become the lead trade, protect, or read-only route-refresh lane when its proof outranks narrower executors.",
		      "Caps next-minute throughput by ready actions, route refresh needs, repeated-execution slots, burst limits, and readiness gates.",
	      "Protection and route repair outrank fresh buys when they are urgent.",
      "Only ready paper/local actions can execute; blocked items stay visible as reasons to observe or stand down.",
      "This plan cannot sign, submit, settle, or move live funds.",
    ],
    items: rankedItems,
  };
}

function autonomousTickPlanItemRank(item: AutonomousTickPlanItem) {
  const statusRank = item.status === "ready" ? 80 : item.status === "watch" ? 40 : 0;
  const actionRank = item.action === "protect-now" ? 70 : item.action === "trade-now" ? 55 : item.action === "refresh-routes" ? 42 : item.action === "refresh-market" ? 36 : item.action === "stand-down" ? 28 : 10;
  const priorityRank = item.priority === "critical" ? 24 : item.priority === "high" ? 16 : item.priority === "normal" ? 8 : 0;
  return statusRank + actionRank + priorityRank + item.confidence_score / 5 + Math.max(0, 30 - item.urgency_seconds) / 2;
}

function withAutonomousEdgeTickLane(
  tickPlan: AutonomousTickPlan,
  edgeExecution: AutonomousEdgeStackExecution,
  loopDirector: AutonomousLoopDirector,
): AutonomousTickPlan {
  if (edgeExecution.status === "idle") return tickPlan;

  const edgeItem = autonomousTickPlanEdgeItem(edgeExecution, loopDirector);
  const sortedItems = [
    edgeItem,
    ...tickPlan.items.filter((item) => item.id !== edgeItem.id),
  ]
    .sort((a, b) => autonomousTickPlanItemRank(b) - autonomousTickPlanItemRank(a));
  const rankedItems = sortedItems.slice(0, 6).some((item) => item.id === edgeItem.id)
    ? sortedItems.slice(0, 6)
    : [...sortedItems.slice(0, 5), edgeItem];
  const ready = rankedItems.filter((item) => item.status === "ready");
  const executeCount = ready.filter((item) => item.action === "trade-now" || item.action === "protect-now").length;
  const refreshCount = ready.filter((item) => item.action === "refresh-routes" || item.action === "refresh-market").length;
  const blockedCount = rankedItems.filter((item) => item.status === "blocked").length;
  const leader = ready[0] ?? rankedItems[0];
  const status = autonomousTickPlanStatus(leader, executeCount, refreshCount, blockedCount);
  const bundleItems = autonomousTickPlanBundleItems(ready, tickPlan.max_actions_next_minute);
  const bundleTradeItems = bundleItems.filter((item) => item.action === "trade-now" || item.action === "protect-now");
  const bundleRefreshItems = bundleItems.filter((item) => item.action === "refresh-routes" || item.action === "refresh-market");
  const bundleSymbols = Array.from(new Set(bundleItems.map((item) => item.symbol).filter((symbol): symbol is string => Boolean(symbol)))).slice(0, 5);
  const bundleTradeBudgetUsd = Math.round(bundleTradeItems.reduce((sum, item) => sum + Math.max(0, item.paper_budget_usd), 0));
  const bundleExpectedEdgeUsd = Math.round(bundleItems.reduce((sum, item) => sum + Math.max(0, item.expected_edge_usd), 0));
  const controls = tickPlan.controls.some((control) => control.includes("fused edge action"))
    ? tickPlan.controls
    : [
        ...tickPlan.controls.slice(0, 2),
        "The fused edge action is injected into the current tick plan after the edge stack resolves, so first-render plans are not stale.",
        ...tickPlan.controls.slice(2),
      ];

  return {
    ...tickPlan,
    status,
    summary: autonomousTickPlanSummary(status, leader, executeCount, refreshCount),
    next_action: leader.blocker ?? leader.reason,
    tick_seconds: Math.max(2, Math.min(...rankedItems.map((item) => item.urgency_seconds))),
    bundle_action_count: bundleItems.length,
    bundle_trade_count: bundleTradeItems.length,
    bundle_refresh_count: bundleRefreshItems.length,
    bundle_symbols: bundleSymbols,
    bundle_expected_edge_usd: bundleExpectedEdgeUsd,
    bundle_trade_budget_usd: bundleTradeBudgetUsd,
    bundle_summary: autonomousTickPlanBundleSummary(bundleItems, bundleTradeItems.length, bundleRefreshItems.length, tickPlan.throughput_mode, tickPlan.throttle_reason),
    execute_count: executeCount,
    refresh_count: refreshCount,
    blocked_count: blockedCount,
    paper_budget_usd: Math.round(ready.reduce((sum, item) => sum + item.paper_budget_usd, 0)),
    expected_edge_usd: Math.round(ready.reduce((sum, item) => sum + Math.max(0, item.expected_edge_usd), 0)),
    risk_usd: Math.round(ready.reduce((sum, item) => sum + Math.max(0, item.risk_usd), 0)),
    controls,
    items: rankedItems,
  };
}

function autonomousTickPlanEdgeItem(
  edgeExecution: AutonomousEdgeStackExecution,
  loopDirector: AutonomousLoopDirector,
): AutonomousTickPlanItem {
  const action = autonomousTickPlanEdgeAction(edgeExecution);
  const status = autonomousTickPlanEdgeStatus(edgeExecution);
  const priority = autonomousTickPlanEdgePriority(edgeExecution);
  const paperBudget = edgeExecution.selected_action === "paper-buy" || edgeExecution.selected_action === "paper-sell"
    ? edgeExecution.paper_size_usd
    : 0;
  const riskUsd = edgeExecution.selected_action === "paper-buy"
    ? Math.max(0, edgeExecution.paper_size_usd - edgeExecution.expected_edge_usd)
    : edgeExecution.selected_action === "paper-sell" || edgeExecution.selected_action === "protect"
      ? Math.max(0, edgeExecution.paper_size_usd - Math.max(0, edgeExecution.projected_cash_delta_usd))
      : 0;
  const blocker = status === "blocked"
    ? edgeExecution.blockers[0] ?? edgeExecution.next_action
    : null;

  return {
    id: "tick-plan-edge-action",
    lane: "edge",
    action,
    symbol: edgeExecution.selected_symbol,
    priority,
    status,
    urgency_seconds: Math.max(2, Math.min(edgeExecution.review_after_seconds, loopDirector.next_tick_seconds || edgeExecution.review_after_seconds || 12)),
    paper_budget_usd: Math.round(Math.max(0, paperBudget)),
    expected_edge_usd: Math.round(Math.max(0, edgeExecution.expected_edge_usd)),
    risk_usd: Math.round(Math.max(0, riskUsd)),
    confidence_score: clamp(
      edgeExecution.edge_score +
        (edgeExecution.status === "queued" ? 12 : edgeExecution.status === "applied" || edgeExecution.status === "refresh-only" ? 6 : 0) -
        (edgeExecution.status === "blocked" ? 18 : 0),
      18,
      98,
    ),
    reason: edgeExecution.summary,
    blocker,
  };
}

function autonomousTickPlanEdgeAction(edgeExecution: AutonomousEdgeStackExecution): AutonomousTickPlanAction {
  if (edgeExecution.selected_action === "paper-sell" || edgeExecution.selected_action === "protect") return "protect-now";
  if (edgeExecution.selected_action === "paper-buy") return "trade-now";
  if (edgeExecution.selected_action === "route-refresh") return "refresh-routes";
  return "stand-down";
}

function autonomousTickPlanEdgeStatus(edgeExecution: AutonomousEdgeStackExecution): AutonomousTickPlanItem["status"] {
  if (edgeExecution.status === "queued" || edgeExecution.status === "refresh-only") return "ready";
  if (edgeExecution.status === "applied" || edgeExecution.status === "protect-only") return "watch";
  return "blocked";
}

function autonomousTickPlanEdgePriority(edgeExecution: AutonomousEdgeStackExecution): AutonomousTickPlanItem["priority"] {
  if (edgeExecution.selected_action === "paper-sell" || edgeExecution.selected_action === "protect") return "critical";
  if (edgeExecution.status === "queued" && edgeExecution.edge_score >= 72) return "high";
  if (edgeExecution.selected_action === "route-refresh") return edgeExecution.status === "refresh-only" ? "high" : "normal";
  if (edgeExecution.status === "blocked") return "normal";
  return "high";
}

function autonomousTickPlanStatus(
  leader: AutonomousTickPlanItem,
  executeCount: number,
  refreshCount: number,
  blockedCount: number,
): AutonomousTickPlan["status"] {
  if (leader.status === "blocked" && executeCount === 0 && refreshCount === 0) return blockedCount > 0 ? "blocked" : "stand-down";
  if (leader.action === "protect-now") return "protect";
  if (leader.action === "trade-now") return "trade";
  if (leader.action === "refresh-routes" || leader.action === "refresh-market") return "refresh";
  if (leader.action === "stand-down") return "stand-down";
  return "observe";
}

function autonomousTickPlanSummary(
  status: AutonomousTickPlan["status"],
  leader: AutonomousTickPlanItem,
  executeCount: number,
  refreshCount: number,
) {
  if (status === "protect") return `Next tick protects ${leader.symbol ?? "the paper book"} before adding risk.`;
  if (status === "trade") return `Next tick can act on ${leader.symbol ?? "the lead setup"} with ${formatCompactValue(leader.paper_budget_usd)} paper budget.`;
  if (status === "refresh") return `Next tick refreshes ${refreshCount} route or market input${refreshCount === 1 ? "" : "s"} before sizing.`;
  if (status === "blocked") return `Next tick is blocked: ${leader.blocker ?? leader.reason}`;
  if (status === "stand-down") return "Next tick stands down and keeps risk monitoring active.";
  return executeCount > 0 ? "Next tick waits for the best ready action to clear." : "Next tick observes until a trade, protect, or refresh lane clears.";
}

function autonomousTickPlanBundleItems(
  ready: AutonomousTickPlanItem[],
  maxActionsNextMinute: number,
) {
  if (maxActionsNextMinute <= 0) return [];
  return ready
    .filter((item) =>
      item.action === "trade-now" ||
      item.action === "protect-now" ||
      item.action === "refresh-routes" ||
      item.action === "refresh-market",
    )
    .sort((a, b) => autonomousTickPlanItemRank(b) - autonomousTickPlanItemRank(a))
    .slice(0, maxActionsNextMinute);
}

function autonomousTickPlanBundleSummary(
  bundleItems: AutonomousTickPlanItem[],
  tradeCount: number,
  refreshCount: number,
  throughputMode: AutonomousTickPlan["throughput_mode"],
  throttleReason: string,
) {
  if (bundleItems.length === 0) return `No next-minute execution bundle is open: ${throttleReason}`;
  if (throughputMode === "protect-first") return `Bundle is protect-first: ${tradeCount} paper execution lane${tradeCount === 1 ? "" : "s"} before fresh risk.`;
  if (throughputMode === "refresh-first") return `Bundle refreshes ${refreshCount} route or market lane${refreshCount === 1 ? "" : "s"} before sizing.`;
  const symbols = Array.from(new Set(bundleItems.map((item) => item.symbol).filter(Boolean))).slice(0, 3).join(", ");
  return `Bundle can rehearse ${bundleItems.length} local action${bundleItems.length === 1 ? "" : "s"}: ${symbols || "desk lanes"}.`;
}

function buildAutonomousTickGovernor({
  tickPlan,
  loopDirector,
  burstScheduler,
  discoveryIntake,
  routeRefreshExecution,
  walletTelemetry,
  tradeReadinessGate,
  riskGovernor,
  profitValidator,
}: {
  tickPlan: AutonomousTickPlan;
  loopDirector: AutonomousLoopDirector;
  burstScheduler: AutonomousBurstScheduler;
  discoveryIntake: AutonomousDiscoveryIntake;
  routeRefreshExecution: AutonomousRouteRefreshExecution;
  walletTelemetry: AutonomousWalletTelemetry;
  tradeReadinessGate: AutonomousTradeReadinessGate;
  riskGovernor: AutonomyRiskGovernor;
  profitValidator: AutonomousProfitValidator;
}): AutonomousTickGovernor {
  const leader = tickPlan.items.find((item) => item.status === "ready") ?? tickPlan.items[0] ?? null;
  const discoveryScore = autonomousTickGovernorDiscoveryScore(discoveryIntake);
  const routeScore = autonomousTickGovernorRouteScore(routeRefreshExecution, tickPlan);
  const walletScore = autonomousTickGovernorWalletScore(walletTelemetry);
  const readinessScore = autonomousTickGovernorReadinessScore(tradeReadinessGate, riskGovernor, loopDirector);
  const profitScore = autonomousTickGovernorProfitScore(profitValidator, tickPlan);
  const throughputScore = autonomousTickGovernorThroughputScore(tickPlan, loopDirector, burstScheduler);
  const checks: AutonomousTickGovernorCheck[] = [
    {
      id: "discovery",
      label: "Discovery",
      status: discoveryScore >= 62 ? "pass" : discoveryScore >= 38 ? "watch" : "fail",
      score: discoveryScore,
      detail: discoveryIntake.next_action,
    },
    {
      id: "route",
      label: "Route",
      status: routeScore >= 62 ? "pass" : routeScore >= 38 ? "watch" : "fail",
      score: routeScore,
      detail: routeRefreshExecution.next_action,
    },
    {
      id: "wallet",
      label: "Wallet",
      status: walletScore >= 62 ? "pass" : walletScore >= 38 ? "watch" : "fail",
      score: walletScore,
      detail: walletTelemetry.next_action,
    },
    {
      id: "readiness",
      label: "Readiness",
      status: readinessScore >= 62 ? "pass" : readinessScore >= 38 ? "watch" : "fail",
      score: readinessScore,
      detail: tradeReadinessGate.next_action,
    },
    {
      id: "profit",
      label: "Profit proof",
      status: profitScore >= 62 ? "pass" : profitScore >= 38 ? "watch" : "fail",
      score: profitScore,
      detail: profitValidator.next_action,
    },
    {
      id: "throughput",
      label: "Throughput",
      status: throughputScore >= 62 ? "pass" : throughputScore >= 38 ? "watch" : "fail",
      score: throughputScore,
      detail: tickPlan.throttle_reason,
    },
  ];
  const blockers = autonomousTickGovernorBlockers({
    tickPlan,
    loopDirector,
    burstScheduler,
    discoveryIntake,
    routeRefreshExecution,
    walletTelemetry,
    tradeReadinessGate,
    riskGovernor,
    profitValidator,
    checks,
  });
  const decisionScore = Math.round(average(checks.map((check) => check.score)));
  const protectiveSellReleaseUsd = Math.round(Math.max(
    0,
    tickPlan.items
      .filter((item) => item.status === "ready" && item.action === "protect-now")
      .reduce((sum, item) => sum + Math.max(item.paper_budget_usd, item.risk_usd), 0),
    tickPlan.status === "protect" || tickPlan.throughput_mode === "protect-first" ? tickPlan.risk_usd : 0,
    profitValidator.should_protect_first ? profitValidator.expected_value_usd : 0,
  ));
  const protectiveSellOverride = protectiveSellReleaseUsd > 0 ||
    tickPlan.status === "protect" ||
    tickPlan.throughput_mode === "protect-first" ||
    profitValidator.should_protect_first;
  const status = autonomousTickGovernorStatus({
    tickPlan,
    loopDirector,
    discoveryIntake,
    routeRefreshExecution,
    walletTelemetry,
    tradeReadinessGate,
    riskGovernor,
    profitValidator,
    blockers,
    decisionScore,
    protectiveSellOverride,
  });
  const action = autonomousTickGovernorAction(status, tickPlan, routeRefreshExecution);
  const canAutoAdvance = status === "run-now" || status === "protect-first";
  const rearmPlan = autonomousTickGovernorRearmPlan({
    status,
    action,
    tickPlan,
    loopDirector,
    discoveryIntake,
    routeRefreshExecution,
    walletTelemetry,
    tradeReadinessGate,
    riskGovernor,
    profitValidator,
    blockers,
    protectiveSellOverride,
    protectiveSellReleaseUsd,
  });
  const maxPaperTrades = canAutoAdvance
    ? Math.max(1, Math.min(tickPlan.bundle_trade_count || tickPlan.execute_count || 1, burstScheduler.max_trades_next_tick || 1, tradeReadinessGate.max_batch_trades || 1))
    : 0;

  return {
    mode: "autonomous-tick-governor",
    status,
    action,
    summary: autonomousTickGovernorSummary(status, action, decisionScore, leader, blockers),
    next_action: autonomousTickGovernorNextAction(status, action, leader, tickPlan, routeRefreshExecution, discoveryIntake, blockers),
    can_auto_advance: canAutoAdvance,
    protective_sell_override: protectiveSellOverride && status === "protect-first",
    protective_sell_release_usd: status === "protect-first" ? protectiveSellReleaseUsd : 0,
    rearm_mode: rearmPlan.mode,
    rearm_eta_seconds: rearmPlan.etaSeconds,
    rearm_steps: rearmPlan.steps,
    should_request_route_quote: (action === "refresh-routes" || rearmPlan.mode === "route-refresh") && routeRefreshExecution.can_request_readonly_quote,
    should_refresh_market_data: action === "refresh-market" || rearmPlan.mode === "market-refresh" || discoveryIntake.status === "refresh-first" || loopDirector.feed_pressure_score >= 62,
    should_protect_first: status === "protect-first",
    should_trade: status === "run-now" && action === "trade",
    next_tick_seconds: status === "paused" || status === "blocked" ? 0 : Math.max(1, Math.min(tickPlan.tick_seconds, loopDirector.next_tick_seconds || tickPlan.tick_seconds, burstScheduler.next_tick_seconds || tickPlan.tick_seconds)),
    max_paper_trades: maxPaperTrades,
    paper_budget_usd: canAutoAdvance ? Math.min(tickPlan.bundle_trade_budget_usd || tickPlan.paper_budget_usd, tickPlan.next_minute_trade_budget_usd || tickPlan.paper_budget_usd) : 0,
    expected_edge_usd: Math.max(0, tickPlan.bundle_expected_edge_usd || tickPlan.expected_edge_usd, profitValidator.expected_value_usd ?? 0),
    risk_budget_usd: Math.max(0, tickPlan.risk_usd, burstScheduler.risk_budget_next_tick_usd),
    decision_score: decisionScore,
    confidence_score: leader ? Math.round((leader.confidence_score + decisionScore) / 2) : decisionScore,
    leader_symbol: leader?.symbol ?? discoveryIntake.leader_symbol,
    blockers,
    controls: [
      "Combines discovery freshness, route proof, wallet telemetry, readiness gates, profit validation, and throughput before the client loop advances.",
      "Protect and refresh decisions outrank fresh buys when wallet, route, or market evidence is weak.",
      "Protect-first override can rehearse eligible paper sells while fresh paper buys remain paused.",
      "Paused trading can still run read-only re-arm steps such as route or market refresh before another paper spend.",
      "Auto-advance permission is local paper-only and cannot sign, submit, settle, custody funds, or guarantee profit.",
    ],
    checks,
  };
}

function autonomousTickGovernorDiscoveryScore(discoveryIntake: AutonomousDiscoveryIntake) {
  const statusBonus = discoveryIntake.status === "attack-ready"
    ? 18
    : discoveryIntake.status === "probe-ready"
      ? 10
      : discoveryIntake.status === "refresh-first" || discoveryIntake.status === "sample"
        ? -4
        : discoveryIntake.status === "blocked"
          ? -24
          : 0;
  return clamp(Math.round(
    discoveryIntake.intake_score * 0.44 +
      discoveryIntake.source_coverage_pct * 0.2 +
      discoveryIntake.pair_coverage_pct * 0.18 +
      Math.max(0, 100 - discoveryIntake.paid_hype_count * 16) * 0.1 +
      Math.min(100, discoveryIntake.mapped_candidate_count * 12) * 0.08 +
      statusBonus,
  ), 0, 100);
}

function autonomousTickGovernorRouteScore(
  routeRefreshExecution: AutonomousRouteRefreshExecution,
  tickPlan: AutonomousTickPlan,
) {
  const statusScore = routeRefreshExecution.status === "ready"
    ? 86
    : routeRefreshExecution.status === "requesting"
      ? 68
      : routeRefreshExecution.status === "watching"
        ? 54
        : routeRefreshExecution.status === "blocked"
          ? 16
          : 42;
  const refreshPenalty = tickPlan.status === "refresh" || tickPlan.throughput_mode === "refresh-first" ? 12 : 0;
  return clamp(Math.round(statusScore * 0.58 + routeRefreshExecution.route_confidence_score * 0.42 - refreshPenalty), 0, 100);
}

function autonomousTickGovernorWalletScore(walletTelemetry: AutonomousWalletTelemetry) {
  const statusScore = walletTelemetry.status === "compounding" || walletTelemetry.status === "harvest"
    ? 88
    : walletTelemetry.status === "recover"
      ? 58
      : walletTelemetry.status === "cooldown"
        ? 40
        : walletTelemetry.status === "protect"
          ? 22
          : 62;
  const drawdownPenalty = Math.min(35, walletTelemetry.max_drawdown_pct * 5);
  const slopeBoost = clamp(Math.round(walletTelemetry.slope_usd_per_tick), -12, 12);
  return clamp(Math.round(statusScore - drawdownPenalty + slopeBoost + Math.max(0, 70 - walletTelemetry.exposure_pct) * 0.08), 0, 100);
}

function autonomousTickGovernorReadinessScore(
  tradeReadinessGate: AutonomousTradeReadinessGate,
  riskGovernor: AutonomyRiskGovernor,
  loopDirector: AutonomousLoopDirector,
) {
  const gateScore = tradeReadinessGate.status === "ready" || tradeReadinessGate.status === "paper-only"
    ? tradeReadinessGate.gate_score
    : tradeReadinessGate.status === "exit-only" || tradeReadinessGate.status === "repair-first"
      ? Math.min(tradeReadinessGate.gate_score, 52)
      : 18;
  const riskScore = riskGovernor.allow_paper_advance ? 76 : 18;
  const loopScore = loopDirector.should_issue_daemon_tick ? 76 : loopDirector.client_should_run ? 52 : 18;
  return clamp(Math.round(gateScore * 0.5 + riskScore * 0.25 + loopScore * 0.25), 0, 100);
}

function autonomousTickGovernorProfitScore(
  profitValidator: AutonomousProfitValidator,
  tickPlan: AutonomousTickPlan,
) {
  const permissionScore = profitValidator.permission === "scale"
    ? 88
    : profitValidator.permission === "trade"
      ? 76
      : profitValidator.permission === "probe"
        ? 58
        : profitValidator.permission === "protect-only" || profitValidator.permission === "refresh-first"
          ? 46
          : 18;
  const edgeScore = clamp(Math.round((tickPlan.expected_edge_usd - tickPlan.risk_usd) / 3 + 50), 0, 100);
  return clamp(Math.round(permissionScore * 0.64 + edgeScore * 0.36), 0, 100);
}

function autonomousTickGovernorThroughputScore(
  tickPlan: AutonomousTickPlan,
  loopDirector: AutonomousLoopDirector,
  burstScheduler: AutonomousBurstScheduler,
) {
  const modeScore = tickPlan.throughput_mode === "burst"
    ? 92
    : tickPlan.throughput_mode === "steady"
      ? 74
      : tickPlan.throughput_mode === "protect-first" || tickPlan.throughput_mode === "refresh-first"
        ? 56
        : tickPlan.throughput_mode === "cooldown"
          ? 34
          : 18;
  return clamp(Math.round(
    modeScore * 0.46 +
      Math.min(100, tickPlan.max_actions_next_minute * 18) * 0.22 +
      Math.min(100, loopDirector.ticks_remaining_before_pause * 22) * 0.14 +
      Math.min(100, burstScheduler.max_trades_next_tick * 24) * 0.18,
  ), 0, 100);
}

function autonomousTickGovernorRearmPlan({
  status,
  action,
  tickPlan,
  loopDirector,
  discoveryIntake,
  routeRefreshExecution,
  walletTelemetry,
  tradeReadinessGate,
  riskGovernor,
  profitValidator,
  blockers,
  protectiveSellOverride,
  protectiveSellReleaseUsd,
}: {
  status: AutonomousTickGovernorStatus;
  action: AutonomousTickGovernorAction;
  tickPlan: AutonomousTickPlan;
  loopDirector: AutonomousLoopDirector;
  discoveryIntake: AutonomousDiscoveryIntake;
  routeRefreshExecution: AutonomousRouteRefreshExecution;
  walletTelemetry: AutonomousWalletTelemetry;
  tradeReadinessGate: AutonomousTradeReadinessGate;
  riskGovernor: AutonomyRiskGovernor;
  profitValidator: AutonomousProfitValidator;
  blockers: string[];
  protectiveSellOverride: boolean;
  protectiveSellReleaseUsd: number;
}): { mode: AutonomousTickGovernorRearmMode; etaSeconds: number; steps: string[] } {
  const routeNeedsRepair = routeRefreshExecution.route_refresh_required ||
    routeRefreshExecution.status === "blocked" ||
    routeRefreshExecution.status === "watching" ||
    routeRefreshExecution.status === "requesting" ||
    tradeReadinessGate.route_refresh_required ||
    blockers.some((blocker) => blocker.toLowerCase().includes("route"));
  const marketNeedsRepair = discoveryIntake.status === "refresh-first" ||
    loopDirector.feed_pressure_score >= 62 ||
    blockers.some((blocker) => {
      const lower = blocker.toLowerCase();
      return lower.includes("market") || lower.includes("feed") || lower.includes("candle");
    });

  if (status === "run-now") {
    return {
      mode: "ready",
      etaSeconds: Math.max(1, tickPlan.tick_seconds),
      steps: [
        `Paper trade can run now for ${tickPlan.items.find((item) => item.status === "ready")?.symbol ?? "the lead setup"}.`,
        "Keep route, wallet, readiness, and profit gates attached before applying the local ledger fill.",
      ],
    };
  }

  if (status === "protect-first" || protectiveSellOverride) {
    return {
      mode: "sell-first",
      etaSeconds: Math.max(1, Math.min(tickPlan.tick_seconds || 6, loopDirector.next_tick_seconds || 6)),
      steps: [
        `Rehearse up to ${formatCompactValue(protectiveSellReleaseUsd)} in defensive paper sells before any fresh buy.`,
        routeNeedsRepair ? "Refresh the sell route after the release if route evidence is still stale." : "Re-score wallet heat and profit control after the release.",
      ],
    };
  }

  if (routeNeedsRepair && routeRefreshExecution.can_request_readonly_quote) {
    return {
      mode: "route-refresh",
      etaSeconds: Math.max(1, Math.min(routeRefreshExecution.next_refresh_seconds || tickPlan.tick_seconds || 12, 30)),
      steps: [
        routeRefreshExecution.selected_symbol
          ? `Refresh read-only route proof for ${routeRefreshExecution.selected_symbol}.`
          : "Refresh read-only route proof for the selected paper lane.",
        "Keep paper buys paused until the route, impact, and freshness checks are scored again.",
      ],
    };
  }

  if (marketNeedsRepair) {
    return {
      mode: "market-refresh",
      etaSeconds: Math.max(3, Math.min(loopDirector.next_tick_seconds || tickPlan.tick_seconds || 15, 45)),
      steps: [
        "Refresh market, candle, or feed evidence before another sizing pass.",
        "Re-rank trending coins after the updated signal/noise and wallet checks arrive.",
      ],
    };
  }

  if (
    loopDirector.status === "cooldown" ||
    walletTelemetry.status === "cooldown" ||
    profitValidator.permission === "stand-down" ||
    tradeReadinessGate.status === "repair-first"
  ) {
    return {
      mode: "cooldown",
      etaSeconds: Math.max(6, Math.min(loopDirector.next_tick_seconds || tickPlan.tick_seconds || 30, 60)),
      steps: [
        blockers[0] ?? walletTelemetry.next_action ?? profitValidator.next_action,
        "Wait for the next paper-memory or readiness update before reopening fresh entries.",
      ],
    };
  }

  return {
    mode: status === "blocked" || !riskGovernor.allow_paper_advance || tradeReadinessGate.status === "blocked" ? "blocked" : "cooldown",
    etaSeconds: 0,
    steps: [
      blockers[0] ?? "The autonomous desk needs a gate to clear before it can re-arm.",
      "Do not open fresh paper exposure until the blocker is repaired.",
    ],
  };
}

function autonomousTickGovernorBlockers({
  tickPlan,
  loopDirector,
  burstScheduler,
  discoveryIntake,
  routeRefreshExecution,
  walletTelemetry,
  tradeReadinessGate,
  riskGovernor,
  profitValidator,
  checks,
}: {
  tickPlan: AutonomousTickPlan;
  loopDirector: AutonomousLoopDirector;
  burstScheduler: AutonomousBurstScheduler;
  discoveryIntake: AutonomousDiscoveryIntake;
  routeRefreshExecution: AutonomousRouteRefreshExecution;
  walletTelemetry: AutonomousWalletTelemetry;
  tradeReadinessGate: AutonomousTradeReadinessGate;
  riskGovernor: AutonomyRiskGovernor;
  profitValidator: AutonomousProfitValidator;
  checks: AutonomousTickGovernorCheck[];
}) {
  const blockers: string[] = [];
  if (tickPlan.status === "blocked") blockers.push(tickPlan.next_action);
  if (!loopDirector.client_should_run) blockers.push(loopDirector.stop_reason ?? loopDirector.tick_reason);
  if (!riskGovernor.allow_paper_advance) blockers.push(riskGovernor.actions[0] ?? riskGovernor.summary);
  if (tradeReadinessGate.status === "blocked") blockers.push(tradeReadinessGate.blockers[0] ?? tradeReadinessGate.next_action);
  if (profitValidator.permission === "stand-down") blockers.push(profitValidator.next_action);
  if (burstScheduler.status === "stand-down" && tickPlan.execute_count > 0) blockers.push(burstScheduler.next_action);
  if (discoveryIntake.status === "blocked" && tickPlan.status === "trade") blockers.push(discoveryIntake.next_action);
  if (routeRefreshExecution.status === "blocked" && (tickPlan.status === "trade" || tickPlan.throughput_mode === "refresh-first")) blockers.push(routeRefreshExecution.next_action);
  if (walletTelemetry.status === "protect" && tickPlan.status === "trade") blockers.push(walletTelemetry.next_action);
  checks.filter((check) => check.status === "fail").forEach((check) => blockers.push(`${check.label}: ${check.detail}`));
  return [...new Set(blockers.filter(Boolean))].slice(0, 6);
}

function autonomousTickGovernorStatus({
  tickPlan,
  loopDirector,
  discoveryIntake,
  routeRefreshExecution,
  walletTelemetry,
  tradeReadinessGate,
  riskGovernor,
  profitValidator,
  blockers,
  decisionScore,
  protectiveSellOverride,
}: {
  tickPlan: AutonomousTickPlan;
  loopDirector: AutonomousLoopDirector;
  discoveryIntake: AutonomousDiscoveryIntake;
  routeRefreshExecution: AutonomousRouteRefreshExecution;
  walletTelemetry: AutonomousWalletTelemetry;
  tradeReadinessGate: AutonomousTradeReadinessGate;
  riskGovernor: AutonomyRiskGovernor;
  profitValidator: AutonomousProfitValidator;
  blockers: string[];
  decisionScore: number;
  protectiveSellOverride: boolean;
}): AutonomousTickGovernorStatus {
  if (blockers.length > 0 && !protectiveSellOverride && !tickPlan.items.some((item) => item.action === "protect-now" && item.status === "ready")) return "blocked";
  if (
    protectiveSellOverride &&
    riskGovernor.allow_paper_advance &&
    tradeReadinessGate.can_apply_sells &&
    tradeReadinessGate.status !== "blocked"
  ) return "protect-first";
  if (!loopDirector.client_should_run || loopDirector.status === "paused" || loopDirector.status === "cooldown") return "paused";
  if (!riskGovernor.allow_paper_advance || tradeReadinessGate.status === "blocked") return "blocked";
  if (walletTelemetry.status === "protect" || profitValidator.permission === "protect-only" || tickPlan.status === "protect") return "protect-first";
  if (
    tickPlan.status === "refresh" ||
    tickPlan.throughput_mode === "refresh-first" ||
    discoveryIntake.status === "refresh-first" ||
    routeRefreshExecution.route_refresh_required
  ) return "refresh-first";
  if (tickPlan.status === "trade" && loopDirector.should_issue_daemon_tick && decisionScore >= 54) return "run-now";
  if (tickPlan.status === "stand-down" || profitValidator.permission === "stand-down") return "paused";
  return "observe";
}

function autonomousTickGovernorAction(
  status: AutonomousTickGovernorStatus,
  tickPlan: AutonomousTickPlan,
  routeRefreshExecution: AutonomousRouteRefreshExecution,
): AutonomousTickGovernorAction {
  if (status === "run-now") return "trade";
  if (status === "protect-first") return "protect";
  if (status === "refresh-first") return routeRefreshExecution.route_refresh_required || tickPlan.items.some((item) => item.action === "refresh-routes" && item.status === "ready") ? "refresh-routes" : "refresh-market";
  if (status === "blocked" || status === "paused") return "pause";
  return "observe";
}

function autonomousTickGovernorSummary(
  status: AutonomousTickGovernorStatus,
  action: AutonomousTickGovernorAction,
  score: number,
  leader: AutonomousTickPlanItem | null,
  blockers: string[],
) {
  if (status === "run-now") return `Tick governor permits a local paper ${action} tick for ${leader?.symbol ?? "the lead setup"} at ${score}/100.`;
  if (status === "protect-first") return `Tick governor sends the next local tick to protection before fresh risk at ${score}/100.`;
  if (status === "refresh-first") return `Tick governor refreshes ${action === "refresh-routes" ? "route proof" : "market evidence"} before sizing the next paper trade.`;
  if (status === "blocked") return blockers[0] ?? "Tick governor blocks the local paper tick until required gates clear.";
  if (status === "paused") return blockers[0] ?? "Tick governor pauses while loop, risk, or profit proof cools down.";
  return `Tick governor observes at ${score}/100 until trade, protect, or refresh evidence improves.`;
}

function autonomousTickGovernorNextAction(
  status: AutonomousTickGovernorStatus,
  action: AutonomousTickGovernorAction,
  leader: AutonomousTickPlanItem | null,
  tickPlan: AutonomousTickPlan,
  routeRefreshExecution: AutonomousRouteRefreshExecution,
  discoveryIntake: AutonomousDiscoveryIntake,
  blockers: string[],
) {
  if (blockers[0] && (status === "blocked" || status === "paused")) return blockers[0];
  if (action === "refresh-routes") return routeRefreshExecution.next_action;
  if (action === "refresh-market") return discoveryIntake.next_action;
  if (action === "trade" || action === "protect") return leader?.reason ?? tickPlan.next_action;
  return tickPlan.throttle_reason;
}

type TickBundleSourceExecution = {
  paper_trade_ready: boolean;
  ledger_applied: boolean;
  paper_trade: AutonomousTrade | null;
  summary: string;
  next_action: string;
  blockers?: string[];
};

function tickBundleSourceExecutions({
  commandCenterExecution,
  positionRiskExecution,
  highFrequencyRaceExecution,
  opportunityRaceExecution,
  trendChaseExecution,
  scoutLifecycle,
}: {
  commandCenterExecution?: AutonomousCommandCenterExecution;
  positionRiskExecution: AutonomousPositionRiskExecution;
  highFrequencyRaceExecution: HighFrequencyProfitRaceExecution;
  opportunityRaceExecution: AutonomousOpportunityRaceExecution;
  trendChaseExecution: TrendChaseExecution;
  scoutLifecycle: ScoutLifecycleController;
}) {
  return new Map<string, TickBundleSourceExecution>([
    ...(commandCenterExecution ? [["tick-plan-command-center", commandCenterExecution] as const] : []),
    ["tick-plan-position-risk", positionRiskExecution],
    ["tick-plan-high-frequency", highFrequencyRaceExecution],
    ["tick-plan-race-execution", opportunityRaceExecution],
    ["tick-plan-trend-chase", trendChaseExecution],
    ["tick-plan-scout-lifecycle", scoutLifecycle],
  ]);
}

function autonomousTickBundleRouteFreshnessBlocker(
  item: AutonomousTickPlanItem | null,
  trade: AutonomousTrade | null,
  routeRefreshExecution: AutonomousRouteRefreshExecution | undefined,
) {
  if (!item || !routeRefreshExecution) return null;
  if (item.action !== "trade-now" || item.lane !== "entry") return null;
  const side = trade?.side ?? "buy";
  if (side !== "buy") return null;
  const symbolMatches = !routeRefreshExecution.selected_symbol ||
    !item.symbol ||
    routeRefreshExecution.selected_symbol === item.symbol;
  if (!symbolMatches) return null;
  if (routeRefreshExecution.status === "blocked") {
    return routeRefreshExecution.blockers[0] ?? `Route refresh is blocked for ${item.symbol ?? "the bundle entry lane"}.`;
  }
  if (routeRefreshExecution.route_refresh_required && !routeRefreshExecution.can_request_readonly_quote && routeRefreshExecution.status !== "ready") {
    return routeRefreshExecution.next_action;
  }
  return null;
}

function buildAutonomousTickBundleExecution({
  tickPlan,
  routeRefreshExecution,
  alphaDecay,
  sourceQuality,
  commandCenterExecution,
  positionRiskExecution,
  highFrequencyRaceExecution,
  opportunityRaceExecution,
  trendChaseExecution,
  scoutLifecycle,
}: {
  tickPlan: AutonomousTickPlan;
  routeRefreshExecution?: AutonomousRouteRefreshExecution;
  alphaDecay?: AlphaDecayController;
  sourceQuality?: AutonomousSourceQualityOracle;
  commandCenterExecution?: AutonomousCommandCenterExecution;
  positionRiskExecution: AutonomousPositionRiskExecution;
  highFrequencyRaceExecution: HighFrequencyProfitRaceExecution;
  opportunityRaceExecution: AutonomousOpportunityRaceExecution;
  trendChaseExecution: TrendChaseExecution;
  scoutLifecycle: ScoutLifecycleController;
}): AutonomousTickBundleExecution {
  const sourceExecutions = tickBundleSourceExecutions({
    commandCenterExecution,
    positionRiskExecution,
    highFrequencyRaceExecution,
    opportunityRaceExecution,
    trendChaseExecution,
    scoutLifecycle,
  });
  const readyBundleItems = autonomousTickPlanBundleItems(tickPlan.items, tickPlan.max_actions_next_minute);
  const appliedBundleItems = tickPlan.items.filter((item) =>
    (item.action === "trade-now" || item.action === "protect-now") &&
    sourceExecutions.get(item.id)?.ledger_applied === true,
  );
  const bundleItems = [
    ...readyBundleItems,
    ...appliedBundleItems.filter((item) => !readyBundleItems.some((ready) => ready.id === item.id)),
  ];
  const items = bundleItems.map((item): AutonomousTickBundleExecutionItem => {
    const source = sourceExecutions.get(item.id);
    if (item.action === "refresh-routes" || item.action === "refresh-market") {
      return {
        id: `bundle-${item.id}`,
        source_item_id: item.id,
        symbol: item.symbol,
        action: item.action,
        status: item.status === "blocked" ? "blocked" : "refresh-only",
        side: "hold",
        lane: item.lane,
        paper_trade_id: null,
        notional_usd: 0,
        expected_edge_usd: item.expected_edge_usd,
        cash_delta_usd: 0,
        exposure_delta_usd: 0,
        reason: item.reason,
        blocker: item.status === "blocked" ? item.blocker ?? "Refresh lane is blocked before bundle rehearsal." : null,
      };
    }
    if (!source) {
      return {
        id: `bundle-${item.id}`,
        source_item_id: item.id,
        symbol: item.symbol,
        action: item.action,
        status: item.status === "blocked" ? "blocked" : "skipped",
        side: "hold",
        lane: item.lane,
        paper_trade_id: null,
        notional_usd: 0,
        expected_edge_usd: item.expected_edge_usd,
        cash_delta_usd: 0,
        exposure_delta_usd: 0,
        reason: item.reason,
        blocker: item.status === "blocked" ? item.blocker ?? "Bundle lane is blocked." : "This lane delegates to the existing one-fill paper advance path.",
      };
    }
    const rawTrade = source.paper_trade;
    const sourceSizedTrade = source.ledger_applied
      ? rawTrade
      : autonomousSourceQualityAdjustedTrade(sourceQuality, rawTrade);
    const sourceQualitySizingBlocker = !source.ledger_applied
      ? autonomousSourceQualitySizingBlocker(sourceQuality, rawTrade)
      : null;
    const trade = sourceSizedTrade ?? rawTrade;
    const notional = Math.round(trade?.size_usd ?? item.paper_budget_usd);
    const side = trade?.side ?? (item.action === "protect-now" ? "sell" : item.action === "trade-now" ? "buy" : "hold");
    const cashDelta = trade ? (trade.side === "buy" ? -trade.size_usd : trade.size_usd) : 0;
    const exposureDelta = trade ? (trade.side === "buy" ? trade.size_usd : -trade.size_usd) : 0;
    const routeFreshnessBlocker = autonomousTickBundleRouteFreshnessBlocker(item, rawTrade, routeRefreshExecution);
    const alphaDecayBlocker = autonomousAlphaDecayTradeBlocker(alphaDecay, rawTrade);
    const sourceQualityBlocker = autonomousSourceQualityTradeBlocker(sourceQuality, rawTrade);
    const blockers = [...new Set([...(source.blockers ?? []), item.blocker, routeFreshnessBlocker, alphaDecayBlocker, sourceQualityBlocker, sourceQualitySizingBlocker].filter((entry): entry is string => Boolean(entry)))];
    const status: AutonomousTickBundleExecutionItem["status"] = source.ledger_applied
      ? "applied"
      : source.paper_trade_ready && trade && blockers.length === 0
        ? "ready"
        : blockers.length > 0 || item.status === "blocked"
          ? "blocked"
          : "skipped";
    return {
      id: `bundle-${item.id}`,
      source_item_id: item.id,
      symbol: item.symbol ?? trade?.symbol ?? null,
      action: item.action,
      status,
      side,
      lane: item.lane,
      paper_trade_id: trade?.id ?? null,
      notional_usd: status === "ready" || status === "applied" ? notional : 0,
      expected_edge_usd: item.expected_edge_usd,
      cash_delta_usd: status === "ready" || status === "applied" ? Math.round(cashDelta) : 0,
      exposure_delta_usd: status === "ready" || status === "applied" ? Math.round(exposureDelta) : 0,
      reason: source.summary || item.reason,
      blocker: status === "blocked" ? blockers[0] ?? source.next_action : status === "skipped" ? source.next_action : null,
    };
  });

  const readyTradeCount = items.filter((item) => item.status === "ready").length;
  const appliedTradeCount = items.filter((item) => item.status === "applied").length;
  const refreshOnlyCount = items.filter((item) => item.status === "refresh-only").length;
  const blockedCount = items.filter((item) => item.status === "blocked").length;
  const skippedCount = items.filter((item) => item.status === "skipped").length;
  const routeVetoedItems = items.filter((item) => Boolean(autonomousTickBundleRouteFreshnessBlocker(
    tickPlan.items.find((planItem) => planItem.id === item.source_item_id) ?? null,
    item.paper_trade_id
      ? sourceExecutions.get(item.source_item_id)?.paper_trade ?? null
      : null,
    routeRefreshExecution,
  )));
  const routeRefreshBlocker = routeVetoedItems.find((item) => item.blocker)?.blocker ?? null;
  const status = tickBundleExecutionStatus(items, readyTradeCount, appliedTradeCount, refreshOnlyCount, blockedCount, skippedCount);
  const paperTradeIds = items.map((item) => item.paper_trade_id).filter((id): id is string => Boolean(id));

  return {
    mode: "tick-bundle-paper-rehearsal",
    status,
    execution_boundary: "paper-ledger-only",
    route_refresh_status: routeRefreshExecution?.status ?? "idle",
    route_refresh_vetoed: routeVetoedItems.length > 0,
    route_refresh_blocker: routeRefreshBlocker,
    route_vetoed_count: routeVetoedItems.length,
    bundle_size: items.length,
    ready_trade_count: readyTradeCount,
    applied_trade_count: appliedTradeCount,
    refresh_only_count: refreshOnlyCount,
    blocked_count: blockedCount,
    skipped_count: skippedCount,
    paper_trade_ids: paperTradeIds,
    projected_cash_delta_usd: Math.round(items.reduce((sum, item) => sum + item.cash_delta_usd, 0)),
    projected_exposure_delta_usd: Math.round(items.reduce((sum, item) => sum + item.exposure_delta_usd, 0)),
    projected_edge_usd: Math.round(items.reduce((sum, item) => sum + Math.max(0, item.expected_edge_usd), 0)),
    summary: tickBundleExecutionSummary(status, items, readyTradeCount, appliedTradeCount, refreshOnlyCount, blockedCount),
    next_action: tickBundleExecutionNextAction(status, items, tickPlan),
    controls: [
      "Can apply the current next-minute tick bundle as bounded local paper fills; it does not create a new live execution path.",
      "Ready paper fills still pass through the existing idempotent paper-ledger boundary before cash or exposure changes.",
      "Fresh entry bundle lanes are vetoed when route-refresh execution is blocked or still requires read-only quote evidence.",
      "Fresh entry bundle lanes are vetoed when alpha timing decay says the setup is stale, late, or above the timing cap.",
      "Fresh entry bundle lanes are vetoed when source quality marks the candidate paid-hype, refresh-first, blocked, or missing current proof.",
      "Refresh-only lanes can accelerate route or market checks, but they do not mutate the paper ledger.",
      "The bundle stays capped by the tick plan throughput envelope and cannot sign, submit, settle, or move live funds.",
    ],
    items,
  };
}

function tickBundleUsd(value: number) {
  const prefix = value < 0 ? "-" : "";
  return `${prefix}$${Math.round(Math.abs(value)).toLocaleString("en-US")}`;
}

function buildAutonomousTickBundleFeedback({
  tickPlan,
  bundleExecution,
  walletTelemetry,
  performance,
  churnEfficiency,
  daemonMemory,
  tradeReadinessGate,
}: {
  tickPlan: AutonomousTickPlan;
  bundleExecution: AutonomousTickBundleExecution;
  walletTelemetry: AutonomousWalletTelemetry;
  performance: PerformanceScorecard;
  churnEfficiency: ChurnEfficiencyAuditor;
  daemonMemory: PaperDaemonMemory;
  tradeReadinessGate: AutonomousTradeReadinessGate;
}): AutonomousTickBundleFeedback {
  const baseCap = Math.max(0, Math.min(
    tickPlan.max_actions_next_minute,
    tradeReadinessGate.max_batch_trades,
    churnEfficiency.max_trades_next_cycle,
  ));
  const readyProtectiveSells = bundleExecution.items.filter((item) =>
    item.status === "ready" &&
    item.side === "sell" &&
    item.action === "protect-now",
  ).length;
  const readyFreshBuys = bundleExecution.items.filter((item) =>
    item.status === "ready" &&
    item.side === "buy",
  ).length;
  const walletScore = walletTelemetry.status === "compounding"
    ? 16
    : walletTelemetry.status === "harvest"
      ? 10
      : walletTelemetry.status === "flat"
        ? 2
        : walletTelemetry.status === "recover"
          ? -10
          : walletTelemetry.status === "cooldown"
            ? -18
            : -24;
  const performanceScore = performance.status === "compounding"
    ? 14
    : performance.status === "learning"
      ? 2
      : performance.status === "overtrading"
        ? -16
        : -24;
  const churnScore = churnEfficiency.status === "accelerate"
    ? 14
    : churnEfficiency.status === "selective"
      ? -2
      : churnEfficiency.status === "cooldown"
        ? -20
        : churnEfficiency.status === "stop"
          ? -34
          : 0;
  const pnlScore = clamp(
    Math.round(walletTelemetry.window_pnl_usd / 18 + walletTelemetry.net_pnl_usd / 120),
    -18,
    18,
  );
  const drawdownPenalty = walletTelemetry.max_drawdown_pct >= 8
    ? 18
    : walletTelemetry.max_drawdown_pct >= 5
      ? 10
      : walletTelemetry.max_drawdown_pct >= 3
        ? 5
        : 0;
  const lossPenalty = Math.min(18, daemonMemory.consecutive_loss_count * 6);
  const blockPenalty = Math.min(12, bundleExecution.blocked_count * 3 + bundleExecution.skipped_count * 2);
  const readinessBoost = Math.min(10, bundleExecution.ready_trade_count * 3 + Math.max(0, bundleExecution.projected_edge_usd) / 25);
  const rawScore = 52 + walletScore + performanceScore + churnScore + pnlScore + readinessBoost - drawdownPenalty - lossPenalty - blockPenalty;
  const bundleQualityScore = clamp(Math.round(rawScore), 0, 100);
  const protectRequested = readyProtectiveSells > 0 ||
    walletTelemetry.status === "protect" ||
    performance.status === "protect" ||
    tickPlan.throughput_mode === "protect-first";
  const cooldownRequested = daemonMemory.pause_new_entries ||
    churnEfficiency.entry_permission === "cooldown" ||
    tradeReadinessGate.status === "repair-first" ||
    tradeReadinessGate.status === "exit-only" ||
    walletTelemetry.status === "cooldown" ||
    performance.status === "overtrading";
  const blocked = baseCap <= 0 || churnEfficiency.entry_permission === "blocked";
  const status: AutonomousTickBundleFeedback["status"] = bundleExecution.bundle_size === 0
    ? "idle"
    : blocked || protectRequested || bundleQualityScore < 26
      ? "protect"
      : cooldownRequested || bundleQualityScore < 45
        ? "cooldown"
        : bundleQualityScore >= 72 && churnEfficiency.can_open_fresh_entries && readyFreshBuys > 0
          ? "press"
          : "selective";
  const protectiveSellOnly = status === "protect" || status === "cooldown";
  const nextBundleTradeCap = status === "idle"
    ? 0
    : status === "press"
      ? baseCap
      : status === "selective"
        ? Math.min(baseCap, Math.max(1, Math.min(2, bundleExecution.ready_trade_count)))
        : protectiveSellOnly
          ? Math.min(baseCap, Math.max(readyProtectiveSells, readyProtectiveSells > 0 ? 1 : 0))
          : Math.min(baseCap, 1);
  const nextSizeMultiplier = status === "press"
    ? 1
    : status === "selective"
      ? 0.72
      : status === "cooldown"
        ? 0.38
        : status === "protect"
          ? 0.24
          : 0;
  const items: AutonomousTickBundleFeedbackItem[] = [
    {
      id: "wallet",
      label: "Wallet",
      status: walletTelemetry.net_pnl_usd >= 0 && walletTelemetry.max_drawdown_pct < 5 ? "pass" : walletTelemetry.max_drawdown_pct < 8 ? "watch" : "fail",
      value: `${roundMetric(walletTelemetry.net_pnl_pct)}%`,
      detail: `${walletTelemetry.status} with ${roundMetric(walletTelemetry.max_drawdown_pct)}% max drawdown.`,
    },
    {
      id: "window",
      label: "Window",
      status: walletTelemetry.window_pnl_usd >= 0 && daemonMemory.consecutive_loss_count === 0 ? "pass" : daemonMemory.consecutive_loss_count < 2 ? "watch" : "fail",
      value: tickBundleUsd(walletTelemetry.window_pnl_usd),
      detail: `${daemonMemory.consecutive_loss_count} consecutive losing tick${daemonMemory.consecutive_loss_count === 1 ? "" : "s"} in daemon memory.`,
    },
    {
      id: "churn",
      label: "Churn",
      status: churnEfficiency.can_open_fresh_entries ? (churnEfficiency.status === "accelerate" ? "pass" : "watch") : "fail",
      value: churnEfficiency.entry_permission,
      detail: `${churnEfficiency.status} with ${churnEfficiency.max_trades_next_cycle} allowed next-cycle trade${churnEfficiency.max_trades_next_cycle === 1 ? "" : "s"}.`,
    },
    {
      id: "bundle",
      label: "Bundle",
      status: bundleExecution.ready_trade_count > 0 && bundleExecution.blocked_count === 0 ? "pass" : bundleExecution.ready_trade_count > 0 ? "watch" : "fail",
      value: `${bundleExecution.ready_trade_count}/${bundleExecution.bundle_size}`,
      detail: `${bundleExecution.projected_edge_usd >= 0 ? "+" : ""}${tickBundleUsd(bundleExecution.projected_edge_usd)} projected edge before paper fill.`,
    },
  ];

  return {
    mode: "tick-bundle-feedback-governor",
    status,
    bundle_quality_score: bundleQualityScore,
    next_bundle_trade_cap: nextBundleTradeCap,
    next_size_multiplier: roundMetric(nextSizeMultiplier),
    applied_trade_count: bundleExecution.applied_trade_count,
    ready_trade_count: bundleExecution.ready_trade_count,
    protective_sell_only: protectiveSellOnly,
    net_pnl_usd: roundMetric(walletTelemetry.net_pnl_usd),
    window_pnl_usd: roundMetric(walletTelemetry.window_pnl_usd),
    churn_permission: churnEfficiency.entry_permission,
    summary: tickBundleFeedbackSummary(status, bundleQualityScore, nextBundleTradeCap, protectiveSellOnly),
    next_action: tickBundleFeedbackNextAction(status, readyFreshBuys, readyProtectiveSells, bundleExecution),
    controls: [
      "Caps bundled paper fills using wallet PnL, recent tick memory, churn permission, readiness gates, and the current tick-plan envelope.",
      "Protect and cooldown modes allow protective paper sells but block fresh bundled buys until the wallet feedback improves.",
      "The governor only changes local paper-ledger sizing and caps; it cannot sign, submit, settle, or move live funds.",
    ],
    items,
  };
}

function tickBundleFeedbackSummary(
  status: AutonomousTickBundleFeedback["status"],
  score: number,
  cap: number,
  protectiveSellOnly: boolean,
) {
  if (status === "idle") return "Bundle feedback is idle until a next-minute paper bundle opens.";
  if (protectiveSellOnly) return `Bundle feedback is ${status}: score ${score}/100, cap ${cap}, protective paper sells only.`;
  if (status === "press") return `Bundle feedback is pressing: score ${score}/100 with up to ${cap} bounded paper fills this tick.`;
  return `Bundle feedback is selective: score ${score}/100 with up to ${cap} highest-signal paper fill${cap === 1 ? "" : "s"}.`;
}

function tickBundleFeedbackNextAction(
  status: AutonomousTickBundleFeedback["status"],
  readyFreshBuys: number,
  readyProtectiveSells: number,
  bundleExecution: AutonomousTickBundleExecution,
) {
  if (status === "idle") return bundleExecution.next_action;
  if (status === "protect") return readyProtectiveSells > 0
    ? "Apply only the protective paper sell lane, then re-score the wallet."
    : "Hold fresh buys and wait for protection or wallet recovery evidence.";
  if (status === "cooldown") return "Skip fresh bundled buys; keep watching for protective exits or cleaner PnL slope.";
  if (status === "press") return `Let the loop apply the strongest ${readyFreshBuys} fresh paper lane${readyFreshBuys === 1 ? "" : "s"} inside the cap.`;
  return "Apply only the best paper lane, then let post-trade feedback decide whether to press.";
}

function buildAutonomousCapitalCommand({
  tickPlan,
  tickGovernor,
  capitalAllocator,
  dailyProfitLock,
  profitIntegrity,
  tradeMission,
  bundleExecution,
  sourceQuality,
  walletTelemetry,
}: {
  tickPlan: AutonomousTickPlan;
  tickGovernor: AutonomousTickGovernor;
  capitalAllocator: AutonomousCapitalAllocator;
  dailyProfitLock: AutonomousDailyProfitLock;
  profitIntegrity: AutonomousProfitIntegrityCircuit;
  tradeMission: AutonomousTradeMission;
  bundleExecution: AutonomousTickBundleExecution;
  sourceQuality: AutonomousSourceQualityOracle;
  walletTelemetry: AutonomousWalletTelemetry;
}): AutonomousCapitalCommand {
  const leader = tickPlan.items[0] ?? null;
  const targetSymbol = tickGovernor.leader_symbol ?? tradeMission.target_symbol ?? leader?.symbol ?? capitalAllocator.items.find((item) => item.priority === "now")?.symbol ?? null;
  const capitalScore = capitalAllocator.allocation_score;
  const tickScore = tickGovernor.decision_score;
  const walletScore = clamp(Math.round(
    56 +
      walletTelemetry.window_pnl_pct * 5 +
      walletTelemetry.slope_usd_per_tick * 0.12 -
      walletTelemetry.max_drawdown_pct * 4 -
      Math.max(0, walletTelemetry.blocked_count - walletTelemetry.fill_count) * 2,
  ), 0, 100);
  const sourceScore = sourceQuality.quality_score;
  const executionScore = clamp(Math.round(
    42 +
      bundleExecution.ready_trade_count * 12 +
      bundleExecution.applied_trade_count * 8 -
      bundleExecution.blocked_count * 10 -
      (bundleExecution.route_refresh_vetoed ? 18 : 0) +
      (bundleExecution.status === "ready" || bundleExecution.status === "applied" ? 12 : 0),
  ), 0, 100);
  const profitScore = profitIntegrity.integrity_score;
  const commandScore = clamp(Math.round(
    tickScore * 0.25 +
      capitalScore * 0.2 +
      profitScore * 0.2 +
      walletScore * 0.14 +
      sourceScore * 0.11 +
      executionScore * 0.1,
  ), 0, 100);
  const blockers = [...new Set([
    ...tickGovernor.blockers,
    ...capitalAllocator.blockers,
    ...(leader?.blocker ? [leader.blocker] : []),
    ...(dailyProfitLock.stop_reason ? [dailyProfitLock.stop_reason] : []),
    ...(profitIntegrity.should_pause_fresh_buys ? ["Profit integrity pauses fresh buys before the next capital command."] : []),
    ...(bundleExecution.route_refresh_vetoed ? [bundleExecution.route_refresh_blocker ?? "Route refresh is vetoing fresh paper entries."] : []),
    ...(sourceQuality.status === "blocked" ? ["Source quality blocks hot-coin chasing until evidence refreshes."] : []),
  ])].filter(Boolean).slice(0, 6);
  const shouldProtect = tickGovernor.should_protect_first ||
    profitIntegrity.should_protect_first ||
    dailyProfitLock.loop_permission === "protect-only" ||
    leader?.action === "protect-now";
  const shouldRefresh = !shouldProtect && (
    tickGovernor.should_request_route_quote ||
    tickGovernor.should_refresh_market_data ||
    tickPlan.status === "refresh" ||
    bundleExecution.route_refresh_vetoed ||
    sourceQuality.status === "refresh-first"
  );
  const shouldHarvest = !shouldProtect &&
    !shouldRefresh &&
    (dailyProfitLock.status === "lock-profit" || dailyProfitLock.status === "harvest" || capitalAllocator.status === "harvest" || tradeMission.objective === "harvest");
  const shouldDeploy = !shouldProtect &&
    !shouldRefresh &&
    !shouldHarvest &&
    tickGovernor.should_trade &&
    tickPlan.bundle_trade_budget_usd > 0 &&
    bundleExecution.ready_trade_count > 0 &&
    dailyProfitLock.fresh_buy_allowed &&
    !profitIntegrity.should_pause_fresh_buys;

  let status: AutonomousCapitalCommand["status"] = "idle";
  let action: AutonomousCapitalCommand["action"] = "observe";
  if ((tickGovernor.status === "blocked" || tickPlan.status === "blocked" || capitalAllocator.status === "blocked") && blockers.length > 0) {
    status = "blocked";
    action = "stand-down";
  } else if (shouldProtect) {
    status = "protect";
    action = "protect-first";
  } else if (shouldRefresh) {
    status = "refresh";
    action = "refresh-first";
  } else if (shouldHarvest) {
    status = "harvest";
    action = "harvest-first";
  } else if (shouldDeploy) {
    status = "deploy";
    action = "deploy-now";
  } else if (tickPlan.status === "observe" || tickGovernor.status === "observe") {
    status = "observe";
    action = "observe";
  }

  const spendBudgetUsd = action === "deploy-now"
    ? Math.round(Math.min(
      tickPlan.bundle_trade_budget_usd,
      tickGovernor.paper_budget_usd || tickPlan.next_minute_trade_budget_usd || tickPlan.bundle_trade_budget_usd,
      capitalAllocator.deploy_budget_usd || tickPlan.bundle_trade_budget_usd,
      dailyProfitLock.deploy_allowed_usd || tickPlan.bundle_trade_budget_usd,
    ))
    : 0;
  const releaseBudgetUsd = action === "protect-first" || action === "harvest-first"
    ? Math.round(Math.max(
      tickGovernor.protective_sell_release_usd,
      capitalAllocator.release_budget_usd,
      dailyProfitLock.release_required_usd,
      tradeMission.release_budget_usd,
    ))
    : 0;
  const canExecutePaper = (action === "deploy-now" || action === "protect-first" || action === "harvest-first") &&
    tickGovernor.can_auto_advance &&
    bundleExecution.ready_trade_count > 0 &&
    bundleExecution.status !== "blocked" &&
    !bundleExecution.route_refresh_vetoed;
  const executionBoundary: AutonomousCapitalCommand["execution_boundary"] = canExecutePaper
    ? "paper-ledger-only"
    : action === "refresh-first"
      ? "read-only-refresh"
      : "blocked-paper-only";
  const items: AutonomousCapitalCommandItem[] = [
    {
      id: "tick",
      label: "Tick plan",
      status: tickPlan.status === "trade" || tickPlan.status === "protect" ? "pass" : tickPlan.status === "blocked" ? "fail" : "watch",
      score: tickScore,
      value: tickPlan.throughput_mode.replace("-", " "),
      detail: `${tickPlan.bundle_action_count} actions, ${formatCompactValue(tickPlan.bundle_trade_budget_usd)} next-minute paper budget.`,
    },
    {
      id: "capital",
      label: "Capital",
      status: capitalAllocator.status === "deploy" || capitalAllocator.status === "rebalance" ? "pass" : capitalAllocator.status === "blocked" ? "fail" : "watch",
      score: capitalScore,
      value: capitalAllocator.status,
      detail: `${formatCompactValue(capitalAllocator.deploy_budget_usd)} deploy, ${formatCompactValue(capitalAllocator.release_budget_usd)} release, ${formatCompactValue(capitalAllocator.reserved_cash_usd)} reserve.`,
    },
    {
      id: "profit",
      label: "Profit gate",
      status: profitIntegrity.can_continue && !profitIntegrity.should_pause_fresh_buys ? "pass" : profitIntegrity.should_protect_first || profitIntegrity.should_pause_fresh_buys ? "fail" : "watch",
      score: profitScore,
      value: profitIntegrity.permission.replace("-", " "),
      detail: `${profitIntegrity.max_next_fills} fills, ${profitIntegrity.size_multiplier}x size, ${formatSignedCompactValue(profitIntegrity.expected_value_usd)} EV.`,
    },
    {
      id: "wallet",
      label: "Wallet",
      status: walletScore >= 65 ? "pass" : walletScore < 38 ? "fail" : "watch",
      score: walletScore,
      value: formatSignedCompactValue(walletTelemetry.window_pnl_usd),
      detail: `${walletTelemetry.max_drawdown_pct.toFixed(1)}% drawdown, ${formatCompactValue(walletTelemetry.exposure_usd)} exposed.`,
    },
    {
      id: "source",
      label: "Source",
      status: sourceQuality.can_chase ? "pass" : sourceQuality.status === "blocked" ? "fail" : "watch",
      score: sourceScore,
      value: sourceQuality.status.replace("-", " "),
      detail: `${sourceQuality.leader_symbol ?? "desk"} · ${sourceQuality.leader_action?.replace("-", " ") ?? "watch"}.`,
    },
    {
      id: "execution",
      label: "Execution",
      status: canExecutePaper ? "pass" : action === "refresh-first" ? "watch" : "fail",
      score: executionScore,
      value: bundleExecution.status.replace("-", " "),
      detail: `${bundleExecution.ready_trade_count} ready, ${bundleExecution.blocked_count} blocked, ${executionBoundary}.`,
    },
  ];

  return {
    mode: "autonomous-capital-command",
    status,
    action,
    target_symbol: targetSymbol,
    command_score: commandScore,
    spend_budget_usd: Math.max(0, spendBudgetUsd),
    release_budget_usd: Math.max(0, releaseBudgetUsd),
    reserved_cash_usd: Math.round(capitalAllocator.reserved_cash_usd),
    expected_edge_usd: roundMetric(Math.max(0, tickPlan.bundle_expected_edge_usd, tickGovernor.expected_edge_usd, tradeMission.expected_profit_usd)),
    risk_budget_usd: Math.round(Math.max(0, tickPlan.risk_usd, tickGovernor.risk_budget_usd, tradeMission.max_risk_usd)),
    next_tick_seconds: Math.max(2, Math.min(tickPlan.tick_seconds, tickGovernor.next_tick_seconds || tickPlan.tick_seconds, tradeMission.next_tick_seconds || tickPlan.tick_seconds)),
    max_child_fills: Math.max(0, Math.min(tickPlan.bundle_trade_count, tickGovernor.max_paper_trades, dailyProfitLock.max_next_fills, profitIntegrity.max_next_fills)),
    can_execute_paper: canExecutePaper,
    execution_boundary: executionBoundary,
    summary: autonomousCapitalCommandSummary(status, action, targetSymbol, commandScore, spendBudgetUsd, releaseBudgetUsd),
    next_action: autonomousCapitalCommandNextAction(action, targetSymbol, spendBudgetUsd, releaseBudgetUsd, blockers, tickPlan, bundleExecution),
    blockers,
    controls: [
      "Compresses the tick plan, governor, capital allocator, profit lock, source quality, wallet, and bundle rehearsal into one next-dollar command.",
      "Deploy/harvest/protect commands remain bounded to the local paper ledger and cannot sign, submit, settle, custody funds, or bypass route/source/profit gates.",
      "Refresh-first and stand-down commands keep the reason visible before another high-frequency paper action is allowed.",
    ],
    items,
  };
}

function autonomousCapitalCommandSummary(
  status: AutonomousCapitalCommand["status"],
  action: AutonomousCapitalCommand["action"],
  targetSymbol: string | null,
  score: number,
  spendUsd: number,
  releaseUsd: number,
) {
  if (status === "deploy") return `Capital command clears ${score}/100: deploy up to ${formatCompactValue(spendUsd)} local paper into ${targetSymbol ?? "the ranked hot lane"}.`;
  if (status === "harvest") return `Capital command harvests ${formatCompactValue(releaseUsd)} before spending fresh paper capital.`;
  if (status === "protect") return `Capital command protects ${targetSymbol ?? "the held book"} first with ${formatCompactValue(releaseUsd)} release pressure.`;
  if (status === "refresh") return `Capital command refreshes route/source evidence before spending on ${targetSymbol ?? "the next lane"}.`;
  if (status === "blocked") return "Capital command stands down because the paper executor is blocked by capital, source, route, or profit gates.";
  if (status === "observe") return `Capital command observes ${targetSymbol ?? "the desk"} until a next-dollar paper edge clears.`;
  return `Capital command is idle; action ${action} waits for the next autonomous tick.`;
}

function autonomousCapitalCommandNextAction(
  action: AutonomousCapitalCommand["action"],
  targetSymbol: string | null,
  spendUsd: number,
  releaseUsd: number,
  blockers: string[],
  tickPlan: AutonomousTickPlan,
  bundleExecution: AutonomousTickBundleExecution,
) {
  if (action === "deploy-now") return `Apply the strongest local paper child fills toward ${targetSymbol ?? "the ranked candidate"} up to ${formatCompactValue(spendUsd)}, then re-score wallet alpha.`;
  if (action === "harvest-first") return `Harvest ${formatCompactValue(releaseUsd)} in local paper before reopening fresh buys.`;
  if (action === "protect-first") return `Protect ${targetSymbol ?? "the held book"} first; fresh paper spending waits behind the release lane.`;
  if (action === "refresh-first") return bundleExecution.route_refresh_blocker ?? tickPlan.throttle_reason;
  if (action === "stand-down") return blockers[0] ?? "Stand down until the next capital command has a clean paper edge.";
  return tickPlan.next_action;
}

function buildAutonomousWalletPerformanceGovernor({
  walletTelemetry,
  performance,
  daemonMemory,
  profitLearning,
  profitControl,
  postTradeReview,
  bundleFeedback,
  policyOptimizer,
}: {
  walletTelemetry: AutonomousWalletTelemetry;
  performance: PerformanceScorecard;
  daemonMemory: PaperDaemonMemory;
  profitLearning: AutonomousProfitLearning;
  profitControl: AutonomousProfitControl;
  postTradeReview: PostTradeReview;
  bundleFeedback: AutonomousTickBundleFeedback;
  policyOptimizer: AutonomousPolicyOptimizer;
}): AutonomousWalletPerformanceGovernor {
  const tradeCount = Math.max(performance.trade_count, daemonMemory.fill_count, bundleFeedback.applied_trade_count);
  const expectancy = tradeCount > 0 ? roundMetric(walletTelemetry.net_pnl_usd / tradeCount) : 0;
  const edge = Math.max(policyOptimizer.expected_net_usd, profitControl.required_edge_usd, bundleFeedback.ready_trade_count > 0 ? bundleFeedback.net_pnl_usd : 0);
  const walletScore = clamp(Math.round(
    50 +
      walletTelemetry.net_pnl_pct * 3.4 +
      walletTelemetry.window_pnl_pct * 5 +
      walletTelemetry.slope_usd_per_tick * 0.08 +
      Math.min(16, Math.max(-16, expectancy * 0.16)) -
      walletTelemetry.max_drawdown_pct * 5.5 -
      daemonMemory.consecutive_loss_count * 7 -
      Math.min(12, Math.max(0, walletTelemetry.blocked_count - walletTelemetry.fill_count) * 1.5),
  ), 0, 100);
  const makeMoneyScore = clamp(Math.round(
    walletScore * 0.42 +
      performance.risk_adjusted_score * 0.22 +
      profitLearning.confidence_score * 0.14 +
      bundleFeedback.bundle_quality_score * 0.12 +
      policyOptimizer.confidence_score * 0.1 +
      (performance.profit_factor >= 1.4 ? 7 : performance.profit_factor < 0.9 ? -8 : 0) +
      (performance.win_rate_pct >= 55 ? 5 : performance.win_rate_pct < 35 && performance.trade_count > 0 ? -6 : 0),
  ), 0, 100);
  const protectRequested = performance.status === "protect" ||
    postTradeReview.decision === "exit-only" ||
    profitControl.status === "protect" ||
    walletTelemetry.status === "protect" ||
    walletTelemetry.max_drawdown_pct >= 5 ||
    daemonMemory.status === "halted" ||
    bundleFeedback.status === "protect";
  const cooldownRequested = postTradeReview.pause_new_entries ||
    daemonMemory.pause_new_entries ||
    profitLearning.status === "tighten" ||
    profitLearning.status === "protect" ||
    performance.status === "overtrading" ||
    bundleFeedback.status === "cooldown";
  const harvestRequested = !protectRequested &&
    !cooldownRequested &&
    (walletTelemetry.status === "harvest" || profitControl.status === "harvest" || profitLearning.release_bias_usd > profitLearning.deploy_bias_usd);
  const status: AutonomousWalletPerformanceGovernor["status"] = protectRequested
    ? "protect"
    : cooldownRequested || makeMoneyScore < 32
      ? "cooldown"
      : harvestRequested
        ? "harvest"
        : tradeCount < 3 || profitLearning.status === "learning" || profitLearning.status === "idle"
          ? "learning"
          : makeMoneyScore >= 76 && profitLearning.status === "press" && bundleFeedback.next_bundle_trade_cap > 0
            ? "press"
            : makeMoneyScore >= 62 && walletTelemetry.net_pnl_usd >= 0
              ? "compound"
              : "selective";
  const protectiveSellOnly = status === "protect" || status === "cooldown" || status === "harvest";
  const freshBuyPermission: AutonomousWalletPerformanceGovernor["fresh_buy_permission"] = protectiveSellOnly
    ? "blocked"
    : status === "press" || status === "compound"
      ? "open"
      : "selective";
  const baseCap = Math.max(0, Math.min(
    bundleFeedback.next_bundle_trade_cap,
    policyOptimizer.max_trades_next_session,
    status === "press" ? 6 : status === "compound" ? 4 : status === "selective" || status === "learning" ? 2 : 1,
  ));
  const nextTradeCap = protectiveSellOnly
    ? Math.max(bundleFeedback.protective_sell_only ? bundleFeedback.next_bundle_trade_cap : 0, profitControl.release_now_usd > 0 ? 1 : 0)
    : baseCap;
  const sizeMultiplier = walletPerformanceSizeMultiplier(status, profitLearning, bundleFeedback, postTradeReview);
  const cadence = walletPerformanceCadence(status, profitLearning, profitControl, postTradeReview);
  const deployBias = freshBuyPermission === "blocked"
    ? 0
    : Math.round(Math.min(policyOptimizer.deploy_budget_usd, profitLearning.deploy_bias_usd || profitControl.deploy_now_usd) * sizeMultiplier);
  const releaseBias = protectiveSellOnly
    ? Math.round(Math.max(profitControl.release_now_usd, profitLearning.release_bias_usd, policyOptimizer.release_budget_usd))
    : Math.round(Math.max(0, Math.min(profitControl.release_now_usd, profitLearning.release_bias_usd)));
  const items = walletPerformanceGovernorItems({
    walletTelemetry,
    performance,
    daemonMemory,
    profitLearning,
    postTradeReview,
    makeMoneyScore,
    expectancy,
  });

  return {
    mode: "wallet-performance-governor",
    status,
    fresh_buy_permission: freshBuyPermission,
    protective_sell_only: protectiveSellOnly,
    make_money_score: makeMoneyScore,
    wallet_score: walletScore,
    expected_edge_usd: Math.round(edge),
    expectancy_usd: expectancy,
    net_pnl_usd: roundMetric(walletTelemetry.net_pnl_usd),
    window_pnl_usd: roundMetric(walletTelemetry.window_pnl_usd),
    equity_slope_usd_per_tick: roundMetric(walletTelemetry.slope_usd_per_tick),
    max_drawdown_pct: roundMetric(walletTelemetry.max_drawdown_pct),
    win_rate_pct: roundMetric(performance.win_rate_pct),
    profit_factor: roundMetric(performance.profit_factor),
    next_trade_cap: nextTradeCap,
    next_size_multiplier: sizeMultiplier,
    cadence_seconds: cadence,
    deploy_bias_usd: deployBias,
    release_bias_usd: releaseBias,
    summary: walletPerformanceSummary(status, makeMoneyScore, walletTelemetry, expectancy, nextTradeCap),
    next_action: walletPerformanceNextAction(status, freshBuyPermission, deployBias, releaseBias, cadence, postTradeReview, profitLearning),
    controls: [
      "Scores whether the paper wallet is actually making money from equity slope, window PnL, drawdown, expectancy, win rate, profit learning, and tick-bundle feedback.",
      "Blocks fresh paper buys in harvest, cooldown, or protect modes while allowing protective paper sells or release bias to run first.",
      "This governor changes local paper-loop caps, size, and cadence only; it cannot sign, submit, custody funds, or guarantee live profit.",
    ],
    items,
  };
}

function walletPerformanceSizeMultiplier(
  status: AutonomousWalletPerformanceGovernor["status"],
  profitLearning: AutonomousProfitLearning,
  bundleFeedback: AutonomousTickBundleFeedback,
  postTradeReview: PostTradeReview,
) {
  if (status === "protect") return 0.18;
  if (status === "cooldown") return 0.28;
  if (status === "harvest") return 0.42;
  if (status === "learning") return 0.56;
  const learned = average([
    profitLearning.size_multiplier,
    bundleFeedback.next_size_multiplier,
    postTradeReview.recommended_size_multiplier,
  ]);
  if (status === "press") return roundMetric(clamp(learned, 0.88, 1.18));
  if (status === "compound") return roundMetric(clamp(learned, 0.72, 1));
  return roundMetric(clamp(learned, 0.45, 0.78));
}

function walletPerformanceCadence(
  status: AutonomousWalletPerformanceGovernor["status"],
  profitLearning: AutonomousProfitLearning,
  profitControl: AutonomousProfitControl,
  postTradeReview: PostTradeReview,
) {
  if (status === "press") return Math.max(3, Math.min(profitLearning.cadence_seconds, profitControl.cadence_seconds, postTradeReview.recommended_cadence_seconds, 8));
  if (status === "compound") return Math.max(5, Math.min(profitLearning.cadence_seconds, profitControl.cadence_seconds, 12));
  if (status === "harvest") return Math.max(4, Math.min(profitControl.cadence_seconds, 12));
  if (status === "selective") return Math.max(8, Math.min(profitLearning.cadence_seconds, 16));
  if (status === "learning") return Math.max(10, Math.min(profitLearning.cadence_seconds, 18));
  return Math.max(16, postTradeReview.recommended_cadence_seconds);
}

function walletPerformanceGovernorItems({
  walletTelemetry,
  performance,
  daemonMemory,
  profitLearning,
  postTradeReview,
  makeMoneyScore,
  expectancy,
}: {
  walletTelemetry: AutonomousWalletTelemetry;
  performance: PerformanceScorecard;
  daemonMemory: PaperDaemonMemory;
  profitLearning: AutonomousProfitLearning;
  postTradeReview: PostTradeReview;
  makeMoneyScore: number;
  expectancy: number;
}): AutonomousWalletPerformanceGovernorItem[] {
  return [
    {
      id: "curve",
      label: "Wallet curve",
      status: walletTelemetry.slope_usd_per_tick > 0 && walletTelemetry.window_pnl_usd >= 0 ? "pass" : walletTelemetry.max_drawdown_pct < 4 ? "watch" : "fail",
      value: formatSignedCompactValue(walletTelemetry.slope_usd_per_tick),
      detail: `${formatSignedCompactValue(walletTelemetry.window_pnl_usd)} window PnL with ${roundMetric(walletTelemetry.max_drawdown_pct)}% drawdown.`,
    },
    {
      id: "expectancy",
      label: "Expectancy",
      status: expectancy > 0 && performance.profit_factor >= 1 ? "pass" : expectancy >= 0 ? "watch" : "fail",
      value: formatSignedCompactValue(expectancy),
      detail: `${roundMetric(performance.win_rate_pct)}% win rate and ${roundMetric(performance.profit_factor)}x profit factor.`,
    },
    {
      id: "drawdown",
      label: "Drawdown",
      status: walletTelemetry.max_drawdown_pct < 2.8 ? "pass" : walletTelemetry.max_drawdown_pct < 5 ? "watch" : "fail",
      value: `${roundMetric(walletTelemetry.max_drawdown_pct)}%`,
      detail: `${postTradeReview.decision.replace("-", " ")} post-trade decision after ${daemonMemory.window_size} remembered ticks.`,
    },
    {
      id: "discipline",
      label: "Discipline",
      status: daemonMemory.pause_new_entries || postTradeReview.pause_new_entries ? "fail" : daemonMemory.consecutive_loss_count > 0 ? "watch" : "pass",
      value: `${daemonMemory.consecutive_loss_count} loss ticks`,
      detail: `${daemonMemory.fill_count} fills and ${daemonMemory.blocked_count} blockers in daemon memory.`,
    },
    {
      id: "learning",
      label: "Learning",
      status: profitLearning.status === "press" || profitLearning.status === "selective" ? "pass" : profitLearning.status === "protect" || profitLearning.status === "tighten" ? "fail" : "watch",
      value: `${makeMoneyScore}/100`,
      detail: profitLearning.next_action,
    },
  ];
}

function walletPerformanceSummary(
  status: AutonomousWalletPerformanceGovernor["status"],
  score: number,
  walletTelemetry: AutonomousWalletTelemetry,
  expectancy: number,
  tradeCap: number,
) {
  if (status === "press") return `Wallet performance can press: score ${score}/100, ${formatSignedCompactValue(expectancy)} expectancy, cap ${tradeCap}.`;
  if (status === "compound") return `Wallet performance can compound selectively with ${formatSignedCompactValue(walletTelemetry.window_pnl_usd)} window PnL.`;
  if (status === "harvest") return `Wallet performance is profitable but harvest-first: ${formatSignedCompactValue(walletTelemetry.net_pnl_usd)} net with exposure to release.`;
  if (status === "protect") return `Wallet performance is protecting because profit-control, post-trade review, or wallet risk outranks fresh buys; drawdown is ${roundMetric(walletTelemetry.max_drawdown_pct)}%.`;
  if (status === "cooldown") return `Wallet performance is cooling down: score ${score}/100 until losses, churn, or blockers clear.`;
  if (status === "learning") return "Wallet performance needs more closed paper outcomes before it can press size.";
  return `Wallet performance is selective: score ${score}/100, keep only the highest-signal paper lanes.`;
}

function walletPerformanceNextAction(
  status: AutonomousWalletPerformanceGovernor["status"],
  freshBuyPermission: AutonomousWalletPerformanceGovernor["fresh_buy_permission"],
  deployBias: number,
  releaseBias: number,
  cadence: number,
  postTradeReview: PostTradeReview,
  profitLearning: AutonomousProfitLearning,
) {
  if (status === "press") return `Allow fresh paper buys up to ${formatCompactValue(deployBias)} at ${cadence}s cadence while route and safety gates stay green.`;
  if (status === "compound") return `Compound only high-signal paper entries at ${cadence}s cadence; keep release checks armed.`;
  if (status === "harvest") return `Harvest or trail ${formatCompactValue(releaseBias)} before another fresh paper buy.`;
  if (status === "protect") return `Block fresh paper buys and run protection first. ${postTradeReview.next_action}`;
  if (status === "cooldown") return `Block fresh paper buys and let ${profitLearning.worst_drag ?? "the weakest lane"} recover before re-arming.`;
  if (status === "learning") return "Keep paper probes small and wait for the wallet curve to prove positive expectancy.";
  return freshBuyPermission === "selective"
    ? `Permit only selective fresh paper buys up to ${formatCompactValue(deployBias)} and re-score immediately after fills.`
    : profitLearning.next_action;
}

function applyAutonomousTickBundleToLedger({
  row,
  market,
  tickPlan,
  routeRefreshExecution,
  alphaDecay,
  sourceQuality,
  protectiveTriggerCoverage,
  commandCenterExecution,
  positionRiskExecution,
  highFrequencyRaceExecution,
  opportunityRaceExecution,
  trendChaseExecution,
  scoutLifecycle,
  tradeReadinessGate,
  bundleFeedback,
  symbolQuarantine,
  laneCapitalController,
  profitAllocationPlan,
  regimeTape,
  walletGrowthDirector,
  profitRouteSelector,
  executionQualityArbiter,
  tokenSafetyClearance,
  sameCycleEntrySymbols,
  protectiveSellOnly = false,
}: {
  row: Web3PaperLedgerRow;
  market: MemecoinMarket[];
  tickPlan: AutonomousTickPlan;
  routeRefreshExecution?: AutonomousRouteRefreshExecution;
  alphaDecay?: AlphaDecayController;
  sourceQuality?: AutonomousSourceQualityOracle;
  protectiveTriggerCoverage?: ProtectiveTriggerCoverage;
  commandCenterExecution?: AutonomousCommandCenterExecution;
  positionRiskExecution: AutonomousPositionRiskExecution;
  highFrequencyRaceExecution: HighFrequencyProfitRaceExecution;
  opportunityRaceExecution: AutonomousOpportunityRaceExecution;
  trendChaseExecution: TrendChaseExecution;
  scoutLifecycle: ScoutLifecycleController;
  tradeReadinessGate: AutonomousTradeReadinessGate;
  bundleFeedback: AutonomousTickBundleFeedback;
  symbolQuarantine: AutonomousSymbolQuarantine;
  laneCapitalController: AutonomousLaneCapitalController;
  profitAllocationPlan?: AutonomousProfitAllocationPlan;
  regimeTape: AutonomousRegimeTape;
  walletGrowthDirector: AutonomousWalletGrowthDirector;
  profitRouteSelector: AutonomousProfitRouteSelector;
  executionQualityArbiter: AutonomousExecutionQualityArbiter;
  tokenSafetyClearance: AutonomousTokenSafetyClearance;
  sameCycleEntrySymbols: Set<string>;
  protectiveSellOnly?: boolean;
}) {
  const sourceExecutions = tickBundleSourceExecutions({
    commandCenterExecution,
    positionRiskExecution,
    highFrequencyRaceExecution,
    opportunityRaceExecution,
    trendChaseExecution,
    scoutLifecycle,
  });
  const entrySymbols = new Set(sameCycleEntrySymbols);
  const maxTrades = Math.max(0, Math.min(
    tickPlan.max_actions_next_minute,
    tradeReadinessGate.max_batch_trades,
    bundleFeedback.next_bundle_trade_cap,
  ));
  let appliedCount = 0;
  let next = row;

  for (const item of autonomousTickPlanBundleItems(tickPlan.items, tickPlan.max_actions_next_minute)) {
    if (appliedCount >= maxTrades) break;
    if (item.action !== "trade-now" && item.action !== "protect-now") continue;
    const source = sourceExecutions.get(item.id);
    const trade = source?.paper_trade ?? null;
    if (!source?.paper_trade_ready || !trade) continue;
    if (protectiveSellOnly && trade.side !== "sell") continue;
    if (autonomousTickBundleRouteFreshnessBlocker(item, trade, routeRefreshExecution)) continue;
    if (!autonomousAlphaDecayAllowsTrade(alphaDecay, trade)) continue;
    if (!autonomousSourceQualityAllowsTrade(sourceQuality, trade)) continue;
    if (!protectiveTriggerCoverageAllowsTrade(protectiveTriggerCoverage, trade)) continue;
    if (bundleFeedback.protective_sell_only && trade.side === "buy") continue;
    if (!autonomousSymbolQuarantineAllowsTrade(symbolQuarantine, trade)) continue;
    const lane = tickPlanItemLaneCapitalId(item);
    const adjustedTrade = allocatorAdjustedPaperTrade(laneCapitalController, profitAllocationPlan, lane, trade);
    if (!adjustedTrade) continue;
    if (!autonomousRegimeTapeAllowsTrade(regimeTape, adjustedTrade)) continue;
    if (!autonomousWalletGrowthDirectorAllowsTrade(walletGrowthDirector, adjustedTrade)) continue;
    if (!autonomousProfitRouteSelectorAllowsTrade(profitRouteSelector, adjustedTrade)) continue;
    if (!autonomousExecutionQualityArbiterAllowsTrade(executionQualityArbiter, adjustedTrade)) continue;
    if (!autonomousTokenSafetyClearanceAllowsTrade(tokenSafetyClearance, adjustedTrade)) continue;
    if (!autonomousSourceQualityAllowsTrade(sourceQuality, adjustedTrade)) continue;
    const sourceSizedTrade = autonomousSourceQualityAdjustedTrade(sourceQuality, adjustedTrade);
    if (!sourceSizedTrade) continue;
    const readinessAllowed = autonomousTradeReadinessAllowsTrade(tradeReadinessGate, sourceSizedTrade) ||
      (item.id === "tick-plan-trend-chase" && trendChaseExecution.uses_scout_reserve);
    if (!readinessAllowed) continue;
    if (entrySymbols.has(sourceSizedTrade.symbol)) continue;

    const before = next;
    next = applyArbiterPaperTradeToLedger(next, market, sourceSizedTrade);
    if (next !== before) {
      appliedCount += 1;
      if (sourceSizedTrade.side === "buy") entrySymbols.add(sourceSizedTrade.symbol);
    }
  }

  return next;
}

function tickPlanItemLaneCapitalId(item: AutonomousTickPlanItem): AutonomousLaneCapitalId {
  if (item.id === "tick-plan-command-center") return "command-center";
  if (item.id === "tick-plan-high-frequency") return "high-frequency";
  if (item.id === "tick-plan-race-execution") return "opportunity-race";
  if (item.id === "tick-plan-trend-chase") return "trend-chase";
  if (item.id === "tick-plan-scout-lifecycle" || item.id === "tick-plan-position-risk") return "portfolio-protect";
  if (item.id.includes("market-pulse")) return "market-pulse";
  if (item.id.includes("market-intelligence")) return "market-intelligence";
  if (item.lane === "protect") return "portfolio-protect";
  return "arbiter";
}

function tickBundleExecutionStatus(
  items: AutonomousTickBundleExecutionItem[],
  readyTradeCount: number,
  appliedTradeCount: number,
  refreshOnlyCount: number,
  blockedCount: number,
  skippedCount: number,
): AutonomousTickBundleExecution["status"] {
  if (items.length === 0) return "empty";
  if (blockedCount === items.length) return "blocked";
  if (appliedTradeCount > 0 && readyTradeCount === 0 && blockedCount === 0) return "applied";
  if (readyTradeCount > 0 && blockedCount === 0 && skippedCount === 0) return "ready";
  if (refreshOnlyCount === items.length) return "refresh-only";
  return "mixed";
}

function tickBundleExecutionSummary(
  status: AutonomousTickBundleExecution["status"],
  items: AutonomousTickBundleExecutionItem[],
  readyTradeCount: number,
  appliedTradeCount: number,
  refreshOnlyCount: number,
  blockedCount: number,
) {
  if (status === "empty") return "No next-minute bundle is ready for paper rehearsal.";
  if (status === "blocked") return `Bundle rehearsal is blocked across ${blockedCount} lane${blockedCount === 1 ? "" : "s"}.`;
  if (status === "applied") return `${appliedTradeCount} bundled paper fill${appliedTradeCount === 1 ? "" : "s"} already landed in the local ledger.`;
  if (status === "ready") return `Bundle rehearsal has ${readyTradeCount} paper fill${readyTradeCount === 1 ? "" : "s"} ready and ${refreshOnlyCount} refresh lane${refreshOnlyCount === 1 ? "" : "s"} queued.`;
  if (status === "refresh-only") return `Bundle rehearsal is refresh-only across ${refreshOnlyCount} route or market lane${refreshOnlyCount === 1 ? "" : "s"}.`;
  const symbols = Array.from(new Set(items.map((item) => item.symbol).filter(Boolean))).slice(0, 3).join(", ");
  return `Bundle rehearsal is mixed for ${symbols || "desk lanes"}: ${readyTradeCount} ready, ${appliedTradeCount} applied, ${refreshOnlyCount} refresh, ${blockedCount} blocked.`;
}

function tickBundleExecutionNextAction(
  status: AutonomousTickBundleExecution["status"],
  items: AutonomousTickBundleExecutionItem[],
  tickPlan: AutonomousTickPlan,
) {
  const leader = items.find((item) => item.status === "ready") ?? items.find((item) => item.status === "refresh-only") ?? items.find((item) => item.status === "blocked") ?? items[0];
  if (!leader) return tickPlan.throttle_reason;
  if (status === "ready") return `Let the existing paper-ledger boundary rehearse ${leader.symbol ?? "the lead lane"} ${leader.side}.`;
  if (status === "applied") return "Read the applied bundle fills, then let post-trade review update sizing and cadence.";
  if (status === "refresh-only") return "Refresh route or market evidence before any bundled paper fill is allowed.";
  if (status === "blocked") return leader.blocker ?? tickPlan.throttle_reason;
  if (status === "empty") return tickPlan.throttle_reason;
  return leader.blocker ?? leader.reason;
}

function autonomousTickPlanThroughput({
  status,
  ready,
  executeCount,
  refreshCount,
  blockedCount,
  loopDirector,
  burstScheduler,
  tradeReadinessGate,
  policyOptimizer,
}: {
  status: AutonomousTickPlan["status"];
  ready: AutonomousTickPlanItem[];
  executeCount: number;
  refreshCount: number;
  blockedCount: number;
  loopDirector: AutonomousLoopDirector;
  burstScheduler: AutonomousBurstScheduler;
  tradeReadinessGate: AutonomousTradeReadinessGate;
  policyOptimizer: AutonomousPolicyOptimizer;
}) {
  const executionSlotsRemaining = Math.max(0, Math.min(
    loopDirector.repeated_execution_limit,
    loopDirector.ticks_remaining_before_pause,
    burstScheduler.max_trades_next_tick + Math.max(0, refreshCount),
  ));
  const readyTradeBudget = Math.round(ready
    .filter((item) => item.action === "trade-now" || item.action === "protect-now")
    .reduce((sum, item) => sum + Math.max(0, item.paper_budget_usd), 0));
  const nextMinuteTradeBudgetUsd = Math.max(0, Math.min(
    readyTradeBudget,
    policyOptimizer.deploy_budget_usd + policyOptimizer.release_budget_usd,
  ));
  const maxActionsNextMinute = status === "blocked" || status === "stand-down"
    ? 0
    : Math.max(0, Math.min(loopDirector.max_ticks_per_minute, executionSlotsRemaining, executeCount + refreshCount));
  const mode: AutonomousTickPlan["throughput_mode"] = status === "blocked" || !tradeReadinessGate.can_apply_batch
    ? "blocked"
    : status === "stand-down" || loopDirector.intensity === "cooldown"
      ? "cooldown"
      : status === "protect"
        ? "protect-first"
        : status === "refresh"
          ? "refresh-first"
          : loopDirector.intensity === "burst" && maxActionsNextMinute >= 2
            ? "burst"
            : "steady";
  const throttleReason = autonomousTickPlanThrottleReason({
    mode,
    status,
    maxActionsNextMinute,
    executionSlotsRemaining,
    executeCount,
    refreshCount,
    blockedCount,
    loopDirector,
    burstScheduler,
    tradeReadinessGate,
  });

  return {
    mode,
    maxActionsNextMinute,
    executionSlotsRemaining,
    nextMinuteTradeBudgetUsd,
    throttleReason,
  };
}

function autonomousTickPlanThrottleReason({
  mode,
  status,
  maxActionsNextMinute,
  executionSlotsRemaining,
  executeCount,
  refreshCount,
  blockedCount,
  loopDirector,
  burstScheduler,
  tradeReadinessGate,
}: {
  mode: AutonomousTickPlan["throughput_mode"];
  status: AutonomousTickPlan["status"];
  maxActionsNextMinute: number;
  executionSlotsRemaining: number;
  executeCount: number;
  refreshCount: number;
  blockedCount: number;
  loopDirector: AutonomousLoopDirector;
  burstScheduler: AutonomousBurstScheduler;
  tradeReadinessGate: AutonomousTradeReadinessGate;
}) {
  if (!tradeReadinessGate.can_apply_batch) return tradeReadinessGate.next_action;
  if (mode === "blocked") return `Throughput blocked by ${blockedCount} blocked next-tick lane${blockedCount === 1 ? "" : "s"}.`;
  if (mode === "cooldown") return `Throughput cooled by ${status} tick status and ${loopDirector.intensity} loop intensity.`;
  if (mode === "protect-first") return "Throughput is sell/protect-first before any fresh exposure.";
  if (mode === "refresh-first") return `Throughput is refresh-first with ${refreshCount} route or market refresh lane${refreshCount === 1 ? "" : "s"} ready.`;
  if (mode === "burst") return `Burst throughput allows up to ${maxActionsNextMinute} local actions this minute inside ${executionSlotsRemaining} remaining slots.`;
  if (executeCount > 0) return `Steady throughput allows ${maxActionsNextMinute} local action${maxActionsNextMinute === 1 ? "" : "s"} this minute inside burst cap ${burstScheduler.max_trades_next_tick}.`;
  return "Steady throughput is observing until a ready execute or refresh lane clears.";
}

function autonomousBurstBlockers({
  signalNoise,
  walletTelemetry,
  loopDirector,
  tradeReadinessGate,
  churnEfficiency,
  performance,
}: {
  signalNoise: SignalNoiseScanner;
  walletTelemetry: AutonomousWalletTelemetry;
  loopDirector: AutonomousLoopDirector;
  tradeReadinessGate: AutonomousTradeReadinessGate;
  churnEfficiency: ChurnEfficiencyAuditor;
  performance: PerformanceScorecard;
}) {
  const blockers = [
    ...loopDirector.blockers,
    ...tradeReadinessGate.blockers,
    ...(signalNoise.status === "noisy" ? [signalNoise.next_action] : []),
    ...(walletTelemetry.status === "protect" ? [walletTelemetry.next_action] : []),
  ];
  if (tradeReadinessGate.status === "blocked") blockers.push(tradeReadinessGate.next_action);
  if (churnEfficiency.status === "stop") blockers.push(churnEfficiency.next_action);
  if (performance.status === "protect") blockers.push(performance.summary);
  return [...new Set(blockers.filter(Boolean))].slice(0, 6);
}

function autonomousBurstItems({
  leader,
  signalNoise,
  arbiter,
  tradeBatch,
  routeRefreshQueue,
  marketStream,
  walletTelemetry,
  loopDirector,
  blockers,
}: {
  leader: SignalNoiseItem | undefined;
  signalNoise: SignalNoiseScanner;
  arbiter: AutonomousTradeArbiter;
  tradeBatch: AutonomousTradeBatch;
  routeRefreshQueue: RouteRefreshQueue;
  marketStream: MarketStreamSupervisor;
  walletTelemetry: AutonomousWalletTelemetry;
  loopDirector: AutonomousLoopDirector;
  blockers: string[];
}): AutonomousBurstSchedulerItem[] {
  const items: AutonomousBurstSchedulerItem[] = [];
  if (leader) {
    items.push({
      id: `burst-signal-${leader.token_id}`,
      lane: leader.action === "protect" ? "protect" : "entry",
      symbol: leader.symbol,
      action: leader.action === "attack" ? "burst" : leader.action === "probe" ? "tick" : leader.action === "protect" ? "protect" : "hold",
      priority: leader.action === "attack" ? "high" : leader.action === "protect" ? "critical" : "normal",
      score: leader.signal_score,
      tick_seconds: leader.review_after_seconds,
      max_trades: leader.max_churn_per_minute,
      expected_profit_usd: Math.max(0, Math.round((arbiter.total_expected_profit_usd || tradeBatch.expected_profit_usd) * leader.recommended_size_multiplier)),
      risk_usd: Math.round(arbiter.total_risk_usd * Math.max(0.25, leader.recommended_size_multiplier)),
      reason: leader.reason,
      blockers: leader.blockers,
    });
  }
  if (tradeBatch.ready_count > 0 || tradeBatch.release_budget_usd > 0) {
    items.push({
      id: "burst-paper-batch",
      lane: tradeBatch.sell_count > 0 ? "exit" : "entry",
      symbol: tradeBatch.items.find((item) => item.symbol)?.symbol ?? null,
      action: tradeBatch.ready_count > 0 ? "burst" : "tick",
      priority: tradeBatch.sell_count > 0 ? "critical" : "high",
      score: Math.min(100, tradeBatch.ready_count * 20 + Math.max(0, tradeBatch.expected_profit_usd)),
      tick_seconds: loopDirector.next_tick_seconds || 8,
      max_trades: tradeBatch.ready_count,
      expected_profit_usd: Math.max(0, tradeBatch.expected_profit_usd),
      risk_usd: Math.max(0, tradeBatch.max_loss_usd),
      reason: tradeBatch.next_action,
      blockers: [...new Set(tradeBatch.items.flatMap((item) => item.blockers))].slice(0, 3),
    });
  }
  if (routeRefreshQueue.status === "refresh-now" || routeRefreshQueue.status === "queued") {
    items.push({
      id: "burst-route-refresh",
      lane: "route-refresh",
      symbol: routeRefreshQueue.items.find((item) => item.symbol)?.symbol ?? null,
      action: "quote-refresh",
      priority: routeRefreshQueue.status === "refresh-now" ? "critical" : "high",
      score: Math.min(100, routeRefreshQueue.refresh_now_count * 24 + routeRefreshQueue.stale_quote_count * 14),
      tick_seconds: Math.max(2, routeRefreshQueue.fastest_refresh_seconds),
      max_trades: 0,
      expected_profit_usd: 0,
      risk_usd: 0,
      reason: routeRefreshQueue.next_action,
      blockers: [...new Set(routeRefreshQueue.items.flatMap((item) => item.blockers))].slice(0, 3),
    });
  }
  if (marketStream.status === "backfill" || marketStream.status === "reconnect") {
    items.push({
      id: "burst-data-refresh",
      lane: "data-refresh",
      symbol: marketStream.watch_symbols[0] ?? null,
      action: "backfill",
      priority: marketStream.status === "reconnect" ? "critical" : "high",
      score: marketStream.gap_risk_score,
      tick_seconds: Math.max(4, marketStream.reconnect_after_seconds || 8),
      max_trades: 0,
      expected_profit_usd: 0,
      risk_usd: 0,
      reason: marketStream.next_action,
      blockers: marketStream.status === "reconnect" ? [marketStream.summary] : [],
    });
  }
  if (walletTelemetry.status === "cooldown" || walletTelemetry.status === "protect") {
    items.push({
      id: "burst-wallet-protection",
      lane: walletTelemetry.status === "protect" ? "protect" : "cooldown",
      symbol: null,
      action: walletTelemetry.status === "protect" ? "protect" : "hold",
      priority: walletTelemetry.status === "protect" ? "critical" : "normal",
      score: Math.min(100, Math.round(walletTelemetry.max_drawdown_pct * 12 + walletTelemetry.blocked_count * 4)),
      tick_seconds: walletTelemetry.status === "protect" ? 8 : 14,
      max_trades: walletTelemetry.status === "protect" ? 1 : 0,
      expected_profit_usd: Math.max(0, walletTelemetry.window_pnl_usd),
      risk_usd: Math.round(walletTelemetry.exposure_usd * 0.05),
      reason: walletTelemetry.next_action,
      blockers: walletTelemetry.risk_notes.slice(0, 3),
    });
  }
  if (items.length === 0) {
    items.push({
      id: "burst-idle",
      lane: blockers.length > 0 ? "cooldown" : "data-refresh",
      symbol: signalNoise.items[0]?.symbol ?? null,
      action: blockers.length > 0 ? "stand-down" : "hold",
      priority: "low",
      score: 0,
      tick_seconds: loopDirector.next_tick_seconds || 10,
      max_trades: 0,
      expected_profit_usd: 0,
      risk_usd: 0,
      reason: blockers[0] ?? "No burst candidate clears the scheduler yet.",
      blockers,
    });
  }
  return items
    .sort((a, b) => autonomousBurstPriorityRank(b.priority) - autonomousBurstPriorityRank(a.priority) || b.score - a.score)
    .slice(0, 6);
}

function autonomousBurstStatus({
  blockers,
  signalNoise,
  walletTelemetry,
  loopDirector,
  tradeReadinessGate,
  tradeBatch,
  churnEfficiency,
}: {
  blockers: string[];
  signalNoise: SignalNoiseScanner;
  walletTelemetry: AutonomousWalletTelemetry;
  loopDirector: AutonomousLoopDirector;
  tradeReadinessGate: AutonomousTradeReadinessGate;
  tradeBatch: AutonomousTradeBatch;
  churnEfficiency: ChurnEfficiencyAuditor;
}): AutonomousBurstScheduler["status"] {
  if (loopDirector.status === "halted" || tradeReadinessGate.status === "blocked" || churnEfficiency.status === "stop") return "stand-down";
  if (walletTelemetry.status === "protect" || signalNoise.status === "protect" || tradeReadinessGate.status === "exit-only") return "protect";
  if (walletTelemetry.status === "cooldown" || loopDirector.intensity === "cooldown" || churnEfficiency.status === "cooldown") return "cooldown";
  if (blockers.length > 0 && tradeBatch.sell_count === 0) return "selective";
  if (signalNoise.attack_count > 0 && tradeBatch.ready_count > 0 && loopDirector.intensity === "burst") return "burst";
  if (signalNoise.attack_count > 0 || tradeBatch.ready_count > 0 || loopDirector.intensity === "active") return "active";
  if (signalNoise.probe_count > 0 || churnEfficiency.status === "selective") return "selective";
  return loopDirector.client_should_run ? "idle" : "stand-down";
}

function autonomousBurstTickSeconds(
  status: AutonomousBurstScheduler["status"],
  loopDirector: AutonomousLoopDirector,
  signalNoise: SignalNoiseScanner,
  walletTelemetry: AutonomousWalletTelemetry,
  churnEfficiency: ChurnEfficiencyAuditor,
  routeRefreshQueue: RouteRefreshQueue,
) {
  if (status === "stand-down" || status === "idle") return 0;
  if (routeRefreshQueue.status === "refresh-now") return Math.max(2, Math.min(5, routeRefreshQueue.fastest_refresh_seconds));
  if (status === "burst") return Math.max(2, Math.min(4, loopDirector.next_tick_seconds || 3));
  if (status === "active") return Math.max(4, Math.min(8, loopDirector.next_tick_seconds || signalNoise.fastest_review_seconds));
  if (status === "protect") return 6;
  if (status === "selective") return Math.max(6, Math.min(12, signalNoise.fastest_review_seconds || churnEfficiency.recommended_cadence_seconds));
  if (walletTelemetry.status === "cooldown") return Math.max(12, Math.min(20, churnEfficiency.recommended_cadence_seconds));
  return Math.max(10, Math.min(30, loopDirector.next_tick_seconds || 10));
}

function autonomousBurstMaxTrades(
  status: AutonomousBurstScheduler["status"],
  tradeBatch: AutonomousTradeBatch,
  churnEfficiency: ChurnEfficiencyAuditor,
  signalNoise: SignalNoiseScanner,
  tradeReadinessGate: AutonomousTradeReadinessGate,
) {
  if (status === "stand-down" || status === "idle" || status === "cooldown") return 0;
  if (status === "protect") return tradeReadinessGate.can_apply_sells ? Math.min(2, tradeBatch.sell_count || 1) : 0;
  const signalCap = signalNoise.items[0]?.max_churn_per_minute ?? 1;
  const churnCap = churnEfficiency.max_trades_next_cycle || 1;
  const readinessCap = tradeReadinessGate.max_batch_trades || 1;
  const batchCap = tradeBatch.ready_count || (status === "selective" ? 1 : 2);
  return Math.max(0, Math.min(batchCap, churnCap, signalCap, readinessCap, status === "burst" ? 4 : 2));
}

function autonomousBurstDexDiscoveryBudget(status: AutonomousBurstScheduler["status"], marketStream: MarketStreamSupervisor) {
  if (status === "stand-down" || status === "idle") return 0;
  if (marketStream.status === "reconnect") return 12;
  if (status === "burst" || status === "active") return 60;
  if (status === "selective") return 30;
  return 15;
}

function autonomousBurstDexPairBudget(status: AutonomousBurstScheduler["status"], marketStream: MarketStreamSupervisor) {
  if (status === "stand-down" || status === "idle") return 0;
  if (marketStream.status === "reconnect") return 30;
  if (status === "burst" || status === "active") return 180;
  if (status === "selective" || status === "protect") return 90;
  return 45;
}

function autonomousBurstRouteBudget(status: AutonomousBurstScheduler["status"], routeRefreshQueue: RouteRefreshQueue) {
  if (status === "stand-down" || status === "idle") return 0;
  if (routeRefreshQueue.status === "refresh-now") return 30;
  if (status === "burst" || status === "active") return 24;
  if (status === "selective" || status === "protect") return 12;
  return 6;
}

function autonomousBurstPriorityRank(priority: AutonomousBurstSchedulerItem["priority"]) {
  if (priority === "critical") return 4;
  if (priority === "high") return 3;
  if (priority === "normal") return 2;
  return 1;
}

function autonomousBurstSummary(
  status: AutonomousBurstScheduler["status"],
  leader: SignalNoiseItem | undefined,
  expectedProfit: number,
  tickSeconds: number,
  maxTrades: number,
  blockers: string[],
) {
  if (status === "burst" && leader) return `Burst scheduler will chase ${leader.symbol} every ${tickSeconds}s with up to ${maxTrades} paper trade${maxTrades === 1 ? "" : "s"} and ${formatCompactValue(expectedProfit)} expected edge.`;
  if (status === "active") return `Burst scheduler stays active every ${tickSeconds}s while expected edge is ${formatCompactValue(expectedProfit)}.`;
  if (status === "selective") return `Burst scheduler allows selective probes every ${tickSeconds}s while blockers or signal/noise gaps remain visible.`;
  if (status === "protect") return "Burst scheduler prioritizes exits, route refresh, and wallet protection before new buys.";
  if (status === "cooldown") return `Burst scheduler cools down for ${tickSeconds}s before the next paper decision.`;
  if (status === "stand-down") return blockers[0] ?? "Burst scheduler stands down until safety gates clear.";
  return "Burst scheduler is idle until a high-signal paper action clears.";
}

function autonomousBurstNextAction(
  status: AutonomousBurstScheduler["status"],
  items: AutonomousBurstSchedulerItem[],
  blockers: string[],
  loopDirector: AutonomousLoopDirector,
  signalNoise: SignalNoiseScanner,
) {
  if (blockers[0] && (status === "stand-down" || status === "cooldown")) return blockers[0];
  const leader = items[0];
  if (!leader) return loopDirector.tick_reason;
  if (leader.blockers[0]) return leader.blockers[0];
  if (status === "burst") return `Issue the next daemon tick for ${leader.symbol ?? signalNoise.items[0]?.symbol ?? "the top signal"} within the burst budget.`;
  if (status === "active" || status === "selective") return leader.reason;
  if (status === "protect") return "Run protective paper actions and refresh routes before any new entry.";
  return loopDirector.tick_reason;
}

function buildAutonomousTradeMission({
  signalNoise,
  arbiter,
  tradeBatch,
  tradeReadinessGate,
  capitalAllocator,
  walletTelemetry,
  sessionSupervisor,
  burstScheduler,
  routeRefreshQueue,
  signalAlpha,
  postTradeReview,
  executionBridge,
  raceExecution,
  performance,
}: {
  signalNoise: SignalNoiseScanner;
  arbiter: AutonomousTradeArbiter;
  tradeBatch: AutonomousTradeBatch;
  tradeReadinessGate: AutonomousTradeReadinessGate;
  capitalAllocator: AutonomousCapitalAllocator;
  walletTelemetry: AutonomousWalletTelemetry;
  sessionSupervisor: AutonomousSessionSupervisor;
  burstScheduler: AutonomousBurstScheduler;
  routeRefreshQueue: RouteRefreshQueue;
  signalAlpha: SignalAlphaAttribution;
  postTradeReview: PostTradeReview;
  executionBridge: AutonomousTradeExecutionBridge;
  raceExecution?: AutonomousOpportunityRaceExecution;
  performance: PerformanceScorecard;
}): AutonomousTradeMission {
  const readyBatchItem = tradeBatch.items.find((item) => item.status === "ready") ??
    tradeBatch.items.find((item) => item.status === "blocked") ??
    tradeBatch.items[0];
  const selectedArbiter = arbiter.items.find((item) => item.id === arbiter.selected_action_id) ??
    arbiter.items.find((item) => item.priority === "now") ??
    arbiter.items[0];
  const leader = signalNoise.items[0];
  const raceCandidate = raceExecution && raceExecution.selected_action && raceExecution.selected_action !== "ignore"
    ? raceExecution
    : undefined;
  const targetSymbol = readyBatchItem?.symbol ?? raceCandidate?.selected_symbol ?? selectedArbiter?.symbol ?? leader?.symbol ?? null;
  const targetSide = readyBatchItem?.side ?? raceCandidate?.selected_side ?? selectedArbiter?.side ?? (leader?.action === "protect" ? "sell" : leader ? "buy" : "hold");
  const targetAction = readyBatchItem?.action ?? raceCandidate?.selected_action ?? selectedArbiter?.action ?? leader?.action ?? "hold";
  const blockers = autonomousTradeMissionBlockers({
    tradeReadinessGate,
    burstScheduler,
    sessionSupervisor,
    capitalAllocator,
    readyBatchItem,
    selectedArbiter,
    leader,
    raceExecution,
  });
  const status = autonomousTradeMissionStatus({
    blockers,
    targetSide,
    signalNoise,
    arbiter,
    tradeBatch,
    tradeReadinessGate,
    capitalAllocator,
    walletTelemetry,
    sessionSupervisor,
    burstScheduler,
    postTradeReview,
    raceExecution,
  });
  const objective = autonomousTradeMissionObjective(status);
  const expectedProfit = Math.round(Math.max(
    0,
    readyBatchItem?.expected_profit_usd ?? 0,
    raceExecution?.expected_edge_usd ?? 0,
    selectedArbiter?.expected_profit_usd ?? 0,
    burstScheduler.expected_profit_next_tick_usd,
    sessionSupervisor.expected_next_profit_usd,
  ));
  const maxRisk = Math.round(Math.max(
    0,
    readyBatchItem?.max_loss_usd ?? 0,
    raceExecution?.risk_usd ?? 0,
    selectedArbiter?.max_loss_usd ?? 0,
    burstScheduler.risk_budget_next_tick_usd,
  ));
  const confidence = autonomousTradeMissionConfidence({
    status,
    leader,
    selectedArbiter,
    signalAlpha,
    tradeReadinessGate,
    burstScheduler,
    performance,
  });
  const evidence = autonomousTradeMissionEvidence({
    leader,
    selectedArbiter,
    readyBatchItem,
    signalAlpha,
    walletTelemetry,
    routeRefreshQueue,
    executionBridge,
    raceExecution,
  });
  const steps = autonomousTradeMissionSteps({
    status,
    targetSymbol,
    targetSide,
    signalNoise,
    capitalAllocator,
    walletTelemetry,
    routeRefreshQueue,
    tradeReadinessGate,
    executionBridge,
    raceExecution,
    burstScheduler,
  });

  return {
    mode: "autonomous-trade-mission",
    status,
    objective,
    target_symbol: targetSymbol,
    target_side: targetSide,
    target_action: targetAction,
    mission_label: autonomousTradeMissionLabel(status, targetSymbol, targetSide, targetAction),
    summary: autonomousTradeMissionSummary(status, targetSymbol, expectedProfit, confidence, blockers),
    next_action: autonomousTradeMissionNextAction(status, blockers, readyBatchItem, selectedArbiter, burstScheduler, sessionSupervisor, raceExecution),
    confidence_score: confidence,
    signal_to_noise_ratio: leader?.signal_to_noise_ratio ?? signalNoise.average_signal_to_noise_ratio,
    expected_profit_usd: expectedProfit,
    max_risk_usd: maxRisk,
    deploy_budget_usd: Math.round(Math.max(0, capitalAllocator.deploy_budget_usd)),
    release_budget_usd: Math.round(Math.max(0, capitalAllocator.release_budget_usd)),
    max_trades: burstScheduler.max_trades_next_tick,
    next_tick_seconds: burstScheduler.next_tick_seconds,
    route_quote_budget_per_minute: burstScheduler.route_quote_budget_per_minute,
    blockers,
    evidence,
    controls: [
      "Mission status is derived from existing trading subsystems instead of a separate decision engine.",
      "Attack and probe missions can only advance the local paper daemon while signer and live-submit gates remain locked.",
      "Harvest and protect missions rank exits before fresh buys when wallet telemetry, drawdown, or sell signals deteriorate.",
      "Blocked missions preserve the first actionable gate so the cockpit explains what must clear next.",
    ],
    steps,
  };
}

function autonomousTradeMissionBlockers({
  tradeReadinessGate,
  burstScheduler,
  sessionSupervisor,
  capitalAllocator,
  readyBatchItem,
  selectedArbiter,
  leader,
  raceExecution,
}: {
  tradeReadinessGate: AutonomousTradeReadinessGate;
  burstScheduler: AutonomousBurstScheduler;
  sessionSupervisor: AutonomousSessionSupervisor;
  capitalAllocator: AutonomousCapitalAllocator;
  readyBatchItem: AutonomousTradeBatchItem | undefined;
  selectedArbiter: AutonomousTradeArbiterItem | undefined;
  leader: SignalNoiseItem | undefined;
  raceExecution?: AutonomousOpportunityRaceExecution;
}) {
  const burstItems = Array.isArray(burstScheduler.items) ? burstScheduler.items : [];
  return [...new Set([
    ...tradeReadinessGate.blockers,
    ...burstItems.flatMap((item) => Array.isArray(item.blockers) ? item.blockers : []),
    ...(burstScheduler.status === "stand-down" ? [burstScheduler.next_action] : []),
    ...sessionSupervisor.blockers,
    ...capitalAllocator.blockers,
    ...(readyBatchItem?.blockers ?? []),
    ...(selectedArbiter?.blockers ?? []),
    ...(leader?.blockers ?? []),
    ...(raceExecution?.status === "blocked" ? raceExecution.blockers : []),
  ].filter((item): item is string => typeof item === "string" && item.length > 0))].slice(0, 7);
}

function autonomousTradeMissionStatus({
  blockers,
  targetSide,
  signalNoise,
  arbiter,
  tradeBatch,
  tradeReadinessGate,
  capitalAllocator,
  walletTelemetry,
  sessionSupervisor,
  burstScheduler,
  postTradeReview,
  raceExecution,
}: {
  blockers: string[];
  targetSide: "buy" | "sell" | "hold";
  signalNoise: SignalNoiseScanner;
  arbiter: AutonomousTradeArbiter;
  tradeBatch: AutonomousTradeBatch;
  tradeReadinessGate: AutonomousTradeReadinessGate;
  capitalAllocator: AutonomousCapitalAllocator;
  walletTelemetry: AutonomousWalletTelemetry;
  sessionSupervisor: AutonomousSessionSupervisor;
  burstScheduler: AutonomousBurstScheduler;
  postTradeReview: PostTradeReview;
  raceExecution?: AutonomousOpportunityRaceExecution;
}): AutonomousTradeMissionStatus {
  if (
    tradeReadinessGate.status === "blocked" ||
    sessionSupervisor.status === "blocked" ||
    burstScheduler.status === "stand-down" ||
    capitalAllocator.status === "blocked"
  ) return "blocked";
  if (raceExecution?.status === "blocked") return "blocked";
  if (
    walletTelemetry.status === "protect" ||
    signalNoise.status === "protect" ||
    tradeReadinessGate.status === "exit-only" ||
    postTradeReview.decision === "exit-only"
  ) return "protect";
  if (raceExecution?.paper_trade_ready || raceExecution?.ledger_applied) {
    if (raceExecution.selected_side === "sell") return "harvest";
    if (raceExecution.selected_action === "attack") return "attack";
    if (raceExecution.selected_action === "probe") return "probe";
    if (raceExecution.selected_action === "protect" || raceExecution.selected_action === "harvest") return "harvest";
  }
  if (targetSide === "sell" || tradeBatch.sell_count > 0 || arbiter.status === "sell" || arbiter.status === "harvest" || capitalAllocator.release_budget_usd > 0) return "harvest";
  if (burstScheduler.status === "cooldown" || sessionSupervisor.status === "cooldown" || postTradeReview.pause_new_entries) return "cooldown";
  if (signalNoise.attack_count > 0 && (tradeBatch.ready_count > 0 || burstScheduler.status === "burst" || burstScheduler.status === "active")) return "attack";
  if (signalNoise.probe_count > 0 || burstScheduler.status === "selective" || tradeReadinessGate.status === "repair-first") return "probe";
  if (blockers.length > 0) return "blocked";
  return "idle";
}

function autonomousTradeMissionObjective(status: AutonomousTradeMissionStatus): AutonomousTradeMission["objective"] {
  if (status === "attack" || status === "probe") return "compound";
  if (status === "harvest") return "harvest";
  if (status === "protect" || status === "blocked" || status === "cooldown") return "protect";
  return "observe";
}

function autonomousTradeMissionConfidence({
  status,
  leader,
  selectedArbiter,
  signalAlpha,
  tradeReadinessGate,
  burstScheduler,
  performance,
}: {
  status: AutonomousTradeMissionStatus;
  leader: SignalNoiseItem | undefined;
  selectedArbiter: AutonomousTradeArbiterItem | undefined;
  signalAlpha: SignalAlphaAttribution;
  tradeReadinessGate: AutonomousTradeReadinessGate;
  burstScheduler: AutonomousBurstScheduler;
  performance: PerformanceScorecard;
}) {
  const base = Math.round(
    (leader?.signal_score ?? 45) * 0.28 +
      (selectedArbiter?.decision_score ?? 45) * 0.28 +
      tradeReadinessGate.gate_score * 0.2 +
      performance.risk_adjusted_score * 0.12 +
      Math.min(100, Math.max(0, signalAlpha.recommended_size_multiplier * 70)) * 0.12,
  );
  const penalty = status === "blocked" ? 28 : status === "cooldown" ? 14 : status === "protect" ? 8 : 0;
  const burstBonus = burstScheduler.status === "burst" ? 8 : burstScheduler.status === "active" ? 4 : 0;
  return clamp(base + burstBonus - penalty, 0, 100);
}

function autonomousTradeMissionEvidence({
  leader,
  selectedArbiter,
  readyBatchItem,
  signalAlpha,
  walletTelemetry,
  routeRefreshQueue,
  executionBridge,
  raceExecution,
}: {
  leader: SignalNoiseItem | undefined;
  selectedArbiter: AutonomousTradeArbiterItem | undefined;
  readyBatchItem: AutonomousTradeBatchItem | undefined;
  signalAlpha: SignalAlphaAttribution;
  walletTelemetry: AutonomousWalletTelemetry;
  routeRefreshQueue: RouteRefreshQueue;
  executionBridge: AutonomousTradeExecutionBridge;
  raceExecution?: AutonomousOpportunityRaceExecution;
}) {
  return [...new Set([
    ...(leader?.evidence ?? []),
    ...(selectedArbiter?.sources ?? []),
    readyBatchItem?.reason,
    signalAlpha.summary,
    walletTelemetry.summary,
    routeRefreshQueue.next_action,
    executionBridge.next_action,
    raceExecution?.next_action,
  ].filter((item): item is string => typeof item === "string" && item.length > 0))].slice(0, 6);
}

function autonomousTradeMissionSteps({
  status,
  targetSymbol,
  targetSide,
  signalNoise,
  capitalAllocator,
  walletTelemetry,
  routeRefreshQueue,
  tradeReadinessGate,
  executionBridge,
  raceExecution,
  burstScheduler,
}: {
  status: AutonomousTradeMissionStatus;
  targetSymbol: string | null;
  targetSide: "buy" | "sell" | "hold";
  signalNoise: SignalNoiseScanner;
  capitalAllocator: AutonomousCapitalAllocator;
  walletTelemetry: AutonomousWalletTelemetry;
  routeRefreshQueue: RouteRefreshQueue;
  tradeReadinessGate: AutonomousTradeReadinessGate;
  executionBridge: AutonomousTradeExecutionBridge;
  raceExecution?: AutonomousOpportunityRaceExecution;
  burstScheduler: AutonomousBurstScheduler;
}): AutonomousTradeMissionStep[] {
  return [
    {
      id: "mission-target",
      lane: "target",
      label: "Target",
      status: targetSymbol && status !== "blocked" ? "pass" : targetSymbol ? "watch" : "fail",
      value: targetSymbol ? `${targetSymbol} ${targetSide}` : "none",
      detail: targetSymbol ? `Mission is focused on the current ${targetSide} candidate.` : "No target has cleared the desk yet.",
    },
    {
      id: "mission-signal",
      lane: "signal",
      label: "Signal/noise",
      status: signalNoise.status === "attack" ? "pass" : signalNoise.status === "noisy" || signalNoise.status === "protect" ? "fail" : "watch",
      value: `${roundMetric(signalNoise.average_signal_to_noise_ratio)}x`,
      detail: signalNoise.next_action,
    },
    {
      id: "mission-capital",
      lane: "capital",
      label: "Capital",
      status: capitalAllocator.status === "blocked" ? "fail" : capitalAllocator.deploy_budget_usd > 0 || capitalAllocator.release_budget_usd > 0 ? "pass" : "watch",
      value: targetSide === "sell" ? formatCompactValue(capitalAllocator.release_budget_usd) : formatCompactValue(capitalAllocator.deploy_budget_usd),
      detail: capitalAllocator.next_action,
    },
    {
      id: "mission-route",
      lane: "route",
      label: "Route",
      status: routeRefreshQueue.status === "blocked" ? "fail" : routeRefreshQueue.status === "refresh-now" || routeRefreshQueue.status === "queued" ? "watch" : "pass",
      value: `${burstScheduler.route_quote_budget_per_minute}/m`,
      detail: routeRefreshQueue.next_action,
    },
    {
      id: "mission-wallet",
      lane: "wallet",
      label: "Wallet",
      status: walletTelemetry.status === "protect" ? "fail" : walletTelemetry.status === "cooldown" || walletTelemetry.status === "recover" ? "watch" : "pass",
      value: formatCompactValue(walletTelemetry.equity_usd),
      detail: walletTelemetry.next_action,
    },
    {
      id: "mission-gate",
      lane: "gate",
      label: "Gate",
      status: tradeReadinessGate.status === "blocked" ? "fail" : tradeReadinessGate.status === "ready" || tradeReadinessGate.status === "paper-only" ? "pass" : "watch",
      value: `${tradeReadinessGate.gate_score}/100`,
      detail: tradeReadinessGate.next_action,
    },
    {
      id: "mission-race-execution",
      lane: "execution",
      label: "Race bridge",
      status: raceExecution?.status === "blocked"
        ? "fail"
        : raceExecution?.paper_trade_ready || raceExecution?.ledger_applied
          ? "pass"
          : raceExecution?.status === "queued"
            ? "watch"
            : "watch",
      value: raceExecution?.selected_symbol ? `${raceExecution.selected_symbol} ${raceExecution.selected_side}` : "none",
      detail: raceExecution?.next_action ?? "No opportunity-race paper action is ready yet.",
    },
    {
      id: "mission-execution",
      lane: "execution",
      label: "Execution",
      status: executionBridge.status === "blocked" ? "fail" : executionBridge.paper_trade_ready || executionBridge.ledger_applied ? "pass" : "watch",
      value: executionBridge.execution_boundary.replaceAll("-", " "),
      detail: executionBridge.next_action,
    },
  ];
}

function autonomousTradeMissionLabel(
  status: AutonomousTradeMissionStatus,
  symbol: string | null,
  side: "buy" | "sell" | "hold",
  action: string,
) {
  if (!symbol) return status === "blocked" ? "Clear mission blocker" : "Observe market";
  return `${status.toUpperCase()} ${symbol} ${side === "hold" ? action : side}`;
}

function autonomousTradeMissionSummary(
  status: AutonomousTradeMissionStatus,
  symbol: string | null,
  expectedProfit: number,
  confidence: number,
  blockers: string[],
) {
  if (status === "blocked") return blockers[0] ?? "Mission is blocked until readiness gates clear.";
  if (status === "protect") return `Mission protects the wallet before adding exposure${symbol ? ` around ${symbol}` : ""}.`;
  if (status === "harvest") return `Mission harvests or trims exposure with ${formatCompactValue(expectedProfit)} modeled paper edge.`;
  if (status === "attack") return `Mission attacks ${symbol ?? "the top signal"} with ${confidence}/100 confidence and ${formatCompactValue(expectedProfit)} expected paper edge.`;
  if (status === "probe") return `Mission probes ${symbol ?? "the watch list"} while signal quality or route freshness is still selective.`;
  if (status === "cooldown") return "Mission cools down until wallet, review, or churn pressure improves.";
  return "Mission observes until a high-signal target clears the agent.";
}

function autonomousTradeMissionNextAction(
  status: AutonomousTradeMissionStatus,
  blockers: string[],
  readyBatchItem: AutonomousTradeBatchItem | undefined,
  selectedArbiter: AutonomousTradeArbiterItem | undefined,
  burstScheduler: AutonomousBurstScheduler,
  sessionSupervisor: AutonomousSessionSupervisor,
  raceExecution?: AutonomousOpportunityRaceExecution,
) {
  if (raceExecution?.status === "queued" || raceExecution?.status === "applied") return raceExecution.next_action;
  if (raceExecution?.status === "blocked" && (status === "blocked" || status === "protect")) return raceExecution.next_action;
  if (blockers[0] && (status === "blocked" || status === "cooldown" || status === "protect")) return blockers[0];
  if (readyBatchItem?.status === "ready") return readyBatchItem.reason;
  if (selectedArbiter?.reason) return selectedArbiter.reason;
  if (status === "attack" || status === "probe") return burstScheduler.next_action;
  return sessionSupervisor.next_action;
}

function autonomousLoopDirectorBlockers(
  sessionSupervisor: AutonomousSessionSupervisor,
  capitalAllocator: AutonomousCapitalAllocator,
  riskGovernor: AutonomyRiskGovernor,
  postTradeReview: PostTradeReview,
  daemonMemory: PaperDaemonMemory,
  tradeReadinessGate?: AutonomousTradeReadinessGate,
) {
  const blockers = [
    ...sessionSupervisor.blockers,
    ...capitalAllocator.blockers,
    ...(tradeReadinessGate?.status === "blocked" ? tradeReadinessGate.blockers : []),
  ];
  if (!sessionSupervisor.should_keep_running) blockers.push(sessionSupervisor.next_action);
  if (riskGovernor.status === "halted") blockers.push(riskGovernor.actions[0] ?? riskGovernor.summary);
  if (postTradeReview.decision === "exit-only") blockers.push(postTradeReview.next_action);
  if (daemonMemory.status === "halted") blockers.push(daemonMemory.recommended_action);
  if (tradeReadinessGate?.status === "repair-first") blockers.push(tradeReadinessGate.next_action);
  return [...new Set(blockers.filter(Boolean))].slice(0, 6);
}

function autonomousLoopDirectorStatus(
  sessionSupervisor: AutonomousSessionSupervisor,
  capitalAllocator: AutonomousCapitalAllocator,
  riskGovernor: AutonomyRiskGovernor,
  postTradeReview: PostTradeReview,
  daemonMemory: PaperDaemonMemory,
  blockers: string[],
  tradeReadinessGate?: AutonomousTradeReadinessGate,
  routeRefreshQueue?: RouteRefreshQueue,
): AutonomousLoopDirector["status"] {
  if (riskGovernor.status === "halted" || sessionSupervisor.status === "stand-down" || postTradeReview.decision === "exit-only" || daemonMemory.status === "halted") return "halted";
  if (tradeReadinessGate?.status === "blocked") return "blocked";
  if (sessionSupervisor.status === "blocked" || capitalAllocator.status === "blocked") return "blocked";
  if (!sessionSupervisor.should_keep_running) return "paused";
  if (sessionSupervisor.status === "cooldown" || postTradeReview.pause_new_entries || daemonMemory.pause_new_entries) return "cooldown";
  if (routeRefreshQueue?.status === "refresh-now") return "tick-now";
  if (routeRefreshQueue?.status === "queued" && sessionSupervisor.status === "observe") return "run";
  if (tradeReadinessGate?.status === "repair-first") return "observe";
  if (tradeReadinessGate?.status === "exit-only" && tradeReadinessGate.can_apply_batch) return "run";
  if (sessionSupervisor.can_advance_paper && (sessionSupervisor.status === "attack" || capitalAllocator.status === "deploy")) return "tick-now";
  if (sessionSupervisor.status === "harvest" || capitalAllocator.status === "harvest" || capitalAllocator.status === "rebalance") return "run";
  if (blockers.length > 0) return "observe";
  return sessionSupervisor.status === "observe" ? "observe" : "run";
}

function autonomousLoopPressure({
  tradeBatch,
  setupMemory,
  routeQuoteSampler,
  routeRefreshQueue,
  marketStream,
  feedIntegrity,
  monitor,
  sessionSupervisor,
}: {
  tradeBatch?: AutonomousTradeBatch;
  setupMemory?: AutonomousSetupMemory;
  routeQuoteSampler?: RouteQuoteSampler;
  routeRefreshQueue?: RouteRefreshQueue;
  marketStream?: MarketStreamSupervisor;
  feedIntegrity?: MarketFeedIntegrity;
  monitor: AutonomousMonitorSchedule;
  sessionSupervisor: AutonomousSessionSupervisor;
}) {
  const batch = clamp(Math.round(
    (tradeBatch?.ready_count ?? 0) * 28 +
      (tradeBatch?.sell_count ?? 0) * 12 +
      (tradeBatch?.buy_count ?? 0) * 8 +
      Math.min(24, Math.abs(tradeBatch?.exposure_delta_usd ?? 0) / 45) +
      (tradeBatch?.status === "partially-applied" ? 14 : tradeBatch?.status === "ready" ? 22 : 0),
  ), 0, 100);
  const feed = clamp(Math.round(
    (monitor.should_refresh_market_data ? 24 : 0) +
      (feedIntegrity?.backfill_required ? 24 : 0) +
      (feedIntegrity?.reconnect_required ? 22 : 0) +
      (marketStream?.status === "backfill" ? 30 : marketStream?.status === "reconnect" ? 38 : marketStream?.status === "streaming" ? 10 : 0) +
      (feedIntegrity ? Math.max(0, 100 - feedIntegrity.confidence) * 0.32 : 16),
  ), 0, 100);
  const route = clamp(Math.round(
    (routeQuoteSampler?.status === "blocked" ? 82 : routeQuoteSampler?.status === "requote" ? 68 : routeQuoteSampler?.status === "probe" ? 48 : routeQuoteSampler?.status === "protect" ? 42 : 12) +
      Math.max(0, 100 - (routeQuoteSampler?.average_confidence_score ?? 64)) * 0.28 +
      Math.min(20, (routeQuoteSampler?.average_impact_drift_bps ?? 0) / 8) +
      (routeRefreshQueue?.status === "refresh-now" ? 28 : routeRefreshQueue?.status === "queued" ? 14 : routeRefreshQueue?.status === "blocked" ? 18 : 0) +
      routeRefreshQueuePressure(routeRefreshQueue),
  ), 0, 100);
  const setup = clamp(Math.round(
    (setupMemory?.status === "press" ? 72 : setupMemory?.status === "cooldown" ? 58 : setupMemory?.status === "selective" ? 34 : 18) +
      (setupMemory?.hot_symbol_count ?? 0) * 8 +
      (setupMemory?.cold_symbol_count ?? 0) * 6 +
      (setupMemory?.items.some((item) => item.action === "exit-first") ? 18 : 0),
  ), 0, 100);
  const session = clamp(Math.round(
    sessionSupervisor.urgency_score * 0.42 +
      sessionSupervisor.loop_score * 0.24 +
      Math.max(0, 100 - sessionSupervisor.risk_score) * 0.18,
  ), 0, 100);
  return { batch, feed, route, setup, session };
}

function routeRefreshQueuePressure(routeRefreshQueue: RouteRefreshQueue | undefined) {
  if (!routeRefreshQueue || routeRefreshQueue.status === "idle") return 0;
  return Math.min(
    28,
    routeRefreshQueue.refresh_now_count * 8 +
      routeRefreshQueue.stale_quote_count * 10 +
      routeRefreshQueue.blocked_count * 3 +
      Math.max(0, 12 - routeRefreshQueue.fastest_refresh_seconds) * 1.2,
  );
}

function autonomousLoopIntensity(
  status: AutonomousLoopDirector["status"],
  pressure: ReturnType<typeof autonomousLoopPressure>,
  sessionSupervisor: AutonomousSessionSupervisor,
  tradeBatch: AutonomousTradeBatch | undefined,
  monitor: AutonomousMonitorSchedule,
): AutonomousLoopDirector["intensity"] {
  if (status === "halted" || status === "blocked" || status === "paused") return "paused";
  if (status === "cooldown" || pressure.route >= 82 || sessionSupervisor.risk_score <= 34) return "cooldown";
  if (
    tradeBatch?.ready_count ||
    status === "tick-now" ||
    pressure.batch >= 58 ||
    pressure.setup >= 78 ||
    monitor.urgency_score >= 76
  ) return "burst";
  if (status === "run" || sessionSupervisor.status === "attack" || sessionSupervisor.status === "harvest" || pressure.session >= 48) return "active";
  if (pressure.feed >= 46 || monitor.should_refresh_market_data) return "watch";
  return status === "observe" ? "watch" : "active";
}

function autonomousLoopTickSeconds(
  status: AutonomousLoopDirector["status"],
  intensity: AutonomousLoopDirector["intensity"],
  sessionSupervisor: AutonomousSessionSupervisor,
  capitalAllocator: AutonomousCapitalAllocator,
  monitor: AutonomousMonitorSchedule,
  postTradeReview: PostTradeReview,
  daemonMemory: PaperDaemonMemory,
) {
  if (status === "halted" || status === "blocked" || status === "paused") return 0;
  if (intensity === "burst") return Math.max(1, Math.min(3, sessionSupervisor.cadence_seconds));
  if (intensity === "active") return Math.max(3, Math.min(8, sessionSupervisor.cadence_seconds));
  if (intensity === "watch") return Math.max(5, Math.min(18, monitor.recommended_interval_seconds));
  const reviewCadence = Math.max(postTradeReview.recommended_cadence_seconds, daemonMemory.status === "cooldown" ? 24 : 12);
  return Math.max(12, Math.min(45, reviewCadence + Math.max(0, capitalAllocator.blockers.length * 4)));
}

function autonomousLoopRouteRefreshTickSeconds(baseSeconds: number, routeRefreshQueue?: RouteRefreshQueue) {
  if (baseSeconds <= 0 || !routeRefreshQueue || routeRefreshQueue.status === "idle") return baseSeconds;
  if (routeRefreshQueue.status === "refresh-now") return Math.min(baseSeconds, Math.max(2, routeRefreshQueue.fastest_refresh_seconds));
  if (routeRefreshQueue.status === "queued") return Math.min(baseSeconds, Math.max(4, routeRefreshQueue.fastest_refresh_seconds));
  if (routeRefreshQueue.status === "blocked") return Math.min(baseSeconds, 10);
  return baseSeconds;
}

function autonomousLoopBurstTicks(
  intensity: AutonomousLoopDirector["intensity"],
  tradeBatch: AutonomousTradeBatch | undefined,
  sessionSupervisor: AutonomousSessionSupervisor,
  repeatedExecutionLimit: number,
) {
  if (intensity !== "burst") return Math.max(1, Math.min(repeatedExecutionLimit, sessionSupervisor.can_advance_paper ? 2 : 1));
  return Math.max(1, Math.min(repeatedExecutionLimit, Math.max(2, tradeBatch?.ready_count ?? 0, sessionSupervisor.can_advance_paper ? 3 : 2)));
}

function autonomousLoopMarketWatchMode(
  marketSource: Web3TradingState["market_source"],
  marketStream: MarketStreamSupervisor | undefined,
  feedIntegrity: MarketFeedIntegrity | undefined,
  intensity: AutonomousLoopDirector["intensity"],
): AutonomousLoopDirector["market_watch_mode"] {
  if (marketSource.status === "sample") return "sample-loop";
  if (marketStream?.transport === "websocket" || marketStream?.status === "streaming") return "stream";
  if (feedIntegrity?.backfill_required || feedIntegrity?.reconnect_required || marketStream?.status === "backfill" || marketStream?.status === "reconnect") return "backfill";
  return intensity === "paused" ? "standby" : "backfill";
}

function autonomousLoopDirectorSummary(
  status: AutonomousLoopDirector["status"],
  intensity: AutonomousLoopDirector["intensity"],
  tickSeconds: number,
  sessionSupervisor: AutonomousSessionSupervisor,
  capitalAllocator: AutonomousCapitalAllocator,
  tradeBatch: AutonomousTradeBatch | undefined,
  pressure: ReturnType<typeof autonomousLoopPressure>,
  blockers: string[],
) {
  if (intensity === "burst") return `Loop director bursts every ${tickSeconds}s for ${tradeBatch?.ready_count ?? 0} ready paper batch action${tradeBatch?.ready_count === 1 ? "" : "s"} and ${sessionSupervisor.loop_score}/100 loop score.`;
  if (intensity === "active") return `Loop director runs every ${tickSeconds}s with ${formatCompactValue(capitalAllocator.deploy_budget_usd)} deploy budget and ${formatCompactValue(capitalAllocator.release_budget_usd)} release budget.`;
  if (intensity === "watch") return `Loop director watches every ${tickSeconds}s while feed pressure is ${pressure.feed}/100 and route pressure is ${pressure.route}/100.`;
  if (status === "cooldown" || intensity === "cooldown") return `Loop director slows to ${tickSeconds}s while route, risk, post-trade review, or daemon memory cool down.`;
  if (status === "blocked") return blockers[0] ?? "Loop director is blocked before the next autonomous tick.";
  if (status === "halted") return blockers[0] ?? "Loop director halted the local autonomous loop.";
  return "Loop director paused the local loop until the session supervisor asks to continue.";
}

function autonomousLoopStopReason(
  status: AutonomousLoopDirector["status"],
  sessionSupervisor: AutonomousSessionSupervisor,
  postTradeReview: PostTradeReview,
  daemonMemory: PaperDaemonMemory,
) {
  if (status === "halted") return postTradeReview.next_action || daemonMemory.recommended_action;
  if (status === "blocked") return sessionSupervisor.next_action;
  if (status === "paused") return "Session supervisor is not asking the local loop to keep running.";
  return null;
}

function autonomousLoopTickReason(
  status: AutonomousLoopDirector["status"],
  intensity: AutonomousLoopDirector["intensity"],
  sessionSupervisor: AutonomousSessionSupervisor,
  capitalAllocator: AutonomousCapitalAllocator,
  monitor: AutonomousMonitorSchedule,
  tradeBatch: AutonomousTradeBatch | undefined,
  pressure: ReturnType<typeof autonomousLoopPressure>,
  routeRefreshQueue?: RouteRefreshQueue,
) {
  if (routeRefreshQueue?.status === "refresh-now") return routeRefreshQueue.next_action;
  if (routeRefreshQueue?.status === "queued" && pressure.route >= 60) return routeRefreshQueue.next_action;
  if (intensity === "burst" && tradeBatch?.ready_count) return tradeBatch.next_action;
  if (intensity === "watch") return `Refresh market evidence before risk-up; feed ${pressure.feed}/100, route ${pressure.route}/100.`;
  if (status === "tick-now") return sessionSupervisor.next_action;
  if (status === "run") return capitalAllocator.next_action;
  if (status === "observe") return monitor.summary;
  if (status === "cooldown") return sessionSupervisor.next_action;
  return "No daemon tick should be issued until blockers clear.";
}

function buildPaperDaemonTick({
  state,
  requested,
  previousCycle,
  advanced,
  monitorDecision,
}: {
  state: PaperDaemonTickState;
  requested: boolean;
  previousCycle: number;
  advanced: boolean;
  monitorDecision?: AutonomousMonitorSchedule;
}): PaperDaemonTick {
  const decision = monitorDecision ?? state.autonomous_monitor;
  const wake = decision;
  const governorBlocked = !state.autonomy_risk_governor.allow_paper_advance;
  const standDown = decision.status === "stand-down" ||
    state.autopilot.status === "stand-down" ||
    state.autonomy_risk_governor.status === "halted";
  const currentTrades = currentCycleTrades(state.trade_tape, state.paper_account.cycle);
  const filledCount = currentTrades.filter((trade) => trade.status === "paper-filled").length;
  const autopilotBlocked = state.autopilot.actions.filter((action) => action.status === "blocked").length;
  const blockedCount = autopilotBlocked + state.execution_intents.blocked_count + state.execution_preflight.blocked_count;
  const observedCount = state.autopilot.actions.filter((action) => action.status === "watching" || action.status === "skipped").length +
    state.execution_intents.cooldown_count +
    state.execution_preflight.watch_count +
    decision.triggers.length;
  const action: PaperDaemonTick["action"] = standDown
    ? "stand-down"
    : requested && advanced && !governorBlocked
      ? "advance"
      : "observe";
  const status: PaperDaemonTick["status"] = action === "advance"
    ? "advanced"
    : action === "stand-down"
      ? "stand-down"
      : "observed";

  return {
    mode: "paper-daemon",
    requested,
    action,
    status,
    previous_cycle: previousCycle,
    current_cycle: state.paper_account.cycle,
    advanced: requested && advanced && !governorBlocked,
    filled_count: requested && advanced && !governorBlocked ? filledCount : 0,
    blocked_count: blockedCount,
    observed_count: observedCount,
    interval_seconds: wake.recommended_interval_seconds,
    next_tick_at: wake.next_wake_at,
    reason: paperDaemonReason({
      requested,
      advanced: requested && advanced,
      standDown,
      monitor: decision,
      blockedCount,
      liveExecutionEnabled: state.execution_gate.live_execution_enabled,
      riskGovernor: state.autonomy_risk_governor,
    }),
    controls: [
      "Paper ledger only; no signed transaction was submitted.",
      "Live execution remains locked behind the execution gate.",
      "Daemon advances only when the autonomous monitor clears advance mode.",
      "Risk governor must clear drawdown, turnover, feed, execution, and learning gates.",
      "Preflight, MEV, retry, and readiness blockers are honored before a fill.",
    ],
  };
}

function paperDaemonReason({
  requested,
  advanced,
  standDown,
  monitor,
  blockedCount,
  liveExecutionEnabled,
  riskGovernor,
}: {
  requested: boolean;
  advanced: boolean;
  standDown: boolean;
  monitor: AutonomousMonitorSchedule;
  blockedCount: number;
  liveExecutionEnabled: boolean;
  riskGovernor: AutonomyRiskGovernor;
}) {
  if (!requested) return "No daemon tick requested; state is ready for the next paper wake.";
  if (!riskGovernor.allow_paper_advance) return `Daemon observed because the risk governor is ${riskGovernor.status}: ${riskGovernor.summary}`;
  if (standDown) return "Daemon stood down because the monitor or policy is preserving capital.";
  if (advanced) return "Daemon advanced the paper ledger because the monitor found actionable ready orders.";
  if (!monitor.should_advance_paper) return "Daemon observed only because the monitor wants fresh surveillance without filling.";
  if (!liveExecutionEnabled && blockedCount > 0) return "Daemon observed while execution blockers stay visible for review.";
  return "Daemon observed; no persistent paper advance was required on this tick.";
}

function autopilotPlanStatus(
  plan: ExecutionPlan | undefined,
  readiness: ExecutionReadiness,
): AutopilotActionStatus {
  if (readinessBlockers(readiness).length > 0) return "blocked";
  if (!plan) return "ready";
  if (plan.status === "no-route" || plan.status === "unsupported-chain" || plan.status === "blocked") return "blocked";
  return "ready";
}

function autopilotExecutionGate(
  plan: ExecutionPlan | undefined,
  readiness: ExecutionReadiness,
  status: AutopilotActionStatus,
) {
  if (status === "paper-filled") return "Paper ledger filled; no signed transaction was submitted.";
  if (status === "skipped") return "Skipped by autonomy policy.";
  const blocker = readinessBlockers(readiness)[0];
  if (blocker) return blocker;
  if (!plan) return "No route check needed for this cycle.";
  if (plan.source === "jupiter" && plan.status === "quoted") {
    return plan.dry_run.transaction_ready
      ? "Unsigned Jupiter payload is ready, but signing/submission remain blocked."
      : "Jupiter quote is available; no live submission is enabled.";
  }
  return plan.message;
}

function autopilotSummary(
  status: AutopilotRunbook["status"],
  actions: AutopilotAction[],
  situation: SituationMonitor,
  policy: AutonomyPolicy,
) {
  if (status === "stand-down") return "Autopilot is standing down from fresh entries and only managing risk.";
  if (status === "executed-paper") {
    const fills = actions.filter((action) => action.status === "paper-filled").length;
    return `${fills} paper action${fills === 1 ? "" : "s"} filled this cycle under ${policy.status_label.toLowerCase()} policy.`;
  }
  if (status === "blocked") return "Every actionable order is blocked by readiness, routing, or policy gates.";
  return `${situation.regime.replace("-", " ")} tape has a planned queue ready for the next paper cycle.`;
}

function buildAutonomousMonitorSchedule({
  asOf,
  baseIntervalSeconds,
  autopilot,
  situation,
  tapeMemory,
  priceAction,
  rugFirewall,
  positionExitLadder,
  liquidityExitSentinel,
  executionMevGuard,
  paperExecutionQuality,
  executionPreflight,
  performance,
  feedIntegrity,
  riskGovernor,
  executionEdge,
  daemonMemory,
  discoveryEdge,
  launchGraduation,
  holderFlow,
  profitLoop,
  liquidityDepth,
  routeQuoteSampler,
  alphaDecay,
  positionCommander,
  profitLock,
  profitCaptureRace,
  churnEfficiency,
  microstructureTape,
  walletEventReactor,
  smartMoney,
}: {
  asOf: string;
  baseIntervalSeconds: number;
  autopilot: AutopilotRunbook;
  situation: SituationMonitor;
  tapeMemory: TapeMemory;
  priceAction: PriceActionMonitor;
  rugFirewall: RugPullFirewall;
  positionExitLadder: PositionExitLadderEngine;
  liquidityExitSentinel?: LiquidityExitSentinel;
  executionMevGuard: ExecutionMevGuard;
  paperExecutionQuality: PaperExecutionQuality;
  executionPreflight: ExecutionPreflightReport;
  performance: PerformanceScorecard;
  feedIntegrity: MarketFeedIntegrity;
  riskGovernor: AutonomyRiskGovernor;
  executionEdge: ExecutionEdgeLadder;
  daemonMemory?: PaperDaemonMemory;
  discoveryEdge?: DiscoveryEdgeSupervisor;
  launchGraduation?: LaunchGraduationSupervisor;
  holderFlow?: HolderFlowSentinel;
  profitLoop?: ProfitLoopController;
  liquidityDepth?: LiquidityDepthController;
  routeQuoteSampler?: RouteQuoteSampler;
  alphaDecay?: AlphaDecayController;
  positionCommander?: PositionCommander;
  profitLock?: ProfitLockAutopilot;
  profitCaptureRace?: ProfitCaptureRace;
  churnEfficiency?: ChurnEfficiencyAuditor;
  microstructureTape?: MicrostructureTape;
  walletEventReactor?: WalletEventReactor;
  smartMoney?: SmartMoneySentinel;
}): AutonomousMonitorSchedule {
  const triggers = autonomousMonitorTriggers({
    autopilot,
    situation,
    tapeMemory,
    priceAction,
    rugFirewall,
    positionExitLadder,
    liquidityExitSentinel,
    executionMevGuard,
    paperExecutionQuality,
    executionPreflight,
    performance,
    feedIntegrity,
    riskGovernor,
    executionEdge,
    daemonMemory,
    discoveryEdge,
    launchGraduation,
    holderFlow,
    profitLoop,
    liquidityDepth,
    routeQuoteSampler,
    alphaDecay,
    positionCommander,
    profitLock,
    profitCaptureRace,
    churnEfficiency,
    microstructureTape,
    walletEventReactor,
    smartMoney,
  });
  const urgentCount = triggers.filter((trigger) => trigger.severity === "urgent").length;
  const watchCount = triggers.filter((trigger) => trigger.severity === "watch").length;
  const urgencyScore = clamp(Math.round(
    situation.risk_score * 0.24 +
      tapeMemory.pressure_score * 0.22 +
      priceAction.average_velocity_score * 0.16 +
      rugFirewall.average_risk_score * 0.18 +
      (liquidityExitSentinel?.average_exit_pressure_score ?? 0) * 0.14 +
      (launchGraduation?.average_graduation_score ?? 0) * 0.08 +
      (holderFlow?.average_insider_risk_score ?? 0) * 0.12 +
      (profitLoop?.status === "compound" || profitLoop?.status === "attack" ? profitLoop.loop_score * 0.12 : 0) +
      (profitLoop?.status === "cooldown" || profitLoop?.status === "protect" ? Math.max(0, 100 - profitLoop.loop_score) * 0.1 : 0) +
      (liquidityDepth?.status === "blocked" || liquidityDepth?.status === "protect" ? Math.max(0, 100 - liquidityDepth.average_depth_score) * 0.12 : 0) +
      (liquidityDepth?.status === "slice" || liquidityDepth?.status === "resize" ? 8 : 0) +
      (routeQuoteSampler?.status === "blocked" || routeQuoteSampler?.status === "requote" ? Math.max(0, 100 - routeQuoteSampler.average_confidence_score) * 0.14 : 0) +
      (routeQuoteSampler?.status === "probe" ? 7 : 0) +
      (alphaDecay?.status === "chase" || alphaDecay?.status === "harvest" ? Math.max(0, alphaDecay.average_alpha_score) * 0.12 : 0) +
      (alphaDecay?.status === "expired" || alphaDecay?.status === "cooldown" ? Math.max(0, 100 - alphaDecay.average_freshness_score) * 0.12 : 0) +
      (positionCommander?.status === "exit" || positionCommander?.status === "trim" ? positionCommander.average_command_score * 0.16 : 0) +
      (positionCommander?.status === "defend" || positionCommander?.status === "moonbag" ? positionCommander.average_command_score * 0.08 : 0) +
      (profitLock?.status === "exit" || profitLock?.status === "harvest" ? profitLock.average_lock_score * 0.17 : 0) +
      (profitLock?.status === "defend" || profitLock?.status === "trail" ? profitLock.average_lock_score * 0.1 : 0) +
      (profitCaptureRace?.status === "race" || profitCaptureRace?.status === "trim" ? profitCaptureRace.average_race_score * 0.18 : 0) +
      (profitCaptureRace?.status === "harvest" || profitCaptureRace?.status === "trail" ? profitCaptureRace.average_race_score * 0.1 : 0) +
      (churnEfficiency?.status === "accelerate" ? churnEfficiency.churn_score * 0.08 : 0) +
      (churnEfficiency?.status === "cooldown" || churnEfficiency?.status === "stop" ? Math.max(0, 100 - churnEfficiency.churn_score) * 0.12 : 0) +
      (microstructureTape?.status === "rug-pull" || microstructureTape?.status === "defensive" ? microstructureTape.average_micro_score * 0.15 : 0) +
      (microstructureTape?.status === "attack" || microstructureTape?.status === "absorb" ? microstructureTape.average_micro_score * 0.1 : 0) +
      (walletEventReactor?.status === "protect" || walletEventReactor?.status === "attack" ? Math.max(...walletEventReactor.items.map((item) => item.pressure_score), 0) * 0.16 : 0) +
      (walletEventReactor?.status === "probe" ? Math.max(...walletEventReactor.items.map((item) => item.pressure_score), 0) * 0.08 : 0) +
      (smartMoney?.status === "exit" || smartMoney?.status === "defensive" ? smartMoney.average_smart_score * 0.12 : 0) +
      (smartMoney?.status === "follow" || smartMoney?.status === "probe" ? smartMoney.average_smart_score * 0.1 : 0) +
      executionMevGuard.average_sandwich_risk_score * 0.08 +
      Math.min(100, paperExecutionQuality.average_slippage_bps / 2) * 0.06 +
      (100 - feedIntegrity.confidence) * 0.12 +
      (executionEdge.executable_count > 0 ? 10 : executionEdge.blocked_count > 0 ? 5 : 0) +
      urgentCount * 9 +
      watchCount * 3,
  ), 0, 100);
  const status: AutonomousMonitorSchedule["status"] = daemonMemory?.pause_new_entries
    ? "cooldown"
    : profitLoop?.status === "stand-down"
      ? "stand-down"
    : profitLoop?.status === "cooldown" || profitLoop?.status === "protect"
      ? "cooldown"
    : liquidityDepth?.status === "blocked"
      ? "cooldown"
    : liquidityDepth?.status === "protect"
      ? "accelerate"
    : routeQuoteSampler?.status === "blocked" || routeQuoteSampler?.status === "requote"
      ? "cooldown"
    : routeQuoteSampler?.status === "protect" || routeQuoteSampler?.status === "probe"
      ? "accelerate"
    : alphaDecay?.status === "expired" || alphaDecay?.status === "cooldown"
      ? "cooldown"
    : alphaDecay?.status === "chase" || alphaDecay?.status === "harvest"
      ? "accelerate"
    : positionCommander?.status === "exit" || positionCommander?.status === "trim" || positionCommander?.status === "defend"
      ? "accelerate"
    : profitLock?.status === "exit" || profitLock?.status === "harvest" || profitLock?.status === "defend"
      ? "accelerate"
    : profitLock?.status === "trail"
      ? "active"
    : profitCaptureRace?.status === "race" || profitCaptureRace?.status === "trim" || profitCaptureRace?.status === "harvest"
      ? "accelerate"
    : profitCaptureRace?.status === "trail" || profitCaptureRace?.status === "press"
      ? "active"
    : churnEfficiency?.status === "stop" || churnEfficiency?.status === "cooldown"
      ? "cooldown"
    : churnEfficiency?.status === "accelerate"
      ? "accelerate"
    : microstructureTape?.status === "rug-pull" || microstructureTape?.status === "attack" || microstructureTape?.status === "defensive"
      ? "accelerate"
    : walletEventReactor?.status === "protect" || walletEventReactor?.status === "attack"
      ? "accelerate"
    : walletEventReactor?.status === "stand-down"
      ? "cooldown"
    : smartMoney?.status === "exit" || smartMoney?.status === "follow"
      ? "accelerate"
    : profitLoop?.status === "compound" || profitLoop?.status === "attack"
      ? "accelerate"
    : discoveryEdge?.status === "stand-down" || discoveryEdge?.status === "cooldown"
      ? "cooldown"
    : launchGraduation?.status === "graduating"
      ? "accelerate"
    : situation.regime === "stand-down" || autopilot.status === "stand-down"
    ? "stand-down"
    : urgentCount > 0 || urgencyScore >= 72
      ? "accelerate"
      : watchCount > 0 || urgencyScore >= 44
        ? "active"
        : executionPreflight.status === "blocked" || paperExecutionQuality.status === "poor"
          ? "cooldown"
          : triggers.length === 0
            ? "idle"
            : "active";
  const recommendedInterval = autonomousMonitorInterval(status, baseIntervalSeconds, urgencyScore, executionPreflight, paperExecutionQuality);
  const shouldAdvancePaper = status !== "idle" &&
    status !== "cooldown" &&
    autopilot.status !== "stand-down" &&
    executionPreflight.status !== "blocked" &&
    paperExecutionQuality.status !== "poor" &&
    feedIntegrity.status !== "fallback" &&
    feedIntegrity.status !== "stale" &&
    feedIntegrity.status !== "degraded" &&
    daemonMemory?.pause_new_entries !== true &&
    discoveryEdge?.status !== "stand-down" &&
    discoveryEdge?.status !== "cooldown" &&
    profitLoop?.allows_paper_advance !== false &&
    liquidityDepth?.status !== "blocked" &&
    routeQuoteSampler?.status !== "blocked" &&
    routeQuoteSampler?.status !== "requote" &&
    alphaDecay?.status !== "expired" &&
    alphaDecay?.status !== "cooldown" &&
    riskGovernor.allow_paper_advance &&
    executionEdge.status !== "blocked" &&
    executionEdge.status !== "idle" &&
    (autopilot.actions.some((action) => action.status === "ready" || action.status === "paper-filled") ||
      walletEventReactor?.items.some((item) => item.status === "ready") === true);
  const watchSymbols = [...new Set([
    ...triggers.map((trigger) => trigger.symbol).filter((symbol): symbol is string => Boolean(symbol)),
    ...executionEdge.items.map((item) => item.symbol),
    ...(launchGraduation?.items.filter((item) => item.action !== "avoid" && item.action !== "wait").map((item) => item.symbol) ?? []),
    ...(holderFlow?.items.filter((item) => item.action !== "allow").map((item) => item.symbol) ?? []),
    ...(profitLoop?.items.map((item) => item.symbol).filter((symbol): symbol is string => Boolean(symbol)) ?? []),
    ...(liquidityDepth?.items.map((item) => item.symbol).filter((symbol): symbol is string => Boolean(symbol)) ?? []),
    ...(routeQuoteSampler?.items.map((item) => item.symbol).filter((symbol): symbol is string => Boolean(symbol)) ?? []),
    ...(alphaDecay?.items.map((item) => item.symbol).filter((symbol): symbol is string => Boolean(symbol)) ?? []),
    ...(positionCommander?.items.map((item) => item.symbol) ?? []),
    ...(profitLock?.items.filter((item) => item.action !== "wait").map((item) => item.symbol) ?? []),
    ...(profitCaptureRace?.items.filter((item) => item.action !== "hold").map((item) => item.symbol) ?? []),
    ...(churnEfficiency?.items.filter((item) => item.action !== "selective").map((item) => item.symbol) ?? []),
    ...(microstructureTape?.items.filter((item) => item.action !== "idle").map((item) => item.symbol) ?? []),
    ...(walletEventReactor?.items.filter((item) => item.status !== "blocked").map((item) => item.symbol) ?? []),
    ...(smartMoney?.items.filter((item) => item.action !== "observe").map((item) => item.symbol) ?? []),
    ...autopilot.actions.map((action) => action.symbol).filter((symbol): symbol is string => Boolean(symbol)),
  ])].slice(0, 8);
  const rankedTriggers = [...triggers].sort((a, b) => autonomousMonitorTriggerRank(b) - autonomousMonitorTriggerRank(a));

  return {
    status,
    mode: "paper-daemon",
    summary: autonomousMonitorSummary(status, recommendedInterval, shouldAdvancePaper, triggers),
    heartbeat_status: recommendedInterval <= baseIntervalSeconds / 2 ? "due" : status === "idle" ? "fresh" : "fresh",
    base_interval_seconds: baseIntervalSeconds,
    recommended_interval_seconds: recommendedInterval,
    next_wake_at: new Date(Date.parse(asOf) + recommendedInterval * 1_000).toISOString(),
    should_advance_paper: shouldAdvancePaper,
    should_refresh_market_data: status !== "idle" || feedIntegrity.backfill_required || feedIntegrity.reconnect_required,
    should_refresh_route_quotes: routeQuoteSampler?.status === "requote" || routeQuoteSampler?.status === "blocked" || routeQuoteSampler?.status === "probe" || routeQuoteSampler?.status === "protect",
    scan_budget_per_minute: Math.max(1, Math.floor(60 / recommendedInterval)),
    urgency_score: urgencyScore,
    watch_symbols: watchSymbols,
    triggers: rankedTriggers.slice(0, 18),
  };
}

function withRouteRefreshMonitorPressure(
  schedule: AutonomousMonitorSchedule,
  routeRefreshQueue: RouteRefreshQueue,
  asOf: string,
): AutonomousMonitorSchedule {
  if (routeRefreshQueue.status === "idle") {
    return { ...schedule, should_refresh_route_quotes: schedule.should_refresh_route_quotes };
  }

  const top = routeRefreshQueue.items[0];
  const refreshNow = routeRefreshQueue.status === "refresh-now";
  const blocked = routeRefreshQueue.status === "blocked";
  const queued = routeRefreshQueue.status === "queued";
  const interval = refreshNow
    ? Math.min(schedule.recommended_interval_seconds, Math.max(2, routeRefreshQueue.fastest_refresh_seconds))
    : queued
      ? Math.min(schedule.recommended_interval_seconds, Math.max(4, routeRefreshQueue.fastest_refresh_seconds))
      : blocked
        ? Math.min(schedule.recommended_interval_seconds, 10)
        : schedule.recommended_interval_seconds;
  const status: AutonomousMonitorSchedule["status"] = schedule.status === "stand-down"
    ? "stand-down"
    : blocked
      ? "cooldown"
      : refreshNow
        ? "accelerate"
        : queued && schedule.status === "idle"
          ? "active"
          : schedule.status;
  const severity: AutonomousMonitorTrigger["severity"] = blocked || refreshNow ? "urgent" : queued ? "watch" : "info";
  const trigger: AutonomousMonitorTrigger = {
    id: "route-refresh-queue",
    label: blocked ? "Refresh blocked" : refreshNow ? "Requote now" : queued ? "Refresh queued" : "Refresh watch",
    severity,
    symbol: top?.symbol ?? null,
    detail: top?.reason ?? routeRefreshQueue.summary,
  };
  const triggers = [trigger, ...schedule.triggers.filter((item) => item.id !== "route-refresh-queue")]
    .sort((a, b) => autonomousMonitorTriggerRank(b) - autonomousMonitorTriggerRank(a))
    .slice(0, 18);
  const urgency = clamp(Math.round(
    schedule.urgency_score +
      (refreshNow ? 18 : queued ? 8 : 0) +
      routeRefreshQueue.stale_quote_count * 8 +
      (blocked ? 10 : 0),
  ), 0, 100);
  return {
    ...schedule,
    status,
    summary: routeRefreshMonitorSummary(schedule.summary, routeRefreshQueue, top),
    heartbeat_status: refreshNow || interval <= Math.max(2, schedule.base_interval_seconds / 2) ? "due" : schedule.heartbeat_status,
    recommended_interval_seconds: interval,
    next_wake_at: isoAfterSeconds(asOf, interval),
    should_refresh_market_data: schedule.should_refresh_market_data || routeRefreshQueue.items.some((item) => item.lane === "dex-backfill"),
    should_refresh_route_quotes: true,
    scan_budget_per_minute: Math.max(schedule.scan_budget_per_minute, Math.max(1, Math.floor(60 / Math.max(1, interval)))),
    urgency_score: urgency,
    watch_symbols: [...new Set([
      ...routeRefreshQueue.watch_symbols,
      ...schedule.watch_symbols,
    ])].slice(0, 8),
    triggers,
  };
}

function withOpportunityRaceExecutionMonitorPressure(
  schedule: AutonomousMonitorSchedule,
  raceExecution: AutonomousOpportunityRaceExecution,
  asOf: string,
): AutonomousMonitorSchedule {
  if (raceExecution.status === "idle") return schedule;

  const urgent = raceExecution.status === "queued" || raceExecution.status === "applied";
  const interval = urgent
    ? Math.min(schedule.recommended_interval_seconds, Math.max(3, Math.min(8, raceExecution.review_after_seconds)))
    : Math.min(schedule.recommended_interval_seconds, 12);
  const trigger: AutonomousMonitorTrigger = {
    id: "opportunity-race-execution",
    label: raceExecution.status === "blocked"
      ? "Race bridge blocked"
      : raceExecution.status === "applied"
        ? "Race paper fill"
        : "Race paper queued",
    severity: urgent ? "urgent" : "watch",
    symbol: raceExecution.selected_symbol,
    detail: raceExecution.next_action,
  };
  const status: AutonomousMonitorSchedule["status"] = schedule.status === "stand-down"
    ? "stand-down"
    : raceExecution.status === "blocked"
      ? schedule.status === "idle" ? "active" : schedule.status
      : "accelerate";
  const triggers = [trigger, ...schedule.triggers.filter((item) => item.id !== trigger.id)]
    .sort((a, b) => autonomousMonitorTriggerRank(b) - autonomousMonitorTriggerRank(a))
    .slice(0, 18);
  const shouldAdvancePaper = schedule.should_advance_paper ||
    (
      raceExecution.status === "queued" &&
      raceExecution.paper_trade_ready &&
      raceExecution.blockers.length === 0 &&
      schedule.status !== "stand-down"
    );

  return {
    ...schedule,
    status,
    summary: raceExecution.status === "blocked"
      ? `Monitor keeps ${raceExecution.selected_symbol ?? "the race winner"} on watch because the opportunity-race bridge is blocked.`
      : `Monitor accelerates to ${interval}s because the opportunity-race bridge ${raceExecution.status === "applied" ? "recorded" : "queued"} ${raceExecution.selected_symbol ?? "the race winner"}.`,
    heartbeat_status: urgent || interval <= Math.max(2, schedule.base_interval_seconds / 2) ? "due" : schedule.heartbeat_status,
    recommended_interval_seconds: interval,
    next_wake_at: isoAfterSeconds(asOf, interval),
    should_advance_paper: shouldAdvancePaper,
    urgency_score: clamp(schedule.urgency_score + (urgent ? 14 : 5), 0, 100),
    watch_symbols: [...new Set([
      raceExecution.selected_symbol,
      ...schedule.watch_symbols,
    ].filter((symbol): symbol is string => Boolean(symbol)))].slice(0, 8),
    triggers,
  };
}

function withHighFrequencyRaceExecutionMonitorPressure(
  schedule: AutonomousMonitorSchedule,
  execution: HighFrequencyProfitRaceExecution,
  asOf: string,
): AutonomousMonitorSchedule {
  if (execution.status === "idle") return schedule;

  const urgent = execution.status === "queued" || execution.status === "applied";
  const interval = urgent
    ? Math.min(schedule.recommended_interval_seconds, Math.max(2, Math.min(6, execution.review_after_seconds)))
    : Math.min(schedule.recommended_interval_seconds, 10);
  const trigger: AutonomousMonitorTrigger = {
    id: "high-frequency-race-execution",
    label: execution.status === "blocked"
      ? "Fast race blocked"
      : execution.status === "applied"
        ? "Fast paper fill"
        : "Fast paper queued",
    severity: urgent ? "urgent" : "watch",
    symbol: execution.selected_symbol,
    detail: execution.next_action,
  };
  const status: AutonomousMonitorSchedule["status"] = schedule.status === "stand-down"
    ? "stand-down"
    : execution.status === "blocked"
      ? schedule.status === "idle" ? "active" : schedule.status
      : "accelerate";
  const triggers = [trigger, ...schedule.triggers.filter((item) => item.id !== trigger.id)]
    .sort((a, b) => autonomousMonitorTriggerRank(b) - autonomousMonitorTriggerRank(a))
    .slice(0, 18);
  const shouldAdvancePaper = schedule.should_advance_paper ||
    (
      execution.status === "queued" &&
      execution.paper_trade_ready &&
      execution.blockers.length === 0 &&
      schedule.status !== "stand-down"
    );

  return {
    ...schedule,
    status,
    summary: execution.status === "blocked"
      ? `Monitor keeps ${execution.selected_symbol ?? "the fast race"} on watch because high-frequency execution is blocked.`
      : `Monitor accelerates to ${interval}s because high-frequency execution ${execution.status === "applied" ? "recorded" : "queued"} ${execution.selected_symbol ?? "the fast race"}.`,
    heartbeat_status: urgent || interval <= Math.max(2, schedule.base_interval_seconds / 2) ? "due" : schedule.heartbeat_status,
    recommended_interval_seconds: interval,
    next_wake_at: isoAfterSeconds(asOf, interval),
    should_advance_paper: shouldAdvancePaper,
    urgency_score: clamp(schedule.urgency_score + (urgent ? 18 : 6), 0, 100),
    watch_symbols: [...new Set([
      execution.selected_symbol,
      ...schedule.watch_symbols,
    ].filter((symbol): symbol is string => Boolean(symbol)))].slice(0, 8),
    triggers,
  };
}

function routeRefreshMonitorSummary(
  summary: string,
  queue: RouteRefreshQueue,
  top: RouteRefreshQueueItem | undefined,
) {
  if (queue.status === "refresh-now") return `${queue.refresh_now_count} route refresh job${queue.refresh_now_count === 1 ? "" : "s"} must requote before the loop sizes again.`;
  if (queue.status === "blocked") return top?.blockers[0] ?? queue.summary;
  if (queue.status === "queued") return `${queue.queued_count} route refresh job${queue.queued_count === 1 ? "" : "s"} are queued; wake in ${queue.fastest_refresh_seconds}s.`;
  if (queue.status === "watch") return `Routes are fresh enough, but ${top?.symbol ?? "the desk"} remains on short refresh watch.`;
  return summary;
}

function autonomousMonitorTriggerRank(trigger: AutonomousMonitorTrigger) {
  const severity = trigger.severity === "urgent" ? 3 : trigger.severity === "watch" ? 2 : 1;
  const source = trigger.id === "route-refresh-queue" ? 0.55 : trigger.id === "wallet-event-reactor" ? 0.4 : 0;
  return severity + source;
}

function withMicrostructureMonitorTrigger(
  schedule: AutonomousMonitorSchedule,
  microstructureTape?: MicrostructureTape,
): AutonomousMonitorSchedule {
  const trigger = microstructureMonitorTrigger(microstructureTape);
  if (!trigger || schedule.triggers.some((item) => item.id === trigger.id)) return schedule;
  return {
    ...schedule,
    watch_symbols: [
      ...new Set([
        trigger.symbol,
        ...schedule.watch_symbols,
        ...(microstructureTape?.items.filter((item) => item.action !== "idle").map((item) => item.symbol) ?? []),
      ].filter((symbol): symbol is string => Boolean(symbol))),
    ].slice(0, 8),
    triggers: [trigger, ...schedule.triggers].slice(0, 12),
  };
}

function microstructureMonitorTrigger(microstructureTape?: MicrostructureTape): AutonomousMonitorTrigger | null {
  if (!microstructureTape || microstructureTape.status === "idle") return null;
  if (microstructureTape.status === "rug-pull" || microstructureTape.status === "defensive") {
    const item = microstructureTape.items.find((entry) => entry.action === "rug-pull" || entry.action === "distribute" || entry.action === "fade") ?? microstructureTape.items[0];
    return {
      id: "microstructure-tape",
      label: microstructureTape.status === "rug-pull" ? "Sell cascade" : "Distribution tape",
      severity: microstructureTape.status === "rug-pull" ? "urgent" : "watch",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? microstructureTape.summary,
    };
  }
  const item = microstructureTape.items.find((entry) => entry.action === "chase" || entry.action === "absorb") ?? microstructureTape.items[0];
  return {
    id: "microstructure-tape",
    label: microstructureTape.status === "attack" ? "Buy burst" : "Absorption",
    severity: microstructureTape.status === "attack" ? "urgent" : "watch",
    symbol: item?.symbol ?? null,
    detail: item?.reason ?? microstructureTape.summary,
  };
}

function autonomousMonitorTriggers({
  autopilot,
  situation,
  tapeMemory,
  priceAction,
  rugFirewall,
  positionExitLadder,
  liquidityExitSentinel,
  executionMevGuard,
  paperExecutionQuality,
  executionPreflight,
  performance,
  feedIntegrity,
  riskGovernor,
  executionEdge,
  daemonMemory,
  discoveryEdge,
  launchGraduation,
  holderFlow,
  profitLoop,
  liquidityDepth,
  routeQuoteSampler,
  alphaDecay,
  positionCommander,
  profitLock,
  profitCaptureRace,
  churnEfficiency,
  microstructureTape,
  walletEventReactor,
  smartMoney,
}: {
  autopilot: AutopilotRunbook;
  situation: SituationMonitor;
  tapeMemory: TapeMemory;
  priceAction: PriceActionMonitor;
  rugFirewall: RugPullFirewall;
  positionExitLadder: PositionExitLadderEngine;
  liquidityExitSentinel?: LiquidityExitSentinel;
  executionMevGuard: ExecutionMevGuard;
  paperExecutionQuality: PaperExecutionQuality;
  executionPreflight: ExecutionPreflightReport;
  performance: PerformanceScorecard;
  feedIntegrity: MarketFeedIntegrity;
  riskGovernor: AutonomyRiskGovernor;
  executionEdge: ExecutionEdgeLadder;
  daemonMemory?: PaperDaemonMemory;
  discoveryEdge?: DiscoveryEdgeSupervisor;
  launchGraduation?: LaunchGraduationSupervisor;
  holderFlow?: HolderFlowSentinel;
  profitLoop?: ProfitLoopController;
  liquidityDepth?: LiquidityDepthController;
  routeQuoteSampler?: RouteQuoteSampler;
  alphaDecay?: AlphaDecayController;
  positionCommander?: PositionCommander;
  profitLock?: ProfitLockAutopilot;
  profitCaptureRace?: ProfitCaptureRace;
  churnEfficiency?: ChurnEfficiencyAuditor;
  microstructureTape?: MicrostructureTape;
  walletEventReactor?: WalletEventReactor;
  smartMoney?: SmartMoneySentinel;
}): AutonomousMonitorTrigger[] {
  const triggers: AutonomousMonitorTrigger[] = [];
  if (churnEfficiency?.status === "stop" || churnEfficiency?.status === "cooldown") {
    const item = churnEfficiency.items.find((entry) => entry.action === "stop" || entry.action === "cooldown") ?? churnEfficiency.items[0];
    triggers.push({
      id: "churn-efficiency-auditor",
      label: churnEfficiency.status === "stop" ? "Stop churn" : "Churn cooldown",
      severity: churnEfficiency.status === "stop" ? "urgent" : "watch",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? churnEfficiency.summary,
    });
  } else if (churnEfficiency?.status === "accelerate") {
    const item = churnEfficiency.items.find((entry) => entry.action === "accelerate") ?? churnEfficiency.items[0];
    triggers.push({
      id: "churn-efficiency-auditor",
      label: "Churn edge",
      severity: "watch",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? churnEfficiency.summary,
    });
  }
  if (profitCaptureRace?.status === "race" || profitCaptureRace?.status === "trim" || profitCaptureRace?.status === "harvest") {
    const item = profitCaptureRace.items.find((entry) => entry.action === "race-exit" || entry.action === "trim-now" || entry.action === "harvest") ?? profitCaptureRace.items[0];
    triggers.push({
      id: "profit-capture-race",
      label: profitCaptureRace.status === "race" ? "Exit race" : profitCaptureRace.status === "trim" ? "Fast trim" : "Profit harvest",
      severity: profitCaptureRace.status === "harvest" ? "watch" : "urgent",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? profitCaptureRace.summary,
    });
  } else if (profitCaptureRace?.status === "trail" || profitCaptureRace?.status === "press") {
    const item = profitCaptureRace.items.find((entry) => entry.action === "trail" || entry.action === "press") ?? profitCaptureRace.items[0];
    triggers.push({
      id: "profit-capture-race",
      label: profitCaptureRace.status === "press" ? "Protected press" : "Race trail",
      severity: "watch",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? profitCaptureRace.summary,
    });
  }
  if (profitLock?.status === "exit" || profitLock?.status === "harvest" || profitLock?.status === "defend") {
    const item = profitLock.items.find((entry) => entry.action === "exit" || entry.action === "harvest" || entry.action === "defend") ?? profitLock.items[0];
    triggers.push({
      id: "profit-lock-autopilot",
      label: profitLock.status === "exit" ? "Lock profit exit" : profitLock.status === "harvest" ? "Harvest profit" : "Defend profit",
      severity: profitLock.status === "defend" ? "watch" : "urgent",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? profitLock.summary,
    });
  } else if (profitLock?.status === "trail" || profitLock?.status === "moonbag") {
    const item = profitLock.items.find((entry) => entry.action === "trail" || entry.action === "moonbag") ?? profitLock.items[0];
    triggers.push({
      id: "profit-lock-autopilot",
      label: profitLock.status === "trail" ? "Trailing profit" : "Moonbag runner",
      severity: "watch",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? profitLock.summary,
    });
  }
  if (walletEventReactor?.status === "protect" || walletEventReactor?.status === "attack" || walletEventReactor?.status === "probe") {
    const item = walletEventReactor.items.find((entry) => entry.status === "ready") ?? walletEventReactor.items[0];
    triggers.push({
      id: "wallet-event-reactor",
      label: walletEventReactor.status === "protect" ? "Wallet exit" : walletEventReactor.status === "attack" ? "Wallet copy" : "Wallet probe",
      severity: walletEventReactor.status === "probe" ? "watch" : "urgent",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? walletEventReactor.summary,
    });
  } else if (walletEventReactor?.status === "stand-down") {
    const item = walletEventReactor.items.find((entry) => entry.status === "blocked") ?? walletEventReactor.items[0];
    triggers.push({
      id: "wallet-event-reactor",
      label: "Wallet block",
      severity: "watch",
      symbol: item?.symbol ?? null,
      detail: item?.blockers[0] ?? walletEventReactor.summary,
    });
  }
  if (smartMoney?.status === "exit" || smartMoney?.status === "defensive") {
    const item = smartMoney.items.find((entry) => entry.action === "exit" || entry.action === "fade") ?? smartMoney.items[0];
    triggers.push({
      id: "smart-money-sentinel",
      label: smartMoney.status === "exit" ? "Smart outflow" : "Smart fade",
      severity: smartMoney.status === "exit" ? "urgent" : "watch",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? smartMoney.summary,
    });
  } else if (smartMoney?.status === "follow" || smartMoney?.status === "probe") {
    const item = smartMoney.items.find((entry) => entry.action === "follow" || entry.action === "probe") ?? smartMoney.items[0];
    triggers.push({
      id: "smart-money-sentinel",
      label: smartMoney.status === "follow" ? "Smart follow" : "Smart probe",
      severity: smartMoney.status === "follow" ? "urgent" : "watch",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? smartMoney.summary,
    });
  }
  const microstructureTrigger = microstructureMonitorTrigger(microstructureTape);
  if (microstructureTrigger) triggers.push(microstructureTrigger);
  if (routeQuoteSampler?.status === "blocked" || routeQuoteSampler?.status === "requote") {
    const item = routeQuoteSampler.items.find((entry) => entry.action === "block" || entry.action === "requote") ?? routeQuoteSampler.items[0];
    triggers.push({
      id: "route-quote-sampler",
      label: routeQuoteSampler.status === "blocked" ? "Quote block" : "Quote refresh",
      severity: routeQuoteSampler.status === "blocked" ? "urgent" : "watch",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? routeQuoteSampler.summary,
    });
  } else if (routeQuoteSampler?.status === "probe" || routeQuoteSampler?.status === "protect") {
    const item = routeQuoteSampler.items.find((entry) => entry.action === "probe" || entry.action === "protect") ?? routeQuoteSampler.items[0];
    triggers.push({
      id: "route-quote-sampler",
      label: routeQuoteSampler.status === "protect" ? "Quote protect" : "Quote probe",
      severity: routeQuoteSampler.status === "protect" ? "urgent" : "watch",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? routeQuoteSampler.summary,
    });
  }
  if (liquidityDepth?.status === "blocked" || liquidityDepth?.status === "protect") {
    const item = liquidityDepth.items.find((entry) => entry.action === "block" || entry.action === "protect") ?? liquidityDepth.items[0];
    triggers.push({
      id: "liquidity-depth-controller",
      label: liquidityDepth.status === "protect" ? "Depth protect" : "Depth block",
      severity: "urgent",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? liquidityDepth.summary,
    });
  } else if (liquidityDepth?.status === "slice" || liquidityDepth?.status === "resize") {
    const item = liquidityDepth.items.find((entry) => entry.action === "slice" || entry.action === "resize") ?? liquidityDepth.items[0];
    triggers.push({
      id: "liquidity-depth-controller",
      label: liquidityDepth.status === "slice" ? "Depth slice" : "Depth resize",
      severity: "watch",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? liquidityDepth.summary,
    });
  }
  if (profitLoop?.status === "compound" || profitLoop?.status === "attack") {
    const item = profitLoop.items.find((entry) => entry.action === "compound" || entry.action === "scalp");
    triggers.push({
      id: "profit-loop-controller",
      label: profitLoop.status === "compound" ? "Profit loop" : "Attack loop",
      severity: "urgent",
      symbol: item?.symbol ?? null,
      detail: profitLoop.summary,
    });
  } else if (profitLoop?.status === "harvest" || profitLoop?.status === "protect") {
    const item = profitLoop.items.find((entry) => entry.action === "harvest" || entry.action === "protect");
    triggers.push({
      id: "profit-loop-controller",
      label: profitLoop.status === "harvest" ? "Harvest loop" : "Protect loop",
      severity: "urgent",
      symbol: item?.symbol ?? null,
      detail: profitLoop.summary,
    });
  } else if (profitLoop?.status === "cooldown" || profitLoop?.status === "stand-down") {
    triggers.push({
      id: "profit-loop-controller",
      label: profitLoop.status === "stand-down" ? "Loop stand-down" : "Loop cooldown",
      severity: profitLoop.status === "stand-down" ? "urgent" : "watch",
      symbol: null,
      detail: profitLoop.summary,
    });
  }
  if (holderFlow?.status === "exit" || holderFlow?.status === "blocked") {
    const item = holderFlow.items.find((entry) => entry.action === "exit" || entry.action === "trim" || entry.action === "block");
    triggers.push({
      id: "holder-flow-sentinel",
      label: holderFlow.status === "exit" ? "Holder exit" : "Holder block",
      severity: "urgent",
      symbol: item?.symbol ?? null,
      detail: item ? item.reason : holderFlow.summary,
    });
  } else if (holderFlow?.status === "watch") {
    const item = holderFlow.items.find((entry) => entry.action === "reduce" || entry.action === "trim");
    triggers.push({
      id: "holder-flow-sentinel",
      label: "Holder flow",
      severity: item?.action === "trim" ? "urgent" : "watch",
      symbol: item?.symbol ?? null,
      detail: item ? item.reason : holderFlow.summary,
    });
  }
  if (launchGraduation?.status === "graduating" || launchGraduation?.status === "hunt" || launchGraduation?.status === "post-graduation") {
    const item = launchGraduation.items.find((entry) => entry.action === "graduate" || entry.action === "snipe" || entry.action === "probe" || entry.action === "trim");
    triggers.push({
      id: "launch-graduation",
      label: launchGraduation.status === "graduating" ? "Launch graduating" : "Graduation tape",
      severity: launchGraduation.status === "graduating" || item?.action === "graduate" ? "urgent" : "watch",
      symbol: item?.symbol ?? null,
      detail: item ? item.reason : launchGraduation.summary,
    });
  } else if (launchGraduation?.status === "cooldown") {
    triggers.push({
      id: "launch-graduation-cooldown",
      label: "Graduation blocked",
      severity: "watch",
      symbol: launchGraduation.items[0]?.symbol ?? null,
      detail: launchGraduation.items[0]?.blockers[0] ?? launchGraduation.summary,
    });
  }
  if (discoveryEdge?.status === "stand-down" || discoveryEdge?.status === "cooldown") {
    triggers.push({
      id: "discovery-edge-quality",
      label: "Discovery edge",
      severity: discoveryEdge.status === "stand-down" ? "urgent" : "watch",
      symbol: discoveryEdge.items[0]?.symbol ?? null,
      detail: discoveryEdge.summary,
    });
  }
  if (daemonMemory?.pause_new_entries) {
    triggers.push({
      id: "daemon-memory-cooldown",
      label: "Daemon memory",
      severity: daemonMemory.status === "halted" ? "urgent" : "watch",
      symbol: null,
      detail: daemonMemory.summary,
    });
  }
  if (executionEdge.status === "attack" || executionEdge.status === "protect") {
    const item = executionEdge.items.find((entry) => entry.action === "execute-paper" || entry.action === "tighten-exit");
    triggers.push({
      id: "execution-edge",
      label: executionEdge.status === "protect" ? "Protect edge" : "Entry edge",
      severity: executionEdge.status === "protect" ? "urgent" : "watch",
      symbol: item?.symbol ?? null,
      detail: executionEdge.summary,
    });
  } else if (executionEdge.status === "blocked") {
    const item = executionEdge.items.find((entry) => entry.action === "block");
    triggers.push({
      id: "execution-edge-blocked",
      label: "Edge blocked",
      severity: "watch",
      symbol: item?.symbol ?? null,
      detail: executionEdge.summary,
    });
  }
  if (riskGovernor.status === "halted" || riskGovernor.status === "cooldown") {
    triggers.push({
      id: "monitor-risk-governor",
      label: riskGovernor.status === "halted" ? "Governor halt" : "Governor cooldown",
      severity: riskGovernor.status === "halted" ? "urgent" : "watch",
      symbol: null,
      detail: riskGovernor.summary,
    });
  } else if (riskGovernor.status === "tighten") {
    triggers.push({
      id: "monitor-risk-governor",
      label: "Governor tighten",
      severity: "watch",
      symbol: null,
      detail: riskGovernor.summary,
    });
  }
  if (feedIntegrity.status === "fallback" || feedIntegrity.status === "stale") {
    triggers.push({
      id: "monitor-feed-integrity-critical",
      label: feedIntegrity.status === "fallback" ? "Source fallback" : "Feed stale",
      severity: "urgent",
      symbol: null,
      detail: feedIntegrity.summary,
    });
  } else if (feedIntegrity.status === "degraded") {
    triggers.push({
      id: "monitor-feed-integrity-watch",
      label: "Feed degraded",
      severity: "watch",
      symbol: null,
      detail: feedIntegrity.summary,
    });
  }
  if (priceAction.snipe_count + priceAction.press_count > 0) {
    const symbol = priceAction.items.find((item) => item.decision === "snipe" || item.decision === "press")?.symbol ?? null;
    triggers.push({
      id: "fast-tape",
      label: "Fast tape",
      severity: priceAction.snipe_count > 0 ? "urgent" : "watch",
      symbol,
      detail: `${priceAction.snipe_count} snipe and ${priceAction.press_count} press window${priceAction.press_count === 1 ? "" : "s"} need a tighter wake cadence.`,
    });
  }
  if (tapeMemory.urgent_count > 0 || tapeMemory.deterioration_count > 0) {
    const event = tapeMemory.events.find((item) => item.severity === "urgent") ?? tapeMemory.events[0];
    triggers.push({
      id: "tape-memory",
      label: "Tape change",
      severity: tapeMemory.urgent_count > 0 ? "urgent" : "watch",
      symbol: event?.symbol ?? null,
      detail: `${tapeMemory.urgent_count} urgent and ${tapeMemory.deterioration_count} deteriorating tape event${tapeMemory.deterioration_count === 1 ? "" : "s"} are active.`,
    });
  }
  if (rugFirewall.exit_count + rugFirewall.quarantine_count > 0) {
    const item = rugFirewall.items.find((entry) => entry.action === "exit" || entry.action === "quarantine");
    triggers.push({
      id: "rug-firewall",
      label: "Rug firewall",
      severity: rugFirewall.exit_count > 0 ? "urgent" : "watch",
      symbol: item?.symbol ?? null,
      detail: `${rugFirewall.exit_count} exit and ${rugFirewall.quarantine_count} quarantine firewall result${rugFirewall.quarantine_count === 1 ? "" : "s"} require monitoring.`,
    });
  }
  if (liquidityExitSentinel && liquidityExitSentinel.status !== "clear") {
    const item = liquidityExitSentinel.items.find((entry) => entry.action === "exit" || entry.action === "trim" || entry.action === "tighten") ?? liquidityExitSentinel.items[0];
    triggers.push({
      id: "liquidity-exit-sentinel",
      label: liquidityExitSentinel.status === "exit" ? "Liquidity exit" : liquidityExitSentinel.status === "trim" ? "Liquidity trim" : "Liquidity watch",
      severity: liquidityExitSentinel.status === "exit" || liquidityExitSentinel.status === "trim" ? "urgent" : "watch",
      symbol: item?.symbol ?? null,
      detail: liquidityExitSentinel.summary,
    });
  }
  if (positionCommander?.status === "exit" || positionCommander?.status === "trim" || positionCommander?.status === "defend") {
    const item = positionCommander.items.find((entry) =>
      positionCommander.status === "exit"
        ? entry.action === "exit" || entry.action === "lockout"
        : positionCommander.status === "trim"
          ? entry.action === "trim"
          : entry.action === "defend",
    ) ?? positionCommander.items[0];
    triggers.push({
      id: "position-commander",
      label: positionCommander.status === "exit" ? "Position exit" : positionCommander.status === "trim" ? "Position trim" : "Position defend",
      severity: positionCommander.status === "defend" ? "watch" : "urgent",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? positionCommander.summary,
    });
  } else if (positionCommander?.status === "moonbag") {
    const item = positionCommander.items.find((entry) => entry.action === "moonbag") ?? positionCommander.items[0];
    triggers.push({
      id: "position-commander",
      label: "Moonbag runner",
      severity: "watch",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? positionCommander.summary,
    });
  }
  if (alphaDecay?.status === "chase" || alphaDecay?.status === "harvest") {
    const item = alphaDecay.items.find((entry) => entry.action === "chase" || entry.action === "harvest") ?? alphaDecay.items[0];
    triggers.push({
      id: "alpha-decay-controller",
      label: alphaDecay.status === "harvest" ? "Alpha harvest" : "Alpha chase",
      severity: "urgent",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? alphaDecay.summary,
    });
  } else if (alphaDecay?.status === "probe" || alphaDecay?.status === "expired" || alphaDecay?.status === "cooldown") {
    const item = alphaDecay.items.find((entry) => entry.action === "probe" || entry.action === "expire" || entry.action === "block") ?? alphaDecay.items[0];
    triggers.push({
      id: "alpha-decay-controller",
      label: alphaDecay.status === "probe" ? "Alpha probe" : "Alpha stale",
      severity: alphaDecay.status === "expired" || alphaDecay.status === "cooldown" ? "watch" : "urgent",
      symbol: item?.symbol ?? null,
      detail: item?.reason ?? alphaDecay.summary,
    });
  }
  if (positionExitLadder.active_count > 0) {
    const item = positionExitLadder.items.find((entry) => entry.status !== "hold");
    triggers.push({
      id: "exit-ladder",
      label: "Exit ladder",
      severity: positionExitLadder.status === "protect" ? "urgent" : "watch",
      symbol: item?.symbol ?? null,
      detail: `${positionExitLadder.active_count} ladder item${positionExitLadder.active_count === 1 ? "" : "s"} are armed or triggered.`,
    });
  }
  if (executionMevGuard.status === "blocked" || executionMevGuard.status === "protect") {
    const item = executionMevGuard.items.find((entry) => entry.status === "blocked" || entry.status === "protect");
    triggers.push({
      id: "mev-guard",
      label: "MEV guard",
      severity: executionMevGuard.status === "blocked" ? "urgent" : "watch",
      symbol: item?.symbol ?? null,
      detail: executionMevGuard.summary,
    });
  }
  if (paperExecutionQuality.status === "poor" || paperExecutionQuality.status === "degraded") {
    const item = paperExecutionQuality.items.find((entry) => entry.status !== "clean");
    triggers.push({
      id: "fill-quality",
      label: "Fill quality",
      severity: paperExecutionQuality.status === "poor" ? "urgent" : "watch",
      symbol: item?.symbol ?? null,
      detail: paperExecutionQuality.summary,
    });
  }
  if (executionPreflight.status === "ready" || executionPreflight.status === "watch") {
    const item = executionPreflight.items.find((entry) => entry.status === "ready" || entry.status === "watch");
    triggers.push({
      id: "preflight",
      label: "Preflight",
      severity: executionPreflight.status === "ready" ? "watch" : "info",
      symbol: item?.symbol ?? null,
      detail: executionPreflight.summary,
    });
  }
  if (performance.status === "protect" || performance.status === "overtrading") {
    triggers.push({
      id: "performance",
      label: "Performance",
      severity: "urgent",
      symbol: null,
      detail: performance.summary,
    });
  }
  if (autopilot.status === "planned" && autopilot.actions.some((action) => action.status === "ready")) {
    const action = autopilot.actions.find((item) => item.status === "ready");
    triggers.push({
      id: "runbook-ready",
      label: "Runbook ready",
      severity: "watch",
      symbol: action?.symbol ?? null,
      detail: "Autopilot has a ready paper action waiting for the next cycle.",
    });
  }
  if (triggers.length === 0 && situation.regime !== "stand-down") {
    triggers.push({
      id: "baseline",
      label: "Baseline scan",
      severity: "info",
      symbol: null,
      detail: "No urgent trigger is active; maintain baseline market and position monitoring.",
    });
  }
  return triggers;
}

function autonomousMonitorInterval(
  status: AutonomousMonitorSchedule["status"],
  baseIntervalSeconds: number,
  urgencyScore: number,
  executionPreflight: ExecutionPreflightReport,
  paperExecutionQuality: PaperExecutionQuality,
) {
  if (status === "accelerate") return urgencyScore >= 86 ? 3 : 5;
  if (status === "stand-down") return 15;
  if (status === "cooldown") return paperExecutionQuality.status === "poor" || executionPreflight.status === "blocked" ? 20 : 14;
  if (status === "idle") return 30;
  return Math.max(6, Math.min(baseIntervalSeconds, urgencyScore >= 58 ? 6 : 10));
}

function autonomousMonitorSummary(
  status: AutonomousMonitorSchedule["status"],
  interval: number,
  shouldAdvancePaper: boolean,
  triggers: AutonomousMonitorTrigger[],
) {
  if (status === "accelerate") return `Monitor accelerates to ${interval}s because ${triggers[0]?.label.toLowerCase() ?? "risk"} needs immediate follow-up.`;
  if (status === "stand-down") return `Monitor wakes every ${interval}s for exits and risk checks while fresh entries stay paused.`;
  if (status === "cooldown") return `Monitor cools down to ${interval}s and observes until blocked or poor-quality execution clears.`;
  if (status === "idle") return `Monitor uses a ${interval}s baseline scan; no active paper action should advance.`;
  return `Monitor wakes in ${interval}s and ${shouldAdvancePaper ? "can advance the paper ledger" : "will refresh without advancing fills"}.`;
}

function buildExecutionIntentQueue({
  asOf,
  autopilot,
  walletEventReactor,
  executionPlans,
  readiness,
  tapeMemory,
  profitOptimizer,
  tokenVetting,
}: {
  asOf: string;
  autopilot: AutopilotRunbook;
  walletEventReactor?: WalletEventReactor;
  executionPlans: ExecutionPlan[];
  readiness: ExecutionReadiness;
  tapeMemory: TapeMemory;
  profitOptimizer: ProfitOptimizer;
  tokenVetting: TokenVettingReport;
}): ExecutionIntentQueue {
  const planBySymbol = new Map(executionPlans.map((plan) => [plan.symbol, plan]));
  const tapeBySymbol = new Map(tapeMemory.events.map((event) => [event.symbol, event]));
  const profitBySymbol = new Map(profitOptimizer.candidates.map((candidate) => [candidate.symbol, candidate]));
  const vettingBySymbol = new Map(tokenVetting.items.map((item) => [item.symbol, item]));
  const readinessFailures = readinessBlockers(readiness);
  const walletActions = walletEventReactorActions(walletEventReactor, autopilot.actions);
  const queueActions = [...autopilot.actions, ...walletActions].slice(0, 12);
  const intents = queueActions.map((action): ExecutionIntent => {
    const plan = action.symbol ? planBySymbol.get(action.symbol) : undefined;
    const tapeEvent = action.symbol ? tapeBySymbol.get(action.symbol) : undefined;
    const profit = action.symbol ? profitBySymbol.get(action.symbol) : undefined;
    const vetting = action.symbol ? vettingBySymbol.get(action.symbol) : undefined;
    return executionIntentForAction({
      action,
      asOf,
      plan,
      readiness,
      readinessFailures,
      tapeEvent,
      profit,
      vetting,
    });
  });
  const readyCount = intents.filter((intent) => intent.status === "ready" || intent.status === "paper-filled").length;
  const blockedCount = intents.filter((intent) => intent.status === "blocked").length;
  const cooldownCount = intents.filter((intent) => intent.status === "cooldown").length;
  const retryTimes = intents
    .map((intent) => intent.retry_after)
    .filter((value): value is string => typeof value === "string")
    .sort();
  const status: ExecutionIntentQueue["status"] = readyCount > 0
    ? "ready"
    : cooldownCount > 0
      ? "cooldown"
      : blockedCount > 0
        ? "blocked"
        : "idle";

  return {
    mode: readiness.config.mode,
    status,
    max_messages_per_minute: 12,
    ready_count: readyCount,
    blocked_count: blockedCount,
    cooldown_count: cooldownCount,
    next_retry_at: retryTimes[0] ?? null,
    summary: executionIntentSummary(status, intents, readiness),
    intents,
  };
}

function walletEventReactorActions(
  reactor: WalletEventReactor | undefined,
  existingActions: AutopilotAction[],
): AutopilotAction[] {
  if (!reactor || reactor.status === "idle") return [];
  let sequence = existingActions.length + 1;
  return reactor.items
    .filter((item) => item.status === "ready" || item.status === "cooldown")
    .slice(0, 4)
    .map((item) => ({
      id: item.id,
      sequence: sequence++,
      lane: "wallet-reactor",
      side: item.side,
      symbol: item.symbol,
      status: item.status === "ready" ? "ready" : "watching",
      size_usd: item.side === "buy" ? item.recommended_size_usd : item.recommended_release_usd,
      trigger: item.reason,
      execution_gate: item.blockers[0] ?? "Wallet event reactor queues this paper intent from mapped on-chain flow.",
      expected_effect: item.side === "buy"
        ? `Deploy ${formatCompactValue(item.recommended_size_usd)} with ${item.pressure_score}/100 wallet pressure and ${item.latency_budget_seconds}s reaction budget.`
        : item.side === "sell"
          ? `Release ${formatCompactValue(item.recommended_release_usd)} before watched-wallet flow turns crowded.`
          : "Keep watching wallet flow without placing an order.",
    }));
}

function executionIntentForAction({
  action,
  asOf,
  plan,
  readiness,
  readinessFailures,
  tapeEvent,
  profit,
  vetting,
}: {
  action: AutopilotAction;
  asOf: string;
  plan: ExecutionPlan | undefined;
  readiness: ExecutionReadiness;
  readinessFailures: string[];
  tapeEvent: TapeMemoryEvent | undefined;
  profit: ProfitCandidate | undefined;
  vetting: TokenVettingItem | undefined;
}): ExecutionIntent {
  const blockers = executionIntentBlockers(action, plan, readinessFailures, tapeEvent, vetting);
  const shortfall = estimatedShortfallBps(plan, profit, tapeEvent);
  const routeQuality = executionRouteQuality(plan, shortfall, blockers, action);
  const cooldownSeconds = executionCooldownSeconds(action, plan, tapeEvent, blockers, shortfall);
  const status = executionIntentStatus(action, blockers, cooldownSeconds);
  const retryAfter = status === "cooldown" || (status === "blocked" && cooldownSeconds > 0)
    ? new Date(Date.parse(asOf) + cooldownSeconds * 1_000).toISOString()
    : null;

  return {
    id: `intent-${action.id}`,
    source_action_id: action.id,
    plan_id: plan?.id ?? null,
    symbol: action.symbol,
    side: action.side,
    priority: executionIntentPriority(action),
    status,
    size_usd: Math.round(action.size_usd),
    route_status: action.status === "paper-filled" ? "paper-ledger" : plan?.status ?? "not-routed",
    route_quality_score: routeQuality,
    price_impact_pct: plan?.price_impact_pct ?? null,
    max_slippage_bps: readiness.config.max_slippage_bps,
    estimated_shortfall_bps: shortfall,
    cooldown_seconds: cooldownSeconds,
    retry_after: retryAfter,
    rationale: action.trigger,
    blockers,
    next_step: executionIntentNextStep(status, action, plan, tapeEvent, blockers),
  };
}

function executionIntentBlockers(
  action: AutopilotAction,
  plan: ExecutionPlan | undefined,
  readinessFailures: string[],
  tapeEvent: TapeMemoryEvent | undefined,
  vetting: TokenVettingItem | undefined,
) {
  const blockers: string[] = [];
  if (action.status === "blocked") blockers.push(action.execution_gate);
  if (action.side === "buy" && readinessFailures.length > 0) blockers.push(...readinessFailures.slice(0, 2));
  if (action.side === "buy" && vetting?.status === "blocked") {
    blockers.push(`Token vetting blocks ${vetting.symbol}: ${vetting.issues[0] ?? vetting.summary}`);
  }
  if (action.side === "buy" && vetting?.status === "watch" && action.size_usd > vetting.max_position_usd) {
    blockers.push(`Token vetting caps ${vetting.symbol} at ${formatCompactValue(vetting.max_position_usd)} until authority/security checks clear.`);
  }
  if (plan?.status === "no-route") blockers.push("Route unavailable; wait for Jupiter/Raydium liquidity before retry.");
  if (plan?.status === "unsupported-chain") blockers.push("No supported route adapter for this chain yet.");
  if (plan?.status === "blocked") blockers.push(plan.message);
  if (plan?.price_impact_pct !== null && plan?.price_impact_pct !== undefined && plan.price_impact_pct > 2.5) {
    blockers.push(`Price impact ${roundMetric(plan.price_impact_pct)}% exceeds autonomous route-quality cap.`);
  }
  if (tapeEvent?.severity === "urgent" && action.side === "buy") {
    blockers.push("Urgent tape event blocks fresh buy intent.");
  }
  return [...new Set(blockers.filter(Boolean))];
}

function executionIntentStatus(
  action: AutopilotAction,
  blockers: string[],
  cooldownSeconds: number,
): ExecutionIntentStatus {
  if (action.status === "paper-filled") return "paper-filled";
  if (blockers.length > 0) return "blocked";
  if (action.status === "skipped" || action.side === "hold") return "watching";
  if (cooldownSeconds > 0) return "cooldown";
  if (action.status === "ready") return "ready";
  return "watching";
}

function executionIntentPriority(action: AutopilotAction): ExecutionIntentPriority {
  if (action.sequence <= 2 || action.lane === "risk-exit" || action.lane === "profit-ladder" || action.lane === "launch-sniper" || action.lane === "wallet-reactor") return "now";
  if (action.sequence <= 5) return "next";
  return "later";
}

function executionRouteQuality(
  plan: ExecutionPlan | undefined,
  shortfallBps: number,
  blockers: string[],
  action: AutopilotAction,
) {
  if (action.status === "paper-filled") return 100;
  if (!plan) return action.side === "sell" ? 72 : 35;
  const impactPenalty = (plan.price_impact_pct ?? 0) * 18;
  const routePenalty = plan.status === "quoted" ? 0 : plan.status === "not-needed" ? 18 : 42;
  return clamp(Math.round(100 - shortfallBps * 0.22 - impactPenalty - routePenalty - blockers.length * 14), 0, 100);
}

function estimatedShortfallBps(
  plan: ExecutionPlan | undefined,
  profit: ProfitCandidate | undefined,
  tapeEvent: TapeMemoryEvent | undefined,
) {
  const routeCost = profit?.estimated_cost_bps ?? plan?.slippage_bps ?? 0;
  const impactCost = (plan?.price_impact_pct ?? 0) * 100;
  const delayCost = tapeEvent
    ? tapeEvent.severity === "urgent"
      ? 80
      : tapeEvent.severity === "watch"
        ? 35
        : 12
    : 15;
  return Math.round(routeCost + impactCost + delayCost);
}

function executionCooldownSeconds(
  action: AutopilotAction,
  plan: ExecutionPlan | undefined,
  tapeEvent: TapeMemoryEvent | undefined,
  blockers: string[],
  shortfallBps: number,
) {
  if (action.status === "paper-filled") return 0;
  if (action.lane === "risk-exit" || action.lane === "profit-ladder") return blockers.length > 0 ? 15 : 0;
  if (plan?.status === "no-route") return 45;
  if (tapeEvent?.severity === "urgent") return 120;
  if (shortfallBps >= 350) return 90;
  if (blockers.length > 0) return 60;
  if (action.status === "skipped") return 30;
  return 0;
}

function executionIntentNextStep(
  status: ExecutionIntentStatus,
  action: AutopilotAction,
  plan: ExecutionPlan | undefined,
  tapeEvent: TapeMemoryEvent | undefined,
  blockers: string[],
) {
  if (status === "paper-filled") return "Record fill, update portfolio, and let position watch manage the next cycle.";
  if (status === "ready") return action.side === "sell"
    ? "Paper exit is ready; prioritize risk release before fresh entries."
    : "Dry-run route is ready; keep signing disabled until operator gates exist.";
  if (status === "cooldown") return tapeEvent
    ? `Wait for ${tapeEvent.symbol} tape pressure to settle before retrying.`
    : "Wait for the retry window before requesting another route.";
  if (status === "blocked") return blockers[0] ?? "Resolve readiness, route, or policy blockers before retrying.";
  if (plan?.status === "not-needed") return "Keep monitoring; no order should be requested from this action yet.";
  return "Keep watching until policy, tape, and route quality align.";
}

function executionIntentSummary(
  status: ExecutionIntentQueue["status"],
  intents: ExecutionIntent[],
  readiness: ExecutionReadiness,
) {
  if (status === "ready") {
    const ready = intents.filter((intent) => intent.status === "ready" || intent.status === "paper-filled").length;
    return `${ready} intent${ready === 1 ? "" : "s"} can proceed inside paper/dry-run gates with signing disabled.`;
  }
  if (status === "cooldown") return "All actionable intents are waiting for route, tape, or shortfall cooldown windows.";
  if (status === "blocked") return `Execution queue is blocked by ${readiness.config.kill_switch ? "kill switch/readiness" : "route or policy"} gates.`;
  return "No execution intent clears the current queue; the agent keeps monitoring.";
}

function buildExecutionCostMonitor({
  executionPlans,
  executionIntents,
  priceAction,
  profitOptimizer,
}: {
  executionPlans: ExecutionPlan[];
  executionIntents: ExecutionIntentQueue;
  priceAction: PriceActionMonitor;
  profitOptimizer: ProfitOptimizer;
}): ExecutionCostMonitor {
  const planById = new Map(executionPlans.map((plan) => [plan.id, plan]));
  const priceActionBySymbol = new Map(priceAction.items.map((item) => [item.symbol, item]));
  const profitBySymbol = new Map(profitOptimizer.candidates.map((candidate) => [candidate.symbol, candidate]));
  const items = executionIntents.intents
    .filter((intent) => intent.side !== "hold")
    .map((intent) => executionCostItem({
      intent,
      plan: intent.plan_id ? planById.get(intent.plan_id) : undefined,
      priceAction: intent.symbol ? priceActionBySymbol.get(intent.symbol) : undefined,
      profit: intent.symbol ? profitBySymbol.get(intent.symbol) : undefined,
    }));
  const landableCount = items.filter((item) => item.status === "send" || item.status === "paper").length;
  const watchCount = items.filter((item) => item.status === "watch" || item.status === "resize").length;
  const blockedCount = items.filter((item) => item.status === "block").length;
  const avgCost = average(items.map((item) => item.total_cost_bps));
  const priorityFees = items.map((item) => item.priority_fee_lamports).sort((a, b) => a - b);
  const status = executionCostStatus(items, landableCount, blockedCount, avgCost);
  const feeDrag = items.reduce((sum, item) => sum + item.notional_usd * (item.total_cost_bps / 10_000), 0);

  return {
    status,
    source: "local-estimate",
    scan_interval_seconds: 10,
    priority_fee_window_blocks: 150,
    summary: executionCostSummary(status, items, avgCost),
    median_priority_fee_lamports: percentile(priorityFees, 0.5),
    p75_priority_fee_lamports: percentile(priorityFees, 0.75),
    p90_priority_fee_lamports: percentile(priorityFees, 0.9),
    average_total_cost_bps: Math.round(avgCost),
    fee_drag_usd: roundMetric(feeDrag),
    landable_count: landableCount,
    watch_count: watchCount,
    blocked_count: blockedCount,
    items,
  };
}

function executionCostItem({
  intent,
  plan,
  priceAction,
  profit,
}: {
  intent: ExecutionIntent;
  plan: ExecutionPlan | undefined;
  priceAction: PriceActionItem | undefined;
  profit: ProfitCandidate | undefined;
}): ExecutionCostItem {
  const notional = Math.max(0, intent.size_usd);
  const priceImpactBps = Math.round((plan?.price_impact_pct ?? intent.price_impact_pct ?? 0) * 100);
  const slippageDragBps = Math.round((plan?.slippage_bps ?? intent.max_slippage_bps ?? 250) * 0.32);
  const routeFeeBps = plan?.dry_run.fee_bps ?? 0;
  const routeCostBps = Math.max(0, priceImpactBps + slippageDragBps + routeFeeBps);
  const congestionScore = executionCongestionScore(intent, plan, priceAction, profit);
  const priorityFeeLamports = intent.status === "paper-filled" || notional <= 0 ? 0 : priorityFeeLamportsFor(congestionScore, intent.priority);
  const priorityFeeUsd = lamportsToUsd(priorityFeeLamports);
  const priorityFeeBps = notional > 0 ? Math.round((priorityFeeUsd / notional) * 10_000) : 0;
  const totalCostBps = Math.max(0, routeCostBps + priorityFeeBps);
  const maxPriorityFeeLamports = maxPriorityFeeLamportsFor(notional, intent.priority);
  const blockers: string[] = [];
  const routeQualityBaseline = plan?.source === "local-gate" && plan.status === "blocked"
    ? Math.max(intent.route_quality_score, 72)
    : intent.route_quality_score;
  const landabilityScore = clamp(Math.round(
    routeQualityBaseline
      - congestionScore * 0.26
      - Math.max(0, totalCostBps - 55) * 0.32
      - (priorityFeeLamports > maxPriorityFeeLamports ? 18 : 0),
  ), 0, 100);

  if (!plan && intent.status !== "paper-filled") blockers.push("No route exists to price route and priority-fee drag.");
  if (
    plan &&
    plan.status !== "quoted" &&
    plan.status !== "not-needed" &&
    !(plan.source === "local-gate" && plan.message.includes("Sample mode")) &&
    intent.status !== "paper-filled"
  ) {
    blockers.push(plan.message);
  }
  if (priorityFeeLamports > maxPriorityFeeLamports) blockers.push("Estimated priority fee exceeds the per-trade fee cap.");
  if (totalCostBps > 180) blockers.push("Total route plus priority-fee cost is above the autonomous ceiling.");
  if (landabilityScore < 32) blockers.push("Congestion-adjusted landability is too weak for autonomous execution.");

  const status = executionCostItemStatus(intent, blockers, totalCostBps, landabilityScore);

  return {
    id: `cost-${intent.id}`,
    intent_id: intent.id,
    plan_id: intent.plan_id,
    symbol: intent.symbol,
    side: intent.side,
    status,
    notional_usd: notional,
    route_cost_bps: routeCostBps,
    price_impact_bps: priceImpactBps,
    slippage_drag_bps: slippageDragBps,
    route_fee_bps: routeFeeBps,
    priority_fee_lamports: priorityFeeLamports,
    priority_fee_usd: roundMetric(priorityFeeUsd),
    priority_fee_bps: priorityFeeBps,
    total_cost_bps: totalCostBps,
    congestion_score: congestionScore,
    landability_score: landabilityScore,
    priority_level: priorityLevelFor(congestionScore, intent.priority),
    compute_unit_price_micro_lamports: computeUnitPriceMicroLamports(priorityFeeLamports),
    max_priority_fee_lamports: maxPriorityFeeLamports,
    summary: executionCostItemSummary(status, intent, totalCostBps, priorityFeeLamports, landabilityScore),
    blockers: [...new Set(blockers)],
  };
}

function buildExecutionMevGuard({
  executionPlans,
  executionIntents,
  executionCost,
  market,
  priceAction,
  rugFirewall,
  readiness,
}: {
  executionPlans: ExecutionPlan[];
  executionIntents: ExecutionIntentQueue;
  executionCost: ExecutionCostMonitor;
  market: MemecoinMarket[];
  priceAction: PriceActionMonitor;
  rugFirewall: RugPullFirewall;
  readiness: ExecutionReadiness;
}): ExecutionMevGuard {
  const planById = new Map(executionPlans.map((plan) => [plan.id, plan]));
  const costByIntent = new Map(executionCost.items.map((item) => [item.intent_id, item]));
  const marketBySymbol = new Map(market.map((item) => [item.symbol, item]));
  const priceActionBySymbol = new Map(priceAction.items.map((item) => [item.symbol, item]));
  const firewallBySymbol = new Map(rugFirewall.items.map((item) => [item.symbol, item]));
  const items = executionIntents.intents
    .filter((intent) => intent.side !== "hold")
    .map((intent) => executionMevGuardItem({
      intent,
      plan: intent.plan_id ? planById.get(intent.plan_id) : undefined,
      cost: costByIntent.get(intent.id),
      token: intent.symbol ? marketBySymbol.get(intent.symbol) : undefined,
      priceAction: intent.symbol ? priceActionBySymbol.get(intent.symbol) : undefined,
      firewall: intent.symbol ? firewallBySymbol.get(intent.symbol) : undefined,
      readiness,
    }));
  const blockedCount = items.filter((item) => item.status === "blocked").length;
  const protectedCount = items.filter((item) => item.status === "protect").length;
  const splitCount = items.filter((item) => item.action === "split").length;
  const privateRouteCount = items.filter((item) => item.private_route === "required" || item.private_route === "preferred").length;
  const paperCount = items.filter((item) => item.status === "paper").length;
  const averageSandwichRisk = Math.round(average(items.map((item) => item.sandwich_risk_score)));
  const averageLiquidityShock = Math.round(average(items.map((item) => item.liquidity_shock_score)));
  const status: ExecutionMevGuard["status"] = items.length === 0
    ? "idle"
    : blockedCount > 0
      ? "blocked"
      : protectedCount > 0
        ? "protect"
        : items.some((item) => item.status === "watch")
          ? "watch"
          : paperCount > 0 && paperCount === items.length
            ? "paper"
            : "clear";

  return {
    status,
    source: "local-mev-risk-model",
    summary: executionMevGuardSummary(status, items, blockedCount, protectedCount, splitCount, privateRouteCount),
    max_slippage_bps: readiness.config.max_slippage_bps,
    average_sandwich_risk_score: averageSandwichRisk,
    average_liquidity_shock_score: averageLiquidityShock,
    protected_count: protectedCount,
    blocked_count: blockedCount,
    split_count: splitCount,
    private_route_count: privateRouteCount,
    items,
  };
}

function executionMevGuardItem({
  intent,
  plan,
  cost,
  token,
  priceAction,
  firewall,
  readiness,
}: {
  intent: ExecutionIntent;
  plan: ExecutionPlan | undefined;
  cost: ExecutionCostItem | undefined;
  token: MemecoinMarket | undefined;
  priceAction: PriceActionItem | undefined;
  firewall: RugFirewallItem | undefined;
  readiness: ExecutionReadiness;
}): ExecutionMevGuardItem {
  const notional = Math.max(0, intent.size_usd);
  const slippageBudget = Math.min(readiness.config.max_slippage_bps, plan?.slippage_bps ?? intent.max_slippage_bps);
  const liquidityUsd = Math.max(1, token?.liquidity_usd ?? 90_000);
  const orderLiquidityPct = (notional / liquidityUsd) * 100;
  const buyPressure = token ? token.buys_5m / Math.max(1, token.buys_5m + token.sells_5m) : 0.5;
  const sandwichRisk = intent.status === "paper-filled"
    ? 0
    : clamp(Math.round(
      18 +
        slippageBudget * 0.11 +
        orderLiquidityPct * 48 +
        (plan?.price_impact_pct ?? intent.price_impact_pct ?? 0) * 12 +
        (priceAction?.velocity_score ?? 45) * 0.18 +
        (intent.priority === "now" ? 8 : 0) +
        (intent.side === "buy" && buyPressure >= 0.68 ? 8 : 0),
    ), 0, 100);
  const liquidityShock = intent.status === "paper-filled"
    ? 0
    : clamp(Math.round(
      14 +
        orderLiquidityPct * 70 +
        Math.max(0, 250_000 - liquidityUsd) / 6_000 +
        (priceAction?.exit_pressure_score ?? 20) * 0.24 +
        (firewall?.liquidity_risk_score ?? 0) * 0.28 +
        Math.max(0, -(token?.price_change_5m_pct ?? 0)) * 2.5,
    ), 0, 100);
  const publicRouteRisk = intent.status === "paper-filled"
    ? 0
    : clamp(Math.round(
      12 +
        Math.max(0, slippageBudget - 120) * 0.16 +
        (cost?.congestion_score ?? 45) * 0.34 +
        (cost?.landability_score !== undefined ? Math.max(0, 75 - cost.landability_score) * 0.42 : 12) +
        (plan?.source === "local-gate" ? 8 : 0),
    ), 0, 100);
  const routeLandability = cost?.landability_score ?? intent.route_quality_score;
  const combinedRisk = Math.round(average([sandwichRisk, liquidityShock, publicRouteRisk]));
  const recommendedSlippage = recommendedMevSlippage(slippageBudget, sandwichRisk, liquidityShock, publicRouteRisk, intent.side);
  const sizeMultiplier = mevSizeMultiplier(sandwichRisk, liquidityShock, publicRouteRisk, routeLandability);
  const recommendedSize = intent.status === "paper-filled" ? 0 : Math.floor(notional * sizeMultiplier);
  const sliceCount = mevSliceCount(notional, recommendedSize, liquidityShock, sandwichRisk);
  const privateRoute = mevPrivateRoute(sandwichRisk, publicRouteRisk, intent.status);
  const blockers = mevGuardBlockers(intent, sandwichRisk, liquidityShock, publicRouteRisk, routeLandability, recommendedSize, slippageBudget);
  const action = mevGuardAction(intent, blockers, sandwichRisk, liquidityShock, publicRouteRisk, recommendedSize, notional, privateRoute);
  const status = mevGuardStatus(intent, action, blockers, combinedRisk);
  const score = clamp(Math.round(100 - combinedRisk * 0.72 - blockers.length * 10 + Math.max(0, routeLandability - 60) * 0.12), 0, 100);

  return {
    id: `mev-${intent.id}`,
    intent_id: intent.id,
    plan_id: intent.plan_id,
    symbol: intent.symbol,
    side: intent.side,
    action,
    status,
    notional_usd: notional,
    recommended_size_usd: recommendedSize,
    slice_count: sliceCount,
    sandwich_risk_score: sandwichRisk,
    liquidity_shock_score: liquidityShock,
    public_route_risk_score: publicRouteRisk,
    route_landability_score: routeLandability,
    slippage_budget_bps: slippageBudget,
    recommended_slippage_bps: recommendedSlippage,
    priority_fee_lamports: cost?.priority_fee_lamports ?? 0,
    private_route: privateRoute,
    score,
    reason: mevGuardReason(action, intent, sandwichRisk, liquidityShock, publicRouteRisk, recommendedSize, sliceCount, recommendedSlippage),
    tactics: mevGuardTactics(action, privateRoute, recommendedSlippage, sliceCount, cost),
    blockers,
  };
}

function recommendedMevSlippage(
  slippageBudget: number,
  sandwichRisk: number,
  liquidityShock: number,
  publicRouteRisk: number,
  side: "buy" | "sell" | "hold",
) {
  if (side === "sell") return Math.min(slippageBudget, 260);
  const risk = Math.max(sandwichRisk, liquidityShock, publicRouteRisk);
  if (risk >= 78) return Math.min(slippageBudget, 120);
  if (risk >= 62) return Math.min(slippageBudget, 170);
  if (risk >= 45) return Math.min(slippageBudget, 220);
  return Math.min(slippageBudget, 300);
}

function mevSizeMultiplier(
  sandwichRisk: number,
  liquidityShock: number,
  publicRouteRisk: number,
  landability: number,
) {
  const maxRisk = Math.max(sandwichRisk, liquidityShock, publicRouteRisk);
  if (maxRisk >= 86 || landability < 26) return 0;
  if (maxRisk >= 74 || landability < 42) return 0.38;
  if (maxRisk >= 62 || landability < 58) return 0.58;
  if (maxRisk >= 48) return 0.76;
  return 1;
}

function mevSliceCount(notional: number, recommendedSize: number, liquidityShock: number, sandwichRisk: number) {
  if (recommendedSize <= 0 || notional <= 0) return 0;
  const risk = Math.max(liquidityShock, sandwichRisk);
  if (risk >= 74 && notional >= 180) return 4;
  if (risk >= 58 && notional >= 140) return 3;
  if (risk >= 42 && notional >= 110) return 2;
  return 1;
}

function mevPrivateRoute(
  sandwichRisk: number,
  publicRouteRisk: number,
  status: ExecutionIntentStatus,
): ExecutionMevGuardItem["private_route"] {
  if (status === "paper-filled") return "not-needed";
  const risk = Math.max(sandwichRisk, publicRouteRisk);
  if (risk >= 76) return "required";
  if (risk >= 58) return "preferred";
  if (risk >= 42) return "optional";
  return "not-needed";
}

function mevGuardBlockers(
  intent: ExecutionIntent,
  sandwichRisk: number,
  liquidityShock: number,
  publicRouteRisk: number,
  landability: number,
  recommendedSize: number,
  slippageBudget: number,
) {
  const blockers: string[] = [];
  if (intent.status !== "paper-filled" && recommendedSize <= 0) blockers.push("MEV guard blocks the trade because risk-adjusted size falls to zero.");
  if (sandwichRisk >= 86) blockers.push("Sandwich risk is too high for public autonomous routing.");
  if (liquidityShock >= 88) blockers.push("Liquidity-shock risk is too high for the requested notional.");
  if (publicRouteRisk >= 84) blockers.push("Public route exposure requires a private/bundled path before signing.");
  if (landability < 26) blockers.push("Route landability is too weak after congestion and priority-fee modeling.");
  if (intent.side === "buy" && slippageBudget > 450 && Math.max(sandwichRisk, publicRouteRisk) >= 70) {
    blockers.push("High slippage budget advertises too much room for adverse execution.");
  }
  return [...new Set(blockers)];
}

function mevGuardAction(
  intent: ExecutionIntent,
  blockers: string[],
  sandwichRisk: number,
  liquidityShock: number,
  publicRouteRisk: number,
  recommendedSize: number,
  notional: number,
  privateRoute: ExecutionMevGuardItem["private_route"],
): ExecutionMevGuardAction {
  if (intent.status === "paper-filled") return "paper";
  if (blockers.length > 0) return "block";
  if (privateRoute === "required" || publicRouteRisk >= 68) return "private-route";
  if (recommendedSize < notional || liquidityShock >= 58) return "split";
  if (sandwichRisk >= 50 || publicRouteRisk >= 50) return "tighten-slippage";
  return "allow";
}

function mevGuardStatus(
  intent: ExecutionIntent,
  action: ExecutionMevGuardAction,
  blockers: string[],
  combinedRisk: number,
): ExecutionMevGuardItem["status"] {
  if (intent.status === "paper-filled" || action === "paper") return "paper";
  if (blockers.length > 0 || action === "block") return "blocked";
  if (action === "split" || action === "private-route") return "protect";
  if (action === "tighten-slippage" || combinedRisk >= 44) return "watch";
  return "clear";
}

function mevGuardReason(
  action: ExecutionMevGuardAction,
  intent: ExecutionIntent,
  sandwichRisk: number,
  liquidityShock: number,
  publicRouteRisk: number,
  recommendedSize: number,
  sliceCount: number,
  recommendedSlippage: number,
) {
  const label = intent.symbol ?? "Desk";
  if (action === "paper") return `${label} is already recorded as a paper fill; no broadcast risk exists.`;
  if (action === "block") return `${label} is blocked by ${Math.max(sandwichRisk, liquidityShock, publicRouteRisk)}/100 MEV or liquidity-shock risk.`;
  if (action === "private-route") return `${label} needs private/bundled routing before signing because public-route risk is ${publicRouteRisk}/100.`;
  if (action === "split") return `${label} should use ${sliceCount} child order${sliceCount === 1 ? "" : "s"} at ${formatCompactValue(recommendedSize)} total to reduce liquidity shock.`;
  if (action === "tighten-slippage") return `${label} keeps size but tightens slippage to ${recommendedSlippage} bps before a route can be trusted.`;
  return `${label} clears MEV guard with ${sandwichRisk}/100 sandwich risk and ${liquidityShock}/100 liquidity-shock risk.`;
}

function mevGuardTactics(
  action: ExecutionMevGuardAction,
  privateRoute: ExecutionMevGuardItem["private_route"],
  recommendedSlippage: number,
  sliceCount: number,
  cost: ExecutionCostItem | undefined,
) {
  const tactics: string[] = [];
  if (privateRoute === "required" || privateRoute === "preferred") tactics.push("Use private/bundled transaction path before any live signing.");
  if (action === "split") tactics.push(`Slice into ${sliceCount} child orders and reprice between slices.`);
  if (action === "tighten-slippage" || action === "split" || action === "private-route") tactics.push(`Cap slippage at ${recommendedSlippage} bps for the next quote.`);
  if ((cost?.congestion_score ?? 0) >= 70) tactics.push(`Keep priority fee near ${formatLamports(cost?.priority_fee_lamports ?? 0)} but do not exceed fee cap.`);
  if (action === "allow") tactics.push("Proceed only inside paper/dry-run gates; live signing remains disabled.");
  if (action === "paper") tactics.push("Record attribution only; no transaction should be broadcast.");
  if (action === "block") tactics.push("Stand down and wait for lower slippage, deeper liquidity, or private execution support.");
  return [...new Set(tactics)];
}

function executionMevGuardSummary(
  status: ExecutionMevGuard["status"],
  items: ExecutionMevGuardItem[],
  blockedCount: number,
  protectedCount: number,
  splitCount: number,
  privateRouteCount: number,
) {
  if (status === "idle") return "No execution intents need MEV or slippage-attack screening.";
  if (status === "paper") return "All current fills are paper records; MEV guard is attribution-only for this cycle.";
  if (status === "blocked") return `${blockedCount} intent${blockedCount === 1 ? "" : "s"} blocked by sandwich, public-route, or liquidity-shock risk.`;
  if (status === "protect") return `${protectedCount} intent${protectedCount === 1 ? "" : "s"} require split sizing or private routing before they can advance.`;
  if (status === "watch") return `${items.length} intent${items.length === 1 ? "" : "s"} pass hard blocks but need tighter slippage discipline.`;
  return `${items.length} intent${items.length === 1 ? "" : "s"} clear MEV guard; ${splitCount} split and ${privateRouteCount} private-route tactics are queued.`;
}

function buildPaperExecutionQuality({
  tradeTape,
  executionIntents,
  executionCost,
  executionMevGuard,
  market,
  priceAction,
}: {
  tradeTape: AutonomousTrade[];
  executionIntents: ExecutionIntentQueue;
  executionCost: ExecutionCostMonitor;
  executionMevGuard: ExecutionMevGuard;
  market: MemecoinMarket[];
  priceAction: PriceActionMonitor;
}): PaperExecutionQuality {
  const intentBySymbolSide = new Map(executionIntents.intents.map((intent) => [`${intent.symbol ?? ""}:${intent.side}`, intent]));
  const costByIntent = new Map(executionCost.items.map((item) => [item.intent_id, item]));
  const mevByIntent = new Map(executionMevGuard.items.map((item) => [item.intent_id, item]));
  const marketBySymbol = new Map(market.map((item) => [item.symbol, item]));
  const priceActionBySymbol = new Map(priceAction.items.map((item) => [item.symbol, item]));
  const items = tradeTape.map((trade) => {
    const intent = intentBySymbolSide.get(`${trade.symbol}:${trade.side}`);
    return paperFillQualityItem({
      trade,
      intent,
      cost: intent ? costByIntent.get(intent.id) : undefined,
      mevGuard: intent ? mevByIntent.get(intent.id) : undefined,
      token: marketBySymbol.get(trade.symbol),
      priceAction: priceActionBySymbol.get(trade.symbol),
    });
  });
  const requested = items.reduce((sum, item) => sum + item.requested_size_usd, 0);
  const filled = items.reduce((sum, item) => sum + item.filled_size_usd, 0);
  const adverseSlippage = items.reduce((sum, item) => sum + item.adverse_slippage_usd, 0);
  const opportunityCost = items.reduce((sum, item) => sum + item.opportunity_cost_usd, 0);
  const shortfall = items.reduce((sum, item) => sum + item.implementation_shortfall_usd, 0);
  const fillRate = requested > 0 ? (filled / requested) * 100 : 0;
  const averageSlippage = average(items.map((item) => item.slippage_bps));
  const partialCount = items.filter((item) => item.status === "partial").length;
  const missedCount = items.filter((item) => item.status === "missed" || item.status === "blocked").length;
  const status: PaperExecutionQuality["status"] = items.length === 0
    ? "idle"
    : fillRate < 70 || shortfall > Math.max(120, requested * 0.018)
      ? "poor"
      : partialCount + missedCount > 0 || averageSlippage > 140
        ? "degraded"
        : averageSlippage > 55 || fillRate < 96
          ? "acceptable"
          : "excellent";

  return {
    status,
    source: "local-fill-simulator",
    summary: paperExecutionQualitySummary(status, items.length, fillRate, averageSlippage, shortfall),
    requested_usd: Math.round(requested),
    filled_usd: Math.round(filled),
    fill_rate_pct: roundMetric(fillRate),
    average_slippage_bps: Math.round(averageSlippage),
    adverse_slippage_usd: Math.round(adverseSlippage),
    opportunity_cost_usd: Math.round(opportunityCost),
    implementation_shortfall_usd: Math.round(shortfall),
    partial_count: partialCount,
    missed_count: missedCount,
    items,
  };
}

function paperFillQualityItem({
  trade,
  intent,
  cost,
  mevGuard,
  token,
  priceAction,
}: {
  trade: AutonomousTrade;
  intent: ExecutionIntent | undefined;
  cost: ExecutionCostItem | undefined;
  mevGuard: ExecutionMevGuardItem | undefined;
  token: MemecoinMarket | undefined;
  priceAction: PriceActionItem | undefined;
}): PaperFillQualityItem {
  const requested = Math.max(0, trade.size_usd);
  const liquidityUsd = Math.max(1, token?.liquidity_usd ?? 80_000);
  const liquiditySharePct = (requested / liquidityUsd) * 100;
  const sideMultiplier = trade.side === "buy" ? 1 : -1;
  const routeSlippage = cost?.total_cost_bps ?? intent?.estimated_shortfall_bps ?? 0;
  const volatilitySlippage = Math.abs(token?.price_change_5m_pct ?? 0) * 7;
  const liquiditySlippage = liquiditySharePct * 55;
  const mevSlippage = Math.max(
    mevGuard?.sandwich_risk_score ?? 0,
    mevGuard?.liquidity_shock_score ?? 0,
    mevGuard?.public_route_risk_score ?? 0,
  ) * 0.9;
  const exitPressureSlippage = trade.side === "sell" ? (priceAction?.exit_pressure_score ?? 20) * 0.5 : 0;
  const slippageBps = Math.round(clamp(routeSlippage + volatilitySlippage + liquiditySlippage + mevSlippage + exitPressureSlippage, 0, 950));
  const blockedByMev = mevGuard?.status === "blocked" || mevGuard?.action === "block";
  const fillRate = blockedByMev
    ? 0
    : clamp(
      100 -
        Math.max(0, slippageBps - 95) * 0.08 -
        Math.max(0, liquiditySharePct - 0.18) * 28 -
        (mevGuard?.action === "split" ? 10 : 0) -
        (mevGuard?.action === "private-route" ? 16 : 0),
      24,
      100,
    );
  const filled = Math.round(requested * (fillRate / 100));
  const priceMove = trade.price_usd * (slippageBps / 10_000) * sideMultiplier;
  const fillPrice = Math.max(0, trade.price_usd + priceMove);
  const adverseSlippage = filled * (slippageBps / 10_000);
  const opportunityCost = Math.max(0, requested - filled) * Math.max(0.0025, Math.abs(token?.price_change_5m_pct ?? 1.5) / 1000);
  const shortfall = adverseSlippage + opportunityCost;
  const status = paperFillQualityStatus(blockedByMev, fillRate, slippageBps);
  const score = clamp(Math.round(100 - slippageBps * 0.13 - Math.max(0, 100 - fillRate) * 0.7 - shortfall * 0.03), 0, 100);

  return {
    id: `fill-quality-${trade.id}`,
    trade_id: trade.id,
    intent_id: intent?.id ?? null,
    symbol: trade.symbol,
    side: trade.side,
    status,
    expected_price_usd: trade.price_usd,
    simulated_fill_price_usd: Number(fillPrice.toPrecision(6)),
    requested_size_usd: Math.round(requested),
    filled_size_usd: Math.round(filled),
    fill_rate_pct: roundMetric(fillRate),
    slippage_bps: slippageBps,
    adverse_slippage_usd: Math.round(adverseSlippage),
    opportunity_cost_usd: Math.round(opportunityCost),
    implementation_shortfall_usd: Math.round(shortfall),
    quality_score: score,
    reason: paperFillQualityReason(status, trade, slippageBps, fillRate, shortfall),
    tactics: paperFillQualityTactics(status, trade, mevGuard, slippageBps, fillRate),
  };
}

function paperFillQualityStatus(
  blockedByMev: boolean,
  fillRate: number,
  slippageBps: number,
): PaperFillQualityItemStatus {
  if (blockedByMev) return "blocked";
  if (fillRate <= 1) return "missed";
  if (fillRate < 88) return "partial";
  if (slippageBps > 120) return "slipped";
  return "clean";
}

function paperFillQualityReason(
  status: PaperFillQualityItemStatus,
  trade: AutonomousTrade,
  slippageBps: number,
  fillRate: number,
  shortfall: number,
) {
  if (status === "blocked") return `${trade.symbol} paper fill would be blocked by execution guard before broadcast.`;
  if (status === "missed") return `${trade.symbol} would miss the fill because route risk exceeds acceptable paper execution quality.`;
  if (status === "partial") return `${trade.symbol} only fills ${roundMetric(fillRate)}% in the simulator, with ${formatCompactValue(shortfall)} shortfall.`;
  if (status === "slipped") return `${trade.symbol} fills but pays ${slippageBps} bps of modeled adverse slippage.`;
  return `${trade.symbol} paper fill is close enough to the arrival price for clean attribution.`;
}

function paperFillQualityTactics(
  status: PaperFillQualityItemStatus,
  trade: AutonomousTrade,
  mevGuard: ExecutionMevGuardItem | undefined,
  slippageBps: number,
  fillRate: number,
) {
  const tactics: string[] = [];
  if (status === "blocked" || status === "missed") tactics.push("Remove from learning wins; wait for deeper liquidity or a safer route.");
  if (status === "partial") tactics.push(`Model ${roundMetric(fillRate)}% fill and require child-order execution next cycle.`);
  if (status === "slipped") tactics.push(`Subtract ${slippageBps} bps from expected edge before sizing up.`);
  if (mevGuard?.action === "split") tactics.push("Prefer split order from MEV guard before another paper fill is trusted.");
  if (mevGuard?.private_route === "required" || mevGuard?.private_route === "preferred") tactics.push("Require private/bundled route proof before a live signer can touch this path.");
  if (trade.side === "sell" && status !== "clean") tactics.push("Prioritize exit urgency, but mark the realized price with adverse slippage.");
  if (tactics.length === 0) tactics.push("Keep this fill eligible for signal attribution.");
  return [...new Set(tactics)];
}

function paperExecutionQualitySummary(
  status: PaperExecutionQuality["status"],
  count: number,
  fillRate: number,
  averageSlippage: number,
  shortfall: number,
) {
  if (status === "idle") return "No paper fills exist yet for execution-quality scoring.";
  if (status === "poor") return `${count} paper fill${count === 1 ? "" : "s"} show poor execution quality: ${roundMetric(fillRate)}% fill rate and ${formatCompactValue(shortfall)} shortfall.`;
  if (status === "degraded") return `${count} paper fill${count === 1 ? "" : "s"} need execution haircuts before learning trusts the PnL.`;
  if (status === "acceptable") return `Paper fills are usable but carry ${Math.round(averageSlippage)} bps average slippage.`;
  return `${count} paper fill${count === 1 ? "" : "s"} are close to arrival price with ${roundMetric(fillRate)}% fill rate.`;
}

function applyExecutionCostsToProfitOptimizer(
  optimizer: ProfitOptimizer,
  executionCost: ExecutionCostMonitor,
): ProfitOptimizer {
  if (executionCost.items.length === 0) return optimizer;
  const costBySymbol = new Map(executionCost.items.map((item) => [item.symbol, item]));
  const candidates = optimizer.candidates.map((candidate) => {
    const cost = costBySymbol.get(candidate.symbol);
    if (!cost || candidate.side !== "buy") return candidate;
    const addedCostBps = Math.max(0, cost.total_cost_bps - candidate.estimated_cost_bps);
    const estimatedCostBps = Math.max(candidate.estimated_cost_bps, cost.total_cost_bps);
    const netEdge = candidate.net_edge_pct - addedCostBps / 100;
    const blockers = [...candidate.blockers];
    if (cost.status === "block") blockers.push(cost.blockers[0] ?? "Execution-cost monitor blocks this trade.");
    if (cost.status === "resize") blockers.push("Execution-cost monitor requires smaller size or a fresher route.");
    if (cost.status === "watch" && netEdge < 3.5) blockers.push("Execution costs leave too little net edge for an autonomous entry.");
    const verdict = profitVerdict(candidate.side, {
      token_id: candidate.token_id,
      symbol: candidate.symbol,
      decision: candidate.verdict === "press" ? "press" : candidate.verdict === "take" ? "probe" : "skip",
      recommended_size_usd: candidate.planned_size_usd,
      risk_budget_usd: candidate.planned_size_usd,
      max_loss_usd: 0,
      edge_score: candidate.confidence,
      size_multiplier: 1,
      reason: candidate.reason,
      blockers,
    }, blockers, netEdge, Math.max(0, candidate.confidence - Math.max(0, cost.congestion_score - 55) * 0.4));
    const adjustedSize = verdict === "press" || verdict === "take"
      ? Math.floor(candidate.adjusted_size_usd * (cost.status === "resize" ? 0.55 : cost.status === "watch" ? 0.75 : 1))
      : 0;
    return {
      ...candidate,
      verdict,
      adjusted_size_usd: adjustedSize,
      estimated_cost_bps: estimatedCostBps,
      breakeven_move_pct: roundMetric(estimatedCostBps / 100),
      net_edge_pct: roundMetric(netEdge),
      expected_pnl_usd: Math.round(adjustedSize * (Math.max(0, netEdge) / 100)),
      reason: cost.status === "send"
        ? candidate.reason
        : `${candidate.symbol} edge is now gated by ${cost.total_cost_bps} bps execution cost and ${cost.landability_score}/100 landability.`,
      blockers: [...new Set(blockers)],
    } satisfies ProfitCandidate;
  });
  const actionable = candidates.filter((candidate) => candidate.verdict === "press" || candidate.verdict === "take");
  const exits = candidates.filter((candidate) => candidate.verdict === "exit");
  const avgGross = average(candidates.map((candidate) => candidate.gross_edge_pct));
  const avgNet = average(candidates.map((candidate) => candidate.net_edge_pct));
  const avgBreakeven = average(candidates.map((candidate) => candidate.breakeven_move_pct));
  const expectedPnl = actionable.reduce((sum, candidate) => sum + candidate.expected_pnl_usd, 0);
  const feeDrag = candidates.reduce((sum, candidate) => {
    const size = candidate.adjusted_size_usd || candidate.planned_size_usd;
    return sum + size * (candidate.estimated_cost_bps / 10_000);
  }, 0);
  const mode: ProfitOptimizer["mode"] = optimizer.mode === "protect" || exits.length > 0
    ? "protect"
    : actionable.some((candidate) => candidate.verdict === "press")
      ? "compound"
      : actionable.length > 0
        ? "selective"
        : "idle";
  return {
    ...optimizer,
    mode,
    gross_edge_pct: roundMetric(avgGross),
    net_edge_pct: roundMetric(avgNet),
    expected_pnl_usd: Math.round(expectedPnl),
    fee_drag_usd: Math.round(feeDrag),
    breakeven_move_pct: roundMetric(avgBreakeven),
    churn_budget_remaining: Math.max(0, optimizer.churn_budget_remaining - Math.max(0, executionCost.blocked_count)),
    summary: executionCost.blocked_count > 0 || executionCost.watch_count > 0
      ? `${actionable.length} setup${actionable.length === 1 ? "" : "s"} still clear costs after route, slippage, priority-fee, and landability checks.`
      : optimizer.summary,
    candidates,
  };
}

function executionCongestionScore(
  intent: ExecutionIntent,
  plan: ExecutionPlan | undefined,
  priceAction: PriceActionItem | undefined,
  profit: ProfitCandidate | undefined,
) {
  const urgency = intent.priority === "now" ? 18 : intent.priority === "next" ? 9 : 3;
  const routeStress = plan?.status === "quoted" ? (plan.price_impact_pct ?? 0) * 16 + (plan.slippage_bps > 300 ? 10 : 0) : 22;
  const tapeStress = priceAction
    ? priceAction.velocity_score * 0.18 + priceAction.flow_score * 0.12 + priceAction.exit_pressure_score * 0.16
    : 18;
  const profitStress = profit?.verdict === "press" ? 12 : profit?.verdict === "take" ? 6 : 0;
  const routePenalty = intent.route_quality_score < 55 ? 15 : 0;
  return clamp(Math.round(18 + urgency + routeStress + tapeStress + profitStress + routePenalty), 0, 100);
}

function priorityFeeLamportsFor(congestionScore: number, priority: ExecutionIntentPriority) {
  const urgencyMultiplier = priority === "now" ? 1.18 : priority === "next" ? 1 : 0.78;
  return Math.round(clamp((8_000 + congestionScore * congestionScore * 680) * urgencyMultiplier, 5_000, 7_500_000));
}

function maxPriorityFeeLamportsFor(notionalUsd: number, priority: ExecutionIntentPriority) {
  const capUsd = Math.max(0.04, notionalUsd * (priority === "now" ? 0.012 : 0.008));
  return Math.round(clamp((capUsd / EXECUTION_COST_SOL_USD) * 1_000_000_000, 300_000, 10_000_000));
}

function lamportsToUsd(lamports: number) {
  return (lamports / 1_000_000_000) * EXECUTION_COST_SOL_USD;
}

function priorityLevelFor(congestionScore: number, priority: ExecutionIntentPriority): ExecutionCostItem["priority_level"] {
  if (priority === "now" || congestionScore >= 72) return "veryHigh";
  if (congestionScore >= 45 || priority === "next") return "high";
  return "medium";
}

function computeUnitPriceMicroLamports(priorityFeeLamports: number) {
  if (priorityFeeLamports <= 0) return 0;
  return Math.round((priorityFeeLamports * 1_000_000) / DEFAULT_MEME_SWAP_COMPUTE_UNITS);
}

function executionCostItemStatus(
  intent: ExecutionIntent,
  blockers: string[],
  totalCostBps: number,
  landabilityScore: number,
): ExecutionCostItemStatus {
  if (intent.status === "paper-filled") return "paper";
  if (blockers.length > 0) return "block";
  if (totalCostBps > 95 || landabilityScore < 52) return "resize";
  if (totalCostBps > 62 || landabilityScore < 68 || intent.status === "cooldown") return "watch";
  return "send";
}

function executionCostStatus(
  items: ExecutionCostItem[],
  landableCount: number,
  blockedCount: number,
  avgCost: number,
): ExecutionCostMonitor["status"] {
  if (items.length === 0) return "idle";
  if (blockedCount > 0 && landableCount === 0) return "blocked";
  if (avgCost >= 90 || items.some((item) => item.congestion_score >= 80)) return "congested";
  if (avgCost <= 38 && landableCount > 0) return "cheap";
  return "normal";
}

function executionCostSummary(
  status: ExecutionCostMonitor["status"],
  items: ExecutionCostItem[],
  avgCost: number,
) {
  if (status === "idle") return "No active execution intent needs priority-fee or route-cost accounting.";
  if (status === "blocked") return "Execution costs or routing block every active intent; wait for a cheaper lane or route.";
  if (status === "congested") return `${items.length} intent${items.length === 1 ? "" : "s"} priced under congested conditions; average all-in cost is ${Math.round(avgCost)} bps.`;
  if (status === "cheap") return "Route and priority-fee drag are light enough for the current paper queue.";
  return `${items.length} intent${items.length === 1 ? "" : "s"} have normal execution friction; size stays tied to landability.`;
}

function executionCostItemSummary(
  status: ExecutionCostItemStatus,
  intent: ExecutionIntent,
  totalCostBps: number,
  priorityFeeLamports: number,
  landabilityScore: number,
) {
  const label = intent.symbol ?? "Desk";
  if (status === "paper") return `${label} already filled in the paper ledger; no priority fee is needed.`;
  if (status === "block") return `${label} is blocked after ${totalCostBps} bps all-in cost and ${landabilityScore}/100 landability.`;
  if (status === "resize") return `${label} needs smaller size or a fresher route; estimated priority fee is ${formatLamports(priorityFeeLamports)}.`;
  if (status === "watch") return `${label} can stay queued, but ${totalCostBps} bps cost requires better edge before pressing.`;
  return `${label} clears execution-cost checks with ${totalCostBps} bps all-in drag and ${landabilityScore}/100 landability.`;
}

function percentile(sortedValues: number[], q: number) {
  if (sortedValues.length === 0) return 0;
  const index = Math.min(sortedValues.length - 1, Math.max(0, Math.ceil(sortedValues.length * q) - 1));
  return sortedValues[index] ?? 0;
}

function formatLamports(value: number) {
  if (value >= 1_000_000) return `${roundMetric(value / 1_000_000)}M lamports`;
  if (value >= 1_000) return `${roundMetric(value / 1_000)}K lamports`;
  return `${value} lamports`;
}

function buildExecutionRetryPlanner({
  asOf,
  executionPlans,
  executionIntents,
  executionCost,
  readiness,
}: {
  asOf: string;
  executionPlans: ExecutionPlan[];
  executionIntents: ExecutionIntentQueue;
  executionCost: ExecutionCostMonitor;
  readiness: ExecutionReadiness;
}): ExecutionRetryPlanner {
  const planById = new Map(executionPlans.map((plan) => [plan.id, plan]));
  const costByIntent = new Map(executionCost.items.map((item) => [item.intent_id, item]));
  const items = executionIntents.intents
    .filter((intent) => intent.side !== "hold")
    .map((intent) => executionRetryItem({
      asOf,
      intent,
      plan: intent.plan_id ? planById.get(intent.plan_id) : undefined,
      cost: costByIntent.get(intent.id),
      readiness,
    }));
  const retryCount = items.filter((item) => item.action === "retry").length;
  const resizeCount = items.filter((item) => item.action === "resize").length;
  const sliceCount = items.filter((item) => item.action === "slice").length;
  const priorityEscalationCount = items.filter((item) => item.action === "escalate-priority").length;
  const standDownCount = items.filter((item) => item.action === "stand-down").length;
  const sendCount = items.filter((item) => item.action === "send").length;
  const paperCount = items.filter((item) => item.action === "paper").length;
  const feeBudgetLamports = items.reduce((sum, item) => {
    const attemptFees = item.max_attempts * item.priority_fee_lamports
      + triangularNumber(Math.max(0, item.max_attempts - 1)) * item.priority_fee_step_lamports;
    return sum + attemptFees * Math.max(1, item.slice_count);
  }, 0);
  const retryTimes = items
    .filter((item) => item.retry_after_seconds > 0)
    .map((item) => Date.parse(asOf) + item.retry_after_seconds * 1_000)
    .filter((time) => Number.isFinite(time));
  const soonestRetryAt = retryTimes.length > 0 ? new Date(Math.min(...retryTimes)).toISOString() : null;
  const status: ExecutionRetryPlanner["status"] = items.length === 0
    ? "idle"
    : standDownCount > 0 && sendCount === 0
      ? "stand-down"
      : resizeCount + sliceCount > 0
        ? "resize"
        : retryCount + priorityEscalationCount > 0
          ? "retry"
          : sendCount > 0
            ? "send"
            : paperCount > 0
              ? "paper"
              : "idle";

  return {
    status,
    source: "local-planner",
    summary: executionRetrySummary(status, sendCount, retryCount, resizeCount, sliceCount, priorityEscalationCount, standDownCount),
    retry_count: retryCount,
    resize_count: resizeCount,
    slice_count: sliceCount,
    priority_escalation_count: priorityEscalationCount,
    stand_down_count: standDownCount,
    estimated_fee_budget_usd: roundMetric(lamportsToUsd(feeBudgetLamports)),
    soonest_retry_at: soonestRetryAt,
    items,
  };
}

function executionRetryItem({
  asOf,
  intent,
  plan,
  cost,
  readiness,
}: {
  asOf: string;
  intent: ExecutionIntent;
  plan: ExecutionPlan | undefined;
  cost: ExecutionCostItem | undefined;
  readiness: ExecutionReadiness;
}): ExecutionRetryItem {
  const totalCostBps = cost?.total_cost_bps ?? Math.max(0, intent.estimated_shortfall_bps);
  const landability = cost?.landability_score ?? intent.route_quality_score;
  const priorityFee = cost?.priority_fee_lamports ?? priorityFeeLamportsFor(55, intent.priority);
  const maxPriorityFee = cost?.max_priority_fee_lamports ?? maxPriorityFeeLamportsFor(intent.size_usd, intent.priority);
  const slippageBps = plan?.slippage_bps ?? intent.max_slippage_bps;
  const targetSlippage = Math.min(readiness.config.max_slippage_bps, Math.max(75, Math.round(slippageBps * 0.82)));
  const routeBlocked = !plan || (
    plan.status !== "quoted" &&
    plan.status !== "not-needed" &&
    !(plan.source === "local-gate" && plan.message.includes("Sample mode"))
  );
  const readinessFailures = readiness.checks
    .filter((check) => check.status === "fail")
    .map((check) => `${check.label}: ${check.detail}`);
  const readinessBlocked = readiness.config.kill_switch || readinessFailures.length > 0;
  const riskBlocked = intent.blockers.some((blocker) =>
    /rug|authority|liquidity|holder|sell-pressure|vetting|blacklist|mint|freeze/i.test(blocker),
  );
  const blockers = [...new Set([
    ...intent.blockers,
    ...(cost?.blockers ?? []),
    ...(readinessBlocked ? readinessFailures.slice(0, 2) : []),
  ])];

  let action: ExecutionRetryAction = "send";
  if (intent.status === "paper-filled" || cost?.status === "paper") {
    action = "paper";
  } else if (readinessBlocked || riskBlocked || (cost?.status === "block" && landability < 28)) {
    action = "stand-down";
  } else if (routeBlocked || intent.status === "cooldown") {
    action = "retry";
  } else if (priorityFee > maxPriorityFee || cost?.status === "resize" || totalCostBps > 95 || landability < 52) {
    action = intent.size_usd >= 260 && landability >= 34 ? "slice" : "resize";
  } else if ((cost?.congestion_score ?? 0) >= 75 && priorityFee + priorityFeeStep(priorityFee, intent.priority) <= maxPriorityFee) {
    action = "escalate-priority";
  } else if (cost?.status === "watch" || totalCostBps > 62 || landability < 68) {
    action = "retry";
  }

  const sizeMultiplier = retrySizeMultiplier(action, totalCostBps, landability);
  const recommendedSize = action === "paper" || action === "stand-down"
    ? 0
    : Math.max(0, Math.floor(intent.size_usd * sizeMultiplier));
  const sliceCount = action === "slice" ? clamp(Math.ceil(intent.size_usd / Math.max(80, recommendedSize || 1)), 2, 4) : 1;
  const sliceSize = sliceCount > 1 ? Math.floor(recommendedSize / sliceCount) : recommendedSize;
  const retryAfterSeconds = retryAfterFor(action, intent, cost, plan, asOf);
  const maxAttempts = maxAttemptsFor(action, readiness);
  const priorityFeeStepLamports = action === "escalate-priority" || action === "retry"
    ? Math.min(priorityFeeStep(priorityFee, intent.priority), Math.max(0, maxPriorityFee - priorityFee))
    : 0;

  return {
    id: `retry-${intent.id}`,
    intent_id: intent.id,
    plan_id: intent.plan_id,
    symbol: intent.symbol,
    side: intent.side,
    action,
    priority: intent.priority,
    original_size_usd: intent.size_usd,
    recommended_size_usd: recommendedSize,
    slice_count: sliceCount,
    slice_size_usd: sliceSize,
    retry_after_seconds: retryAfterSeconds,
    max_attempts: maxAttempts,
    priority_fee_lamports: priorityFee,
    priority_fee_step_lamports: priorityFeeStepLamports,
    slippage_bps: slippageBps,
    target_slippage_bps: targetSlippage,
    landability_score: landability,
    total_cost_bps: totalCostBps,
    reason: executionRetryReason(action, intent, cost, plan, totalCostBps, landability, recommendedSize, sliceCount),
    blockers,
  };
}

function retrySizeMultiplier(action: ExecutionRetryAction, totalCostBps: number, landability: number) {
  if (action === "send" || action === "escalate-priority" || action === "retry") return 1;
  if (action === "slice") return clamp(0.68 - Math.max(0, totalCostBps - 95) / 420 - Math.max(0, 52 - landability) / 160, 0.35, 0.68);
  if (action === "resize") return clamp(0.58 - Math.max(0, totalCostBps - 95) / 360 - Math.max(0, 52 - landability) / 140, 0.25, 0.58);
  return 0;
}

function retryAfterFor(
  action: ExecutionRetryAction,
  intent: ExecutionIntent,
  cost: ExecutionCostItem | undefined,
  plan: ExecutionPlan | undefined,
  asOf: string,
) {
  if (action === "send" || action === "paper" || action === "stand-down") return 0;
  const explicitRetryAt = intent.retry_after ? Math.max(0, Math.round((Date.parse(intent.retry_after) - Date.parse(asOf)) / 1_000)) : 0;
  if (explicitRetryAt > 0) return explicitRetryAt;
  if (!plan || plan.status === "blocked") return 18;
  if ((cost?.congestion_score ?? 0) >= 80) return 12;
  if (action === "slice" || action === "resize") return 9;
  return 6;
}

function maxAttemptsFor(action: ExecutionRetryAction, readiness: ExecutionReadiness) {
  if (action === "send" || action === "paper" || action === "stand-down") return 1;
  if (readiness.config.mode === "paper") return 2;
  return action === "escalate-priority" ? 3 : 2;
}

function priorityFeeStep(priorityFeeLamports: number, priority: ExecutionIntentPriority) {
  const multiplier = priority === "now" ? 0.32 : priority === "next" ? 0.24 : 0.16;
  return Math.round(clamp(priorityFeeLamports * multiplier, 20_000, 1_250_000));
}

function triangularNumber(value: number) {
  return (value * (value + 1)) / 2;
}

function executionRetryReason(
  action: ExecutionRetryAction,
  intent: ExecutionIntent,
  cost: ExecutionCostItem | undefined,
  plan: ExecutionPlan | undefined,
  totalCostBps: number,
  landability: number,
  recommendedSize: number,
  sliceCount: number,
) {
  const label = intent.symbol ?? "Desk";
  if (action === "paper") return `${label} already filled in paper; no retry is scheduled.`;
  if (action === "stand-down") return `${label} stands down because live readiness, token risk, or landability blocks the trade.`;
  if (action === "slice") return `${label} is split into ${sliceCount} child order${sliceCount === 1 ? "" : "s"} at ${formatCompactValue(recommendedSize)} total to reduce ${totalCostBps} bps drag.`;
  if (action === "resize") return `${label} is resized to ${formatCompactValue(recommendedSize)} because all-in cost is ${totalCostBps} bps with ${landability}/100 landability.`;
  if (action === "escalate-priority") return `${label} keeps size and steps priority fee once because congestion is high but inside the fee cap.`;
  if (action === "retry") return `${label} requotes before action; ${plan?.message ?? cost?.summary ?? "route quality is not stable enough yet"}.`;
  return `${label} can proceed in paper/dry-run mode with retry budget capped at one attempt.`;
}

function executionRetrySummary(
  status: ExecutionRetryPlanner["status"],
  sendCount: number,
  retryCount: number,
  resizeCount: number,
  sliceCount: number,
  priorityEscalationCount: number,
  standDownCount: number,
) {
  if (status === "idle") return "No active execution intent needs a retry or order-slicing plan.";
  if (status === "stand-down") return `${standDownCount} intent${standDownCount === 1 ? "" : "s"} stand down until readiness, route, or risk blockers clear.`;
  if (status === "resize") return `${resizeCount + sliceCount} intent${resizeCount + sliceCount === 1 ? "" : "s"} need smaller or sliced orders before a paper fill can be considered.`;
  if (status === "retry") return `${retryCount} requote${retryCount === 1 ? "" : "s"} and ${priorityEscalationCount} priority step${priorityEscalationCount === 1 ? "" : "s"} are queued with bounded attempts.`;
  if (status === "send") return `${sendCount} intent${sendCount === 1 ? "" : "s"} can stay on the paper send path with no additional retry loop.`;
  return "Paper fills are recorded; live retries remain disabled.";
}

function buildExecutionPreflight({
  asOf,
  executionPlans,
  executionIntents,
  executionCost,
  executionMevGuard,
  executionRetry,
  readiness,
  tokenVetting,
}: {
  asOf: string;
  executionPlans: ExecutionPlan[];
  executionIntents: ExecutionIntentQueue;
  executionCost: ExecutionCostMonitor;
  executionMevGuard: ExecutionMevGuard;
  executionRetry: ExecutionRetryPlanner;
  readiness: ExecutionReadiness;
  tokenVetting: TokenVettingReport;
}): ExecutionPreflightReport {
  const planById = new Map(executionPlans.map((plan) => [plan.id, plan]));
  const vettingBySymbol = new Map(tokenVetting.items.map((item) => [item.symbol, item]));
  const costByIntent = new Map(executionCost.items.map((item) => [item.intent_id, item]));
  const mevByIntent = new Map(executionMevGuard.items.map((item) => [item.intent_id, item]));
  const retryByIntent = new Map(executionRetry.items.map((item) => [item.intent_id, item]));
  const items = executionIntents.intents
    .filter((intent) => intent.side !== "hold")
    .map((intent) => executionPreflightItem({
      asOf,
      intent,
      plan: intent.plan_id ? planById.get(intent.plan_id) : undefined,
      cost: costByIntent.get(intent.id),
      mevGuard: mevByIntent.get(intent.id),
      retry: retryByIntent.get(intent.id),
      readiness,
      vetting: intent.symbol ? vettingBySymbol.get(intent.symbol) : undefined,
    }));
  const readyCount = items.filter((item) => item.status === "ready").length;
  const watchCount = items.filter((item) => item.status === "watch").length;
  const blockedCount = items.filter((item) => item.status === "blocked").length;
  const paperCount = items.filter((item) => item.status === "paper").length;
  const status: ExecutionPreflightReport["status"] = readyCount > 0
    ? "ready"
    : blockedCount > 0
      ? "blocked"
      : watchCount > 0
        ? "watch"
        : paperCount > 0
          ? "paper"
          : "idle";

  return {
    status,
    summary: executionPreflightSummary(status, readyCount, watchCount, blockedCount, paperCount, readiness),
    max_quote_age_seconds: 15,
    ready_count: readyCount,
    watch_count: watchCount,
    blocked_count: blockedCount,
    paper_count: paperCount,
    items,
  };
}

function executionPreflightItem({
  asOf,
  intent,
  plan,
  cost,
  mevGuard,
  retry,
  readiness,
  vetting,
}: {
  asOf: string;
  intent: ExecutionIntent;
  plan: ExecutionPlan | undefined;
  cost: ExecutionCostItem | undefined;
  mevGuard: ExecutionMevGuardItem | undefined;
  retry: ExecutionRetryItem | undefined;
  readiness: ExecutionReadiness;
  vetting: TokenVettingItem | undefined;
}): ExecutionPreflightItem {
  const quoteAge = executionPlanQuoteAgeSeconds(asOf, plan);
  const feeBps = cost?.total_cost_bps ?? plan?.dry_run.fee_bps ?? null;
  const estimatedFee = typeof feeBps === "number" ? roundMetric(intent.size_usd * feeBps / 10_000) : null;
  const checks = executionPreflightChecks(intent, plan, cost, mevGuard, retry, readiness, vetting, quoteAge);
  const failed = checks.filter((check) => check.status === "fail");
  const warned = checks.filter((check) => check.status === "warn");
  const status: ExecutionPreflightItemStatus = intent.status === "paper-filled"
    ? "paper"
    : failed.length > 0
      ? "blocked"
      : warned.length > 0
        ? "watch"
        : "ready";
  const score = clamp(
    Math.round(
      intent.route_quality_score
        - failed.length * 24
        - warned.length * 9
        - (plan?.price_impact_pct ?? 0) * 12
        - (feeBps ?? 0) * 0.12
        - (mevGuard ? Math.max(0, 70 - mevGuard.score) * 0.28 : 0)
        + ((cost?.landability_score ?? 60) - 60) * 0.18,
    ),
    0,
    100,
  );
  const blockers = [...new Set([
    ...intent.blockers,
    ...(cost?.blockers ?? []),
    ...(mevGuard?.blockers ?? []),
    ...failed.map((check) => `${check.label}: ${check.detail}`),
  ])];

  return {
    id: `preflight-${intent.id}`,
    intent_id: intent.id,
    plan_id: intent.plan_id,
    symbol: intent.symbol,
    side: intent.side,
    status,
    score,
    notional_usd: intent.size_usd,
    quote_age_seconds: quoteAge,
    price_impact_pct: plan?.price_impact_pct ?? null,
    max_slippage_bps: readiness.config.max_slippage_bps,
    route_slippage_bps: plan?.slippage_bps ?? null,
    fee_bps: feeBps,
    estimated_fee_usd: estimatedFee,
    estimated_priority_fee_lamports: cost?.priority_fee_lamports ?? null,
    payload_ready: plan?.dry_run.transaction_ready ?? false,
    summary: executionPreflightItemSummary(status, intent, plan, feeBps, estimatedFee),
    blockers,
    checks,
    next_action: executionPreflightNextAction(status, intent, plan, blockers),
  };
}

function executionPlanQuoteAgeSeconds(asOf: string, plan: ExecutionPlan | undefined) {
  if (!plan || plan.status !== "quoted" || !plan.quoted_at) return null;
  const asOfMs = Date.parse(asOf);
  const quotedMs = Date.parse(plan.quoted_at);
  if (!Number.isFinite(asOfMs) || !Number.isFinite(quotedMs)) return null;
  return Math.max(0, Math.round((asOfMs - quotedMs) / 1_000));
}

function executionPreflightChecks(
  intent: ExecutionIntent,
  plan: ExecutionPlan | undefined,
  cost: ExecutionCostItem | undefined,
  mevGuard: ExecutionMevGuardItem | undefined,
  retry: ExecutionRetryItem | undefined,
  readiness: ExecutionReadiness,
  vetting: TokenVettingItem | undefined,
  quoteAge: number | null,
): ExecutionPreflightCheck[] {
  return [
    routePreflightCheck(intent, plan),
    quoteFreshnessCheck(intent, plan, quoteAge),
    impactPreflightCheck(plan),
    slippagePreflightCheck(plan, readiness),
    sizePreflightCheck(intent, readiness, vetting),
    vettingPreflightCheck(intent, vetting),
    payloadPreflightCheck(intent, plan, readiness),
    feePreflightCheck(plan, cost),
    mevPreflightCheck(intent, mevGuard),
    retryPreflightCheck(intent, retry),
  ];
}

function routePreflightCheck(intent: ExecutionIntent, plan: ExecutionPlan | undefined): ExecutionPreflightCheck {
  if (intent.status === "paper-filled") {
    return { id: "route", label: "Route", status: "pass", detail: "Paper ledger fill already recorded for this cycle." };
  }
  if (!plan) return { id: "route", label: "Route", status: "fail", detail: "No execution plan is attached to this intent." };
  if (plan.status === "quoted") return { id: "route", label: "Route", status: "pass", detail: `${plan.route_label} quote is attached.` };
  if (plan.status === "not-needed") return { id: "route", label: "Route", status: "warn", detail: "No route is needed while the agent is watching." };
  return { id: "route", label: "Route", status: "fail", detail: plan.message };
}

function quoteFreshnessCheck(
  intent: ExecutionIntent,
  plan: ExecutionPlan | undefined,
  quoteAge: number | null,
): ExecutionPreflightCheck {
  if (intent.status === "paper-filled") {
    return { id: "freshness", label: "Freshness", status: "pass", detail: "Paper fill uses current deterministic cycle telemetry." };
  }
  if (!plan || plan.status !== "quoted") {
    return { id: "freshness", label: "Freshness", status: "warn", detail: "No fresh Jupiter quote is available for this intent." };
  }
  return {
    id: "freshness",
    label: "Freshness",
    status: quoteAge !== null && quoteAge <= 15 ? "pass" : "fail",
    detail: quoteAge !== null ? `${quoteAge}s quote age against a 15s trading window.` : "Quote age could not be measured.",
  };
}

function impactPreflightCheck(plan: ExecutionPlan | undefined): ExecutionPreflightCheck {
  const impact = plan?.price_impact_pct;
  if (impact === null || impact === undefined) {
    return { id: "impact", label: "Impact", status: "warn", detail: "Price impact is unknown until a live route quote is attached." };
  }
  if (impact > 2.5) return { id: "impact", label: "Impact", status: "fail", detail: `${roundMetric(impact)}% price impact exceeds the 2.5% cap.` };
  if (impact > 1.25) return { id: "impact", label: "Impact", status: "warn", detail: `${roundMetric(impact)}% price impact needs reduced size or a better route.` };
  return { id: "impact", label: "Impact", status: "pass", detail: `${roundMetric(impact)}% price impact is inside the route cap.` };
}

function slippagePreflightCheck(plan: ExecutionPlan | undefined, readiness: ExecutionReadiness): ExecutionPreflightCheck {
  if (!plan) return { id: "slippage", label: "Slippage", status: "fail", detail: "No route slippage setting exists." };
  if (plan.slippage_bps > readiness.config.max_slippage_bps) {
    return { id: "slippage", label: "Slippage", status: "fail", detail: `${plan.slippage_bps} bps exceeds the ${readiness.config.max_slippage_bps} bps cap.` };
  }
  if (plan.slippage_bps > 300) return { id: "slippage", label: "Slippage", status: "warn", detail: `${plan.slippage_bps} bps is high for autonomous entries.` };
  return { id: "slippage", label: "Slippage", status: "pass", detail: `${plan.slippage_bps} bps route tolerance is within cap.` };
}

function sizePreflightCheck(
  intent: ExecutionIntent,
  readiness: ExecutionReadiness,
  vetting: TokenVettingItem | undefined,
): ExecutionPreflightCheck {
  const cap = Math.min(readiness.config.max_trade_usd, readiness.cap_remaining_usd, vetting?.max_position_usd ?? Number.POSITIVE_INFINITY);
  if (intent.size_usd > cap) {
    return { id: "size", label: "Size", status: "fail", detail: `${formatCompactValue(intent.size_usd)} exceeds the ${formatCompactValue(cap)} available cap.` };
  }
  if (intent.size_usd > cap * 0.85) {
    return { id: "size", label: "Size", status: "warn", detail: `${formatCompactValue(intent.size_usd)} uses most of the available cap.` };
  }
  return { id: "size", label: "Size", status: "pass", detail: `${formatCompactValue(intent.size_usd)} fits execution, spend, and vetting caps.` };
}

function vettingPreflightCheck(intent: ExecutionIntent, vetting: TokenVettingItem | undefined): ExecutionPreflightCheck {
  if (intent.side !== "buy") return { id: "vetting", label: "Vetting", status: "pass", detail: "Exit intent does not require entry vetting." };
  if (!vetting) return { id: "vetting", label: "Vetting", status: "fail", detail: "No token-vetting record is attached." };
  if (vetting.status === "blocked") return { id: "vetting", label: "Vetting", status: "fail", detail: vetting.issues[0] ?? vetting.summary };
  if (vetting.status === "watch") return { id: "vetting", label: "Vetting", status: "warn", detail: "Authority/RugCheck or quality checks still require live adapters." };
  return { id: "vetting", label: "Vetting", status: "pass", detail: "Token clears local vetting." };
}

function payloadPreflightCheck(
  intent: ExecutionIntent,
  plan: ExecutionPlan | undefined,
  readiness: ExecutionReadiness,
): ExecutionPreflightCheck {
  if (intent.status === "paper-filled") {
    return { id: "payload", label: "Payload", status: "pass", detail: "No signer payload is needed for the recorded paper fill." };
  }
  if (readiness.config.mode === "paper") {
    return { id: "payload", label: "Payload", status: "warn", detail: "Paper mode blocks unsigned order payload requests." };
  }
  if (plan?.dry_run.transaction_ready) {
    return { id: "payload", label: "Payload", status: "pass", detail: "Unsigned order payload is hash-validated and waiting at the signing boundary." };
  }
  return { id: "payload", label: "Payload", status: "warn", detail: plan?.dry_run.message ?? "No unsigned payload has been built." };
}

function feePreflightCheck(plan: ExecutionPlan | undefined, cost: ExecutionCostItem | undefined): ExecutionPreflightCheck {
  if (!cost) {
    const feeBps = plan?.dry_run.fee_bps;
    if (feeBps === null || feeBps === undefined) {
      return { id: "fees", label: "Fees", status: "warn", detail: "Execution-cost monitor has no priority-fee estimate for this intent." };
    }
    if (feeBps > 100) return { id: "fees", label: "Fees", status: "fail", detail: `${feeBps} bps route fees exceed the autonomous fee ceiling.` };
    if (feeBps > 50) return { id: "fees", label: "Fees", status: "warn", detail: `${feeBps} bps route fees are high; retry for a cleaner route.` };
    return { id: "fees", label: "Fees", status: "pass", detail: `${feeBps} bps route fees are inside the ceiling.` };
  }
  if (cost.status === "block") return { id: "fees", label: "Fees", status: "fail", detail: cost.blockers[0] ?? cost.summary };
  if (cost.total_cost_bps > 95 || cost.status === "resize") {
    return { id: "fees", label: "Fees", status: "warn", detail: `${cost.total_cost_bps} bps all-in cost needs smaller size or fresher routing.` };
  }
  if (cost.total_cost_bps > 62 || cost.status === "watch") {
    return { id: "fees", label: "Fees", status: "warn", detail: `${cost.total_cost_bps} bps all-in cost is watchlisted against ${formatLamports(cost.priority_fee_lamports)} priority fee.` };
  }
  return { id: "fees", label: "Fees", status: "pass", detail: `${cost.total_cost_bps} bps route plus priority-fee drag clears the ceiling.` };
}

function mevPreflightCheck(intent: ExecutionIntent, mevGuard: ExecutionMevGuardItem | undefined): ExecutionPreflightCheck {
  if (intent.status === "paper-filled") {
    return { id: "mev-guard", label: "MEV guard", status: "pass", detail: "Paper fill has no broadcast exposure; guard records attribution only." };
  }
  if (!mevGuard) return { id: "mev-guard", label: "MEV guard", status: "warn", detail: "No sandwich or liquidity-shock guard item is attached." };
  if (mevGuard.status === "blocked") {
    return { id: "mev-guard", label: "MEV guard", status: "fail", detail: mevGuard.blockers[0] ?? mevGuard.reason };
  }
  if (mevGuard.status === "protect" || mevGuard.status === "watch") {
    return { id: "mev-guard", label: "MEV guard", status: "warn", detail: mevGuard.reason };
  }
  return { id: "mev-guard", label: "MEV guard", status: "pass", detail: mevGuard.reason };
}

function retryPreflightCheck(intent: ExecutionIntent, retry: ExecutionRetryItem | undefined): ExecutionPreflightCheck {
  if (intent.status === "paper-filled") {
    return { id: "retry-plan", label: "Retry plan", status: "pass", detail: "No retry is needed for an already recorded paper fill." };
  }
  if (!retry) return { id: "retry-plan", label: "Retry plan", status: "warn", detail: "No retry planner item is attached." };
  if (retry.action === "stand-down") {
    return { id: "retry-plan", label: "Retry plan", status: "fail", detail: retry.reason };
  }
  if (retry.action === "resize" || retry.action === "slice" || retry.action === "retry" || retry.action === "escalate-priority") {
    return { id: "retry-plan", label: "Retry plan", status: "warn", detail: retry.reason };
  }
  return { id: "retry-plan", label: "Retry plan", status: "pass", detail: retry.reason };
}

function executionPreflightSummary(
  status: ExecutionPreflightReport["status"],
  ready: number,
  watch: number,
  blocked: number,
  paper: number,
  readiness: ExecutionReadiness,
) {
  if (status === "ready") return `${ready} intent${ready === 1 ? "" : "s"} clears quote, impact, cap, fee, and payload preflight. Signing remains disabled.`;
  if (status === "paper") return `${paper} paper fill${paper === 1 ? "" : "s"} recorded; no live payload should be signed.`;
  if (status === "watch") return `${watch} intent${watch === 1 ? " needs" : "s need"} fresher route, fee, or security proof before sizing up.`;
  if (status === "blocked") return `${blocked} intent${blocked === 1 ? "" : "s"} blocked by ${readiness.config.kill_switch ? "kill switch/readiness" : "preflight"} gates.`;
  return "No execution preflight items are active.";
}

function executionPreflightItemSummary(
  status: ExecutionPreflightItemStatus,
  intent: ExecutionIntent,
  plan: ExecutionPlan | undefined,
  feeBps: number | null,
  estimatedFee: number | null,
) {
  if (status === "paper") return `${intent.symbol ?? "Desk"} is already paper-filled; continue monitoring exits and PnL.`;
  if (status === "blocked") return `${intent.symbol ?? "Desk"} cannot advance until failed preflight checks clear.`;
  if (status === "watch") return `${intent.symbol ?? "Desk"} needs tighter route proof before autonomous execution.`;
  const feeText = feeBps !== null && estimatedFee !== null ? ` with about ${formatCompactValue(estimatedFee)} in Jupiter fees` : "";
  return `${intent.symbol ?? "Desk"} clears preflight through ${plan?.route_label ?? "local route"}${feeText}.`;
}

function executionPreflightNextAction(
  status: ExecutionPreflightItemStatus,
  intent: ExecutionIntent,
  plan: ExecutionPlan | undefined,
  blockers: string[],
) {
  if (status === "ready") return plan?.dry_run.transaction_ready
    ? "Hold at signer boundary; require explicit future live-execution controls before signing."
    : "Request an unsigned dry-run order before any signer handoff.";
  if (status === "paper") return "Let the position watcher manage stop, take-profit, and next-cycle sizing.";
  if (status === "blocked") return blockers[0] ?? "Resolve failed route, cap, vetting, or readiness checks.";
  if (intent.status === "cooldown") return "Wait for retry window, then refresh route and fee proof.";
  return "Refresh quote, security proof, and fee data before allowing this intent to size up.";
}

function average(values: number[]) {
  if (values.length === 0) return 0;
  return values.reduce((sum, value) => sum + value, 0) / values.length;
}

function buildOpportunityRadar(
  market: MemecoinMarket[],
  signals: TradingSignal[],
  portfolio: TradingPortfolio,
  strategyLab: StrategyLab,
): OpportunityRadar {
  const selectedProfile = strategyProfiles.find((profile) => profile.id === strategyLab.selected_profile_id)
    ?? strategyProfiles[1];
  const heldTokenIds = new Set(portfolio.open_positions.map((position) => position.token_id));
  const signalByToken = new Map(signals.map((signal) => [signal.token_id, signal]));
  const items = market
    .map((token) => opportunityRadarItem(token, signalByToken.get(token.id), selectedProfile, heldTokenIds, portfolio))
    .sort((a, b) => b.rank - a.rank || b.confidence - a.confidence)
    .map((item, index) => ({ ...item, rank: index + 1 }));

  return {
    selected_profile_id: selectedProfile.id,
    enter_count: items.filter((item) => item.action === "enter").length,
    watch_count: items.filter((item) => item.action === "watch").length,
    blocked_count: items.filter((item) => item.action === "blocked").length,
    items,
  };
}

function opportunityRadarItem(
  token: MemecoinMarket,
  signal: TradingSignal | undefined,
  profile: StrategyProfile,
  heldTokenIds: Set<string>,
  portfolio: TradingPortfolio,
): OpportunityRadarItem {
  const buyPressure = token.buys_5m / Math.max(1, token.buys_5m + token.sells_5m);
  const volumeToLiquidity = token.volume_1h_usd / Math.max(1, token.liquidity_usd);
  const velocity = clamp(Math.round(
    token.price_change_5m_pct * 0.9 +
      token.price_change_1h_pct * 0.45 +
      volumeToLiquidity * 22 +
      buyPressure * 18 +
      token.boosts * 1.2,
  ), 0, 100);
  const riskScore = opportunityRiskScore(token, profile, heldTokenIds);
  const confidence = clamp(Math.round(
    (signal?.score ?? 35) * 0.52 +
      velocity * 0.33 +
      (buyPressure * 100) * 0.16 -
      riskScore * 0.42,
  ), 0, 100);
  const blockers = opportunityBlockers(token, signal, profile, heldTokenIds, riskScore);
  const alreadyHeld = heldTokenIds.has(token.id);
  let action: OpportunityRadarItem["action"] = "watch";
  if (blockers.length > 0) action = alreadyHeld && blockers.length === 1 ? "watch" : "blocked";
  else if ((signal?.action === "buy" || signal?.action === "watch") && confidence >= profile.min_score - 4) action = "enter";
  const maxSize = Math.floor(Math.min(
    signal?.suggested_size_usd ?? 0,
    portfolio.equity_usd * profile.max_position_pct,
    portfolio.cash_usd,
  ) * profile.size_multiplier);
  const suggestedSize = action === "enter" ? Math.max(0, maxSize) : 0;
  const urgency: OpportunityRadarItem["urgency"] =
    action === "enter" && (velocity >= 76 || token.price_change_5m_pct >= 6) ? "high" :
      action === "enter" || confidence >= 64 ? "medium" : "low";

  return {
    token_id: token.id,
    symbol: token.symbol,
    chain: token.chain,
    action,
    rank: confidence,
    confidence,
    urgency,
    suggested_size_usd: suggestedSize >= 100 ? suggestedSize : 0,
    liquidity_usd: token.liquidity_usd,
    volume_1h_usd: token.volume_1h_usd,
    age_minutes: token.age_minutes,
    buy_pressure_pct: Math.round(buyPressure * 100),
    velocity_score: velocity,
    risk_score: riskScore,
    snipe_window_seconds: action === "enter" ? snipeWindowSeconds(token, velocity, riskScore) : 0,
    thesis: opportunityThesis(token, signal, action, confidence, profile),
    triggers: opportunityTriggers(token, buyPressure, volumeToLiquidity, velocity),
    blockers,
    invalidation: opportunityInvalidation(token, profile),
  };
}

function opportunityRiskScore(token: MemecoinMarket, profile: StrategyProfile, heldTokenIds: Set<string>) {
  let risk = token.risk_flags.length * 16;
  if (heldTokenIds.has(token.id)) risk += 35;
  if (token.age_minutes < profile.min_age_minutes) risk += 24;
  if (token.liquidity_usd < profile.min_liquidity_usd) risk += 22;
  if (token.paid_orders >= 3 || token.boosts >= 10) risk += 14;
  if (token.sells_5m > token.buys_5m * 1.4) risk += 18;
  if (token.price_change_5m_pct < -4) risk += 16;
  return clamp(Math.round(risk), 0, 100);
}

function opportunityBlockers(
  token: MemecoinMarket,
  signal: TradingSignal | undefined,
  profile: StrategyProfile,
  heldTokenIds: Set<string>,
  riskScore: number,
) {
  const blockers: string[] = [];
  if (heldTokenIds.has(token.id)) blockers.push("Already held; watch for scale-in or exit instead of duplicate entry.");
  if (!signal || signal.action === "sell" || signal.action === "hold") blockers.push("Signal is not strong enough for a fresh entry.");
  if (token.age_minutes < profile.min_age_minutes) blockers.push(`Pair age is below ${profile.min_age_minutes} minute profile minimum.`);
  if (token.liquidity_usd < profile.min_liquidity_usd) blockers.push(`Liquidity is below ${formatCompactValue(profile.min_liquidity_usd)} profile minimum.`);
  if (token.risk_flags.length > profile.max_risk_flags) blockers.push(`Risk flags exceed ${profile.max_risk_flags} allowed for ${profile.label}.`);
  if (riskScore >= 72) blockers.push("Composite risk score is too high for autonomous entry.");
  return blockers;
}

function snipeWindowSeconds(token: MemecoinMarket, velocity: number, riskScore: number) {
  const base = velocity >= 82 ? 30 : velocity >= 70 ? 60 : 120;
  const riskPenalty = riskScore >= 45 ? 0.5 : 1;
  const agePenalty = token.age_minutes < 120 ? 0.75 : 1;
  return Math.max(20, Math.round(base * riskPenalty * agePenalty));
}

function opportunityThesis(
  token: MemecoinMarket,
  signal: TradingSignal | undefined,
  action: OpportunityRadarItem["action"],
  confidence: number,
  profile: StrategyProfile,
) {
  if (action === "enter") {
    return `${token.symbol} clears ${profile.label} with ${confidence}/100 confidence and enough flow for a paper entry.`;
  }
  if (action === "blocked") {
    return `${token.symbol} has attention, but the profile blocks autonomous entry until risk improves.`;
  }
  if (signal?.action === "buy" || signal?.action === "watch") {
    return `${token.symbol} stays on watch at ${confidence}/100 confidence while the agent waits for a cleaner fresh-entry setup.`;
  }
  return `${token.symbol} is on watch while the agent waits for cleaner continuation.`;
}

function opportunityTriggers(
  token: MemecoinMarket,
  buyPressure: number,
  volumeToLiquidity: number,
  velocity: number,
) {
  return [
    `${formatPct(token.price_change_5m_pct)} 5m / ${formatPct(token.price_change_1h_pct)} 1h`,
    `${Math.round(buyPressure * 100)}% buy flow`,
    `${volumeToLiquidity.toFixed(2)}x 1h volume/liquidity`,
    `velocity ${velocity}`,
  ];
}

function opportunityInvalidation(token: MemecoinMarket, profile: StrategyProfile) {
  return [
    `${formatPct(profile.stop_loss_pct)} from entry`,
    `liquidity below ${formatCompactValue(Math.max(100_000, profile.min_liquidity_usd * 0.5))}`,
    `5m price below ${formatPct(-5)} or sell flow above 60%`,
    token.age_minutes < 180 ? "new-pair risk remains elevated" : "momentum break",
  ].join(" / ");
}

function portfolioFromLedger(row: Web3PaperLedgerRow, market: MemecoinMarket[]): TradingPortfolio {
  const data = parseLedgerData(row.data);
  const positions = markPositions(data.positions, market);
  const exposure = positions.reduce((sum, position) => sum + position.value_usd, 0);
  const unrealized = positions.reduce((sum, position) => sum + position.pnl_usd, 0);
  const equity = row.cash_usd + exposure;
  const drawdown = data.high_watermark_usd > 0
    ? Math.max(0, ((data.high_watermark_usd - equity) / data.high_watermark_usd) * 100)
    : 0;
  return {
    starting_cash_usd: data.starting_cash_usd,
    cash_usd: row.cash_usd,
    equity_usd: equity,
    exposure_usd: exposure,
    realized_pnl_usd: row.realized_pnl_usd,
    unrealized_pnl_usd: unrealized,
    max_drawdown_pct: drawdown,
    open_positions: positions,
  };
}

function ledgerTrades(row: Web3PaperLedgerRow): AutonomousTrade[] {
  return parseLedgerData(row.data).trades;
}

function recordOnchainEvents(request: OnchainEventIngestRequest | undefined, now: string) {
  if (!request || !Array.isArray(request.events) || request.events.length === 0) return;
  const source = isOnchainEventSource(request.source) ? request.source : "helius-webhook";
  const current = readLedger() ?? createLedger(now);
  const data = parseLedgerData(current.data);
  const existingById = new Map(data.onchain_events.map((event) => [event.id, event]));
  const normalized = request.events
    .slice(0, 25)
    .map((event, index) => normalizeOnchainEvent(event, source, now, index))
    .filter((event): event is OnchainEventLedgerRow => event !== null);
  for (const event of normalized) {
    if (!existingById.has(event.id)) existingById.set(event.id, event);
  }
  const onchainEvents = [...existingById.values()]
    .sort((a, b) => Date.parse(a.received_at) - Date.parse(b.received_at))
    .slice(-100);
  store().upsertWeb3PaperLedger({
    ...current,
    updated_at: now,
    data: {
      ...data,
      onchain_events: onchainEvents,
    } satisfies LedgerData,
  });
}

function normalizeOnchainEvent(
  value: unknown,
  source: OnchainEventSource,
  receivedAt: string,
  index: number,
): OnchainEventLedgerRow | null {
  if (!value || typeof value !== "object") return null;
  const row = value as Record<string, any>;
  const transfer = primaryTokenTransfer(row);
  const signature = [
    stringField(row, "signature"),
    stringField(row, "transactionSignature"),
    stringField(row, "txSignature"),
    stringField(row, "id"),
  ].find((item): item is string => Boolean(item?.trim())) ?? `event-${eventPayloadHash(row)}-${index}`;
  const eventType = (
    stringField(row, "type") ??
    stringField(row, "transactionType") ??
    stringField(row, "eventType") ??
    "UNKNOWN"
  ).toUpperCase();
  const direction = normalizeOnchainDirection(stringField(row, "direction"), eventType, transfer);
  const timestamp = normalizeEventTimestamp(row.timestamp ?? row.blockTime ?? row.createdAt, receivedAt);
  const tokenAddress = stringField(row, "token_address") ??
    stringField(row, "tokenAddress") ??
    stringField(row, "mint") ??
    transfer?.mint ??
    null;
  const symbol = stringField(row, "symbol") ??
    stringField(row, "tokenSymbol") ??
    transfer?.symbol ??
    null;
  const walletAddress = stringField(row, "wallet_address") ??
    stringField(row, "walletAddress") ??
    stringField(row, "feePayer") ??
    (direction === "sell" ? transfer?.fromUserAccount : transfer?.toUserAccount) ??
    null;
  const counterparty = stringField(row, "counterparty") ??
    (direction === "sell" ? transfer?.toUserAccount : transfer?.fromUserAccount) ??
    null;
  const amount = numberLike(row.amount) ??
    numberLike(row.tokenAmount) ??
    numberLike(transfer?.tokenAmount) ??
    0;
  const amountUsd = numberLike(row.amount_usd) ??
    numberLike(row.amountUsd) ??
    numberLike(row.usdAmount) ??
    numberLike(transfer?.amountUsd) ??
    null;
  const confidence = clamp(Math.round(
    (source === "helius-webhook" ? 72 : source === "helius-history" ? 66 : 54) +
      (signature.startsWith("event-") ? -16 : 8) +
      (tokenAddress ? 8 : -10) +
      (direction === "buy" || direction === "sell" ? 8 : direction === "mint" ? 2 : -4) +
      (amountUsd && amountUsd > 5_000 ? 6 : 0),
  ), 0, 100);

  return {
    id: signature,
    source,
    signature,
    event_type: eventType,
    timestamp,
    received_at: receivedAt,
    wallet_address: walletAddress,
    counterparty,
    token_address: tokenAddress,
    symbol,
    amount,
    amount_usd: amountUsd === null ? null : roundMetric(amountUsd),
    direction,
    confidence,
    raw_type: eventType,
  };
}

function primaryTokenTransfer(row: Record<string, any>) {
  const transfers = Array.isArray(row.tokenTransfers)
    ? row.tokenTransfers
    : Array.isArray(row.token_transfers)
      ? row.token_transfers
      : [];
  let best: Record<string, any> | null = null;
  for (const transfer of transfers) {
    if (!transfer || typeof transfer !== "object") continue;
    const record = transfer as Record<string, any>;
    if (!best || (numberLike(record.tokenAmount) ?? 0) > (numberLike(best.tokenAmount) ?? 0)) {
      best = record;
    }
  }
  if (!best) return null;
  return {
    mint: stringField(best, "mint"),
    symbol: stringField(best, "symbol") ?? stringField(best, "tokenSymbol"),
    tokenAmount: numberLike(best.tokenAmount) ?? numberLike(best.amount),
    amountUsd: numberLike(best.amountUsd) ?? numberLike(best.usdAmount),
    fromUserAccount: stringField(best, "fromUserAccount") ?? stringField(best, "fromUserAccountOwner"),
    toUserAccount: stringField(best, "toUserAccount") ?? stringField(best, "toUserAccountOwner"),
  };
}

function normalizeOnchainDirection(
  provided: string | null,
  eventType: string,
  transfer: ReturnType<typeof primaryTokenTransfer>,
): OnchainEventDirection {
  const lower = provided?.toLowerCase();
  if (lower === "buy" || lower === "sell" || lower === "transfer" || lower === "mint") return lower;
  if (eventType.includes("MINT")) return "mint";
  if (eventType.includes("SWAP")) return transfer?.toUserAccount ? "buy" : "transfer";
  if (eventType.includes("TRANSFER")) return "transfer";
  return "unknown";
}

function normalizeEventTimestamp(value: unknown, fallback: string) {
  if (typeof value === "string" && !Number.isNaN(Date.parse(value))) return new Date(value).toISOString();
  if (typeof value === "number" && Number.isFinite(value)) {
    const millis = value > 10_000_000_000 ? value : value * 1_000;
    return new Date(millis).toISOString();
  }
  return fallback;
}

function numberLike(value: unknown): number | null {
  if (typeof value === "number" && Number.isFinite(value)) return value;
  if (typeof value === "string" && value.trim().length > 0) {
    const parsed = Number(value);
    if (Number.isFinite(parsed)) return parsed;
  }
  return null;
}

function eventPayloadHash(value: unknown) {
  return createHash("sha256").update(JSON.stringify(value)).digest("hex").slice(0, 16);
}

function parseLedgerData(value: unknown): LedgerData {
  const data = value && typeof value === "object" ? (value as Partial<LedgerData>) : {};
  return {
    starting_cash_usd: typeof data.starting_cash_usd === "number" ? data.starting_cash_usd : 25_000,
    high_watermark_usd: typeof data.high_watermark_usd === "number" ? data.high_watermark_usd : 25_000,
    positions: Array.isArray(data.positions) ? data.positions.filter(isTradingPosition) : [],
    trades: Array.isArray(data.trades) ? data.trades.filter(isAutonomousTrade) : [],
    trigger_reconciliations: Array.isArray(data.trigger_reconciliations)
      ? data.trigger_reconciliations.filter(isTriggerLedgerReconciliationPatch)
      : [],
    daemon_ticks: Array.isArray(data.daemon_ticks)
      ? data.daemon_ticks.filter(isPaperDaemonMemoryTick)
      : [],
    onchain_events: Array.isArray(data.onchain_events)
      ? data.onchain_events.filter(isOnchainEventLedgerRow)
      : [],
    last_autonomous_session_run: isAutonomousSessionRunReport(data.last_autonomous_session_run)
      ? data.last_autonomous_session_run
      : null,
    last_autonomous_loop_tick: isAutonomousLoopTickReport(data.last_autonomous_loop_tick)
      ? data.last_autonomous_loop_tick
      : null,
    last_autonomous_candle_refresh: isAutonomousCandleRefreshReceipt(data.last_autonomous_candle_refresh)
      ? data.last_autonomous_candle_refresh
      : null,
  };
}

function isAutonomousCandleRefreshReceipt(value: unknown): value is AutonomousCandleRefreshReceipt {
  if (!value || typeof value !== "object") return false;
  const row = value as Partial<AutonomousCandleRefreshReceipt>;
  const statuses: AutonomousCandleRefreshReceipt["status"][] = ["idle", "ready", "fallback", "blocked"];
  const signalActions: AutonomousCandleRefreshReceipt["signal_action"][] = ["press", "probe", "hold", "trim", "exit", "avoid", "none"];
  const paperActions: AutonomousCandleRefreshReceipt["paper_action"][] = ["paper-buy", "paper-sell", "paper-hold", "paper-block", "none"];
  return row.mode === "autonomous-candle-refresh" &&
    typeof row.requested === "boolean" &&
    statuses.includes(row.status as AutonomousCandleRefreshReceipt["status"]) &&
    (row.provider === "geckoterminal" || row.provider === "sample" || row.provider === "unknown") &&
    (row.source === null || typeof row.source === "string") &&
    (row.symbol === null || typeof row.symbol === "string") &&
    (row.pool === null || typeof row.pool === "string") &&
    (row.network === null || typeof row.network === "string") &&
    (row.timeframe === null || row.timeframe === "minute" || row.timeframe === "hour" || row.timeframe === "day") &&
    typeof row.candle_count === "number" &&
    typeof row.last_price_usd === "number" &&
    signalActions.includes(row.signal_action as AutonomousCandleRefreshReceipt["signal_action"]) &&
    paperActions.includes(row.paper_action as AutonomousCandleRefreshReceipt["paper_action"]) &&
    (row.paper_side === "buy" || row.paper_side === "sell" || row.paper_side === "hold") &&
    typeof row.paper_notional_usd === "number" &&
    typeof row.confidence_score === "number" &&
    typeof row.momentum_score === "number" &&
    typeof row.volume_score === "number" &&
    typeof row.risk_score === "number" &&
    typeof row.review_after_seconds === "number" &&
    (row.fetched_at === null || typeof row.fetched_at === "string") &&
    typeof row.summary === "string" &&
    typeof row.next_action === "string" &&
    Array.isArray(row.blockers) &&
    row.blockers.every((item) => typeof item === "string") &&
    Array.isArray(row.controls) &&
    row.controls.every((item) => typeof item === "string");
}

function isAutonomousLoopTickReport(value: unknown): value is AutonomousLoopTickReport {
  if (!value || typeof value !== "object") return false;
  const row = value as Partial<AutonomousLoopTickReport>;
  const statuses: AutonomousLoopTickReport["status"][] = ["idle", "refreshed", "session-run", "stand-down"];
  return row.mode === "autonomous-loop-tick" &&
    typeof row.requested === "boolean" &&
    statuses.includes(row.status as AutonomousLoopTickReport["status"]) &&
    typeof row.action === "string" &&
    typeof row.throttle_status === "string" &&
    (row.target_symbol === null || typeof row.target_symbol === "string") &&
    (row.selected_tactic === null || typeof row.selected_tactic === "string") &&
    typeof row.selected_tactic_label === "string" &&
    typeof row.selected_tactic_status === "string" &&
    typeof row.tactic_confidence_score === "number" &&
    typeof row.tactic_expected_net_usd === "number" &&
    typeof row.tactic_max_trade_usd === "number" &&
    typeof row.tactic_cadence_seconds === "number" &&
    typeof row.route_refreshed === "boolean" &&
    typeof row.session_requested === "boolean" &&
    typeof row.started_cycle === "number" &&
    typeof row.ended_cycle === "number" &&
    typeof row.cycle_delta === "number" &&
    typeof row.started_equity_usd === "number" &&
    typeof row.ended_equity_usd === "number" &&
    typeof row.net_pnl_usd === "number" &&
    typeof row.fill_count === "number" &&
    typeof row.blocked_count === "number" &&
    typeof row.summary === "string" &&
    typeof row.next_action === "string";
}

function isAutonomousSessionRunReport(value: unknown): value is AutonomousSessionRunReport {
  if (!value || typeof value !== "object") return false;
  const row = value as Partial<AutonomousSessionRunReport>;
  const statuses: AutonomousSessionRunReport["status"][] = ["idle", "completed", "partial", "blocked"];
  const policyModes: AutonomousSessionRunReport["policy_mode"][] = ["auto", "manual"];
  return row.mode === "autonomous-session-run" &&
    typeof row.requested === "boolean" &&
    statuses.includes(row.status as AutonomousSessionRunReport["status"]) &&
    policyModes.includes(row.policy_mode as AutonomousSessionRunReport["policy_mode"]) &&
    typeof row.policy_status === "string" &&
    typeof row.policy_label === "string" &&
    typeof row.planner_status === "string" &&
    typeof row.planner_session_kind === "string" &&
    (row.planner_selected_tactic === null || typeof row.planner_selected_tactic === "string") &&
    typeof row.planner_selected_tactic_label === "string" &&
    (row.planner_target_symbol === null || typeof row.planner_target_symbol === "string") &&
    typeof row.planner_deploy_budget_usd === "number" &&
    typeof row.planner_release_budget_usd === "number" &&
    typeof row.planner_route_refresh_required === "boolean" &&
    typeof row.requested_ticks === "number" &&
    typeof row.completed_ticks === "number" &&
    typeof row.max_total_fills === "number" &&
    typeof row.start_equity_usd === "number" &&
    typeof row.end_equity_usd === "number" &&
    typeof row.net_pnl_usd === "number" &&
    typeof row.cash_delta_usd === "number" &&
    typeof row.exposure_delta_usd === "number" &&
    typeof row.fill_count === "number" &&
    typeof row.blocked_count === "number" &&
    typeof row.protective_sell_count === "number" &&
    typeof row.summary === "string" &&
    typeof row.next_action === "string" &&
    Array.isArray(row.safeguards) &&
    row.safeguards.every((item) => typeof item === "string") &&
    Array.isArray(row.ticks) &&
    row.ticks.every(isAutonomousSessionTickReport);
}

function isAutonomousSessionTickReport(value: unknown): value is AutonomousSessionTickReport {
  if (!value || typeof value !== "object") return false;
  const row = value as Partial<AutonomousSessionTickReport>;
  return typeof row.tick === "number" &&
    typeof row.cycle === "number" &&
    typeof row.scenario === "string" &&
    typeof row.daemon_status === "string" &&
    typeof row.daemon_action === "string" &&
    typeof row.mission_status === "string" &&
    typeof row.burst_status === "string" &&
    typeof row.equity_usd === "number" &&
    typeof row.cash_usd === "number" &&
    typeof row.exposure_usd === "number" &&
    typeof row.net_pnl_usd === "number" &&
    typeof row.filled_count === "number" &&
    typeof row.blocked_count === "number" &&
    typeof row.protective_sell_count === "number" &&
    typeof row.next_action === "string";
}

function isOnchainEventLedgerRow(value: unknown): value is OnchainEventLedgerRow {
  if (!value || typeof value !== "object") return false;
  const row = value as Partial<OnchainEventLedgerRow>;
  return typeof row.id === "string" &&
    isOnchainEventSource(row.source) &&
    typeof row.signature === "string" &&
    typeof row.event_type === "string" &&
    typeof row.timestamp === "string" &&
    typeof row.received_at === "string" &&
    typeof row.amount === "number" &&
    (row.amount_usd === null || typeof row.amount_usd === "number") &&
    isOnchainEventDirection(row.direction) &&
    typeof row.confidence === "number";
}

function isOnchainEventSource(value: unknown): value is OnchainEventSource {
  return value === "helius-webhook" || value === "helius-history" || value === "manual";
}

function isOnchainEventDirection(value: unknown): value is OnchainEventDirection {
  return value === "buy" || value === "sell" || value === "transfer" || value === "mint" || value === "unknown";
}

function isTriggerLedgerReconciliationPatch(value: unknown): value is TriggerLedgerReconciliationPatch {
  if (!value || typeof value !== "object") return false;
  const row = value as Partial<TriggerLedgerReconciliationPatch>;
  return typeof row.order_id === "string" &&
    typeof row.applied_at === "string" &&
    typeof row.output_usd === "number" &&
    typeof row.estimated_realized_pnl_usd === "number" &&
    typeof row.filled_quantity === "number";
}

function markPositions(positions: TradingPosition[], market: MemecoinMarket[]) {
  return positions.map((position) => {
    const token = market.find(
      (item) => item.id === position.token_id || item.symbol.toUpperCase() === position.symbol.toUpperCase(),
    );
    const mark = token?.price_usd ?? position.mark_price_usd;
    const peak = Math.max(position.peak_price_usd || position.entry_price_usd, mark);
    const value = position.quantity * mark;
    const cost = position.quantity * position.entry_price_usd;
    return {
      ...position,
      mark_price_usd: mark,
      peak_price_usd: peak,
      trailing_stop_price_usd: trailingStopPrice(peak, position.stop_loss_pct),
      value_usd: value,
      pnl_usd: value - cost,
      pnl_pct: ((mark - position.entry_price_usd) / position.entry_price_usd) * 100,
    };
  });
}

function isTradingPosition(value: unknown): value is TradingPosition {
  if (!value || typeof value !== "object") return false;
  const row = value as Partial<TradingPosition>;
  return typeof row.id === "string" && typeof row.token_id === "string" && typeof row.symbol === "string";
}

function isAutonomousTrade(value: unknown): value is AutonomousTrade {
  if (!value || typeof value !== "object") return false;
  const row = value as Partial<AutonomousTrade>;
  return typeof row.id === "string" && (row.side === "buy" || row.side === "sell") && typeof row.symbol === "string";
}

function buildTradeTape(
  market: MemecoinMarket[],
  signals: TradingSignal[],
  portfolio: TradingPortfolio,
  cycles: number,
  policy: AutonomyPolicy,
  optimizer: ProfitOptimizer,
  priceAction?: PriceActionMonitor,
  launchSniper?: LaunchSniper,
  compounder?: AutonomousCompounder,
  launchGraduation?: LaunchGraduationSupervisor,
  holderFlow?: HolderFlowSentinel,
): AutonomousTrade[] {
  const sells = portfolio.open_positions
    .map((position) => ({ position, signal: signals.find((item) => item.token_id === position.token_id) }))
    .filter(({ position, signal }) => signal?.action === "sell" || position.pnl_pct <= position.stop_loss_pct)
    .map(({ position, signal }, index): AutonomousTrade => ({
      id: `paper-sell-${cycles}-${index}`,
      side: "sell",
      symbol: position.symbol,
      size_usd: Math.round(position.value_usd),
      price_usd: position.mark_price_usd,
      status: "paper-filled",
      reason: signal?.thesis ?? "Stop-loss gate tripped.",
      created_at: shiftedTime(cycles, index),
    }));

  const heldSymbols = new Set(portfolio.open_positions.map((position) => position.symbol));
  const policyByToken = new Map(policy.orders.map((order) => [order.token_id, order]));
  const profitByToken = new Map(optimizer.candidates.map((candidate) => [candidate.token_id, candidate]));
  const priceActionByToken = new Map(priceAction?.items.map((item) => [item.token_id, item]) ?? []);
  const holderFlowByToken = new Map(holderFlow?.items.map((item) => [item.token_id, item]) ?? []);
  const graduationBuys = (launchGraduation?.items ?? [])
    .filter((item) =>
      (item.action === "graduate" || item.action === "snipe" || item.action === "probe") &&
      item.blockers.length === 0 &&
      item.suggested_entry_usd >= 100 &&
      !heldSymbols.has(item.symbol) &&
      !holderFlowBlocksEntry(holderFlowByToken.get(item.token_id))
    )
    .slice(0, 2)
    .map((item, index): AutonomousTrade => {
      const token = market.find((entry) => entry.id === item.token_id);
      heldSymbols.add(item.symbol);
      return {
        id: `paper-graduation-${item.action}-${cycles}-${index}`,
        side: "buy",
        symbol: item.symbol,
        size_usd: Math.min(item.suggested_entry_usd * (holderFlowByToken.get(item.token_id)?.recommended_size_multiplier ?? 1), compounder?.launch_order_cap_usd ?? item.suggested_entry_usd),
        price_usd: token?.price_usd ?? 0,
        status: "paper-filled",
        reason: `Launch graduation ${item.action}: ${item.reason}`,
        created_at: shiftedTime(cycles, index + sells.length),
      };
    });
  const sniperBuys = (launchSniper?.items ?? [])
    .filter((item) =>
      (item.verdict === "snipe" || item.verdict === "probe") &&
      item.blockers.length === 0 &&
      item.suggested_entry_usd >= 100 &&
      !heldSymbols.has(item.symbol) &&
      !holderFlowBlocksEntry(holderFlowByToken.get(item.token_id))
    )
    .slice(0, 2)
    .map((item, index): AutonomousTrade => {
      const token = market.find((entry) => entry.id === item.token_id);
      heldSymbols.add(item.symbol);
      return {
        id: `paper-launch-${item.verdict}-${cycles}-${index}`,
        side: "buy",
        symbol: item.symbol,
        size_usd: Math.min(item.suggested_entry_usd * (holderFlowByToken.get(item.token_id)?.recommended_size_multiplier ?? 1), compounder?.launch_order_cap_usd ?? item.suggested_entry_usd),
        price_usd: token?.price_usd ?? 0,
        status: "paper-filled",
        reason: `${item.verdict === "snipe" ? "Launch sniper snipe" : "Launch sniper probe"}: ${item.reasons[0] ?? item.next_action}`,
        created_at: shiftedTime(cycles, index + sells.length + graduationBuys.length),
      };
    });

  const buys = signals
    .filter((signal) => {
      const order = policyByToken.get(signal.token_id);
      const profit = profitByToken.get(signal.token_id);
      const fastTape = priceActionByToken.get(signal.token_id);
      const holder = holderFlowByToken.get(signal.token_id);
      return signal.action === "buy" &&
        !heldSymbols.has(signal.symbol) &&
        !holderFlowBlocksEntry(holder) &&
        (order?.decision === "press" || order?.decision === "probe") &&
        order.recommended_size_usd >= 100 &&
        (profit?.verdict === "press" || profit?.verdict === "take") &&
        profit.adjusted_size_usd >= 100 &&
        fastTape?.decision !== "avoid" &&
        fastTape?.decision !== "eject" &&
        fastTape?.decision !== "trim";
    })
    .slice(0, Math.max(0, policy.max_new_positions - graduationBuys.length - sniperBuys.length))
    .map((signal, index): AutonomousTrade => {
      const token = market.find((item) => item.id === signal.token_id);
      const order = policyByToken.get(signal.token_id);
      const profit = profitByToken.get(signal.token_id);
      const holder = holderFlowByToken.get(signal.token_id);
      const size = Math.min(
        profit?.adjusted_size_usd ?? order?.recommended_size_usd ?? signal.suggested_size_usd,
        (order?.recommended_size_usd ?? signal.suggested_size_usd) * (holder?.recommended_size_multiplier ?? 1),
        compounder?.next_order_cap_usd ?? Number.POSITIVE_INFINITY,
      );
      return {
        id: `paper-buy-${cycles}-${index}`,
        side: "buy",
        symbol: signal.symbol,
        size_usd: Math.round(size),
        price_usd: token?.price_usd ?? 0,
        status: "paper-filled",
        reason: profit?.reason ?? order?.reason ?? signal.thesis,
        created_at: shiftedTime(cycles, index + sells.length + graduationBuys.length + sniperBuys.length),
      };
    });

  return [...sells, ...graduationBuys, ...sniperBuys, ...buys];
}

function holderFlowBlocksEntry(item: HolderFlowItem | undefined) {
  return item?.action === "block" || item?.action === "exit" || item?.action === "trim";
}

function applyTradeTape(portfolio: TradingPortfolio, trades: AutonomousTrade[]): TradingPortfolio {
  const soldSymbols = new Set(trades.filter((trade) => trade.side === "sell").map((trade) => trade.symbol));
  const buys = trades.filter((trade) => trade.side === "buy");
  const sells = trades.filter((trade) => trade.side === "sell");
  const cashAfterSells = portfolio.cash_usd + sells.reduce((sum, trade) => sum + trade.size_usd, 0);
  const cashAfterBuys = cashAfterSells - buys.reduce((sum, trade) => sum + trade.size_usd, 0);
  const buyPositions: TradingPosition[] = buys.map((trade) => ({
    id: `pos-${trade.symbol.toLowerCase()}`,
    token_id: trade.symbol.toLowerCase(),
    symbol: trade.symbol,
    quantity: trade.price_usd > 0 ? trade.size_usd / trade.price_usd : 0,
    entry_price_usd: trade.price_usd,
    mark_price_usd: trade.price_usd,
    peak_price_usd: trade.price_usd,
    trailing_stop_price_usd: trailingStopPrice(trade.price_usd, -8),
    value_usd: trade.size_usd,
    pnl_usd: 0,
    pnl_pct: 0,
    stop_loss_pct: -8,
    take_profit_pct: 18,
    opened_at: trade.created_at,
  }));
  const open_positions = [
    ...portfolio.open_positions.filter((position) => !soldSymbols.has(position.symbol)),
    ...buyPositions,
  ];
  const exposure = open_positions.reduce((sum, position) => sum + position.value_usd, 0);
  const unrealized = open_positions.reduce((sum, position) => sum + position.pnl_usd, 0);
  return {
    ...portfolio,
    cash_usd: cashAfterBuys,
    exposure_usd: exposure,
    equity_usd: cashAfterBuys + exposure,
    unrealized_pnl_usd: unrealized,
    open_positions,
  };
}

function applyScenario(markets: MemecoinMarket[], scenario: TradingScenario, cycles: number): MemecoinMarket[] {
  return markets.map((market, index) => {
    const cycleLift = cycles * (index % 2 === 0 ? 0.9 : -0.35);
    if (scenario === "breakout" && market.id === "fartcoin-sol") {
      return {
        ...market,
        price_usd: market.price_usd * (1 + (cycles + 1) * 0.025),
        price_change_5m_pct: market.price_change_5m_pct + 3 + cycleLift,
        price_change_1h_pct: market.price_change_1h_pct + 8 + cycles * 1.3,
        buys_5m: market.buys_5m + 110 + cycles * 18,
        volume_5m_usd: market.volume_5m_usd * 1.32,
      };
    }
    if (scenario === "rug-risk" && market.id === "launchx-sol") {
      return {
        ...market,
        price_usd: market.price_usd * 0.58,
        liquidity_usd: 41_000,
        sells_5m: market.sells_5m + 660,
        price_change_5m_pct: -42.5,
        price_change_1h_pct: -58.7,
        risk_flags: [...new Set([...market.risk_flags, "liquidity-pulled", "sell-wall"])],
      };
    }
    return {
      ...market,
      price_usd: market.price_usd * (1 + cycleLift / 100),
      price_change_5m_pct: market.price_change_5m_pct + cycleLift,
    };
  });
}

function executionGate(readiness: ExecutionReadiness): ExecutionGate {
  const readinessBlocker = readiness.checks.find((check) => check.status === "fail");
  return {
    mode: readiness.config.mode,
    live_execution_enabled: false,
    live_blockers: [
      readinessBlocker
        ? `${readinessBlocker.label}: ${readinessBlocker.detail}`
        : "Dry-run preflight passes, but live execution is still disabled.",
      "No wallet signer or temporary session key is connected.",
      "No production Jupiter or Raydium transaction builder is allowed to submit signed payloads.",
      "No persisted operator-approved spend caps exist for real capital.",
      "No tax, compliance, or loss-limit sign-off is recorded.",
    ],
    adapters: [
      {
        name: "DEX Screener",
        status: "researched",
        purpose: "Market discovery and pair telemetry.",
      },
      {
        name: "CoinGecko trending",
        status: "researched",
        purpose: "Attention context and broader coin discovery.",
      },
      {
        name: "Jupiter / Raydium execution",
        status: readiness.config.mode === "dry-run" ? "researched" : "stubbed",
        purpose: "Quote and unsigned order dry-run path before live gates exist.",
      },
      {
        name: "Wallet signer",
        status: "missing-credentials",
        purpose: "Required before any on-chain transaction can move funds.",
      },
    ],
  };
}

function shiftedTime(cycles: number, index: number) {
  return new Date(Date.parse(AS_OF) + (cycles * 10 + index) * 1000).toISOString();
}

async function getDexScreenerDiscovery(fetchImpl: FetchLike): Promise<DexDiscoveryResult> {
  const [topBoosts, latestBoosts, latestProfiles, communityTakeovers, latestAds] = await Promise.all([
    fetchDexDiscoveryEndpoint<DexScreenerBoost>(
      fetchImpl,
      "dex-top-boosts",
      "Top boosts",
      "/token-boosts/top/v1",
      "Most actively boosted tokens.",
    ),
    fetchDexDiscoveryEndpoint<DexScreenerBoost>(
      fetchImpl,
      "dex-latest-boosts",
      "Latest boosts",
      "/token-boosts/latest/v1",
      "Freshly boosted tokens.",
    ),
    fetchDexDiscoveryEndpoint<DexScreenerProfile>(
      fetchImpl,
      "dex-latest-profiles",
      "Latest profiles",
      "/token-profiles/latest/v1",
      "Recently created token profile pages.",
    ),
    fetchDexDiscoveryEndpoint<DexScreenerProfile>(
      fetchImpl,
      "dex-community-takeovers",
      "Community takeovers",
      "/community-takeovers/latest/v1",
      "Latest community takeover candidates.",
    ),
    fetchDexDiscoveryEndpoint<DexScreenerAd>(
      fetchImpl,
      "dex-latest-ads",
      "Latest ads",
      "/ads/latest/v1",
      "Latest paid ad placements.",
    ),
  ]);

  const sourceResults = [topBoosts, latestBoosts, latestProfiles, communityTakeovers, latestAds];
  const candidateMap = new Map<string, DexDiscoveryItem>();

  for (const result of sourceResults) {
    if (result.status !== "ok") continue;
    for (const item of result.items) {
      if (!item.chainId || !item.tokenAddress || !isSupportedChain(item.chainId)) continue;
      const key = `${item.chainId}:${item.tokenAddress.toLowerCase()}`;
      const current = candidateMap.get(key) ?? {
        chainId: item.chainId,
        tokenAddress: item.tokenAddress,
        sources: [],
        amount: 0,
        totalAmount: 0,
        adImpressions: 0,
        paidOrderChecked: false,
        activePaidOrderCount: 0,
        approvedPaidOrderCount: 0,
        paidAdOrderCount: 0,
        paidOrderStatuses: [],
        description: null,
        url: null,
      };
      if (!current.sources.includes(result.id)) current.sources.push(result.id);
      current.amount = Math.max(current.amount, numberOrZero((item as DexScreenerBoost).amount));
      current.totalAmount = Math.max(current.totalAmount, numberOrZero((item as DexScreenerBoost).totalAmount));
      current.adImpressions = Math.max(current.adImpressions, numberOrZero((item as DexScreenerAd).impressions));
      current.description = current.description ?? item.description ?? null;
      current.url = current.url ?? item.url ?? null;
      candidateMap.set(key, current);
    }
  }

  const sources = sourceResults.map(({ id, label, status, items, detail }) => ({
    id,
    label,
    status,
    count: items.length,
    detail,
  }));
  const candidates = [...candidateMap.values()]
    .sort((a, b) => discoveryItemQuality(b) - discoveryItemQuality(a))
    .slice(0, 48);

  if (candidates.length === 0) {
    const failed = sources.find((source) => source.status === "failed");
    throw new Error(failed?.detail ?? "DEX Screener returned no supported discovery candidates.");
  }

  return {
    candidates,
    sources,
    tokensConsidered: candidates.length,
  };
}

async function enrichDexScreenerPaidOrders(
  fetchImpl: FetchLike,
  candidates: DexDiscoveryItem[],
): Promise<DexDiscoveryItem[]> {
  const auditTargets = candidates.slice(0, 12);
  const auditResults: Array<readonly [string, DexPaidOrderAuditResult]> = await Promise.all(
    auditTargets.map(async (candidate) => {
      try {
        const response = await fetchImpl(`${DEX_SCREENER_BASE_URL}/orders/v1/${candidate.chainId}/${candidate.tokenAddress}`, {
          headers: { accept: "application/json" },
        });
        if (!response.ok) {
          return [discoveryItemKey(candidate), { checked: false, orders: [] as DexScreenerPaidOrder[] }] as const;
        }
        const json = await response.json();
        return [discoveryItemKey(candidate), {
          checked: true,
          orders: Array.isArray(json) ? (json as DexScreenerPaidOrder[]) : [],
        }] as const;
      } catch {
        return [discoveryItemKey(candidate), { checked: false, orders: [] as DexScreenerPaidOrder[] }] as const;
      }
    }),
  );
  const auditByKey = new Map(auditResults);

  return candidates.map((candidate) => {
    const audit = auditByKey.get(discoveryItemKey(candidate));
    if (!audit) return candidate;
    const activeOrders = audit.orders.filter((order) => isActivePaidOrder(order.status));
    const approvedOrders = audit.orders.filter((order) => order.status === "approved");
    const paidAdOrders = activeOrders.filter((order) => order.type === "tokenAd" || order.type === "trendingBarAd");
    return {
      ...candidate,
      paidOrderChecked: audit.checked,
      activePaidOrderCount: activeOrders.length,
      approvedPaidOrderCount: approvedOrders.length,
      paidAdOrderCount: paidAdOrders.length,
      paidOrderStatuses: [...new Set(audit.orders.map((order) => `${order.type ?? "unknown"}:${order.status ?? "unknown"}`))],
    };
  });
}

function discoveryItemKey(candidate: Pick<DexDiscoveryItem, "chainId" | "tokenAddress">) {
  return `${candidate.chainId}:${candidate.tokenAddress.toLowerCase()}`;
}

function isActivePaidOrder(status: DexScreenerPaidOrder["status"]) {
  return status === "approved" || status === "processing" || status === "on-hold";
}

async function fetchDexDiscoveryEndpoint<T extends DexScreenerBoost | DexScreenerProfile | DexScreenerAd>(
  fetchImpl: FetchLike,
  id: DiscoverySourceId,
  label: string,
  path: string,
  okDetail: string,
): Promise<{ id: DiscoverySourceId; label: string; status: DiscoverySourceStatus; items: T[]; detail: string }> {
  try {
    const response = await fetchImpl(`${DEX_SCREENER_BASE_URL}${path}`, {
      headers: { accept: "application/json" },
    });
    if (!response.ok) {
      return {
        id,
        label,
        status: "failed",
        items: [],
        detail: `${label} failed with ${response.status}.`,
      };
    }
    const json = await response.json();
    const items = Array.isArray(json) ? (json as T[]) : [];
    return {
      id,
      label,
      status: items.length > 0 ? "ok" : "degraded",
      items,
      detail: items.length > 0 ? okDetail : `${label} returned no items.`,
    };
  } catch (error) {
    return {
      id,
      label,
      status: "failed",
      items: [],
      detail: error instanceof Error ? error.message : `${label} fetch failed.`,
    };
  }
}

function discoveryItemQuality(item: DexDiscoveryItem) {
  const sourceWeight = item.sources.reduce((sum, source) => {
    if (source === "dex-top-boosts") return sum + 5;
    if (source === "dex-latest-boosts") return sum + 4;
    if (source === "dex-community-takeovers") return sum + 4;
    if (source === "dex-latest-profiles") return sum + 2;
    if (source === "dex-latest-ads") return sum + 1;
    return sum + 1;
  }, 0);
  return sourceWeight * 10 + item.amount * 2 + item.totalAmount + Math.min(20, item.adImpressions / 10_000);
}

async function getDexScreenerPairs(
  fetchImpl: FetchLike,
  candidates: DexDiscoveryItem[],
): Promise<DexScreenerPair[]> {
  const byChain = new Map<string, string[]>();
  for (const candidate of candidates) {
    if (!isSupportedChain(candidate.chainId)) continue;
    const current = byChain.get(candidate.chainId) ?? [];
    if (!current.includes(candidate.tokenAddress)) current.push(candidate.tokenAddress);
    byChain.set(candidate.chainId, current);
  }

  const responses = await Promise.all(
    [...byChain.entries()].map(async ([chainId, addresses]) => {
      const tokens = addresses.slice(0, 30).join(",");
      const response = await fetchImpl(`${DEX_SCREENER_BASE_URL}/tokens/v1/${chainId}/${tokens}`, {
        headers: { accept: "application/json" },
      });
      if (!response.ok) {
        throw new Error(`DEX Screener pairs failed with ${response.status}.`);
      }
      const json = await response.json();
      return Array.isArray(json) ? (json as DexScreenerPair[]) : [];
    }),
  );
  return responses.flat();
}

function sampleMarketSource(): Web3TradingState["market_source"] {
  return {
    mode: "sample",
    status: "sample",
    label: "Sample market loop",
    detail: "Deterministic local memecoin tape for offline review and tests.",
    fetched_at: AS_OF,
  };
}

function pairQuality(pair: DexScreenerPair) {
  return numberOrZero(pair.liquidity?.usd) + numberOrZero(pair.volume?.h1) * 0.2 + numberOrZero(pair.volume?.m5);
}

function marketQuality(market: MemecoinMarket) {
  return market.liquidity_usd + market.volume_1h_usd * 0.2 + market.volume_5m_usd + market.boosts * 50_000;
}

function sampleDiscoveryTape(market: MemecoinMarket[]): DiscoveryTape {
  return buildDiscoveryTape("sample", market, [
    {
      id: "sample-seed",
      label: "Sample tape",
      status: "ok",
      count: market.length,
      detail: "Deterministic local candidates for offline review and repeatable tests.",
    },
  ], market.length);
}

function fallbackDiscoveryTape(status: "fallback", detail: string | undefined): DiscoveryTape {
  return {
    status,
    tokens_considered: 0,
    pairs_mapped: 0,
    sources: [
      {
        id: "dex-top-boosts",
        label: "DEX Screener discovery",
        status: "failed",
        count: 0,
        detail: detail ?? "Live discovery was unavailable; sample tape is being used.",
      },
    ],
    top_candidates: [],
  };
}

function buildDiscoveryTape(
  status: DiscoveryTape["status"],
  market: MemecoinMarket[],
  sources: DiscoverySource[],
  tokensConsidered: number,
  candidates: DexDiscoveryItem[] = [],
): DiscoveryTape {
  const candidateByToken = new Map(
    candidates.map((candidate) => [`${candidate.chainId}-${candidate.tokenAddress}`.toLowerCase(), candidate]),
  );
  return {
    status,
    tokens_considered: tokensConsidered,
    pairs_mapped: market.length,
    sources,
    top_candidates: market.slice(0, 8).map((token) => discoveryCandidate(token, candidateByToken.get(token.id))),
  };
}

function discoveryCandidate(token: MemecoinMarket, exactDiscovery?: DexDiscoveryItem): DiscoveryCandidate {
  const volumeToLiquidity = token.volume_1h_usd / Math.max(1, token.liquidity_usd);
  const freshnessScore = clamp(token.age_minutes < 30 ? 100 : token.age_minutes < 120 ? 80 : token.age_minutes < 720 ? 52 : 24, 0, 100);
  const paidOrderCount = exactDiscovery?.activePaidOrderCount ?? token.paid_orders;
  const approvedPaidOrderCount = exactDiscovery?.approvedPaidOrderCount ?? Math.max(0, Math.min(token.paid_orders, token.paid_orders > 0 ? 1 : 0));
  const paidAdOrderCount = exactDiscovery?.paidAdOrderCount ?? (token.risk_flags.includes("paid-promotion-heavy") ? Math.max(1, Math.min(token.paid_orders, 2)) : 0);
  const promotionIntensity = clamp(
    token.boosts * 8 +
      token.paid_orders * 4 +
      approvedPaidOrderCount * 5 +
      paidAdOrderCount * 14 +
      (exactDiscovery?.adImpressions ?? 0) / 12_000,
    0,
    100,
  );
  const scoutScore = clamp(Math.round(
    token.price_change_5m_pct * 0.4 +
      token.price_change_1h_pct * 0.35 +
      volumeToLiquidity * 24 +
      Math.log10(Math.max(token.liquidity_usd, 1)) * 7 +
      promotionIntensity * 0.18 +
      freshnessScore * 0.12 -
      token.risk_flags.length * 8,
  ), 0, 100);
  return {
    token_id: token.id,
    symbol: token.symbol,
    chain: token.chain,
    sources: exactDiscovery?.sources && exactDiscovery.sources.length > 0 ? exactDiscovery.sources : discoverySourcesForMarket(token),
    scout_score: scoutScore,
    liquidity_usd: token.liquidity_usd,
    volume_1h_usd: token.volume_1h_usd,
    age_minutes: token.age_minutes,
    promotion_intensity: promotionIntensity,
    paid_order_checked: exactDiscovery?.paidOrderChecked ?? token.token_address.endsWith("sample"),
    paid_order_count: paidOrderCount,
    approved_paid_order_count: approvedPaidOrderCount,
    paid_ad_order_count: paidAdOrderCount,
    freshness_score: freshnessScore,
    risk_flags: token.risk_flags,
    note: discoveryNote(token, scoutScore),
  };
}

function discoverySourcesForMarket(token: MemecoinMarket): DiscoverySourceId[] {
  if (token.token_address.endsWith("sample")) return ["sample-seed"];
  const sources: DiscoverySourceId[] = [];
  if (token.boosts > 0 || token.paid_orders > 0) sources.push("dex-top-boosts");
  if (token.age_minutes < 240 || token.boosts > 0) sources.push("dex-latest-boosts");
  if (token.risk_flags.includes("community-takeover")) sources.push("dex-community-takeovers");
  if (token.risk_flags.includes("paid-promotion-heavy") || token.paid_orders >= 3) sources.push("dex-latest-ads");
  sources.push("dex-latest-profiles");
  return [...new Set(sources)];
}

function discoveryNote(token: MemecoinMarket, score: number) {
  if (token.risk_flags.includes("thin-liquidity")) return `${token.symbol} has attention, but liquidity is too thin for autonomous entry.`;
  if (token.risk_flags.includes("new-pair")) return `${token.symbol} is fresh; the agent keeps it on scout watch until age/liquidity improve.`;
  if (score >= 70) return `${token.symbol} is a high-priority scout because momentum, flow, and liquidity align.`;
  if (score >= 45) return `${token.symbol} is worth monitoring, but needs stronger continuation before sizing.`;
  return `${token.symbol} is low-priority until momentum or buyer flow improves.`;
}

function buildAutonomousDiscoveryIntake({
  discoveryTape,
  dexStreamFreshness,
  ingestionPlan,
}: {
  discoveryTape: DiscoveryTape;
  dexStreamFreshness: DexStreamFreshness;
  ingestionPlan: MarketIngestionPlan;
}): AutonomousDiscoveryIntake {
  const pairCoverage = discoveryTape.tokens_considered > 0
    ? clamp(Math.round((discoveryTape.pairs_mapped / discoveryTape.tokens_considered) * 100), 0, 100)
    : discoveryTape.status === "sample" ? 100 : 0;
  const streamBonus = dexStreamFreshness.status === "hot"
    ? 10
    : dexStreamFreshness.status === "ready"
      ? 6
      : dexStreamFreshness.status === "backfill" || dexStreamFreshness.status === "watch"
        ? -6
        : dexStreamFreshness.status === "blocked"
          ? -16
          : 0;
  const budgetPenalty = ingestionPlan.provider_budget_status === "throttled"
    ? 14
    : ingestionPlan.provider_budget_status === "paused"
      ? 18
      : 0;
  const items = discoveryTape.top_candidates
    .map((candidate): AutonomousDiscoveryIntakeItem => {
      const sourceCount = candidate.sources.filter((source) => source !== "sample-seed").length || candidate.sources.length;
      const liquidityScore = clamp(Math.round(Math.log10(Math.max(candidate.liquidity_usd, 1)) * 12), 0, 100);
      const volumeScore = clamp(Math.round(Math.log10(Math.max(candidate.volume_1h_usd, 1)) * 10), 0, 100);
      const sourceScore = clamp(sourceCount * 18 + (candidate.paid_order_checked ? 8 : 0), 0, 100);
      const intakeScore = clamp(Math.round(
        candidate.scout_score * 0.32 +
          candidate.freshness_score * 0.18 +
          sourceScore * 0.16 +
          liquidityScore * 0.12 +
          volumeScore * 0.1 +
          (100 - candidate.promotion_intensity) * 0.12 +
          streamBonus -
          budgetPenalty,
      ), 0, 100);
      const blockers = autonomousDiscoveryIntakeBlockers({
        discoveryTape,
        dexStreamFreshness,
        ingestionPlan,
        candidate,
        sourceCount,
        pairCoverage,
        intakeScore,
      });
      const action = autonomousDiscoveryIntakeAction({
        discoveryTape,
        candidate,
        intakeScore,
        blockers,
        ingestionPlan,
      });
      const status: AutonomousDiscoveryIntakeItem["status"] = blockers.length > 0
        ? action === "refresh" ? "refresh" : "blocked"
        : action === "attack" || action === "probe"
          ? "ready"
          : "watch";
      const maxPaperSize = autonomousDiscoveryIntakeSize(action, candidate, intakeScore);

      return {
        token_id: candidate.token_id,
        symbol: candidate.symbol,
        chain: candidate.chain,
        action,
        status,
        intake_score: intakeScore,
        source_count: sourceCount,
        scout_score: candidate.scout_score,
        freshness_score: candidate.freshness_score,
        promotion_intensity: candidate.promotion_intensity,
        paid_order_count: candidate.paid_order_count,
        liquidity_usd: candidate.liquidity_usd,
        volume_1h_usd: candidate.volume_1h_usd,
        max_paper_size_usd: maxPaperSize,
        review_after_seconds: autonomousDiscoveryIntakeReviewSeconds(action, candidate, dexStreamFreshness),
        sources: candidate.sources,
        reason: autonomousDiscoveryIntakeReason(action, candidate.symbol, intakeScore, maxPaperSize, blockers),
        blockers,
      };
    })
    .sort((a, b) =>
      autonomousDiscoveryIntakeActionRank(b.action) - autonomousDiscoveryIntakeActionRank(a.action) ||
      b.intake_score - a.intake_score ||
      b.volume_1h_usd - a.volume_1h_usd,
    )
    .slice(0, 8);

  const hotCount = items.filter((item) => item.action === "attack" && item.status === "ready").length;
  const probeCount = items.filter((item) => item.action === "probe" && item.status === "ready").length;
  const refreshCount = items.filter((item) => item.action === "refresh" || item.status === "refresh").length;
  const blockedCount = items.filter((item) => item.action === "block" || item.status === "blocked").length;
  const paidHypeCount = discoveryTape.top_candidates.filter((item) => item.promotion_intensity >= 58 || item.paid_ad_order_count > 0).length;
  const leader = items.find((item) => item.status === "ready") ?? items[0] ?? null;
  const status: AutonomousDiscoveryIntake["status"] = discoveryTape.status === "sample"
    ? "sample"
    : hotCount > 0
      ? "attack-ready"
      : probeCount > 0
        ? "probe-ready"
        : refreshCount > 0 || discoveryTape.status === "fallback" || ingestionPlan.status === "repair"
          ? "refresh-first"
          : blockedCount > 0
            ? "blocked"
            : "idle";
  const averageScore = items.length > 0 ? Math.round(average(items.map((item) => item.intake_score))) : 0;

  return {
    mode: "autonomous-discovery-intake",
    status,
    source_mode: discoveryTape.status,
    summary: autonomousDiscoveryIntakeSummary(status, hotCount, probeCount, refreshCount, blockedCount, discoveryTape, averageScore),
    next_action: autonomousDiscoveryIntakeNextAction(status, leader, ingestionPlan),
    leader_symbol: leader?.symbol ?? null,
    intake_score: leader?.intake_score ?? averageScore,
    hot_candidate_count: hotCount,
    probe_candidate_count: probeCount,
    refresh_candidate_count: refreshCount,
    blocked_candidate_count: blockedCount,
    mapped_candidate_count: discoveryTape.pairs_mapped,
    paid_hype_count: paidHypeCount,
    source_coverage_pct: dexStreamFreshness.source_coverage_pct,
    pair_coverage_pct: pairCoverage,
    max_paper_size_usd: Math.max(0, ...items.filter((item) => item.status === "ready").map((item) => item.max_paper_size_usd)),
    next_refresh_seconds: Math.max(5, Math.min(
      ingestionPlan.next_provider_refresh_seconds || 30,
      dexStreamFreshness.fastest_stream_seconds || 30,
      leader?.review_after_seconds ?? 30,
    )),
    controls: [
      "Reads DEX Screener profile, boost, community-takeover, ad, paid-order, and token-pair evidence before a candidate can reach the paper trading lanes.",
      "Ranks candidates by source confirmation, freshness, pair mapping, liquidity, volume, paid-hype pressure, and provider budget state.",
      "This intake is read-only and paper-gated; it cannot sign swaps, move wallet funds, bypass provider rate limits, or guarantee profit.",
    ],
    items,
  };
}

function autonomousDiscoveryIntakeBlockers({
  discoveryTape,
  dexStreamFreshness,
  ingestionPlan,
  candidate,
  sourceCount,
  pairCoverage,
  intakeScore,
}: {
  discoveryTape: DiscoveryTape;
  dexStreamFreshness: DexStreamFreshness;
  ingestionPlan: MarketIngestionPlan;
  candidate: DiscoveryCandidate;
  sourceCount: number;
  pairCoverage: number;
  intakeScore: number;
}) {
  const blockers: string[] = [];
  if (discoveryTape.status === "fallback") blockers.push("Live DEX discovery fell back; refresh DEX Screener before paper attack.");
  if (ingestionPlan.status === "blocked" || ingestionPlan.provider_budget_status === "paused") blockers.push(ingestionPlan.summary);
  if (ingestionPlan.provider_budget_status === "throttled") blockers.push("Provider budget is throttled; wait before spending more discovery calls.");
  if (discoveryTape.status === "live" && dexStreamFreshness.status === "blocked") blockers.push(dexStreamFreshness.summary);
  if (discoveryTape.status === "live" && sourceCount < 2) blockers.push("Only one DEX discovery source confirms this candidate.");
  if (discoveryTape.status === "live" && pairCoverage < 45) blockers.push("Too few discovered tokens have mapped pairs.");
  if (candidate.freshness_score < 28) blockers.push("Candidate is stale for a memecoin intake chase.");
  if (candidate.promotion_intensity >= 76 || candidate.paid_ad_order_count > 0 && candidate.promotion_intensity >= 58) blockers.push("Paid-hype pressure is too high for autonomous intake.");
  if (candidate.liquidity_usd < 75_000) blockers.push("Liquidity is too thin for autonomous paper intake.");
  if (candidate.risk_flags.includes("thin-liquidity")) blockers.push("Thin-liquidity risk flag blocks fresh intake.");
  if (intakeScore < 30) blockers.push("Composite discovery intake score is below the minimum floor.");
  return [...new Set(blockers)].slice(0, 5);
}

function autonomousDiscoveryIntakeAction({
  discoveryTape,
  candidate,
  intakeScore,
  blockers,
  ingestionPlan,
}: {
  discoveryTape: DiscoveryTape;
  candidate: DiscoveryCandidate;
  intakeScore: number;
  blockers: string[];
  ingestionPlan: MarketIngestionPlan;
}): AutonomousDiscoveryIntakeAction {
  if (blockers.length > 0) return blockers.some((blocker) => /refresh|source|pair|provider|fallback|budget/i.test(blocker)) ? "refresh" : "block";
  if (ingestionPlan.status === "repair" || ingestionPlan.provider_budget_status === "hot") return "refresh";
  if (discoveryTape.status === "sample") return intakeScore >= 55 ? "probe" : "watch";
  if (intakeScore >= 72 && candidate.freshness_score >= 50 && candidate.promotion_intensity < 58) return "attack";
  if (intakeScore >= 52 && candidate.promotion_intensity < 70) return "probe";
  return "watch";
}

function autonomousDiscoveryIntakeSize(
  action: AutonomousDiscoveryIntakeAction,
  candidate: DiscoveryCandidate,
  intakeScore: number,
) {
  if (action !== "attack" && action !== "probe") return 0;
  const base = action === "attack" ? 360 : 145;
  const scoreBudget = Math.max(0, intakeScore - 45) * (action === "attack" ? 7 : 4);
  const liquidityCap = candidate.liquidity_usd * (action === "attack" ? 0.0025 : 0.0012);
  const volumeCap = candidate.volume_1h_usd * (action === "attack" ? 0.006 : 0.003);
  const hypePenalty = candidate.promotion_intensity >= 55 ? 0.55 : 1;
  return Math.round(clamp(Math.min(base + scoreBudget, liquidityCap, volumeCap) * hypePenalty, 35, action === "attack" ? 900 : 300));
}

function autonomousDiscoveryIntakeReviewSeconds(
  action: AutonomousDiscoveryIntakeAction,
  candidate: DiscoveryCandidate,
  dexStreamFreshness: DexStreamFreshness,
) {
  if (action === "attack") return Math.max(5, Math.min(12, dexStreamFreshness.fastest_stream_seconds || 10));
  if (action === "probe") return Math.max(8, Math.min(20, dexStreamFreshness.fastest_stream_seconds || 16));
  if (action === "refresh") return Math.max(8, Math.min(30, dexStreamFreshness.fastest_stream_seconds || 18));
  if (candidate.freshness_score >= 55) return 30;
  return 45;
}

function autonomousDiscoveryIntakeReason(
  action: AutonomousDiscoveryIntakeAction,
  symbol: string,
  score: number,
  maxPaperSizeUsd: number,
  blockers: string[],
) {
  if (action === "attack") return `${symbol} clears discovery intake at ${score}/100; queue bounded paper attack up to ${formatCompactValue(maxPaperSizeUsd)}.`;
  if (action === "probe") return `${symbol} clears enough discovery evidence for a small paper probe up to ${formatCompactValue(maxPaperSizeUsd)}.`;
  if (action === "refresh") return blockers[0] ?? `Refresh DEX discovery evidence for ${symbol} before paper sizing.`;
  if (action === "block") return blockers[0] ?? `Block ${symbol} from autonomous discovery intake.`;
  return `Watch ${symbol}; discovery evidence is not strong enough to spend paper budget.`;
}

function autonomousDiscoveryIntakeActionRank(action: AutonomousDiscoveryIntakeAction) {
  if (action === "attack") return 5;
  if (action === "probe") return 4;
  if (action === "refresh") return 3;
  if (action === "watch") return 2;
  return 1;
}

function autonomousDiscoveryIntakeSummary(
  status: AutonomousDiscoveryIntake["status"],
  hotCount: number,
  probeCount: number,
  refreshCount: number,
  blockedCount: number,
  discoveryTape: DiscoveryTape,
  averageScore: number,
) {
  if (status === "attack-ready") return `${hotCount} DEX discovery candidate${hotCount === 1 ? "" : "s"} clear source, freshness, pair, hype, and liquidity gates for paper attack.`;
  if (status === "probe-ready") return `${probeCount} DEX discovery candidate${probeCount === 1 ? "" : "s"} can be probed while the agent waits for attack-grade confirmation.`;
  if (status === "refresh-first") return `${refreshCount} discovery lane${refreshCount === 1 ? "" : "s"} need fresher DEX source, pair, paid-order, or budget evidence before intake.`;
  if (status === "blocked") return `${blockedCount} discovery candidate${blockedCount === 1 ? "" : "s"} are blocked by source, pair, hype, liquidity, or provider constraints.`;
  if (status === "sample") return `Sample discovery intake is rehearsing ${discoveryTape.pairs_mapped} mapped candidate${discoveryTape.pairs_mapped === 1 ? "" : "s"} at ${averageScore}/100 average score.`;
  return "Discovery intake is waiting for a candidate with enough source-confirmed edge.";
}

function autonomousDiscoveryIntakeNextAction(
  status: AutonomousDiscoveryIntake["status"],
  leader: AutonomousDiscoveryIntakeItem | null,
  ingestionPlan: MarketIngestionPlan,
) {
  if (!leader) return ingestionPlan.next_action;
  if (status === "attack-ready" || status === "probe-ready") return leader.reason;
  if (status === "refresh-first") return ingestionPlan.next_action;
  if (status === "sample") return "Use sample intake for rehearsal only; switch to Live DEX before treating candidates as current.";
  if (status === "blocked") return leader.blockers[0] ?? "Keep discovery intake blocked until source, pair, hype, or liquidity gates clear.";
  return "Keep monitoring DEX discovery until intake score improves.";
}

function buildAutonomousDataFreshnessGate({
  ingestionPlan,
  dexStreamFreshness,
  discoveryIntake,
  routeRefreshExecution,
  candleConviction,
  orderTicket,
}: {
  ingestionPlan: MarketIngestionPlan;
  dexStreamFreshness: DexStreamFreshness;
  discoveryIntake: AutonomousDiscoveryIntake;
  routeRefreshExecution: AutonomousRouteRefreshExecution;
  candleConviction: AutonomousCandleConviction;
  orderTicket: AutonomousOrderTicket;
}): AutonomousDataFreshnessGate {
  const isBuy = orderTicket.side === "buy";
  const sampleMode = ingestionPlan.status === "sample" || dexStreamFreshness.status === "sample" || discoveryIntake.status === "sample";
  const streamScore = clamp(Math.round(dexStreamFreshness.status === "hot" ? 94 : dexStreamFreshness.status === "ready" ? 82 : dexStreamFreshness.status === "backfill" || dexStreamFreshness.status === "watch" ? 56 : dexStreamFreshness.status === "sample" ? 48 : 24), 0, 100);
  const discoveryScore = clamp(Math.round(discoveryIntake.status === "attack-ready" ? 90 : discoveryIntake.status === "probe-ready" ? 76 : discoveryIntake.status === "refresh-first" ? 52 : discoveryIntake.status === "sample" ? 48 : discoveryIntake.status === "idle" ? 44 : 26), 0, 100);
  const paidLane = ingestionPlan.provider_budget_lanes.find((lane) => lane.id === "dex-paid-orders");
  const paidOrderScore = clamp(Math.round(ingestionPlan.paid_order_check_count === 0 ? 82 : paidLane?.status === "hot" || paidLane?.status === "active" ? 76 - ingestionPlan.paid_order_check_count * 3 : paidLane?.status === "reserved" ? 58 : paidLane?.status === "paused" ? 42 : 30), 0, 100);
  const candleScore = clamp(Math.round(candleConviction.status === "confirm" ? Math.max(72, candleConviction.conviction_score) : candleConviction.status === "probe" ? Math.max(58, candleConviction.conviction_score) : candleConviction.status === "refresh" ? Math.min(54, candleConviction.conviction_score) : candleConviction.status === "protect" || candleConviction.status === "reject" ? Math.min(34, candleConviction.conviction_score) : 44), 0, 100);
  const quoteFresh = routeRefreshExecution.quote_age_seconds !== null &&
    routeRefreshExecution.quote_age_seconds <= Math.max(5, routeRefreshExecution.selected_quote_request?.max_quote_age_seconds ?? 20);
  const quoteScore = clamp(Math.round(!isBuy ? 78 : routeRefreshExecution.status === "ready" && quoteFresh ? Math.max(70, routeRefreshExecution.route_confidence_score) : routeRefreshExecution.status === "requesting" || routeRefreshExecution.can_request_readonly_quote ? 54 : routeRefreshExecution.route_refresh_required ? 36 : routeRefreshExecution.route_confidence_score), 0, 100);
  const budgetScore = clamp(Math.round(ingestionPlan.provider_budget_status === "within-budget" ? 86 : ingestionPlan.provider_budget_status === "hot" ? 68 : ingestionPlan.provider_budget_status === "throttled" ? 34 : 28), 0, 100);
  const dataScore = clamp(Math.round(streamScore * 0.17 + discoveryScore * 0.17 + paidOrderScore * 0.14 + candleScore * 0.2 + quoteScore * 0.2 + budgetScore * 0.12), 0, 100);
  const quoteBlocks = isBuy && (routeRefreshExecution.route_refresh_required || routeRefreshExecution.status === "blocked" || quoteScore < 42);
  const candleBlocks = isBuy && (candleConviction.blocks_fresh_buy || candleConviction.status === "reject" || candleConviction.status === "protect");
  const streamBlocks = isBuy && (dexStreamFreshness.status === "blocked" || ingestionPlan.status === "blocked");
  const budgetBlocks = isBuy && ingestionPlan.provider_budget_status === "throttled" && ingestionPlan.provider_budget_utilization_pct >= 92;
  const refreshLane = autonomousDataFreshnessNextLane({
    ingestionPlan,
    dexStreamFreshness,
    discoveryIntake,
    routeRefreshExecution,
    candleConviction,
    quoteScore,
    candleScore,
    paidOrderScore,
  });
  const status: AutonomousDataFreshnessGate["status"] = sampleMode
    ? "sample"
    : streamBlocks || quoteBlocks || candleBlocks || budgetBlocks
      ? "blocked"
      : routeRefreshExecution.route_refresh_required || quoteScore < 58 || candleConviction.refresh_required
        ? "refresh"
        : dexStreamFreshness.status === "backfill" || discoveryIntake.status === "refresh-first" || ingestionPlan.status === "repair"
          ? "backfill"
          : dataScore >= 72
            ? "clear"
            : "tradeable";
  const action: AutonomousDataFreshnessGate["action"] = status === "clear"
    ? "allow-paper"
    : status === "tradeable"
      ? "size-down"
      : refreshLane === "gecko-ohlcv"
        ? "fetch-candles"
        : refreshLane === "jupiter-quote"
          ? "refresh-quote"
          : status === "backfill" || refreshLane === "dex-rest" || refreshLane === "dex-stream"
            ? "refresh-stream"
            : status === "blocked"
              ? "stand-down"
              : "size-down";
  const sizeMultiplier = autonomousDataFreshnessSizeMultiplier(status, dataScore, isBuy);
  const maxNextFills = autonomousDataFreshnessMaxFills(status, dataScore, isBuy);
  const maxStalenessSeconds = Math.max(dexStreamFreshness.fastest_stream_seconds, ingestionPlan.next_provider_refresh_seconds, routeRefreshExecution.quote_age_seconds ?? 0, candleConviction.review_after_seconds);
  const items: AutonomousDataFreshnessGateItem[] = [
    {
      id: "stream",
      label: "DEX stream",
      status: streamScore >= 70 ? "pass" : streamScore >= 45 ? "watch" : "fail",
      score: streamScore,
      value: dexStreamFreshness.websocket_ready ? "websocket" : dexStreamFreshness.status,
      detail: `${dexStreamFreshness.stream_count} stream lanes, ${dexStreamFreshness.rest_fallback_count} REST fallbacks, ${dexStreamFreshness.fresh_candidate_count} fresh candidates.`,
    },
    {
      id: "discovery",
      label: "Discovery map",
      status: discoveryScore >= 70 ? "pass" : discoveryScore >= 45 ? "watch" : "fail",
      score: discoveryScore,
      value: discoveryIntake.leader_symbol ?? "desk",
      detail: `${discoveryIntake.source_coverage_pct}% source coverage, ${discoveryIntake.pair_coverage_pct}% pair coverage, ${discoveryIntake.hot_candidate_count} attack-ready.`,
    },
    {
      id: "paid-orders",
      label: "Paid orders",
      status: paidOrderScore >= 70 ? "pass" : paidOrderScore >= 45 ? "watch" : "fail",
      score: paidOrderScore,
      value: `${ingestionPlan.paid_order_check_count} checks`,
      detail: `${paidLane?.provider ?? "DEX Screener"} ${paidLane?.status ?? "paused"}; boosted or ad-heavy candidates stay behind this lane.`,
    },
    {
      id: "ohlcv",
      label: "OHLCV/candles",
      status: candleScore >= 70 ? "pass" : candleScore >= 45 ? "watch" : "fail",
      score: candleScore,
      value: candleConviction.status,
      detail: `${candleConviction.target_symbol ?? "desk"} chart score ${candleConviction.chart_score}/100; refresh ${candleConviction.refresh_required ? "required" : "clear"}.`,
    },
    {
      id: "quote",
      label: "Route quote",
      status: quoteScore >= 70 ? "pass" : quoteScore >= 45 ? "watch" : "fail",
      score: quoteScore,
      value: routeRefreshExecution.quote_age_seconds === null ? "missing" : `${routeRefreshExecution.quote_age_seconds}s`,
      detail: `${routeRefreshExecution.route_confidence_score}/100 route confidence; ${routeRefreshExecution.can_request_readonly_quote ? "read-only quote can refresh" : routeRefreshExecution.status}.`,
    },
    {
      id: "budget",
      label: "Provider budget",
      status: budgetScore >= 70 ? "pass" : budgetScore >= 45 ? "watch" : "fail",
      score: budgetScore,
      value: `${ingestionPlan.provider_budget_utilization_pct}%`,
      detail: `${ingestionPlan.provider_budget_status.replace("-", " ")} across ${ingestionPlan.provider_budget_lanes.length} provider lanes; next refresh in ${ingestionPlan.next_provider_refresh_seconds}s.`,
    },
  ];

  return {
    mode: "autonomous-data-freshness-gate",
    status,
    action,
    can_trade: !isBuy || status === "clear" || status === "tradeable",
    data_score: dataScore,
    next_refresh_lane: refreshLane,
    max_staleness_seconds: maxStalenessSeconds,
    size_multiplier: sizeMultiplier,
    max_next_fills: maxNextFills,
    summary: autonomousDataFreshnessSummary(status, dataScore, refreshLane, orderTicket.symbol),
    next_action: autonomousDataFreshnessNextAction(status, action, refreshLane, orderTicket.symbol, maxNextFills, sizeMultiplier),
    controls: [
      "Requires provider-aware freshness across DEX Screener stream/REST discovery, paid-order context, GeckoTerminal-style OHLCV, and Jupiter-style read-only route quotes before fresh paper buys.",
      "Protective paper sells can bypass fresh-buy data blocks, but fresh simulated buys are capped by this gate before burst child fills are created.",
      "This is local/read-only data discipline only; it does not open durable sockets, bypass provider limits, sign swaps, submit transactions, move funds, or guarantee profit.",
    ],
    items,
  };
}

function autonomousDataFreshnessNextLane({
  ingestionPlan,
  dexStreamFreshness,
  discoveryIntake,
  routeRefreshExecution,
  candleConviction,
  quoteScore,
  candleScore,
  paidOrderScore,
}: {
  ingestionPlan: MarketIngestionPlan;
  dexStreamFreshness: DexStreamFreshness;
  discoveryIntake: AutonomousDiscoveryIntake;
  routeRefreshExecution: AutonomousRouteRefreshExecution;
  candleConviction: AutonomousCandleConviction;
  quoteScore: number;
  candleScore: number;
  paidOrderScore: number;
}): AutonomousDataFreshnessGate["next_refresh_lane"] {
  if (routeRefreshExecution.route_refresh_required || quoteScore < 58) return "jupiter-quote";
  if (candleConviction.refresh_required || candleScore < 50) return "gecko-ohlcv";
  if (paidOrderScore < 50 || ingestionPlan.paid_order_check_count > 0) return "paid-orders";
  if (dexStreamFreshness.status === "backfill" || discoveryIntake.status === "refresh-first" || ingestionPlan.status === "repair") return "dex-rest";
  if (!dexStreamFreshness.websocket_ready && dexStreamFreshness.status !== "sample") return "dex-stream";
  return "none";
}

function autonomousDataFreshnessSizeMultiplier(status: AutonomousDataFreshnessGate["status"], score: number, isBuy: boolean) {
  if (!isBuy) return 0.75;
  if (status === "clear") return roundMetric(clamp(0.82 + score / 520, 0.9, 1.08));
  if (status === "tradeable") return roundMetric(clamp(0.36 + score / 250, 0.45, 0.7));
  if (status === "sample") return 0.35;
  return 0;
}

function autonomousDataFreshnessMaxFills(status: AutonomousDataFreshnessGate["status"], score: number, isBuy: boolean) {
  if (!isBuy) return 2;
  if (status === "clear") return Math.max(1, Math.min(6, Math.round(score / 18)));
  if (status === "tradeable" || status === "sample") return 1;
  return 0;
}

function autonomousDataFreshnessSummary(
  status: AutonomousDataFreshnessGate["status"],
  score: number,
  lane: AutonomousDataFreshnessGate["next_refresh_lane"],
  symbol: string | null,
) {
  const target = symbol ?? "the leading setup";
  if (status === "clear") return `Data freshness gate clears ${target}: ${score}/100 across stream, paid-order, candle, quote, and budget proof.`;
  if (status === "tradeable") return `Data freshness gate allows only reduced paper size on ${target}: ${score}/100 evidence needs tighter confirmation.`;
  if (status === "refresh") return `Data freshness gate wants ${lane.replace("-", " ")} refreshed before fresh paper size on ${target}.`;
  if (status === "backfill") return `Data freshness gate needs DEX backfill before trusting ${target} for more than a probe.`;
  if (status === "blocked") return `Data freshness gate blocks fresh buys on ${target}; refresh ${lane.replace("-", " ")} first.`;
  return `Data freshness gate is in sample mode for ${target}; paper size remains intentionally tiny.`;
}

function autonomousDataFreshnessNextAction(
  status: AutonomousDataFreshnessGate["status"],
  action: AutonomousDataFreshnessGate["action"],
  lane: AutonomousDataFreshnessGate["next_refresh_lane"],
  symbol: string | null,
  maxFills: number,
  multiplier: number,
) {
  const target = symbol ?? "the leader";
  if (status === "clear") return `Allow up to ${maxFills} data-cleared child fill${maxFills === 1 ? "" : "s"} on ${target} at ${multiplier}x size.`;
  if (status === "tradeable") return `Use one reduced paper probe on ${target}, then refresh ${lane === "none" ? "provider evidence" : lane.replace("-", " ")}.`;
  if (action === "fetch-candles") return `Fetch read-only OHLCV candles for ${target} before another fresh buy.`;
  if (action === "refresh-quote") return `Refresh the read-only Jupiter-style route quote for ${target} before sizing.`;
  if (action === "refresh-stream") return "Backfill DEX discovery/pair context and paid-order evidence before sizing.";
  if (status === "sample") return "Keep sample-mode paper size tiny and do not infer live freshness from seeded tape.";
  return "Stand down from fresh buys until the data contract is repaired.";
}

function buildAutonomousMarketEvidenceFusion({
  market,
  marketIntelligence,
  watchlistRotation,
  alphaConviction,
  dataFreshnessGate,
  candleConviction,
  routeRefreshExecution,
  walletTelemetry,
  trapRadar,
}: {
  market: MemecoinMarket[];
  marketIntelligence: AutonomousMarketIntelligence;
  watchlistRotation: AutonomousWatchlistRotation;
  alphaConviction: AutonomousAlphaConviction;
  dataFreshnessGate: AutonomousDataFreshnessGate;
  candleConviction: AutonomousCandleConviction;
  routeRefreshExecution: AutonomousRouteRefreshExecution;
  walletTelemetry: AutonomousWalletTelemetry;
  trapRadar: AutonomousTrapRadar;
}): AutonomousMarketEvidenceFusion {
  const intelligenceByToken = new Map(marketIntelligence.items.map((item) => [item.token_id, item]));
  const rotationByToken = new Map(watchlistRotation.items.map((item) => [item.token_id, item]));
  const alphaByToken = new Map(alphaConviction.items.map((item) => [item.token_id, item]));
  const trapByToken = new Map(trapRadar.items.map((item) => [item.token_id, item]));
  const marketByToken = new Map(market.map((item) => [item.id, item]));
  const candidateIds = [...new Set([
    ...marketIntelligence.items.map((item) => item.token_id),
    ...watchlistRotation.items.map((item) => item.token_id),
    ...alphaConviction.items.map((item) => item.token_id),
    ...trapRadar.items.map((item) => item.token_id),
    ...market.slice(0, 6).map((item) => item.id),
  ])].slice(0, 10);
  const walletFit = clamp(Math.round(
    78 -
      walletTelemetry.max_drawdown_pct * 7 -
      Math.max(0, walletTelemetry.exposure_pct - 58) * 1.2 +
      (walletTelemetry.window_pnl_usd > 0 ? 8 : walletTelemetry.window_pnl_usd < 0 ? -10 : 0) -
      Math.max(0, walletTelemetry.open_position_count - 5) * 4,
  ), 0, 100);
  const dataScore = dataFreshnessGate.data_score;
  const globalRouteScore = routeRefreshExecution.route_confidence_score;
  const globalChartScore = candleConviction.conviction_score;
  const quoteRefreshNeeded = dataFreshnessGate.next_refresh_lane === "jupiter-quote" ||
    routeRefreshExecution.route_refresh_required ||
    routeRefreshExecution.status === "blocked";
  const candleRefreshNeeded = dataFreshnessGate.next_refresh_lane === "gecko-ohlcv" ||
    candleConviction.refresh_required ||
    candleConviction.status === "refresh";

  const items = candidateIds.map((tokenId): AutonomousMarketEvidenceFusionItem => {
    const token = marketByToken.get(tokenId);
    const intelligence = intelligenceByToken.get(tokenId);
    const rotation = rotationByToken.get(tokenId);
    const alpha = alphaByToken.get(tokenId);
    const trap = trapByToken.get(tokenId);
    const symbol = intelligence?.symbol ?? rotation?.symbol ?? alpha?.symbol ?? trap?.symbol ?? token?.symbol ?? tokenId;
    const chartScore = clamp(Math.round(
      (intelligence?.chart_score ?? globalChartScore) * 0.5 +
        (alpha?.velocity_score ?? token ? clamp(Math.round((token?.price_change_5m_pct ?? 0) * 4 + 50), 0, 100) : globalChartScore) * 0.22 +
        (alpha?.pulse_score ?? intelligence?.signal_score ?? 50) * 0.28,
    ), 0, 100);
    const routeScore = clamp(Math.round(
      (intelligence?.route_score ?? globalRouteScore) * 0.55 +
        (alpha?.route_score ?? globalRouteScore) * 0.25 +
        (rotation?.route_refresh_required ? 24 : globalRouteScore) * 0.2,
    ), 0, 100);
    const organicMomentumScore = clamp(Math.round(
      (trap?.organic_score ?? alpha?.signal_score ?? intelligence?.signal_score ?? 45) * 0.28 +
        (trap?.chase_score ?? intelligence?.confidence_score ?? alpha?.conviction_score ?? 45) * 0.24 +
        chartScore * 0.22 +
        Math.min(100, (intelligence?.signal_to_noise_ratio ?? alpha?.signal_to_noise_ratio ?? 1) * 48) * 0.18 +
        Math.min(100, (intelligence?.source_count ?? 1) * 18) * 0.08,
    ), 0, 100);
    const promotionNoiseScore = clamp(Math.round(
      (trap?.paid_hype_score ?? 0) * 0.34 +
        (trap?.trap_score ?? 0) * 0.28 +
        Math.max(0, 100 - (trap?.organic_score ?? 64)) * 0.18 +
        Math.max(0, 55 - routeScore) * 0.12 +
        Math.max(0, (token?.risk_flags.length ?? 0) * 8),
    ), 0, 100);
    const localDataScore = clamp(Math.round(
      dataScore * 0.45 +
        routeScore * 0.2 +
        chartScore * 0.2 +
        (rotation?.pair_refresh_required ? 42 : 74) * 0.15,
    ), 0, 100);
    const fusionScore = clamp(Math.round(
      organicMomentumScore * 0.28 +
        chartScore * 0.17 +
        routeScore * 0.16 +
        localDataScore * 0.17 +
        walletFit * 0.12 +
        Math.min(100, Math.max(intelligence?.expected_edge_usd ?? 0, alpha?.expected_edge_usd ?? 0) * 5) * 0.1 -
        promotionNoiseScore * 0.2,
    ), 0, 100);
    const blockers = [
      ...(intelligence?.blockers ?? []),
      ...(rotation?.blockers ?? []),
      ...(alpha?.blockers ?? []),
      ...(trap?.blockers ?? []),
    ];
    if (!dataFreshnessGate.can_trade) blockers.push(`Data freshness gate is ${dataFreshnessGate.status}.`);
    if (quoteRefreshNeeded && routeScore < 62) blockers.push("Route quote needs read-only refresh.");
    if (candleRefreshNeeded && chartScore < 64) blockers.push("OHLCV candle proof needs refresh.");
    if (promotionNoiseScore >= 70) blockers.push("Promotion or trap noise is too high for fresh size.");
    if (walletFit < 42) blockers.push(`Wallet fit is ${walletFit}/100; protect equity first.`);
    const uniqueBlockers = [...new Set(blockers)].slice(0, 5);
    const action = marketEvidenceFusionAction({
      fusionScore,
      organicMomentumScore,
      promotionNoiseScore,
      routeScore,
      chartScore,
      dataFreshnessGate,
      quoteRefreshNeeded,
      candleRefreshNeeded,
      walletFit,
      alpha,
      trap,
      blockers: uniqueBlockers,
    });
    const maxPaperSize = marketEvidenceFusionMaxPaperSize({
      action,
      dataFreshnessGate,
      alpha,
      intelligence,
      trap,
      walletFit,
      fusionScore,
    });
    const reviewAfterSeconds = Math.max(1, Math.min(
      rotation?.refresh_after_seconds ?? 30,
      alpha?.review_after_seconds ?? 30,
      intelligence?.chase_window_seconds ?? 30,
      trap?.review_after_seconds ?? 30,
      dataFreshnessGate.max_staleness_seconds,
    ));

    return {
      token_id: tokenId,
      symbol,
      action,
      lane: marketEvidenceFusionLane(action),
      fusion_score: fusionScore,
      organic_momentum_score: organicMomentumScore,
      promotion_noise_score: promotionNoiseScore,
      chart_score: chartScore,
      route_score: routeScore,
      data_score: localDataScore,
      wallet_fit_score: walletFit,
      expected_edge_usd: roundMetric(Math.max(intelligence?.expected_edge_usd ?? 0, alpha?.expected_edge_usd ?? 0)),
      max_paper_size_usd: maxPaperSize,
      review_after_seconds: reviewAfterSeconds,
      reason: marketEvidenceFusionReason(action, symbol, fusionScore, promotionNoiseScore, dataFreshnessGate),
      evidence: [
        `${organicMomentumScore}/100 organic momentum`,
        `${promotionNoiseScore}/100 promo noise`,
        `${chartScore}/100 candle proof`,
        `${routeScore}/100 route proof`,
        `${localDataScore}/100 data contract`,
        `${walletFit}/100 wallet fit`,
      ],
      blockers: uniqueBlockers,
    };
  }).sort((a, b) => marketEvidenceFusionActionRank(b.action) - marketEvidenceFusionActionRank(a.action) || b.fusion_score - a.fusion_score).slice(0, 8);
  const leader = items[0] ?? null;
  const tradeCount = items.filter((item) => item.action === "trade").length;
  const probeCount = items.filter((item) => item.action === "probe").length;
  const refreshCount = items.filter((item) => item.action === "refresh-route" || item.action === "refresh-candles").length;
  const protectCount = items.filter((item) => item.action === "protect").length;
  const blockedCount = items.filter((item) => item.action === "reject").length;
  const status: AutonomousMarketEvidenceFusion["status"] = dataFreshnessGate.status === "sample"
    ? "sample"
    : !leader
      ? "idle"
      : protectCount > 0 && leader.action === "protect"
        ? "protect"
        : tradeCount > 0 && leader.action === "trade"
          ? "attack"
          : probeCount > 0 && leader.action === "probe"
            ? "selective"
            : refreshCount > 0 && (leader.action === "refresh-route" || leader.action === "refresh-candles")
              ? "refresh"
              : blockedCount === items.length
                ? "blocked"
                : "watch";
  const canTrade = Boolean(leader && (leader.action === "trade" || leader.action === "probe") && dataFreshnessGate.can_trade && leader.blockers.length === 0);
  const maxNextFills = canTrade ? Math.min(dataFreshnessGate.max_next_fills, status === "attack" ? 3 : 1) : 0;

  return {
    mode: "autonomous-market-evidence-fusion",
    status,
    leader_symbol: leader?.symbol ?? null,
    leader_action: leader?.action ?? null,
    fusion_score: Math.round(average(items.map((item) => item.fusion_score))),
    organic_momentum_score: Math.round(average(items.map((item) => item.organic_momentum_score))),
    promotion_noise_score: Math.round(average(items.map((item) => item.promotion_noise_score))),
    data_score: Math.round(average(items.map((item) => item.data_score))),
    route_score: Math.round(average(items.map((item) => item.route_score))),
    chart_score: Math.round(average(items.map((item) => item.chart_score))),
    wallet_fit_score: walletFit,
    can_trade: canTrade,
    expected_edge_usd: roundMetric(items.reduce((sum, item) => sum + (item.action === "trade" || item.action === "probe" ? item.expected_edge_usd : 0), 0)),
    max_paper_size_usd: Math.max(0, ...items.map((item) => item.max_paper_size_usd)),
    max_next_fills: maxNextFills,
    fastest_review_seconds: items.length > 0 ? Math.min(...items.map((item) => item.review_after_seconds)) : 30,
    next_refresh_lane: dataFreshnessGate.next_refresh_lane,
    provider_lane: marketEvidenceFusionProviderLane(status, leader, dataFreshnessGate),
    summary: marketEvidenceFusionSummary(status, leader, dataFreshnessGate),
    next_action: marketEvidenceFusionNextAction(status, leader, canTrade, maxNextFills),
    controls: [
      "Fuses hot-coin tape, organic momentum, promotion/trap noise, OHLCV candle proof, Jupiter-style route proof, provider freshness, and wallet fit into one action board.",
      "Prioritizes refresh-route and refresh-candles ahead of fresh paper buys when provider proof is weaker than price action.",
      "This is a paper/read-only evidence layer; it cannot guarantee profit, keep running after the app stops, sign swaps, submit transactions, or move funds.",
    ],
    items,
  };
}

function marketEvidenceFusionAction({
  fusionScore,
  organicMomentumScore,
  promotionNoiseScore,
  routeScore,
  chartScore,
  dataFreshnessGate,
  quoteRefreshNeeded,
  candleRefreshNeeded,
  walletFit,
  alpha,
  trap,
  blockers,
}: {
  fusionScore: number;
  organicMomentumScore: number;
  promotionNoiseScore: number;
  routeScore: number;
  chartScore: number;
  dataFreshnessGate: AutonomousDataFreshnessGate;
  quoteRefreshNeeded: boolean;
  candleRefreshNeeded: boolean;
  walletFit: number;
  alpha?: AutonomousAlphaConvictionItem;
  trap?: AutonomousTrapRadarItem;
  blockers: string[];
}): AutonomousMarketEvidenceFusionAction {
  if (trap?.verdict === "exit-only" || alpha?.action === "protect" || alpha?.action === "trim" || walletFit < 32) return "protect";
  if (promotionNoiseScore >= 82 || blockers.length >= 5 || dataFreshnessGate.status === "blocked") return "reject";
  if (quoteRefreshNeeded && routeScore < 64) return "refresh-route";
  if (candleRefreshNeeded && chartScore < 66) return "refresh-candles";
  if (!dataFreshnessGate.can_trade) return dataFreshnessGate.next_refresh_lane === "gecko-ohlcv" ? "refresh-candles" : dataFreshnessGate.next_refresh_lane === "jupiter-quote" ? "refresh-route" : "watch";
  if (fusionScore >= 72 && organicMomentumScore >= 66 && promotionNoiseScore < 58 && routeScore >= 58 && chartScore >= 58) return "trade";
  if (fusionScore >= 55 && promotionNoiseScore < 70 && routeScore >= 46 && chartScore >= 48) return "probe";
  return "watch";
}

function marketEvidenceFusionLane(action: AutonomousMarketEvidenceFusionAction): AutonomousMarketEvidenceFusionItem["lane"] {
  if (action === "trade" || action === "probe") return "hot-tape";
  if (action === "refresh-route") return "route";
  if (action === "refresh-candles") return "chart";
  if (action === "protect") return "protection";
  return "watch";
}

function marketEvidenceFusionActionRank(action: AutonomousMarketEvidenceFusionAction) {
  if (action === "protect") return 7;
  if (action === "trade") return 6;
  if (action === "probe") return 5;
  if (action === "refresh-route") return 4;
  if (action === "refresh-candles") return 3;
  if (action === "watch") return 2;
  return 1;
}

function marketEvidenceFusionMaxPaperSize({
  action,
  dataFreshnessGate,
  alpha,
  intelligence,
  trap,
  walletFit,
  fusionScore,
}: {
  action: AutonomousMarketEvidenceFusionAction;
  dataFreshnessGate: AutonomousDataFreshnessGate;
  alpha?: AutonomousAlphaConvictionItem;
  intelligence?: AutonomousMarketIntelligenceItem;
  trap?: AutonomousTrapRadarItem;
  walletFit: number;
  fusionScore: number;
}) {
  if (action !== "trade" && action !== "probe") return 0;
  const rawCap = Math.max(alpha?.max_size_usd ?? 0, intelligence ? intelligence.expected_edge_usd * 12 : 0, trap?.max_chase_usd ?? 0, 25);
  const actionMultiplier = action === "trade" ? 1 : 0.42;
  const walletMultiplier = clamp(walletFit / 82, 0.25, 1);
  return Math.round(rawCap * actionMultiplier * walletMultiplier * dataFreshnessGate.size_multiplier * clamp(fusionScore / 74, 0.55, 1.15));
}

function marketEvidenceFusionProviderLane(
  status: AutonomousMarketEvidenceFusion["status"],
  leader: AutonomousMarketEvidenceFusionItem | null,
  dataFreshnessGate: AutonomousDataFreshnessGate,
): AutonomousMarketEvidenceFusion["provider_lane"] {
  if (status === "protect") return "wallet-protect";
  if (dataFreshnessGate.next_refresh_lane !== "none") return dataFreshnessGate.next_refresh_lane;
  if (leader?.action === "refresh-route") return "jupiter-quote";
  if (leader?.action === "refresh-candles") return "gecko-ohlcv";
  if (leader?.action === "trade" || leader?.action === "probe") return "dex-stream";
  return "none";
}

function marketEvidenceFusionReason(
  action: AutonomousMarketEvidenceFusionAction,
  symbol: string,
  fusionScore: number,
  promotionNoiseScore: number,
  dataFreshnessGate: AutonomousDataFreshnessGate,
) {
  if (action === "trade") return `${symbol} has the cleanest fused paper-trade evidence at ${fusionScore}/100 with promo noise held to ${promotionNoiseScore}/100.`;
  if (action === "probe") return `${symbol} has enough fused evidence for a reduced paper probe, but not a full press.`;
  if (action === "refresh-route") return `${symbol} needs a fresh read-only route quote before sizing.`;
  if (action === "refresh-candles") return `${symbol} needs fresh OHLCV candle proof before sizing.`;
  if (action === "protect") return `${symbol} is protection-first while wallet, held-position, or trap risk outranks new exposure.`;
  if (action === "reject") return `${symbol} is rejected by promotion, trap, provider, or blocker pressure.`;
  return `${symbol} stays on watch until fused evidence clears ${dataFreshnessGate.status} data discipline.`;
}

function marketEvidenceFusionSummary(
  status: AutonomousMarketEvidenceFusion["status"],
  leader: AutonomousMarketEvidenceFusionItem | null,
  dataFreshnessGate: AutonomousDataFreshnessGate,
) {
  if (!leader) return "Market evidence fusion is waiting for a candidate.";
  if (status === "attack") return `Market evidence fusion is attack-ready on ${leader.symbol}: ${leader.fusion_score}/100 fused evidence and ${formatCompactValue(leader.max_paper_size_usd)} max paper size.`;
  if (status === "selective") return `Market evidence fusion allows only a reduced probe on ${leader.symbol}; data gate is ${dataFreshnessGate.status}.`;
  if (status === "refresh") return `Market evidence fusion wants ${leader.action.replace("-", " ")} for ${leader.symbol} before fresh size.`;
  if (status === "protect") return `Market evidence fusion is protect-first; ${leader.symbol} leads the risk/protection queue.`;
  if (status === "blocked") return "Market evidence fusion rejects the tape because blockers or promotion noise outrank edge.";
  if (status === "sample") return `Market evidence fusion is rehearsing ${leader.symbol} in sample mode only.`;
  return `Market evidence fusion watches ${leader.symbol} until organic momentum, route, chart, and provider proof align.`;
}

function marketEvidenceFusionNextAction(
  status: AutonomousMarketEvidenceFusion["status"],
  leader: AutonomousMarketEvidenceFusionItem | null,
  canTrade: boolean,
  maxNextFills: number,
) {
  if (!leader) return "Wait for a fused market candidate.";
  if (canTrade) return `Allow up to ${maxNextFills} fused paper fill${maxNextFills === 1 ? "" : "s"} on ${leader.symbol}; review again in ${leader.review_after_seconds}s.`;
  if (status === "refresh") return leader.reason;
  if (status === "protect") return `Run protection or harvest work before adding exposure to ${leader.symbol}.`;
  if (status === "blocked") return leader.blockers[0] ?? "Stand down until fusion blockers clear.";
  if (status === "sample") return "Keep this as sample rehearsal; switch to Live DEX before trusting the tape.";
  return `Watch ${leader.symbol}; refresh the weakest evidence lane before sizing.`;
}

function buildAutonomousSignalNoiseTradeDecision({
  marketEvidenceFusion,
  dataFreshnessGate,
  walletTelemetry,
  profitRunGuard,
  dailyProfitLock,
  replayGate,
  loopFeedback,
}: {
  marketEvidenceFusion: AutonomousMarketEvidenceFusion;
  dataFreshnessGate: AutonomousDataFreshnessGate;
  walletTelemetry: AutonomousWalletTelemetry;
  profitRunGuard: AutonomousProfitRunGuard;
  dailyProfitLock: AutonomousDailyProfitLock;
  replayGate: AutonomousReplayGate;
  loopFeedback: AutonomousLoopFeedback;
}): AutonomousSignalNoiseTradeDecision {
  const leader = marketEvidenceFusion.items[0] ?? null;
  if (!leader) {
    return {
      mode: "autonomous-signal-noise-trade-decision",
      status: "idle",
      action: "watch",
      symbol: null,
      token_id: null,
      signal_score: 0,
      noise_score: 0,
      signal_to_noise_ratio: 0,
      route_score: 0,
      chart_score: 0,
      wallet_fit_score: walletTelemetry.equity_usd > 0 ? clamp(Math.round(100 - walletTelemetry.max_drawdown_pct * 8), 0, 100) : 0,
      data_score: dataFreshnessGate.data_score,
      decision_score: 0,
      expected_edge_usd: 0,
      recommended_size_usd: 0,
      size_multiplier: 0,
      max_next_fills: 0,
      review_after_seconds: dataFreshnessGate.max_staleness_seconds,
      can_auto_paper: false,
      should_refresh_route: dataFreshnessGate.next_refresh_lane === "jupiter-quote",
      should_refresh_chart: dataFreshnessGate.next_refresh_lane === "gecko-ohlcv",
      should_protect_first: loopFeedback.should_protect_first || dailyProfitLock.loop_permission === "protect-only",
      summary: "Signal/noise trade decision is waiting for a fused candidate.",
      next_action: "Refresh market evidence before sizing a local paper action.",
      evidence: [],
      blockers: ["No fused candidate is available."],
      controls: signalNoiseTradeDecisionControls(),
    };
  }

  const signalScore = clamp(Math.round(
    leader.fusion_score * 0.34 +
      leader.organic_momentum_score * 0.24 +
      leader.chart_score * 0.18 +
      leader.route_score * 0.14 +
      leader.wallet_fit_score * 0.1,
  ), 0, 100);
  const noiseScore = clamp(Math.round(
    leader.promotion_noise_score * 0.6 +
      Math.max(0, 60 - leader.route_score) * 0.18 +
      Math.max(0, 58 - leader.chart_score) * 0.14 +
      Math.max(0, 50 - leader.wallet_fit_score) * 0.08,
  ), 0, 100);
  const signalToNoiseRatio = roundMetric(signalScore / Math.max(1, noiseScore));
  const runPermission = !profitRunGuard.blocks_fresh_buy && profitRunGuard.status !== "blocked" && profitRunGuard.status !== "cooldown";
  const dailyPermission = dailyProfitLock.fresh_buy_allowed && dailyProfitLock.loop_permission === "open";
  const replayPermission = replayGate.can_spend && replayGate.action !== "stand-down" && replayGate.action !== "protect-only";
  const feedbackPermission = !loopFeedback.should_pause_fresh_buys && loopFeedback.status !== "cooldown";
  const routeRefresh = leader.action === "refresh-route" || dataFreshnessGate.next_refresh_lane === "jupiter-quote" || leader.route_score < 50;
  const chartRefresh = leader.action === "refresh-candles" || dataFreshnessGate.next_refresh_lane === "gecko-ohlcv" || leader.chart_score < 50;
  const protectFirst = leader.action === "protect" ||
    dailyProfitLock.loop_permission === "protect-only" ||
    profitRunGuard.action === "protect-wallet" ||
    loopFeedback.should_protect_first ||
    walletTelemetry.max_drawdown_pct >= 5;
  const canFreshPaper = (leader.action === "trade" || leader.action === "probe") &&
    marketEvidenceFusion.can_trade &&
    dataFreshnessGate.can_trade &&
    runPermission &&
    dailyPermission &&
    replayPermission &&
    feedbackPermission &&
    !protectFirst &&
    leader.blockers.length === 0 &&
    signalScore >= (leader.action === "trade" ? 62 : 50) &&
    noiseScore < (leader.action === "trade" ? 64 : 76);
  const blockers = [
    ...leader.blockers,
    !marketEvidenceFusion.can_trade ? "Market evidence fusion is not cleared for paper trading." : null,
    !dataFreshnessGate.can_trade ? `Data freshness gate is ${dataFreshnessGate.status}.` : null,
    !runPermission ? `Profit run guard is ${profitRunGuard.status}.` : null,
    !dailyPermission ? `Daily profit lock is ${dailyProfitLock.loop_permission}.` : null,
    !replayPermission ? `Replay gate is ${replayGate.status}.` : null,
    !feedbackPermission ? `Loop feedback is ${loopFeedback.status}.` : null,
    protectFirst ? "Wallet or held-position state is protect-first." : null,
    signalScore < 50 ? `Signal score is ${signalScore}/100.` : null,
    noiseScore >= 76 ? `Promotion/noise score is ${noiseScore}/100.` : null,
  ].filter((item): item is string => Boolean(item));
  const action: AutonomousSignalNoiseTradeDecisionAction = canFreshPaper
    ? leader.action === "trade" ? "paper-buy" : "paper-probe"
    : protectFirst
      ? "protect"
      : routeRefresh
        ? "refresh-route"
        : chartRefresh
          ? "refresh-candles"
          : blockers.length > 0 || leader.action === "reject"
            ? "stand-down"
            : "watch";
  const status: AutonomousSignalNoiseTradeDecision["status"] = action === "paper-buy"
    ? "attack"
    : action === "paper-probe"
      ? "probe"
      : action === "protect"
        ? "protect"
        : action === "refresh-route" || action === "refresh-candles"
          ? "refresh"
          : action === "stand-down"
            ? "blocked"
            : "watch";
  const sizeMultiplier = canFreshPaper
    ? roundMetric(clamp(
      (leader.action === "trade" ? 1 : 0.42) *
        dataFreshnessGate.size_multiplier *
        replayGate.size_multiplier *
        loopFeedback.size_multiplier *
        clamp(signalToNoiseRatio / 2.2, 0.35, 1.2),
      0.05,
      1.25,
    ))
    : 0;
  const maxNextFills = canFreshPaper
    ? Math.max(1, Math.min(
      marketEvidenceFusion.max_next_fills,
      dataFreshnessGate.max_next_fills,
      replayGate.max_next_fills,
      profitRunGuard.max_next_fills,
      dailyProfitLock.max_next_fills,
      loopFeedback.max_next_fills,
    ))
    : 0;
  const recommendedSizeUsd = canFreshPaper
    ? Math.round(Math.max(0, Math.min(
      leader.max_paper_size_usd,
      marketEvidenceFusion.max_paper_size_usd,
      dailyProfitLock.deploy_allowed_usd || leader.max_paper_size_usd,
    )) * sizeMultiplier)
    : 0;
  const decisionScore = clamp(Math.round(
    signalScore * 0.42 +
      leader.route_score * 0.14 +
      leader.chart_score * 0.12 +
      leader.wallet_fit_score * 0.12 +
      dataFreshnessGate.data_score * 0.1 +
      replayGate.replay_score * 0.1 -
      noiseScore * 0.2,
  ), 0, 100);

  return {
    mode: "autonomous-signal-noise-trade-decision",
    status,
    action,
    symbol: leader.symbol,
    token_id: leader.token_id,
    signal_score: signalScore,
    noise_score: noiseScore,
    signal_to_noise_ratio: signalToNoiseRatio,
    route_score: leader.route_score,
    chart_score: leader.chart_score,
    wallet_fit_score: leader.wallet_fit_score,
    data_score: leader.data_score,
    decision_score: decisionScore,
    expected_edge_usd: leader.expected_edge_usd,
    recommended_size_usd: recommendedSizeUsd,
    size_multiplier: sizeMultiplier,
    max_next_fills: maxNextFills,
    review_after_seconds: Math.min(leader.review_after_seconds, profitRunGuard.next_review_seconds, dailyProfitLock.review_after_seconds),
    can_auto_paper: canFreshPaper,
    should_refresh_route: routeRefresh,
    should_refresh_chart: chartRefresh,
    should_protect_first: protectFirst,
    summary: signalNoiseTradeDecisionSummary(action, leader.symbol, decisionScore, signalScore, noiseScore, recommendedSizeUsd),
    next_action: signalNoiseTradeDecisionNextAction(action, leader.symbol, blockers, maxNextFills, leader.review_after_seconds),
    evidence: [
      `${signalScore}/100 blended signal`,
      `${noiseScore}/100 promotion noise`,
      `${leader.route_score}/100 route proof`,
      `${leader.chart_score}/100 chart proof`,
      `${leader.wallet_fit_score}/100 wallet fit`,
      `${signalToNoiseRatio}x signal/noise`,
    ],
    blockers: [...new Set(blockers)].slice(0, 6),
    controls: signalNoiseTradeDecisionControls(),
  };
}

function signalNoiseTradeDecisionSummary(
  action: AutonomousSignalNoiseTradeDecisionAction,
  symbol: string,
  decisionScore: number,
  signalScore: number,
  noiseScore: number,
  recommendedSizeUsd: number,
) {
  if (action === "paper-buy") return `${symbol} clears signal/noise for a ${formatCompactValue(recommendedSizeUsd)} paper buy at ${decisionScore}/100 decision strength.`;
  if (action === "paper-probe") return `${symbol} clears only a reduced paper probe: ${signalScore}/100 signal versus ${noiseScore}/100 noise.`;
  if (action === "protect") return `${symbol} is blocked behind protection-first wallet or held-position work.`;
  if (action === "refresh-route") return `${symbol} needs fresh route proof before any paper entry.`;
  if (action === "refresh-candles") return `${symbol} needs fresh chart proof before any paper entry.`;
  if (action === "stand-down") return `${symbol} does not clear the current signal/noise, profit, replay, or wallet gates.`;
  return `${symbol} stays on watch until the signal/noise ratio improves.`;
}

function signalNoiseTradeDecisionNextAction(
  action: AutonomousSignalNoiseTradeDecisionAction,
  symbol: string,
  blockers: string[],
  maxNextFills: number,
  reviewAfterSeconds: number,
) {
  if (action === "paper-buy" || action === "paper-probe") return `Allow ${maxNextFills} local paper fill${maxNextFills === 1 ? "" : "s"} on ${symbol}, then re-score in ${reviewAfterSeconds}s.`;
  if (action === "refresh-route") return `Refresh the read-only route quote for ${symbol}, then re-run signal/noise sizing.`;
  if (action === "refresh-candles") return `Refresh OHLCV candle evidence for ${symbol}, then re-run signal/noise sizing.`;
  if (action === "protect") return `Run protect/harvest work before adding fresh exposure to ${symbol}.`;
  if (action === "stand-down") return blockers[0] ?? `Stand down on ${symbol} until blockers clear.`;
  return `Watch ${symbol}; do not size a fresh paper entry yet.`;
}

function signalNoiseTradeDecisionControls() {
  return [
    "Consumes fused market evidence, provider freshness, wallet telemetry, profit-run guard, daily lock, replay proof, and loop feedback before sizing.",
    "Allows only local paper buys/probes; live signing, custody, swap submission, and background trading remain locked.",
    "Promotion noise, stale route/chart proof, replay failure, wallet drawdown, and protect-first states force refresh, protect, or stand-down.",
  ];
}

function buildAutonomousExecutionRunway({
  signalNoiseDecision,
  actionQueue,
  actionQueueExecution,
  executionHeartbeat,
  orderTicket,
  orderTicketExecution,
  candleConviction,
  loopThrottle,
  walletTelemetry,
}: {
  signalNoiseDecision: AutonomousSignalNoiseTradeDecision;
  actionQueue: AutonomousActionQueue;
  actionQueueExecution: AutonomousActionQueueExecution;
  executionHeartbeat: AutonomousExecutionHeartbeat;
  orderTicket: AutonomousOrderTicket;
  orderTicketExecution: AutonomousOrderTicketExecution;
  candleConviction: AutonomousCandleConviction;
  loopThrottle: AutonomousLoopThrottle;
  walletTelemetry: AutonomousWalletTelemetry;
}): AutonomousExecutionRunway {
  const targetSymbol = signalNoiseDecision.symbol ??
    orderTicketExecution.symbol ??
    orderTicket.symbol ??
    actionQueueExecution.selected_symbol ??
    actionQueue.leader_symbol ??
    executionHeartbeat.target_symbol;
  const targetLane = actionQueueExecution.selected_lane ??
    actionQueue.leader_lane ??
    orderTicket.lane ??
    (signalNoiseDecision.symbol ? "signal-noise" : null);
  const routeRefresh = signalNoiseDecision.should_refresh_route ||
    actionQueueExecution.route_refresh_vetoed ||
    executionHeartbeat.should_refresh_routes ||
    orderTicketExecution.status === "route-refresh" ||
    orderTicket.route_required;
  const chartRefresh = signalNoiseDecision.should_refresh_chart ||
    candleConviction.refresh_required ||
    candleConviction.action === "refresh" ||
    orderTicket.execution_boundary === "read-only-chart-refresh";
  const protectFirst = signalNoiseDecision.should_protect_first ||
    executionHeartbeat.should_protect_first ||
    loopThrottle.action === "protect-book" ||
    orderTicketExecution.status === "protect-only" ||
    walletTelemetry.status === "protect";
  const queueSellReady = actionQueueExecution.paper_trade_ready &&
    actionQueueExecution.selected_side === "sell" &&
    ["sell", "protect", "harvest"].includes(actionQueueExecution.selected_action);
  const paperReady = signalNoiseDecision.can_auto_paper ||
    orderTicketExecution.paper_trade_ready ||
    actionQueueExecution.paper_trade_ready;
  const canAutoPaper = paperReady && !routeRefresh && !chartRefresh && (!protectFirst || queueSellReady);
  const action: AutonomousExecutionRunwayAction = routeRefresh
    ? "refresh-route"
    : chartRefresh
      ? "refresh-candles"
      : queueSellReady
        ? "paper-sell"
        : protectFirst
          ? "protect"
          : canAutoPaper && signalNoiseDecision.action === "paper-buy"
            ? "paper-buy"
            : canAutoPaper && signalNoiseDecision.action === "paper-probe"
              ? "paper-probe"
              : executionHeartbeat.status === "blocked" || loopThrottle.status === "blocked" || signalNoiseDecision.action === "stand-down"
                ? "stand-down"
                : "watch";
  const status: AutonomousExecutionRunway["status"] = action === "paper-buy"
    ? "attack"
    : action === "paper-probe"
      ? "probe"
      : action === "paper-sell" || action === "protect"
        ? "protect"
        : action === "refresh-route" || action === "refresh-candles"
          ? "refresh"
          : action === "stand-down"
            ? "blocked"
            : signalNoiseDecision.status === "idle"
              ? "idle"
              : "watch";
  const paperSizeUsd = action === "paper-sell"
    ? Math.max(actionQueueExecution.paper_size_usd, orderTicketExecution.paper_size_usd)
    : Math.max(signalNoiseDecision.recommended_size_usd, orderTicketExecution.paper_size_usd, actionQueueExecution.paper_size_usd);
  const blockers = uniqueArray([
    ...signalNoiseDecision.blockers,
    ...actionQueueExecution.blockers,
    ...orderTicketExecution.blockers,
    ...executionHeartbeat.blockers,
    routeRefresh ? actionQueueExecution.route_refresh_blocker ?? "Route proof needs refresh before the next executable step." : null,
    chartRefresh ? candleConviction.blockers[0] ?? "Candle evidence needs refresh before the next executable step." : null,
    protectFirst && !queueSellReady ? "Protection lane outranks fresh exposure." : null,
  ].filter((item): item is string => Boolean(item))).slice(0, 7);
  const runwayScore = clamp(Math.round(
    signalNoiseDecision.decision_score * 0.24 +
      actionQueueExecution.queue_score * 0.18 +
      executionHeartbeat.heartbeat_score * 0.18 +
      orderTicket.confidence_score * 0.16 +
      candleConviction.conviction_score * 0.1 +
      loopThrottle.throttle_score * 0.1 +
      Math.max(0, 100 - walletTelemetry.max_drawdown_pct * 10) * 0.04 -
      blockers.length * 4,
  ), 0, 100);
  const nextTickSeconds = Math.max(1, Math.min(
    signalNoiseDecision.review_after_seconds || 60,
    actionQueueExecution.review_after_seconds || 60,
    executionHeartbeat.next_tick_seconds || 60,
    orderTicketExecution.review_after_seconds || 60,
    loopThrottle.cadence_seconds || 60,
  ));
  const nextStepId: AutonomousExecutionRunwayStep["id"] = routeRefresh
    ? "route"
    : chartRefresh
      ? "decide"
      : action === "paper-buy" || action === "paper-probe" || action === "paper-sell"
        ? "paper"
        : protectFirst
          ? "wallet"
          : "scan";
  const executionBoundary: AutonomousExecutionRunway["execution_boundary"] = routeRefresh
    ? "read-only-route-refresh"
    : chartRefresh
      ? "read-only-chart-refresh"
      : canAutoPaper
        ? "paper-ledger-only"
        : "blocked-paper-only";
  const steps: AutonomousExecutionRunwayStep[] = [
    {
      id: "scan",
      label: "Scan",
      status: signalNoiseDecision.data_score >= 58 ? "done" : "waiting",
      action: "watch",
      score: signalNoiseDecision.data_score,
      symbol: targetSymbol,
      notional_usd: 0,
      eta_seconds: Math.max(1, Math.min(nextTickSeconds, executionHeartbeat.next_tick_seconds)),
      detail: `${signalNoiseDecision.signal_score}/100 signal, ${signalNoiseDecision.noise_score}/100 noise, ${signalNoiseDecision.signal_to_noise_ratio}x ratio.`,
      blocker: signalNoiseDecision.data_score < 58 ? "Scanner/data evidence is below tradeable confidence." : null,
    },
    {
      id: "decide",
      label: "Decide",
      status: signalNoiseDecision.action === "stand-down" ? "blocked" : signalNoiseDecision.action === "watch" ? "waiting" : "done",
      action: signalNoiseDecision.action === "stand-down" ? "stand-down" : signalNoiseDecision.action,
      score: signalNoiseDecision.decision_score,
      symbol: signalNoiseDecision.symbol,
      notional_usd: signalNoiseDecision.recommended_size_usd,
      eta_seconds: Math.max(1, Math.min(nextTickSeconds, signalNoiseDecision.review_after_seconds)),
      detail: signalNoiseDecision.summary,
      blocker: signalNoiseDecision.action === "stand-down" ? signalNoiseDecision.blockers[0] ?? "Decision is blocked." : null,
    },
    {
      id: "route",
      label: "Route",
      status: routeRefresh ? "running" : orderTicket.route_score >= 58 ? "done" : "waiting",
      action: routeRefresh ? "refresh-route" : action,
      score: orderTicket.route_score,
      symbol: targetSymbol,
      notional_usd: paperSizeUsd,
      eta_seconds: routeRefresh ? Math.max(1, nextTickSeconds) : Math.max(1, orderTicketExecution.review_after_seconds),
      detail: `${orderTicket.route_score}/100 route confidence; ${orderTicket.friction_cost_bps}bps route/friction cost.`,
      blocker: routeRefresh ? actionQueueExecution.route_refresh_blocker ?? orderTicket.blockers.find((blocker) => /route/i.test(blocker)) ?? "Read-only route quote must refresh." : null,
    },
    {
      id: "paper",
      label: "Paper",
      status: canAutoPaper ? "ready" : action === "stand-down" ? "blocked" : "waiting",
      action,
      score: Math.max(actionQueueExecution.queue_score, orderTicketExecution.confidence_score, signalNoiseDecision.decision_score),
      symbol: targetSymbol,
      notional_usd: paperSizeUsd,
      eta_seconds: nextTickSeconds,
      detail: `${executionBoundary.replaceAll("-", " ")} - ${formatCompactValue(paperSizeUsd)} notional - ${Math.max(signalNoiseDecision.max_next_fills, loopThrottle.max_total_fills)} fill cap.`,
      blocker: canAutoPaper ? null : blockers[0] ?? "Paper execution is waiting for the runway to clear.",
    },
    {
      id: "wallet",
      label: "Wallet",
      status: protectFirst ? "running" : walletTelemetry.max_drawdown_pct >= 4 ? "waiting" : "done",
      action: protectFirst ? "protect" : "watch",
      score: clamp(Math.round(100 - walletTelemetry.max_drawdown_pct * 10 + Math.max(-20, walletTelemetry.window_pnl_pct * 2)), 0, 100),
      symbol: targetSymbol,
      notional_usd: loopThrottle.release_budget_usd,
      eta_seconds: Math.max(1, loopThrottle.cadence_seconds),
      detail: `${formatCompactValue(walletTelemetry.equity_usd)} equity, ${formatCompactValue(walletTelemetry.exposure_usd)} exposure, ${walletTelemetry.max_drawdown_pct.toFixed(1)}% max drawdown.`,
      blocker: protectFirst ? "Protect or harvest before fresh exposure." : null,
    },
  ];

  return {
    mode: "autonomous-execution-runway",
    status,
    action,
    target_symbol: targetSymbol,
    target_lane: targetLane,
    next_step_id: nextStepId,
    runway_score: runwayScore,
    latency_target_ms: Math.max(250, nextTickSeconds * 1000),
    next_tick_seconds: nextTickSeconds,
    ticks_per_minute: executionHeartbeat.ticks_per_minute,
    paper_size_usd: paperSizeUsd,
    expected_edge_usd: Math.max(signalNoiseDecision.expected_edge_usd, actionQueueExecution.expected_edge_usd, orderTicketExecution.paper_size_usd > 0 ? orderTicket.expected_value_usd : 0),
    expected_profit_per_minute_usd: Math.max(executionHeartbeat.expected_profit_per_minute_usd, actionQueueExecution.expected_profit_per_minute_usd, orderTicket.expected_value_per_minute_usd),
    max_next_fills: Math.max(signalNoiseDecision.max_next_fills, loopThrottle.max_total_fills, canAutoPaper ? 1 : 0),
    can_auto_paper: canAutoPaper,
    should_refresh_route: routeRefresh,
    should_refresh_chart: chartRefresh,
    should_protect_first: protectFirst,
    route_vetoed: actionQueueExecution.route_refresh_vetoed || executionHeartbeat.route_vetoed,
    chart_refresh_required: chartRefresh,
    execution_boundary: executionBoundary,
    summary: executionRunwaySummary(action, targetSymbol, runwayScore, nextTickSeconds, paperSizeUsd),
    next_action: executionRunwayNextAction(action, targetSymbol, blockers, nextTickSeconds),
    blockers,
    controls: [
      "Condenses scanner, signal/noise decision, route/candle refresh, action queue, order ticket, heartbeat, and wallet protection into one immediate paper-runway receipt.",
      "Runway can start only local paper fills or read-only route/chart refreshes; live signing and swap submission remain credential-gated outside this receipt.",
      "Route vetoes, stale candles, protect-first wallet state, and blocked queue/order tickets stop fresh paper exposure before ledger mutation.",
    ],
    steps,
  };
}

function executionRunwaySummary(
  action: AutonomousExecutionRunwayAction,
  symbol: string | null,
  runwayScore: number,
  nextTickSeconds: number,
  paperSizeUsd: number,
) {
  const target = symbol ?? "the desk";
  if (action === "paper-buy") return `${target} is on the execution runway for a ${formatCompactValue(paperSizeUsd)} paper buy at ${runwayScore}/100.`;
  if (action === "paper-probe") return `${target} is on the execution runway for a reduced ${formatCompactValue(paperSizeUsd)} paper probe.`;
  if (action === "paper-sell") return `${target} is on the execution runway for a protective paper sell within ${nextTickSeconds}s.`;
  if (action === "protect") return `The execution runway is protect-first before any new ${target} exposure.`;
  if (action === "refresh-route") return `${target} needs read-only route proof before the runway can spend paper capital.`;
  if (action === "refresh-candles") return `${target} needs fresh candle proof before the runway can spend paper capital.`;
  if (action === "stand-down") return "The execution runway is blocked; no fresh paper exposure should be added.";
  return `The execution runway is watching ${target} for a cleaner next tick.`;
}

function executionRunwayNextAction(
  action: AutonomousExecutionRunwayAction,
  symbol: string | null,
  blockers: string[],
  nextTickSeconds: number,
) {
  const target = symbol ?? "the selected coin";
  if (action === "paper-buy" || action === "paper-probe") return `Run one bounded local paper ${action === "paper-buy" ? "buy" : "probe"} on ${target}, then verify wallet PnL in ${nextTickSeconds}s.`;
  if (action === "paper-sell") return `Run the protective local paper sell for ${target}, then re-score wallet exposure.`;
  if (action === "protect") return `Run protect/harvest work before new exposure; re-check in ${nextTickSeconds}s.`;
  if (action === "refresh-route") return `Refresh the read-only route quote for ${target}, then rebuild the runway.`;
  if (action === "refresh-candles") return `Refresh candle evidence for ${target}, then rebuild the runway.`;
  if (action === "stand-down") return blockers[0] ?? "Stand down until the runway blockers clear.";
  return `Watch ${target}; ask the backend loop for the next tick in ${nextTickSeconds}s.`;
}

function buildAutonomousNowDecision({
  marketEvidenceFusion,
  executionRunway,
  chartProofTarget,
  orderTicket,
  orderTicketExecution,
  walletTelemetry,
  loopThrottle,
  wakePlan,
  sessionRun,
  executionGate,
}: {
  marketEvidenceFusion: AutonomousMarketEvidenceFusion;
  executionRunway: AutonomousExecutionRunway;
  chartProofTarget: AutonomousChartProofTarget;
  orderTicket: AutonomousOrderTicket;
  orderTicketExecution: AutonomousOrderTicketExecution;
  walletTelemetry: AutonomousWalletTelemetry;
  loopThrottle: AutonomousLoopThrottle;
  wakePlan: AutonomousWakePlan;
  sessionRun: AutonomousSessionRunReport;
  executionGate: ExecutionGate;
}): AutonomousNowDecision {
  const targetSymbol = executionRunway.target_symbol ??
    orderTicketExecution.symbol ??
    orderTicket.symbol ??
    wakePlan.target_symbol ??
    loopThrottle.target_symbol ??
    marketEvidenceFusion.leader_symbol;
  const routeRefreshRequired = executionRunway.should_refresh_route ||
    orderTicket.route_required ||
    orderTicketExecution.status === "route-refresh";
  const chartProofRequired = executionRunway.should_refresh_chart ||
    chartProofTarget.should_fetch ||
    chartProofTarget.status === "blocked";
  const protectFirst = executionRunway.should_protect_first ||
    loopThrottle.action === "protect-book" ||
    wakePlan.status === "protect";
  const action: AutonomousNowDecisionAction = executionRunway.action === "watch" &&
    loopThrottle.can_run &&
    wakePlan.can_auto_watch_run &&
    !routeRefreshRequired &&
    !chartProofRequired
    ? "run-loop"
    : executionRunway.action;
  const status: AutonomousNowDecision["status"] = action === "paper-buy"
    ? "attack"
    : action === "paper-probe"
      ? "probe"
      : action === "paper-sell" || action === "protect"
        ? "protect"
        : action === "refresh-route" || action === "refresh-candles"
          ? "refresh"
          : action === "run-loop"
            ? "loop"
            : action === "stand-down"
              ? "blocked"
              : executionRunway.status === "idle"
                ? "idle"
                : "watch";
  const maxNextFills = Math.max(
    executionRunway.max_next_fills,
    loopThrottle.max_total_fills,
    wakePlan.max_total_fills,
    orderTicketExecution.paper_trade_ready ? 1 : 0,
  );
  const paperSizeUsd = Math.max(
    executionRunway.paper_size_usd,
    orderTicket.paper_notional_usd,
    orderTicketExecution.paper_size_usd,
  );
  const expectedEdgeUsd = Math.max(
    executionRunway.expected_edge_usd,
    marketEvidenceFusion.expected_edge_usd,
    orderTicket.expected_value_usd,
    loopThrottle.expected_profit_usd,
  );
  const expectedProfitPerMinuteUsd = Math.max(
    executionRunway.expected_profit_per_minute_usd,
    wakePlan.expected_profit_per_minute_usd,
    orderTicket.expected_value_per_minute_usd,
  );
  const reviewAfterSeconds = Math.max(1, Math.min(
    executionRunway.next_tick_seconds || 60,
    wakePlan.next_wake_seconds || 60,
    orderTicketExecution.review_after_seconds || 60,
  ));
  const blockers = uniqueArray([
    ...executionRunway.blockers,
    ...orderTicketExecution.blockers,
    ...wakePlan.blockers,
    chartProofRequired && chartProofTarget.reason ? chartProofTarget.reason : null,
    routeRefreshRequired ? orderTicket.next_action : null,
    protectFirst && action !== "paper-sell" ? "Protection work outranks fresh exposure right now." : null,
  ].filter((item): item is string => Boolean(item))).slice(0, 8);
  const decisionScore = clamp(Math.round(
    executionRunway.runway_score * 0.34 +
      marketEvidenceFusion.fusion_score * 0.18 +
      orderTicket.confidence_score * 0.16 +
      loopThrottle.throttle_score * 0.14 +
      Math.max(0, 100 - walletTelemetry.max_drawdown_pct * 10) * 0.1 +
      (wakePlan.can_auto_watch_run ? 8 : 0) -
      blockers.length * 3,
  ), 0, 100);
  const buttonLabel: AutonomousNowDecision["button_label"] = routeRefreshRequired
    ? "Refresh read"
    : chartProofRequired
      ? "Proof + tick"
      : action === "run-loop"
        ? wakePlan.next_client_action === "run-minute" ? "Run minute" : "Run tick"
        : action === "paper-buy" || action === "paper-probe" || action === "paper-sell"
          ? wakePlan.next_client_action === "run-minute" ? "Run minute" : "Run tick"
          : action === "refresh-candles"
            ? "Chart proof"
            : action === "protect"
              ? "Protect book"
              : action === "stand-down"
                ? "Stand down"
                : wakePlan.should_refresh_first ? "Refresh read" : "Run tick";
  const proof: AutonomousNowDecisionProof[] = [
    {
      id: "market",
      label: "Market",
      status: marketEvidenceFusion.can_trade ? "pass" : marketEvidenceFusion.status === "blocked" ? "fail" : "watch",
      score: marketEvidenceFusion.fusion_score,
      value: marketEvidenceFusion.leader_action?.replace("-", " ") ?? marketEvidenceFusion.status,
      detail: `${marketEvidenceFusion.leader_symbol ?? "Desk"} at ${marketEvidenceFusion.fusion_score}/100 fusion with ${formatSignedCompactValue(marketEvidenceFusion.expected_edge_usd)} edge.`,
    },
    {
      id: "route",
      label: "Route",
      status: routeRefreshRequired ? "fail" : orderTicket.route_score >= 60 ? "pass" : "watch",
      score: orderTicket.route_score,
      value: routeRefreshRequired ? "refresh" : `${orderTicket.route_score}/100`,
      detail: routeRefreshRequired ? orderTicket.next_action : `${orderTicket.friction_cost_bps}bps route/friction drag before paper sizing.`,
    },
    {
      id: "chart",
      label: "Chart",
      status: chartProofRequired ? "watch" : chartProofTarget.proof_target_matched ? "pass" : "watch",
      score: executionRunway.steps.find((step) => step.id === "decide")?.score ?? orderTicket.confidence_score,
      value: chartProofRequired ? "proof needed" : chartProofTarget.proof_target_matched ? "matched" : chartProofTarget.status,
      detail: chartProofTarget.reason,
    },
    {
      id: "wallet",
      label: "Wallet",
      status: walletTelemetry.status === "protect" || walletTelemetry.max_drawdown_pct >= 5 ? "fail" : walletTelemetry.window_pnl_usd >= 0 ? "pass" : "watch",
      score: clamp(Math.round(100 - walletTelemetry.max_drawdown_pct * 10 + Math.max(-20, walletTelemetry.window_pnl_pct * 2)), 0, 100),
      value: formatSignedCompactValue(walletTelemetry.window_pnl_usd),
      detail: `${formatCompactValue(walletTelemetry.equity_usd)} equity, ${formatCompactValue(walletTelemetry.exposure_usd)} exposure, ${walletTelemetry.max_drawdown_pct.toFixed(1)}% drawdown.`,
    },
    {
      id: "loop",
      label: "Loop",
      status: wakePlan.can_auto_watch_run || loopThrottle.can_run ? "pass" : loopThrottle.status === "blocked" || wakePlan.status === "blocked" ? "fail" : "watch",
      score: loopThrottle.throttle_score,
      value: wakePlan.auto_watch_label,
      detail: `${wakePlan.next_client_action.replace("-", " ")} in ${wakePlan.next_wake_seconds}s; ${maxNextFills} fill cap.`,
    },
    {
      id: "ticket",
      label: "Ticket",
      status: orderTicketExecution.paper_trade_ready || orderTicket.status === "ready" || orderTicket.status === "protect" ? "pass" : orderTicket.status === "blocked" ? "fail" : "watch",
      score: orderTicket.confidence_score,
      value: orderTicket.status,
      detail: orderTicketExecution.summary,
    },
  ];

  return {
    mode: "autonomous-now-decision",
    status,
    action,
    target_symbol: targetSymbol,
    target_lane: executionRunway.target_lane,
    button_label: buttonLabel,
    decision_score: decisionScore,
    expected_edge_usd: roundMetric(expectedEdgeUsd),
    expected_profit_per_minute_usd: roundMetric(expectedProfitPerMinuteUsd),
    paper_size_usd: roundMetric(paperSizeUsd),
    max_next_fills: maxNextFills,
    review_after_seconds: reviewAfterSeconds,
    wallet_equity_usd: roundMetric(walletTelemetry.equity_usd),
    wallet_window_pnl_usd: roundMetric(walletTelemetry.window_pnl_usd),
    wallet_drawdown_pct: roundMetric(walletTelemetry.max_drawdown_pct),
    can_auto_paper: executionRunway.can_auto_paper,
    can_auto_watch_run: wakePlan.can_auto_watch_run,
    chart_proof_required: chartProofRequired,
    chart_proof_status: chartProofTarget.status,
    route_refresh_required: routeRefreshRequired,
    live_execution_enabled: executionGate.live_execution_enabled,
    execution_boundary: executionRunway.execution_boundary,
    summary: autonomousNowDecisionSummary(status, action, targetSymbol, paperSizeUsd, decisionScore, sessionRun),
    next_action: autonomousNowDecisionNextAction(action, targetSymbol, buttonLabel, blockers, reviewAfterSeconds),
    blockers,
    safeguards: [
      "This verdict can only advance local paper-ledger actions or read-only refreshes in the current build.",
      "Live signing, custody, and swap submission stay locked unless the execution gate is explicitly configured elsewhere.",
      "Route, chart, wallet-protection, and blocker checks outrank fresh buys even when market momentum is strong.",
    ],
    proof,
  };
}

function autonomousNowDecisionSummary(
  status: AutonomousNowDecision["status"],
  action: AutonomousNowDecisionAction,
  targetSymbol: string | null,
  paperSizeUsd: number,
  decisionScore: number,
  sessionRun: AutonomousSessionRunReport,
) {
  const target = targetSymbol ?? "the desk";
  if (action === "paper-buy") return `Now decision: press ${target} with ${formatCompactValue(paperSizeUsd)} paper size at ${decisionScore}/100.`;
  if (action === "paper-probe") return `Now decision: probe ${target} with reduced ${formatCompactValue(paperSizeUsd)} paper size.`;
  if (action === "paper-sell") return `Now decision: protect the book with a ${formatCompactValue(paperSizeUsd)} paper sell on ${target}.`;
  if (action === "protect") return `Now decision: protect first; fresh ${target} exposure waits.`;
  if (action === "refresh-route") return `Now decision: refresh read-only route proof before spending paper capital on ${target}.`;
  if (action === "refresh-candles") return `Now decision: refresh chart proof before spending paper capital on ${target}.`;
  if (action === "run-loop") return `Now decision: run the backend loop; last cycle ${sessionRun.requested ? formatSignedCompactValue(sessionRun.net_pnl_usd) : "has not run yet"}.`;
  if (status === "blocked") return "Now decision: stand down instead of forcing low-quality churn.";
  return `Now decision: watch ${target} until the next proof gate clears.`;
}

function autonomousNowDecisionNextAction(
  action: AutonomousNowDecisionAction,
  targetSymbol: string | null,
  buttonLabel: AutonomousNowDecision["button_label"],
  blockers: string[],
  reviewAfterSeconds: number,
) {
  const target = targetSymbol ?? "the selected coin";
  if (action === "paper-buy" || action === "paper-probe") return `Use ${buttonLabel} to let the backend apply at most the bounded local paper entry on ${target}, then re-score in ${reviewAfterSeconds}s.`;
  if (action === "paper-sell") return `Use ${buttonLabel} to let the backend apply the protective local paper sell on ${target}.`;
  if (action === "protect") return `Use ${buttonLabel} or the next backend tick to reduce risk before adding exposure.`;
  if (action === "refresh-route") return `Use ${buttonLabel} to refresh read-only route evidence, then rerun the now decision.`;
  if (action === "refresh-candles") return `Use ${buttonLabel} to refresh chart proof for ${target}, then rerun the backend tick.`;
  if (action === "run-loop") return `Use ${buttonLabel} to let the backend choose the next bounded paper action.`;
  if (action === "stand-down") return blockers[0] ?? "Stand down until the blocker stack clears.";
  return `Watch ${target}; rerun the now decision in ${reviewAfterSeconds}s.`;
}

function buildAutonomousMakeMoneyPulse({
  walletTelemetry,
  marketEvidenceFusion,
  profitLaneScoreboard,
  positionSituation,
  protectiveCoverage,
  protectionCoordinator,
  profitRunGuard,
  dailyProfitLock,
  runEnvelope,
  nowDecision,
  loopFeedback,
  profitAccountability,
}: {
  walletTelemetry: AutonomousWalletTelemetry;
  marketEvidenceFusion: AutonomousMarketEvidenceFusion;
  profitLaneScoreboard: AutonomousProfitLaneScoreboard;
  positionSituation: AutonomousPositionSituationBoard;
  protectiveCoverage: ProtectiveTriggerCoverage;
  protectionCoordinator: AutonomousProtectionCoordinator;
  profitRunGuard: AutonomousProfitRunGuard;
  dailyProfitLock: AutonomousDailyProfitLock;
  runEnvelope: AutonomousRunEnvelope;
  nowDecision: AutonomousNowDecision;
  loopFeedback: AutonomousLoopFeedback;
  profitAccountability: AutonomousProfitAccountability;
}): AutonomousMakeMoneyPulse {
  const walletScore = clamp(Math.round(
    58 +
      Math.max(-18, Math.min(18, walletTelemetry.window_pnl_pct * 2.4)) +
      Math.max(-14, Math.min(14, walletTelemetry.slope_usd_per_tick / 6)) -
      walletTelemetry.max_drawdown_pct * 6 -
      (walletTelemetry.status === "protect" || walletTelemetry.status === "recover" ? 14 : 0) +
      (walletTelemetry.status === "compounding" ? 8 : 0),
  ), 0, 100);
  const marketScore = clamp(Math.round(
    marketEvidenceFusion.fusion_score * 0.72 +
      nowDecision.decision_score * 0.28 -
      (marketEvidenceFusion.can_trade ? 0 : 12) -
      (nowDecision.route_refresh_required || nowDecision.chart_proof_required ? 10 : 0),
  ), 0, 100);
  const profitScore = clamp(Math.round(
    profitLaneScoreboard.make_money_score * 0.42 +
      profitRunGuard.profit_guard_score * 0.24 +
      profitAccountability.accountability_score * 0.22 +
      (profitAccountability.making_money ? 8 : -8) +
      Math.max(-10, Math.min(10, profitLaneScoreboard.expected_profit_per_minute_usd / 2)),
  ), 0, 100);
  const protectiveSellRequired = positionSituation.fresh_buy_blocked ||
    protectiveCoverage.should_pause_fresh_buys ||
    protectionCoordinator.status === "queued" ||
    protectionCoordinator.status === "blocked" ||
    positionSituation.status === "exit" ||
    positionSituation.status === "trim" ||
    positionSituation.status === "harvest";
  const protectionScore = clamp(Math.round(
    94 -
      (protectiveCoverage.should_pause_fresh_buys ? 28 : 0) -
      (positionSituation.fresh_buy_blocked ? 24 : 0) -
      (protectionCoordinator.status === "blocked" ? 24 : 0) -
      (protectionCoordinator.status === "queued" ? 14 : 0) -
      Math.min(18, protectiveCoverage.exposed_notional_usd / Math.max(1, walletTelemetry.equity_usd) * 100) +
      (protectiveCoverage.status === "covered" ? 8 : 0),
  ), 0, 100);
  const loopScore = clamp(Math.round(
    runEnvelope.run_confidence_score * 0.36 +
      runEnvelope.loop_score * 0.24 +
      loopFeedback.feedback_score * 0.22 +
      (runEnvelope.run_enabled ? 10 : -10) +
      (loopFeedback.should_pause_fresh_buys ? -8 : 0),
  ), 0, 100);
  const qualityScore = clamp(Math.round(
    nowDecision.decision_score * 0.35 +
      marketEvidenceFusion.data_score * 0.18 +
      marketEvidenceFusion.route_score * 0.16 +
      marketEvidenceFusion.chart_score * 0.16 +
      marketEvidenceFusion.wallet_fit_score * 0.15 -
      nowDecision.blockers.length * 3,
  ), 0, 100);
  const blockers = uniqueArray([
    ...nowDecision.blockers,
    dailyProfitLock.fresh_buy_allowed ? null : dailyProfitLock.stop_reason ?? dailyProfitLock.next_action,
    profitRunGuard.blocks_fresh_buy ? profitRunGuard.stop_reason ?? profitRunGuard.next_action : null,
    protectiveCoverage.should_pause_fresh_buys ? protectiveCoverage.next_action : null,
    positionSituation.fresh_buy_blocked ? positionSituation.next_action : null,
    loopFeedback.should_pause_fresh_buys ? loopFeedback.next_action : null,
    runEnvelope.run_enabled ? null : runEnvelope.stop_reason ?? runEnvelope.next_action,
  ].filter((item): item is string => Boolean(item))).slice(0, 8);
  const freshBuyAllowed = dailyProfitLock.fresh_buy_allowed &&
    !profitRunGuard.blocks_fresh_buy &&
    !positionSituation.fresh_buy_blocked &&
    !protectiveCoverage.should_pause_fresh_buys &&
    !loopFeedback.should_pause_fresh_buys &&
    nowDecision.can_auto_paper &&
    nowDecision.action !== "paper-sell" &&
    nowDecision.action !== "protect";
  const pulseScore = clamp(Math.round(
    walletScore * 0.17 +
      marketScore * 0.22 +
      profitScore * 0.23 +
      protectionScore * 0.16 +
      loopScore * 0.14 +
      qualityScore * 0.08 -
      blockers.length * 2,
  ), 0, 100);
  const reactionSeconds = Math.max(5, Math.min(
    nowDecision.review_after_seconds,
    marketEvidenceFusion.fastest_review_seconds,
    profitLaneScoreboard.review_after_seconds,
    positionSituation.fastest_review_seconds,
    protectiveCoverage.fastest_review_seconds,
    protectionCoordinator.fastest_review_seconds,
    profitRunGuard.next_review_seconds,
    dailyProfitLock.review_after_seconds,
    runEnvelope.next_wake_seconds,
  ));
  const targetSymbol = positionSituation.leader_symbol ??
    protectionCoordinator.selected_symbol ??
    nowDecision.target_symbol ??
    profitLaneScoreboard.leader_symbol ??
    marketEvidenceFusion.leader_symbol;
  let status: AutonomousMakeMoneyPulseStatus = "observe";
  let action: AutonomousMakeMoneyPulseAction = "observe";
  if (protectionCoordinator.status === "blocked" || nowDecision.status === "blocked" || runEnvelope.status === "blocked") {
    status = "blocked";
    action = "stand-down";
  } else if (protectiveSellRequired && Math.max(positionSituation.release_usd, protectionCoordinator.release_usd, dailyProfitLock.release_required_usd) > 0) {
    status = positionSituation.status === "harvest" ? "harvest" : "protect";
    action = positionSituation.status === "harvest" ? "paper-harvest" : "paper-protect";
  } else if (nowDecision.route_refresh_required || nowDecision.chart_proof_required || marketEvidenceFusion.status === "refresh" || runEnvelope.status === "refresh") {
    status = "refresh";
    action = "refresh-proof";
  } else if (dailyProfitLock.loop_permission === "paused" || dailyProfitLock.status === "cooldown" || profitRunGuard.status === "cooldown" || runEnvelope.status === "cooldown") {
    status = "cooldown";
    action = "cooldown";
  } else if (freshBuyAllowed && pulseScore >= 72 && marketEvidenceFusion.can_trade && profitLaneScoreboard.ready_lane_count > 0) {
    status = "attack";
    action = "paper-attack";
  } else if (freshBuyAllowed && pulseScore >= 58 && marketEvidenceFusion.leader_symbol) {
    status = "probe";
    action = "paper-probe";
  }
  const deployNowUsd = action === "paper-attack" || action === "paper-probe"
    ? Math.min(nowDecision.paper_size_usd, dailyProfitLock.deploy_allowed_usd, marketEvidenceFusion.max_paper_size_usd)
    : 0;
  const releaseNowUsd = action === "paper-harvest" || action === "paper-protect"
    ? Math.max(positionSituation.release_usd, protectionCoordinator.release_usd, dailyProfitLock.release_required_usd)
    : 0;
  const expectedProfitPerMinuteUsd = roundMetric(Math.max(
    0,
    nowDecision.expected_profit_per_minute_usd,
    profitLaneScoreboard.expected_profit_per_minute_usd,
    runEnvelope.expected_profit_per_minute_usd,
  ));
  const items: AutonomousMakeMoneyPulseItem[] = [
    {
      id: "wallet",
      label: "Wallet",
      status: walletScore >= 70 ? "pass" : walletScore < 45 ? "fail" : "watch",
      score: walletScore,
      value: formatSignedCompactValue(walletTelemetry.window_pnl_usd),
      detail: `${walletTelemetry.status} wallet with ${formatCompactValue(walletTelemetry.equity_usd)} equity and ${roundMetric(walletTelemetry.max_drawdown_pct)}% drawdown.`,
    },
    {
      id: "market",
      label: "Market",
      status: marketEvidenceFusion.can_trade && marketScore >= 62 ? "pass" : marketEvidenceFusion.status === "blocked" ? "fail" : "watch",
      score: marketScore,
      value: marketEvidenceFusion.leader_symbol ?? "desk",
      detail: `${marketEvidenceFusion.status} signal at ${marketEvidenceFusion.fusion_score}/100 with ${formatSignedCompactValue(marketEvidenceFusion.expected_edge_usd)} edge.`,
    },
    {
      id: "profit",
      label: "Profit",
      status: profitScore >= 64 && profitAccountability.making_money ? "pass" : profitScore < 42 ? "fail" : "watch",
      score: profitScore,
      value: formatSignedCompactValue(profitLaneScoreboard.expected_profit_per_minute_usd),
      detail: `${profitLaneScoreboard.status} lane, ${profitRunGuard.status} guard, accountability ${profitAccountability.status}.`,
    },
    {
      id: "protection",
      label: "Protection",
      status: protectionScore >= 70 && !protectiveSellRequired ? "pass" : protectionScore < 48 || protectiveSellRequired ? "fail" : "watch",
      score: protectionScore,
      value: positionSituation.status,
      detail: `${formatCompactValue(releaseNowUsd)} release pressure, ${Math.round(protectiveCoverage.coverage_pct)}% trigger coverage.`,
    },
    {
      id: "loop",
      label: "Loop",
      status: runEnvelope.run_enabled && loopScore >= 62 ? "pass" : runEnvelope.status === "blocked" ? "fail" : "watch",
      score: loopScore,
      value: `${runEnvelope.max_trades_next_minute}/m`,
      detail: `${runEnvelope.status} envelope, wake in ${runEnvelope.next_wake_seconds}s, ${loopFeedback.status} feedback.`,
    },
    {
      id: "quality",
      label: "Quality",
      status: qualityScore >= 64 && blockers.length === 0 ? "pass" : qualityScore < 42 || blockers.length > 2 ? "fail" : "watch",
      score: qualityScore,
      value: `${nowDecision.decision_score}/100`,
      detail: `${nowDecision.action.replace("-", " ")} decision with ${nowDecision.blockers.length} blockers.`,
    },
  ];
  return {
    mode: "autonomous-make-money-pulse",
    status,
    action,
    target_symbol: targetSymbol,
    pulse_score: pulseScore,
    wallet_score: walletScore,
    market_score: marketScore,
    profit_score: profitScore,
    protection_score: protectionScore,
    loop_score: loopScore,
    expected_profit_per_minute_usd: expectedProfitPerMinuteUsd,
    deploy_now_usd: roundMetric(Math.max(0, deployNowUsd)),
    release_now_usd: roundMetric(Math.max(0, releaseNowUsd)),
    max_next_fills: Math.max(0, Math.min(nowDecision.max_next_fills, profitRunGuard.max_next_fills, dailyProfitLock.max_next_fills, runEnvelope.max_trades_next_minute)),
    reaction_seconds: reactionSeconds,
    fresh_buy_allowed: freshBuyAllowed,
    protective_sell_required: protectiveSellRequired,
    summary: autonomousMakeMoneyPulseSummary(status, action, targetSymbol, pulseScore, deployNowUsd, releaseNowUsd, expectedProfitPerMinuteUsd),
    next_action: autonomousMakeMoneyPulseNextAction(status, action, targetSymbol, blockers, reactionSeconds),
    blockers,
    controls: [
      "Single make-money pulse fuses wallet PnL, market edge, profit lanes, protection, and loop permission.",
      "Paper attack/probe actions stay bounded to the local paper ledger until live execution is separately armed.",
      "Held-position protection and trigger coverage outrank every fresh memecoin entry.",
    ],
    items,
  };
}

function autonomousMakeMoneyPulseSummary(
  status: AutonomousMakeMoneyPulseStatus,
  action: AutonomousMakeMoneyPulseAction,
  targetSymbol: string | null,
  pulseScore: number,
  deployNowUsd: number,
  releaseNowUsd: number,
  expectedProfitPerMinuteUsd: number,
) {
  const target = targetSymbol ?? "the desk";
  if (action === "paper-attack") return `Make-money pulse attacks ${target}: ${pulseScore}/100 score, ${formatCompactValue(deployNowUsd)} paper deploy, ${formatSignedCompactValue(expectedProfitPerMinuteUsd)}/min modeled edge.`;
  if (action === "paper-probe") return `Make-money pulse probes ${target}: edge is present but still selective at ${pulseScore}/100.`;
  if (action === "paper-harvest") return `Make-money pulse harvests ${target}: release ${formatCompactValue(releaseNowUsd)} before new exposure.`;
  if (action === "paper-protect") return `Make-money pulse protects ${target}: release ${formatCompactValue(releaseNowUsd)} and re-score before chasing.`;
  if (action === "refresh-proof") return `Make-money pulse refreshes proof first; route, chart, or provider evidence is not clean enough to trade.`;
  if (action === "cooldown") return `Make-money pulse cools down instead of forcing churn while profit or loop guards recover.`;
  if (action === "stand-down" || status === "blocked") return `Make-money pulse stands down; blocker stack outranks the current market edge.`;
  return `Make-money pulse observes ${target}; wait for cleaner edge, wallet, and loop alignment.`;
}

function autonomousMakeMoneyPulseNextAction(
  status: AutonomousMakeMoneyPulseStatus,
  action: AutonomousMakeMoneyPulseAction,
  targetSymbol: string | null,
  blockers: string[],
  reactionSeconds: number,
) {
  const target = targetSymbol ?? "the lead setup";
  if (action === "paper-attack") return `Run the bounded paper loop on ${target}, then re-score the wallet and protection stack in ${reactionSeconds}s.`;
  if (action === "paper-probe") return `Probe ${target} with reduced paper size and require the next tape to confirm within ${reactionSeconds}s.`;
  if (action === "paper-harvest") return `Harvest the queued paper release on ${target}, then let profits compound from a cleaner book.`;
  if (action === "paper-protect") return `Protect ${target} first; fresh buys stay paused until the held-position board clears.`;
  if (action === "refresh-proof") return `Refresh read-only route/chart evidence, then rerun the make-money pulse.`;
  if (action === "cooldown") return `Cool down and wake in ${reactionSeconds}s unless a protection event arrives first.`;
  if (action === "stand-down" || status === "blocked") return blockers[0] ?? "Stand down until the blocker stack clears.";
  return `Observe ${target}; rerun the pulse in ${reactionSeconds}s.`;
}

function buildAutonomousProfitBenchmark({
  market,
  walletTelemetry,
  marketEvidenceFusion,
  profitLaneScoreboard,
  makeMoneyPulse,
}: {
  market: MemecoinMarket[];
  walletTelemetry: AutonomousWalletTelemetry;
  marketEvidenceFusion: AutonomousMarketEvidenceFusion;
  profitLaneScoreboard: AutonomousProfitLaneScoreboard;
  makeMoneyPulse: AutonomousMakeMoneyPulse;
}): AutonomousProfitBenchmark {
  const startingCash = Math.max(1, walletTelemetry.starting_cash_usd);
  const agentEquity = walletTelemetry.equity_usd;
  const selectedSymbol = makeMoneyPulse.target_symbol ?? marketEvidenceFusion.leader_symbol ?? profitLaneScoreboard.leader_symbol;
  const selectedToken = selectedSymbol ? market.find((token) => token.symbol === selectedSymbol) ?? null : null;
  const hotToken = [...market].sort((a, b) => {
    const scoreA = tokenBenchmarkHeatScore(a);
    const scoreB = tokenBenchmarkHeatScore(b);
    return scoreB - scoreA;
  })[0] ?? null;
  const selectedBaseline = selectedToken ? tokenBenchmarkValue(startingCash, selectedToken) : startingCash;
  const hotBaseline = hotToken ? tokenBenchmarkValue(startingCash, hotToken) : startingCash;
  const cashAlpha = agentEquity - startingCash;
  const selectedAlpha = agentEquity - selectedBaseline;
  const hotAlpha = agentEquity - hotBaseline;
  const opportunityGap = Math.max(0, hotBaseline - agentEquity);
  const drawdownPenalty = startingCash * Math.max(0, walletTelemetry.max_drawdown_pct) / 100;
  const riskAdjustedAlpha = cashAlpha - drawdownPenalty;
  const cashScore = clamp(Math.round(50 + (cashAlpha / startingCash) * 260 - walletTelemetry.max_drawdown_pct * 3), 0, 100);
  const selectedScore = clamp(Math.round(50 + (selectedAlpha / startingCash) * 160), 0, 100);
  const hotScore = clamp(Math.round(50 + (hotAlpha / startingCash) * 120), 0, 100);
  const riskScore = clamp(Math.round(92 - walletTelemetry.max_drawdown_pct * 8 - Math.max(0, walletTelemetry.exposure_pct - 65) * 0.7), 0, 100);
  const executionScore = clamp(Math.round(
    makeMoneyPulse.pulse_score * 0.45 +
      profitLaneScoreboard.make_money_score * 0.25 +
      marketEvidenceFusion.fusion_score * 0.18 +
      (makeMoneyPulse.fresh_buy_allowed || makeMoneyPulse.protective_sell_required ? 8 : -4),
  ), 0, 100);
  const benchmarkScore = clamp(Math.round(cashScore * 0.34 + selectedScore * 0.15 + hotScore * 0.12 + riskScore * 0.2 + executionScore * 0.19), 0, 100);
  let status: AutonomousProfitBenchmark["status"] = "learning";
  if (cashAlpha >= 0 && riskAdjustedAlpha >= 0 && hotAlpha >= 0) status = "beating-cash";
  if (cashAlpha < 0) status = "lagging-cash";
  if (selectedToken && selectedAlpha >= 0 && cashAlpha >= 0) status = "beating-selected";
  if (selectedToken && selectedAlpha < 0 && cashAlpha >= 0) status = "lagging-selected";
  if (makeMoneyPulse.protective_sell_required || walletTelemetry.status === "protect" || riskScore < 45) status = "protecting-capital";
  const items: AutonomousProfitBenchmarkItem[] = [
    {
      id: "cash",
      label: "Cash baseline",
      status: cashAlpha >= 0 ? "pass" : "fail",
      score: cashScore,
      value: formatSignedCompactValue(cashAlpha),
      detail: `${formatCompactValue(agentEquity)} agent equity versus ${formatCompactValue(startingCash)} idle cash.`,
    },
    {
      id: "selected-coin",
      label: "Selected coin",
      status: selectedToken ? selectedAlpha >= 0 ? "pass" : "watch" : "watch",
      score: selectedScore,
      value: selectedToken ? formatSignedCompactValue(selectedAlpha) : "none",
      detail: selectedToken
        ? `${selectedToken.symbol} one-hour baseline is ${formatCompactValue(selectedBaseline)} from ${formatPct(selectedToken.price_change_1h_pct)} 1h tape.`
        : "No selected coin benchmark is active while the desk is standing down.",
    },
    {
      id: "hot-coin",
      label: "Hot coin",
      status: hotAlpha >= 0 ? "pass" : opportunityGap > startingCash * 0.08 ? "fail" : "watch",
      score: hotScore,
      value: hotToken ? formatSignedCompactValue(hotAlpha) : "none",
      detail: hotToken
        ? `${hotToken.symbol} is the hindsight heat check; ${formatCompactValue(opportunityGap)} gap is learning signal, not chase permission.`
        : "No visible hot-coin tape is available.",
    },
    {
      id: "risk",
      label: "Risk adjusted",
      status: riskAdjustedAlpha >= 0 && riskScore >= 60 ? "pass" : riskScore < 45 ? "fail" : "watch",
      score: riskScore,
      value: formatSignedCompactValue(riskAdjustedAlpha),
      detail: `${roundMetric(walletTelemetry.max_drawdown_pct)}% drawdown penalty against ${formatCompactValue(walletTelemetry.exposure_usd)} exposure.`,
    },
    {
      id: "execution",
      label: "Execution edge",
      status: executionScore >= 64 ? "pass" : executionScore < 42 ? "fail" : "watch",
      score: executionScore,
      value: `${makeMoneyPulse.pulse_score}/100`,
      detail: `${makeMoneyPulse.status} pulse with ${profitLaneScoreboard.status} profit lanes and ${marketEvidenceFusion.status} market evidence.`,
    },
  ];
  return {
    mode: "autonomous-profit-benchmark",
    status,
    benchmark_score: benchmarkScore,
    agent_equity_usd: roundMetric(agentEquity),
    cash_baseline_usd: roundMetric(startingCash),
    selected_coin_baseline_usd: roundMetric(selectedBaseline),
    hot_coin_baseline_usd: roundMetric(hotBaseline),
    cash_alpha_usd: roundMetric(cashAlpha),
    selected_coin_alpha_usd: roundMetric(selectedAlpha),
    hot_coin_alpha_usd: roundMetric(hotAlpha),
    opportunity_gap_usd: roundMetric(opportunityGap),
    risk_adjusted_alpha_usd: roundMetric(riskAdjustedAlpha),
    selected_symbol: selectedToken?.symbol ?? null,
    hot_coin_symbol: hotToken?.symbol ?? null,
    conclusion: autonomousProfitBenchmarkConclusion(status, benchmarkScore, cashAlpha, hotAlpha, opportunityGap, hotToken?.symbol ?? null),
    next_action: autonomousProfitBenchmarkNextAction(status, makeMoneyPulse, opportunityGap, hotToken?.symbol ?? null),
    controls: [
      "Benchmarks compare the local paper wallet against idle cash and visible one-hour memecoin tape.",
      "Hot-coin alpha is a hindsight learning signal; it cannot override route, safety, wallet, or protection gates.",
      "Risk-adjusted alpha subtracts drawdown pressure so the agent is rewarded for protecting capital, not just chasing volatility.",
    ],
    items,
  };
}

function tokenBenchmarkValue(startingCash: number, token: MemecoinMarket) {
  const move = clamp(token.price_change_1h_pct, -95, 400);
  return Math.max(0, startingCash * (1 + move / 100));
}

function tokenBenchmarkHeatScore(token: MemecoinMarket) {
  const buyShare = token.buys_5m + token.sells_5m > 0 ? token.buys_5m / (token.buys_5m + token.sells_5m) : 0.5;
  return (
    token.price_change_5m_pct * 4 +
    token.price_change_1h_pct * 1.7 +
    token.price_change_6h_pct * 0.25 +
    Math.min(80, token.volume_1h_usd / Math.max(1, token.liquidity_usd) * 22) +
    buyShare * 30 -
    token.risk_flags.length * 10 -
    (token.liquidity_usd < 100_000 ? 24 : 0)
  );
}

function autonomousProfitBenchmarkConclusion(
  status: AutonomousProfitBenchmark["status"],
  score: number,
  cashAlpha: number,
  hotAlpha: number,
  opportunityGap: number,
  hotSymbol: string | null,
) {
  if (status === "protecting-capital") return `Benchmark ${score}/100: protect capital first; paper alpha is ${formatSignedCompactValue(cashAlpha)} versus cash while hot-coin gap is ${formatCompactValue(opportunityGap)}.`;
  if (status === "lagging-cash") return `Benchmark ${score}/100: the paper agent is lagging idle cash by ${formatCompactValue(Math.abs(cashAlpha))}; tighten size and learn before pressing.`;
  if (hotAlpha >= 0) return `Benchmark ${score}/100: the paper agent beats cash and the visible ${hotSymbol ?? "hot-coin"} baseline right now.`;
  if (status === "lagging-selected") return `Benchmark ${score}/100: agent beats cash but trails the selected-coin baseline; use this as sizing and target-selection feedback.`;
  return `Benchmark ${score}/100: paper alpha is ${formatSignedCompactValue(cashAlpha)} versus cash; hottest visible gap is ${formatCompactValue(opportunityGap)}.`;
}

function autonomousProfitBenchmarkNextAction(
  status: AutonomousProfitBenchmark["status"],
  makeMoneyPulse: AutonomousMakeMoneyPulse,
  opportunityGap: number,
  hotSymbol: string | null,
) {
  if (status === "lagging-cash") return "Shrink fresh size, keep protection armed, and require the next pulse to prove positive paper alpha before pressing.";
  if (status === "protecting-capital") return makeMoneyPulse.next_action;
  if (opportunityGap > 0 && hotSymbol) return `Review why ${hotSymbol} beat the paper wallet, then feed the lesson into signal/noise and lane sizing without bypassing safety gates.`;
  if (makeMoneyPulse.action === "paper-attack" || makeMoneyPulse.action === "paper-probe") return `Let the pulse run its bounded paper action, then compare equity against cash and hot-coin baselines on the next tick.`;
  return "Keep collecting paper-loop evidence until the benchmark proves repeatable alpha over cash and visible hot-coin alternatives.";
}

function buildAutonomousAlphaFeedbackLoop({
  benchmark,
  makeMoneyPulse,
  walletTelemetry,
  profitLaneScoreboard,
}: {
  benchmark: AutonomousProfitBenchmark;
  makeMoneyPulse: AutonomousMakeMoneyPulse;
  walletTelemetry: AutonomousWalletTelemetry;
  profitLaneScoreboard: AutonomousProfitLaneScoreboard;
}): AutonomousAlphaFeedbackLoop {
  const missedAlphaUsd = Math.max(0, benchmark.opportunity_gap_usd);
  const riskPenaltyUsd = Math.max(0, benchmark.cash_alpha_usd - benchmark.risk_adjusted_alpha_usd);
  const cashAlphaRatio = benchmark.cash_baseline_usd > 0 ? benchmark.cash_alpha_usd / benchmark.cash_baseline_usd : 0;
  const gapRatio = benchmark.cash_baseline_usd > 0 ? missedAlphaUsd / benchmark.cash_baseline_usd : 0;
  const targetBiasScore = clamp(Math.round(
    50 +
      gapRatio * 180 +
      (benchmark.hot_coin_symbol && benchmark.hot_coin_symbol !== benchmark.selected_symbol ? 12 : 0) -
      (makeMoneyPulse.protective_sell_required ? 20 : 0) -
      walletTelemetry.max_drawdown_pct * 4,
  ), 0, 100);
  let status: AutonomousAlphaFeedbackLoop["status"] = "learn";
  let action: AutonomousAlphaFeedbackLoop["action"] = "collect-evidence";
  if (makeMoneyPulse.protective_sell_required || benchmark.status === "protecting-capital") {
    status = "protect";
    action = "protect-capital";
  } else if (benchmark.status === "lagging-cash" || benchmark.risk_adjusted_alpha_usd < 0) {
    status = "tighten";
    action = "tighten-size";
  } else if (targetBiasScore >= 68 && benchmark.hot_coin_symbol && benchmark.hot_coin_symbol !== benchmark.selected_symbol) {
    status = "retarget";
    action = "retarget-hot-lane";
  } else if (benchmark.cash_alpha_usd >= 0 && benchmark.risk_adjusted_alpha_usd >= 0 && makeMoneyPulse.fresh_buy_allowed) {
    status = "press";
    action = "increase-bias";
  } else if (makeMoneyPulse.status === "blocked" || benchmark.benchmark_score < 35) {
    status = "idle";
    action = "stand-down";
  }
  const sizeBias = autonomousAlphaFeedbackSizeBias(status, cashAlphaRatio, gapRatio, makeMoneyPulse, walletTelemetry);
  const feedbackScore = clamp(Math.round(
    benchmark.benchmark_score * 0.38 +
      makeMoneyPulse.pulse_score * 0.24 +
      profitLaneScoreboard.make_money_score * 0.18 +
      targetBiasScore * 0.12 +
      (status === "press" ? 8 : status === "protect" ? 4 : 0) -
      walletTelemetry.max_drawdown_pct * 2,
  ), 0, 100);
  const reviewAfterSeconds = Math.max(5, Math.min(
    makeMoneyPulse.reaction_seconds,
    profitLaneScoreboard.review_after_seconds,
    status === "retarget" || status === "tighten" ? 15 : 45,
  ));
  const items: AutonomousAlphaFeedbackItem[] = [
    {
      id: "benchmark",
      label: "Benchmark",
      status: benchmark.cash_alpha_usd >= 0 ? "pass" : "fail",
      score: benchmark.benchmark_score,
      value: formatSignedCompactValue(benchmark.cash_alpha_usd),
      detail: `${benchmark.status.replace("-", " ")} with ${formatSignedCompactValue(benchmark.risk_adjusted_alpha_usd)} risk-adjusted alpha.`,
    },
    {
      id: "gap",
      label: "Missed alpha",
      status: missedAlphaUsd <= benchmark.cash_baseline_usd * 0.03 ? "pass" : missedAlphaUsd >= benchmark.cash_baseline_usd * 0.1 ? "fail" : "watch",
      score: clamp(Math.round(100 - gapRatio * 280), 0, 100),
      value: formatCompactValue(missedAlphaUsd),
      detail: benchmark.hot_coin_symbol ? `${benchmark.hot_coin_symbol} is the visible hot-tape learning comparison.` : "No hot-tape learning symbol is available.",
    },
    {
      id: "target",
      label: "Target bias",
      status: targetBiasScore >= 68 ? "watch" : targetBiasScore <= 35 ? "fail" : "pass",
      score: targetBiasScore,
      value: benchmark.hot_coin_symbol ?? "none",
      detail: benchmark.hot_coin_symbol && benchmark.hot_coin_symbol !== benchmark.selected_symbol
        ? `Retarget review compares ${benchmark.selected_symbol ?? "desk"} against ${benchmark.hot_coin_symbol}.`
        : "Current target and hot-tape evidence are aligned enough for this tick.",
    },
    {
      id: "sizing",
      label: "Sizing",
      status: sizeBias >= 0.9 ? "pass" : sizeBias < 0.55 ? "fail" : "watch",
      score: clamp(Math.round(sizeBias * 100), 0, 100),
      value: `${sizeBias}x`,
      detail: `${status.replace("-", " ")} feedback adjusts next paper sizing without bypassing gates.`,
    },
    {
      id: "protection",
      label: "Protection",
      status: makeMoneyPulse.protective_sell_required ? "fail" : riskPenaltyUsd > benchmark.cash_baseline_usd * 0.04 ? "watch" : "pass",
      score: clamp(Math.round(100 - riskPenaltyUsd / Math.max(1, benchmark.cash_baseline_usd) * 250), 0, 100),
      value: formatCompactValue(riskPenaltyUsd),
      detail: makeMoneyPulse.protective_sell_required ? makeMoneyPulse.next_action : `${roundMetric(walletTelemetry.max_drawdown_pct)}% drawdown penalty is tracked before pressing.`,
    },
  ];
  return {
    mode: "autonomous-alpha-feedback-loop",
    status,
    action,
    feedback_score: feedbackScore,
    size_bias: sizeBias,
    target_bias_score: targetBiasScore,
    missed_alpha_usd: roundMetric(missedAlphaUsd),
    risk_penalty_usd: roundMetric(riskPenaltyUsd),
    learning_symbol: status === "retarget" ? benchmark.hot_coin_symbol : benchmark.selected_symbol ?? benchmark.hot_coin_symbol,
    review_after_seconds: reviewAfterSeconds,
    summary: autonomousAlphaFeedbackSummary(status, sizeBias, missedAlphaUsd, benchmark.hot_coin_symbol, benchmark.cash_alpha_usd),
    next_action: autonomousAlphaFeedbackNextAction(action, benchmark.hot_coin_symbol, reviewAfterSeconds, makeMoneyPulse),
    controls: [
      "Alpha feedback turns benchmark gaps into local paper sizing, target-review, protect, or evidence-collection bias.",
      "Hindsight hot-coin gaps are learning signals only; they cannot override safety, route, trigger, or wallet gates.",
      "Feedback changes local paper posture and review cadence, not live signing or real-wallet execution.",
    ],
    items,
  };
}

function autonomousAlphaFeedbackSizeBias(
  status: AutonomousAlphaFeedbackLoop["status"],
  cashAlphaRatio: number,
  gapRatio: number,
  makeMoneyPulse: AutonomousMakeMoneyPulse,
  walletTelemetry: AutonomousWalletTelemetry,
) {
  if (status === "protect" || makeMoneyPulse.protective_sell_required) return 0;
  if (status === "tighten") return roundMetric(clamp(0.42 + Math.max(0, cashAlphaRatio) * 0.8, 0.32, 0.62));
  if (status === "retarget") return roundMetric(clamp(0.52 + gapRatio * 0.8, 0.45, 0.82));
  if (status === "press") return roundMetric(clamp(0.9 + cashAlphaRatio * 1.6 - walletTelemetry.max_drawdown_pct / 40, 0.82, 1.18));
  if (status === "idle") return 0;
  return roundMetric(clamp(0.62 - walletTelemetry.max_drawdown_pct / 45, 0.4, 0.72));
}

function autonomousAlphaFeedbackSummary(
  status: AutonomousAlphaFeedbackLoop["status"],
  sizeBias: number,
  missedAlphaUsd: number,
  hotSymbol: string | null,
  cashAlphaUsd: number,
) {
  if (status === "press") return `Alpha feedback presses with ${sizeBias}x paper bias because cash alpha is ${formatSignedCompactValue(cashAlphaUsd)} and protection gates are clear.`;
  if (status === "retarget") return `Alpha feedback retargets review toward ${hotSymbol ?? "the hot tape"} after ${formatCompactValue(missedAlphaUsd)} missed visible alpha.`;
  if (status === "tighten") return `Alpha feedback tightens size to ${sizeBias}x until paper alpha beats idle cash again.`;
  if (status === "protect") return "Alpha feedback protects capital first; held-position and trigger gates outrank new alpha capture.";
  if (status === "idle") return "Alpha feedback stands down while the current blocker stack prevents useful paper learning.";
  return `Alpha feedback keeps learning with ${sizeBias}x paper bias and no live-wallet authority.`;
}

function autonomousAlphaFeedbackNextAction(
  action: AutonomousAlphaFeedbackLoop["action"],
  hotSymbol: string | null,
  reviewAfterSeconds: number,
  makeMoneyPulse: AutonomousMakeMoneyPulse,
) {
  if (action === "increase-bias") return `Allow the next bounded paper action, then review alpha again in ${reviewAfterSeconds}s.`;
  if (action === "retarget-hot-lane") return `Review ${hotSymbol ?? "the hot tape"} against current safety and route gates before the next paper entry.`;
  if (action === "tighten-size") return `Tighten fresh paper size and require benchmark recovery within ${reviewAfterSeconds}s.`;
  if (action === "protect-capital") return makeMoneyPulse.next_action;
  if (action === "stand-down") return "Stand down until the paper loop has a cleaner benchmark and blocker stack.";
  return `Collect one more evidence tick, then re-score alpha feedback in ${reviewAfterSeconds}s.`;
}

function buildAutonomousProfitThesisVerifier({
  benchmark,
  makeMoneyPulse,
  alphaFeedback,
  walletTelemetry,
  profitLaneScoreboard,
}: {
  benchmark: AutonomousProfitBenchmark;
  makeMoneyPulse: AutonomousMakeMoneyPulse;
  alphaFeedback: AutonomousAlphaFeedbackLoop;
  walletTelemetry: AutonomousWalletTelemetry;
  profitLaneScoreboard: AutonomousProfitLaneScoreboard;
}): AutonomousProfitThesisVerifier {
  const cashBase = Math.max(1, benchmark.cash_baseline_usd);
  const cashAlphaRatio = benchmark.cash_alpha_usd / cashBase;
  const riskAdjustedRatio = benchmark.risk_adjusted_alpha_usd / cashBase;
  const missedAlphaRatio = Math.max(0, benchmark.opportunity_gap_usd) / cashBase;
  const drawdownPenalty = Math.max(0, walletTelemetry.max_drawdown_pct);
  const evidenceScore = clamp(Math.round(
    makeMoneyPulse.market_score * 0.26 +
      makeMoneyPulse.profit_score * 0.18 +
      benchmark.benchmark_score * 0.22 +
      profitLaneScoreboard.make_money_score * 0.2 +
      alphaFeedback.feedback_score * 0.14,
  ), 0, 100);
  const outcomeScore = clamp(Math.round(
    52 +
      cashAlphaRatio * 520 +
      riskAdjustedRatio * 420 -
      missedAlphaRatio * 210 -
      drawdownPenalty * 3.2,
  ), 0, 100);
  const alphaScore = clamp(Math.round(
    alphaFeedback.feedback_score * 0.36 +
      benchmark.benchmark_score * 0.24 +
      alphaFeedback.target_bias_score * 0.16 +
      makeMoneyPulse.pulse_score * 0.16 +
      (benchmark.cash_alpha_usd >= 0 ? 8 : -10),
  ), 0, 100);
  const riskScore = clamp(Math.round(
    makeMoneyPulse.protection_score * 0.34 +
      (makeMoneyPulse.protective_sell_required ? 0 : 24) +
      (benchmark.risk_adjusted_alpha_usd >= 0 ? 18 : 2) +
      Math.max(0, 24 - drawdownPenalty * 3) -
      Math.min(18, Math.max(0, alphaFeedback.risk_penalty_usd / cashBase) * 180),
  ), 0, 100);
  const thesisScore = clamp(Math.round(
    evidenceScore * 0.28 +
      outcomeScore * 0.24 +
      alphaScore * 0.22 +
      riskScore * 0.18 +
      makeMoneyPulse.loop_score * 0.08,
  ), 0, 100);
  let status: AutonomousProfitThesisVerifier["status"] = "learning";
  let action: AutonomousProfitThesisVerifier["action"] = "collect-evidence";
  if (makeMoneyPulse.protective_sell_required || alphaFeedback.status === "protect" || benchmark.status === "protecting-capital") {
    status = "protect";
    action = "protect-capital";
  } else if (makeMoneyPulse.status === "blocked" || alphaFeedback.status === "idle") {
    status = "blocked";
    action = "block-thesis";
  } else if (alphaFeedback.status === "retarget") {
    status = "retarget";
    action = "retarget-thesis";
  } else if (alphaFeedback.status === "tighten" || benchmark.risk_adjusted_alpha_usd < 0 || thesisScore < 42) {
    status = "tighten";
    action = "tighten-size";
  } else if (thesisScore >= 72 && makeMoneyPulse.fresh_buy_allowed && alphaFeedback.size_bias >= 0.78) {
    status = "validated";
    action = "press-thesis";
  } else if (thesisScore >= 50 && makeMoneyPulse.fresh_buy_allowed) {
    status = "probing";
    action = "probe-thesis";
  }
  const sizingMultiplier = autonomousProfitThesisSizing(status, thesisScore, alphaFeedback.size_bias);
  const missedAlphaUsd = Math.max(0, benchmark.opportunity_gap_usd);
  const chaseAllowed = makeMoneyPulse.fresh_buy_allowed &&
    !makeMoneyPulse.protective_sell_required &&
    status !== "protect" &&
    status !== "blocked" &&
    status !== "tighten";
  const chaseUrgencyScore = chaseAllowed
    ? clamp(Math.round(
      thesisScore * 0.28 +
        alphaFeedback.target_bias_score * 0.24 +
        makeMoneyPulse.market_score * 0.18 +
        profitLaneScoreboard.trade_frequency_score * 0.14 +
        clamp(Math.round(missedAlphaRatio * 520), 0, 18) -
        Math.max(0, walletTelemetry.max_drawdown_pct - 2.5) * 4,
    ), 0, 100)
    : 0;
  const chaseSizeMultiplier = chaseAllowed
    ? roundMetric(clamp(
      sizingMultiplier *
        (status === "retarget" ? 1.08 : status === "validated" ? 1.02 : 0.88) +
        Math.min(0.18, missedAlphaRatio * 1.4) -
        Math.max(0, walletTelemetry.max_drawdown_pct - 3) / 60,
      status === "validated" ? 0.72 : 0.32,
      status === "validated" ? 1.2 : status === "retarget" ? 0.92 : 0.72,
    ))
    : 0;
  const baseChaseBudgetUsd = Math.max(
    makeMoneyPulse.deploy_now_usd,
    profitLaneScoreboard.expected_net_profit_usd > 0 ? profitLaneScoreboard.expected_net_profit_usd * 4 : 0,
    missedAlphaUsd > 0 ? missedAlphaUsd * 0.12 : 0,
  );
  const chaseBudgetUsd = chaseAllowed
    ? Math.round(Math.max(0, Math.min(baseChaseBudgetUsd, makeMoneyPulse.deploy_now_usd || baseChaseBudgetUsd) * chaseSizeMultiplier))
    : 0;
  const reviewAfterSeconds = Math.max(5, Math.min(
    makeMoneyPulse.reaction_seconds,
    alphaFeedback.review_after_seconds,
    profitLaneScoreboard.review_after_seconds,
    chaseUrgencyScore >= 72 ? 8 : status === "validated" || status === "probing" ? 12 : 45,
  ));
  const targetSymbol = alphaFeedback.learning_symbol ?? makeMoneyPulse.target_symbol ?? benchmark.selected_symbol ?? benchmark.hot_coin_symbol;
  const expectedNetEdgeUsd = roundMetric(
    benchmark.risk_adjusted_alpha_usd +
      makeMoneyPulse.expected_profit_per_minute_usd * (reviewAfterSeconds / 60) -
      Math.max(0, benchmark.opportunity_gap_usd) * (status === "retarget" ? 0.05 : 0.12),
  );
  const blockers = [
    ...makeMoneyPulse.blockers,
    ...(benchmark.risk_adjusted_alpha_usd < 0 ? [`Risk-adjusted alpha is ${formatSignedCompactValue(benchmark.risk_adjusted_alpha_usd)}.`] : []),
    ...(alphaFeedback.status === "retarget" ? [`Hot-tape comparison points to ${benchmark.hot_coin_symbol ?? "another target"}.`] : []),
    ...(walletTelemetry.max_drawdown_pct > 4 ? [`Wallet drawdown is ${roundMetric(walletTelemetry.max_drawdown_pct)}%.`] : []),
  ].slice(0, 5);
  const items: AutonomousProfitThesisItem[] = [
    {
      id: "setup",
      label: "Setup",
      status: makeMoneyPulse.fresh_buy_allowed ? "pass" : makeMoneyPulse.protective_sell_required ? "fail" : "watch",
      score: makeMoneyPulse.pulse_score,
      value: makeMoneyPulse.target_symbol ?? "desk",
      detail: `${makeMoneyPulse.status.replace("-", " ")} pulse with ${makeMoneyPulse.action.replace("-", " ")} action.`,
    },
    {
      id: "evidence",
      label: "Evidence",
      status: evidenceScore >= 70 ? "pass" : evidenceScore < 45 ? "fail" : "watch",
      score: evidenceScore,
      value: `${evidenceScore}/100`,
      detail: `${profitLaneScoreboard.status.replace("-", " ")} lane and ${benchmark.status.replace("-", " ")} benchmark are fused.`,
    },
    {
      id: "outcome",
      label: "Outcome",
      status: outcomeScore >= 64 ? "pass" : outcomeScore < 42 ? "fail" : "watch",
      score: outcomeScore,
      value: formatSignedCompactValue(benchmark.cash_alpha_usd),
      detail: `${formatSignedCompactValue(benchmark.risk_adjusted_alpha_usd)} after risk and ${formatCompactValue(benchmark.opportunity_gap_usd)} opportunity gap.`,
    },
    {
      id: "alpha",
      label: "Alpha",
      status: alphaScore >= 68 ? "pass" : alphaScore < 45 ? "fail" : "watch",
      score: alphaScore,
      value: `${sizingMultiplier}x`,
      detail: `${alphaFeedback.status.replace("-", " ")} feedback sets the next paper sizing multiplier.`,
    },
    {
      id: "risk",
      label: "Risk",
      status: riskScore >= 70 ? "pass" : riskScore < 45 ? "fail" : "watch",
      score: riskScore,
      value: `${riskScore}/100`,
      detail: makeMoneyPulse.protective_sell_required ? makeMoneyPulse.next_action : `${roundMetric(drawdownPenalty)}% drawdown and trigger coverage are inside the thesis score.`,
    },
  ];
  return {
    mode: "autonomous-profit-thesis-verifier",
    status,
    action,
    target_symbol: targetSymbol,
    thesis_score: thesisScore,
    evidence_score: evidenceScore,
    outcome_score: outcomeScore,
    alpha_score: alphaScore,
    risk_score: riskScore,
    sizing_multiplier: sizingMultiplier,
    chase_urgency_score: chaseUrgencyScore,
    chase_size_multiplier: chaseSizeMultiplier,
    chase_budget_usd: roundMetric(chaseBudgetUsd),
    expected_net_edge_usd: expectedNetEdgeUsd,
    missed_alpha_usd: roundMetric(missedAlphaUsd),
    review_after_seconds: reviewAfterSeconds,
    summary: autonomousProfitThesisSummary(status, thesisScore, targetSymbol, expectedNetEdgeUsd),
    next_action: autonomousProfitThesisNextAction(action, targetSymbol, reviewAfterSeconds, makeMoneyPulse),
    blockers,
    controls: [
      "Profit thesis must beat idle cash, visible hot-coin opportunity, and risk-adjusted paper outcome before pressing size.",
      "Chase pressure converts missed visible alpha into a bounded local paper urgency, size multiplier, and budget for the opportunity ranker.",
      "Retarget, tighten, protect, and block verdicts reduce or stop fresh paper entries before any live signing path is considered.",
      "Thesis sizing is bounded by local paper evidence and cannot override custody, route, trigger, or wallet protection gates.",
    ],
    items,
  };
}

function autonomousProfitThesisSizing(
  status: AutonomousProfitThesisVerifier["status"],
  thesisScore: number,
  alphaSizeBias: number,
) {
  if (status === "protect" || status === "blocked") return 0;
  if (status === "tighten") return roundMetric(clamp(alphaSizeBias * 0.68, 0.28, 0.52));
  if (status === "retarget") return roundMetric(clamp(alphaSizeBias * 0.84, 0.38, 0.78));
  if (status === "validated") return roundMetric(clamp(alphaSizeBias * (0.92 + thesisScore / 220), 0.78, 1.2));
  if (status === "probing") return roundMetric(clamp(alphaSizeBias * 0.78, 0.42, 0.72));
  return roundMetric(clamp(alphaSizeBias * 0.62, 0.28, 0.58));
}

function autonomousProfitThesisSummary(
  status: AutonomousProfitThesisVerifier["status"],
  thesisScore: number,
  targetSymbol: string | null,
  expectedNetEdgeUsd: number,
) {
  if (status === "validated") return `Profit thesis validates ${targetSymbol ?? "the current target"} at ${thesisScore}/100 with ${formatSignedCompactValue(expectedNetEdgeUsd)} expected net edge.`;
  if (status === "probing") return `Profit thesis probes ${targetSymbol ?? "the target"} at ${thesisScore}/100; size stays bounded until outcome evidence improves.`;
  if (status === "retarget") return `Profit thesis retargets toward ${targetSymbol ?? "the hot tape"} because the visible opportunity gap is stronger than the current wallet result.`;
  if (status === "tighten") return `Profit thesis tightens size at ${thesisScore}/100 until risk-adjusted paper alpha improves.`;
  if (status === "protect") return "Profit thesis protects capital first; held-position and trigger gates outrank fresh entries.";
  if (status === "blocked") return "Profit thesis blocks fresh entries because the current blocker stack makes the next trade unprofitable to learn from.";
  return `Profit thesis keeps learning at ${thesisScore}/100 before increasing trade frequency.`;
}

function autonomousProfitThesisNextAction(
  action: AutonomousProfitThesisVerifier["action"],
  targetSymbol: string | null,
  reviewAfterSeconds: number,
  makeMoneyPulse: AutonomousMakeMoneyPulse,
) {
  if (action === "press-thesis") return `Press the bounded paper thesis on ${targetSymbol ?? "the current target"}, then verify wallet alpha again in ${reviewAfterSeconds}s.`;
  if (action === "probe-thesis") return `Probe ${targetSymbol ?? "the target"} with reduced size and re-score the thesis in ${reviewAfterSeconds}s.`;
  if (action === "retarget-thesis") return `Retarget review to ${targetSymbol ?? "the strongest visible tape"} before allowing another fresh paper entry.`;
  if (action === "tighten-size") return `Reduce fresh paper size and require a better risk-adjusted outcome within ${reviewAfterSeconds}s.`;
  if (action === "protect-capital") return makeMoneyPulse.next_action;
  if (action === "block-thesis") return "Block fresh entries until pulse, benchmark, and protection evidence produce a useful trade thesis.";
  return `Collect another evidence tick, then re-run the profit thesis in ${reviewAfterSeconds}s.`;
}

function buildAutonomousOpportunityRanker({
  scanner,
  alphaQuality,
  trapRadar,
  tradeability,
  thesis,
}: {
  scanner: LiveScannerReadiness;
  alphaQuality: AutonomousAlphaQuality;
  trapRadar: AutonomousTrapRadar;
  tradeability: AutonomousTradeabilitySimulator;
  thesis: AutonomousProfitThesisVerifier;
}): AutonomousOpportunityRanker {
  const scannerBySymbol = new Map(scanner.items.map((item) => [item.symbol, item]));
  const alphaBySymbol = new Map(alphaQuality.items.map((item) => [item.symbol, item]));
  const trapBySymbol = new Map(trapRadar.items.map((item) => [item.symbol, item]));
  const tradeabilityBySymbol = new Map(tradeability.items.map((item) => [item.symbol, item]));
  const symbols = [...new Set([
    ...scanner.items.map((item) => item.symbol),
    ...alphaQuality.items.map((item) => item.symbol),
    ...trapRadar.items.map((item) => item.symbol),
    ...tradeability.items.map((item) => item.symbol),
    thesis.target_symbol,
  ].filter((item): item is string => Boolean(item)))].slice(0, 10);

  const items = symbols.map((symbol): AutonomousOpportunityRankItem => {
    const scannerItem = scannerBySymbol.get(symbol);
    const alpha = alphaBySymbol.get(symbol);
    const trap = trapBySymbol.get(symbol);
    const trade = tradeabilityBySymbol.get(symbol);
    const tokenId = scannerItem?.token_id ?? alpha?.token_id ?? trap?.token_id ?? trade?.token_id ?? symbol.toLowerCase();
    const scannerScore = scannerItem?.scanner_score ?? 0;
    const alphaScore = alpha?.alpha_quality_score ?? 0;
    const trapClearanceScore = trap
      ? clamp(Math.round((100 - trap.trap_score) * 0.56 + trap.chase_score * 0.44), 0, 100)
      : 50;
    const tradeabilityScore = trade?.tradeability_score ?? 0;
    const chaseTarget = thesis.target_symbol === symbol;
    const chaseUrgency = chaseTarget ? thesis.chase_urgency_score : 0;
    const thesisFitScore = chaseTarget
      ? clamp(Math.round(thesis.thesis_score * 0.68 + chaseUrgency * 0.32), 0, 100)
      : clamp(Math.round(
        48 +
          (thesis.status === "retarget" ? 12 : 0) +
          (scannerItem?.action === "attack" ? 10 : scannerItem?.action === "probe" ? 5 : 0) +
          (alpha?.tradable_now ? 8 : 0) -
          (thesis.status === "protect" ? 18 : thesis.status === "blocked" ? 22 : 0),
      ), 0, 100);
    const noiseScore = Math.max(alpha?.noise_score ?? 0, trap ? trap.trap_score : 0, scannerItem?.paid_hype_score ?? 0);
    const opportunityScore = clamp(Math.round(
      scannerScore * 0.2 +
        alphaScore * 0.24 +
        trapClearanceScore * 0.18 +
        tradeabilityScore * 0.22 +
        thesisFitScore * 0.16 -
        noiseScore * 0.08 +
        chaseUrgency * 0.08,
    ), 0, 100);
    const blockers = [...new Set([
      ...(scannerItem?.blockers ?? []),
      ...(alpha?.blockers ?? []),
      ...(trap?.blockers ?? []),
      ...(trade?.blockers ?? []),
      thesis.status === "protect" ? "Profit thesis is protect-first; fresh entries wait behind capital protection." : null,
      thesis.status === "blocked" ? "Profit thesis blocks fresh entries until evidence improves." : null,
      trap?.verdict === "trap" || trap?.verdict === "exit-only" ? trap.reason : null,
      noiseScore >= 78 ? "Noise or paid-hype pressure is above the chase ceiling." : null,
    ].filter((item): item is string => Boolean(item)))].slice(0, 6);
    const action = autonomousOpportunityRankAction({
      thesis,
      scannerItem,
      alpha,
      trap,
      trade,
      blockers,
      opportunityScore,
      trapClearanceScore,
      noiseScore,
    });
    const status = autonomousOpportunityRankStatus(action);
    const sizeBase = Math.max(
      scannerItem?.max_paper_size_usd ?? 0,
      alpha?.max_paper_size_usd ?? 0,
      trade?.recommended_size_usd ?? 0,
      trap?.max_chase_usd ?? 0,
      chaseTarget ? thesis.chase_budget_usd : 0,
    );
    const thesisSizeMultiplier = thesis.chase_size_multiplier > 0 ? thesis.chase_size_multiplier : thesis.sizing_multiplier;
    const sizeMultiplier = action === "paper-attack" ? thesisSizeMultiplier || 0.82 : action === "paper-probe" ? Math.max(0.28, Math.min(0.58, thesisSizeMultiplier || 0.42)) : 0;
    const maxPaperSizeUsd = Math.round(Math.max(0, sizeBase * sizeMultiplier));
    const executionDrag = trade?.expected_shortfall_usd ?? 0;
    const expectedEdgeUsd = roundMetric(maxPaperSizeUsd * Math.max(-0.35, (opportunityScore - 50) / 100) + (thesis.target_symbol === symbol ? thesis.expected_net_edge_usd * 0.12 : 0) - executionDrag);
    const reviewAfterSeconds = Math.max(5, Math.min(
      scannerItem?.review_after_seconds ?? 45,
      alpha?.review_after_seconds ?? 45,
      trap?.review_after_seconds ?? 45,
      trade?.review_after_seconds ?? 45,
      thesis.review_after_seconds,
    ));
    return {
      token_id: tokenId,
      symbol,
      status,
      action,
      opportunity_score: opportunityScore,
      scanner_score: scannerScore,
      alpha_quality_score: alphaScore,
      trap_clearance_score: trapClearanceScore,
      tradeability_score: tradeabilityScore,
      thesis_fit_score: thesisFitScore,
      noise_score: noiseScore,
      max_paper_size_usd: maxPaperSizeUsd,
      expected_edge_usd: expectedEdgeUsd,
      review_after_seconds: reviewAfterSeconds,
      decision: autonomousOpportunityRankDecision(action, symbol, opportunityScore, maxPaperSizeUsd, expectedEdgeUsd, blockers),
      evidence: [
        `${scannerScore}/100 scanner`,
        `${alphaScore}/100 alpha quality`,
        `${trapClearanceScore}/100 trap clearance`,
        `${tradeabilityScore}/100 tradeability`,
        `${thesisFitScore}/100 thesis fit`,
        chaseTarget ? `${chaseUrgency}/100 chase urgency` : null,
        `${noiseScore}/100 noise`,
      ].filter((item): item is string => Boolean(item)),
      blockers,
    };
  }).sort((a, b) =>
    autonomousOpportunityActionRank(b.action) - autonomousOpportunityActionRank(a.action) ||
    b.opportunity_score - a.opportunity_score ||
    b.expected_edge_usd - a.expected_edge_usd,
  ).slice(0, 6);

  const leader = items.find((item) => item.action === "paper-attack" || item.action === "paper-probe") ?? items[0] ?? null;
  const attackCount = items.filter((item) => item.action === "paper-attack").length;
  const probeCount = items.filter((item) => item.action === "paper-probe").length;
  const refreshCount = items.filter((item) => item.action === "refresh-proof").length;
  const blockedCount = items.filter((item) => item.action === "block").length;
  const status: AutonomousOpportunityRanker["status"] = thesis.status === "protect"
    ? "protect"
    : thesis.status === "retarget"
      ? "retarget"
      : attackCount > 0
        ? "attack-ready"
        : probeCount > 0
          ? "probe-ready"
          : refreshCount > 0
            ? "refresh"
            : blockedCount > 0
              ? "blocked"
              : items.length > 0
                ? "learning"
                : "idle";

  return {
    mode: "autonomous-opportunity-ranker",
    status,
    leader_symbol: leader?.symbol ?? null,
    leader_action: leader?.action ?? null,
    ranked_count: items.length,
    attack_count: attackCount,
    probe_count: probeCount,
    refresh_count: refreshCount,
    blocked_count: blockedCount,
    best_score: leader?.opportunity_score ?? 0,
    recommended_size_usd: leader?.max_paper_size_usd ?? 0,
    expected_edge_usd: roundMetric(leader?.expected_edge_usd ?? 0),
    fastest_review_seconds: items.length ? Math.min(...items.map((item) => item.review_after_seconds)) : thesis.review_after_seconds,
    summary: autonomousOpportunityRankSummary(status, leader, attackCount, probeCount, refreshCount, blockedCount),
    next_action: leader?.decision ?? "Keep scanning until a candidate clears signal, trap, route, wallet, and thesis checks.",
    controls: [
      "Ranks visible memecoin candidates by scanner readiness, alpha quality, trap clearance, tradeability, and current profit thesis fit.",
      "Attack/probe verdicts are local-paper only and still depend on route, trigger, custody, wallet, and live-execution gates.",
      "Trap, protect, refresh, and block outcomes outrank chase pressure even when a coin is hot.",
    ],
    items,
  };
}

function autonomousOpportunityRankAction({
  thesis,
  scannerItem,
  alpha,
  trap,
  trade,
  blockers,
  opportunityScore,
  trapClearanceScore,
  noiseScore,
}: {
  thesis: AutonomousProfitThesisVerifier;
  scannerItem: LiveScannerReadinessItem | undefined;
  alpha: AutonomousAlphaQualityItem | undefined;
  trap: AutonomousTrapRadarItem | undefined;
  trade: AutonomousTradeabilityItem | undefined;
  blockers: string[];
  opportunityScore: number;
  trapClearanceScore: number;
  noiseScore: number;
}): AutonomousOpportunityRankItem["action"] {
  if (thesis.status === "protect" || trap?.verdict === "exit-only" || alpha?.action === "protect" || trade?.action === "protect") return "protect-capital";
  if (blockers.some((blocker) => /refresh|route|quote|fallback|source|feed/i.test(blocker)) || scannerItem?.action === "refresh" || trade?.action === "requote") return "refresh-proof";
  if (thesis.status === "blocked" || noiseScore >= 86 || trap?.verdict === "trap") return "block";
  if (
    opportunityScore >= 72 &&
    trapClearanceScore >= 58 &&
    (scannerItem?.action === "attack" || alpha?.action === "paper-attack" || trade?.action === "paper-fill") &&
    (thesis.status === "validated" || thesis.status === "probing" || thesis.status === "retarget" || thesis.status === "learning")
  ) return "paper-attack";
  if (
    opportunityScore >= 52 &&
    trapClearanceScore >= 44 &&
    (scannerItem?.action === "probe" || alpha?.action === "paper-probe" || trade?.action === "paper-probe" || thesis.status === "retarget")
  ) return "paper-probe";
  return blockers.length > 0 ? "block" : "watch";
}

function autonomousOpportunityRankStatus(action: AutonomousOpportunityRankItem["action"]): AutonomousOpportunityRankItem["status"] {
  if (action === "paper-attack") return "attack";
  if (action === "paper-probe") return "probe";
  if (action === "refresh-proof") return "refresh";
  if (action === "protect-capital") return "protect";
  if (action === "block") return "blocked";
  return "watch";
}

function autonomousOpportunityActionRank(action: AutonomousOpportunityRankItem["action"]) {
  if (action === "paper-attack") return 6;
  if (action === "paper-probe") return 5;
  if (action === "protect-capital") return 4;
  if (action === "refresh-proof") return 3;
  if (action === "watch") return 2;
  return 1;
}

function autonomousOpportunityRankDecision(
  action: AutonomousOpportunityRankItem["action"],
  symbol: string,
  score: number,
  sizeUsd: number,
  expectedEdgeUsd: number,
  blockers: string[],
) {
  if (action === "paper-attack") return `Ranker chooses ${symbol} for local paper attack up to ${formatCompactValue(sizeUsd)} with ${score}/100 opportunity and ${formatSignedCompactValue(expectedEdgeUsd)} modeled edge.`;
  if (action === "paper-probe") return `Ranker probes ${symbol} up to ${formatCompactValue(sizeUsd)} while the thesis and route evidence keep sizing capped.`;
  if (action === "refresh-proof") return blockers[0] ?? `Refresh route, source, or chart proof for ${symbol} before sizing.`;
  if (action === "protect-capital") return `Protect capital before chasing ${symbol}; held-position and wallet gates have priority.`;
  if (action === "block") return blockers[0] ?? `Block ${symbol}; opportunity rank is not worth paper churn.`;
  return `Watch ${symbol}; opportunity rank is ${score}/100 and not yet worth paper budget.`;
}

function autonomousOpportunityRankSummary(
  status: AutonomousOpportunityRanker["status"],
  leader: AutonomousOpportunityRankItem | null,
  attackCount: number,
  probeCount: number,
  refreshCount: number,
  blockedCount: number,
) {
  if (status === "attack-ready") return `${attackCount} ranked candidate${attackCount === 1 ? "" : "s"} clear the combined scanner, trap, tradeability, and thesis gate.`;
  if (status === "probe-ready") return `${probeCount} candidate${probeCount === 1 ? "" : "s"} can be probed with capped local paper size.`;
  if (status === "retarget") return `${leader?.symbol ?? "The leader"} is the retarget comparison while the current thesis reviews missed hot-tape alpha.`;
  if (status === "protect") return "Opportunity ranker is protect-first; candidate chasing waits behind wallet and held-position defense.";
  if (status === "refresh") return `${refreshCount} candidate${refreshCount === 1 ? "" : "s"} need fresher route, source, or chart evidence before paper sizing.`;
  if (status === "blocked") return `${blockedCount} candidate${blockedCount === 1 ? "" : "s"} are blocked by noise, trap risk, route gaps, or thesis blockers.`;
  if (status === "learning") return `${leader?.symbol ?? "Candidates"} are ranked for learning, but none clear enough evidence to spend paper budget yet.`;
  return "Opportunity ranker is idle until scanner, alpha, trap, and tradeability evidence exist.";
}

function buildAutonomousRotationDirector({
  ranker,
  thesis,
  capitalRotation,
  positionSituation,
  portfolioMark,
  profitIntegrity,
}: {
  ranker: AutonomousOpportunityRanker;
  thesis: AutonomousProfitThesisVerifier;
  capitalRotation: CapitalRotationEngine;
  positionSituation: AutonomousPositionSituationBoard;
  portfolioMark: AutonomousPortfolioMarkBoard;
  profitIntegrity: AutonomousProfitIntegrityCircuit;
}): AutonomousRotationDirector {
  const candidate = ranker.items.find((item) => item.action === "paper-attack" || item.action === "paper-probe") ?? ranker.items[0] ?? null;
  const release = capitalRotation.items.find((item) => item.lane === "release" && item.priority === "now" && item.blockers.length === 0)
    ?? capitalRotation.items.find((item) => item.lane === "release" && item.blockers.length === 0)
    ?? null;
  const deploy = capitalRotation.items.find((item) => item.lane === "deploy" && item.symbol === candidate?.symbol && item.blockers.length === 0)
    ?? capitalRotation.items.find((item) => item.lane === "deploy" && item.blockers.length === 0)
    ?? null;
  const opportunityScore = candidate?.opportunity_score ?? 0;
  const releaseScore = Math.max(
    release?.confidence ?? 0,
    positionSituation.average_situation_score,
    portfolioMark.release_pressure_usd > 0 ? 64 : 0,
  );
  const integrityScore = profitIntegrity.integrity_score;
  const capitalScore = capitalRotation.rotation_score;
  const rotationScore = clamp(Math.round(
    opportunityScore * 0.28 +
      capitalScore * 0.22 +
      integrityScore * 0.22 +
      Math.max(releaseScore, deploy?.confidence ?? 0) * 0.16 +
      thesis.thesis_score * 0.12 -
      (profitIntegrity.should_pause_fresh_buys ? 18 : 0) -
      (positionSituation.fresh_buy_blocked && !release ? 12 : 0),
  ), 0, 100);
  const blockers = [...new Set([
    ...(candidate?.blockers ?? []),
    ...((release?.blockers ?? []).slice(0, 2)),
    ...(profitIntegrity.should_pause_fresh_buys ? ["Profit integrity pauses fresh buys until the wallet loop improves."] : []),
    ...(profitIntegrity.should_protect_first ? ["Profit integrity requires protection before fresh rotation."] : []),
    ...(thesis.status === "blocked" ? ["Profit thesis blocks fresh entries until evidence improves."] : []),
    ...(capitalRotation.status === "blocked" ? ["Capital rotation is blocked by optimizer, route, or safety gates."] : []),
    ...(candidate && candidate.noise_score >= 78 ? ["Candidate noise is above the chase ceiling."] : []),
  ])].slice(0, 6);
  const canDeploy = Boolean(deploy && deploy.size_usd > 0) || capitalRotation.deploy_usd > 0 || (candidate?.max_paper_size_usd ?? 0) > 0;
  const canRelease = Boolean(release && release.size_usd > 0) || capitalRotation.release_usd > 0 || positionSituation.release_usd > 0;
  let status: AutonomousRotationDirector["status"] = "idle";
  let action: AutonomousRotationDirector["action"] = "hold-current";
  if (!candidate && positionSituation.held_count === 0) {
    status = "idle";
    action = "stand-down";
  } else if (blockers.length > 0 && rotationScore < 48) {
    status = "blocked";
    action = "stand-down";
  } else if (profitIntegrity.should_protect_first || positionSituation.fresh_buy_blocked || ranker.status === "protect" || thesis.status === "protect") {
    status = canRelease ? "protect" : "blocked";
    action = canRelease ? "protect-position" : "stand-down";
  } else if (capitalRotation.status === "harvest" || portfolioMark.status === "harvest") {
    status = "harvest";
    action = "harvest-profit";
  } else if (ranker.status === "retarget" || thesis.status === "retarget") {
    status = canDeploy && rotationScore >= 52 ? "retarget" : "hold";
    action = canDeploy && rotationScore >= 52 ? "retarget-hot-coin" : "hold-current";
  } else if (capitalRotation.status === "rotate" && canDeploy && canRelease && rotationScore >= 58) {
    status = "rotate-now";
    action = "rotate-capital";
  } else if ((ranker.status === "attack-ready" || ranker.status === "probe-ready") && canDeploy && rotationScore >= 56) {
    status = "retarget";
    action = "retarget-hot-coin";
  } else {
    status = "hold";
    action = "hold-current";
  }
  const deployUsd = Math.max(deploy?.size_usd ?? 0, capitalRotation.deploy_usd, candidate?.max_paper_size_usd ?? 0);
  const releaseUsd = Math.max(release?.size_usd ?? 0, capitalRotation.release_usd, positionSituation.release_usd);
  const reviewAfterSeconds = Math.max(5, Math.min(
    ranker.fastest_review_seconds,
    thesis.review_after_seconds,
    positionSituation.fastest_review_seconds,
    profitIntegrity.cadence_seconds,
    45,
  ));
  const items: AutonomousRotationDirectorItem[] = [
    {
      id: "candidate",
      label: "Hot candidate",
      status: opportunityScore >= 68 ? "pass" : opportunityScore < 42 ? "fail" : "watch",
      score: opportunityScore,
      value: candidate?.symbol ?? "none",
      detail: candidate ? `${candidate.action.replace("-", " ")} with ${formatSignedCompactValue(candidate.expected_edge_usd)} expected edge.` : "No ranked candidate is clean enough to rotate into.",
    },
    {
      id: "release",
      label: "Release source",
      status: canRelease ? releaseScore >= 58 ? "pass" : "watch" : "fail",
      score: clamp(Math.round(releaseScore), 0, 100),
      value: release?.symbol ?? positionSituation.leader_symbol ?? "none",
      detail: canRelease ? `${formatCompactValue(releaseUsd)} can be released or protected from the held-position book.` : "No held paper position is authorized for release.",
    },
    {
      id: "capital",
      label: "Capital route",
      status: capitalRotation.status === "rotate" || capitalRotation.status === "accumulate" ? "pass" : capitalRotation.status === "blocked" ? "fail" : "watch",
      score: capitalScore,
      value: capitalRotation.status,
      detail: `${formatCompactValue(capitalRotation.deploy_usd)} deploy, ${formatCompactValue(capitalRotation.release_usd)} release, ${capitalRotation.churn_cost_bps} bps churn.`,
    },
    {
      id: "profit",
      label: "Profit thesis",
      status: thesis.status === "validated" || thesis.status === "probing" || thesis.status === "retarget" ? "pass" : thesis.status === "blocked" || thesis.status === "protect" ? "fail" : "watch",
      score: thesis.thesis_score,
      value: thesis.action.replace("-", " "),
      detail: `${formatSignedCompactValue(thesis.expected_net_edge_usd)} thesis edge with ${thesis.sizing_multiplier}x size.`,
    },
    {
      id: "integrity",
      label: "Integrity",
      status: profitIntegrity.can_continue && !profitIntegrity.should_pause_fresh_buys ? "pass" : profitIntegrity.should_protect_first || profitIntegrity.should_pause_fresh_buys ? "fail" : "watch",
      score: integrityScore,
      value: profitIntegrity.permission.replace("-", " "),
      detail: `${profitIntegrity.size_multiplier}x size, ${profitIntegrity.max_next_fills} fills, ${profitIntegrity.cadence_seconds}s cadence.`,
    },
  ];
  return {
    mode: "autonomous-rotation-director",
    status,
    action,
    from_symbol: release?.symbol ?? positionSituation.leader_symbol ?? portfolioMark.leader_symbol ?? null,
    to_symbol: candidate?.symbol ?? ranker.leader_symbol ?? thesis.target_symbol,
    rotation_score: rotationScore,
    opportunity_score: opportunityScore,
    release_score: clamp(Math.round(releaseScore), 0, 100),
    integrity_score: integrityScore,
    expected_edge_usd: roundMetric((candidate?.expected_edge_usd ?? 0) + capitalRotation.expected_pnl_usd + thesis.expected_net_edge_usd * 0.08),
    release_usd: Math.round(releaseUsd),
    deploy_usd: Math.round(deployUsd),
    max_paper_size_usd: Math.round(Math.max(candidate?.max_paper_size_usd ?? 0, deploy?.size_usd ?? 0)),
    review_after_seconds: reviewAfterSeconds,
    summary: autonomousRotationDirectorSummary(status, release?.symbol ?? positionSituation.leader_symbol ?? null, candidate?.symbol ?? null, rotationScore, deployUsd, releaseUsd),
    next_action: autonomousRotationDirectorNextAction(action, release?.symbol ?? positionSituation.leader_symbol ?? null, candidate?.symbol ?? null, reviewAfterSeconds, blockers),
    blockers,
    controls: [
      "Fuses the ranked hot coin, profit thesis, capital rotation, held-position pressure, and profit-integrity circuit into one rotate/retarget/protect/hold directive.",
      "The directive is local-paper only; it cannot sign, submit, custody funds, or override route, trigger, safety, or live-execution gates.",
      "Rotation requires both a clean target and either deployable cash or a justified held-position release, so the agent does not churn just because a coin is noisy.",
    ],
    items,
  };
}

function autonomousRotationDirectorSummary(
  status: AutonomousRotationDirector["status"],
  fromSymbol: string | null,
  toSymbol: string | null,
  score: number,
  deployUsd: number,
  releaseUsd: number,
) {
  if (status === "rotate-now") return `Rotation director clears ${score}/100: release ${fromSymbol ?? "held paper capital"} and rotate toward ${toSymbol ?? "the ranked hot coin"}.`;
  if (status === "retarget") return `Rotation director retargets toward ${toSymbol ?? "the hot lane"} with ${formatCompactValue(deployUsd)} max paper deployment.`;
  if (status === "protect") return `Rotation director protects ${fromSymbol ?? "the held book"} before chasing fresh entries.`;
  if (status === "harvest") return `Rotation director harvests ${formatCompactValue(releaseUsd)} before redeploying into a new runner.`;
  if (status === "blocked") return "Rotation director blocks churn until candidate, release, and integrity gates clear together.";
  if (status === "idle") return "Rotation director is idle because there is no clean ranked candidate or held paper book to rotate.";
  return `Rotation director holds current posture at ${score}/100; no rotation pays for churn yet.`;
}

function autonomousRotationDirectorNextAction(
  action: AutonomousRotationDirector["action"],
  fromSymbol: string | null,
  toSymbol: string | null,
  reviewAfterSeconds: number,
  blockers: string[],
) {
  if (action === "rotate-capital") return `Queue the next local paper rotation from ${fromSymbol ?? "the release source"} into ${toSymbol ?? "the hot candidate"}, then re-score in ${reviewAfterSeconds}s.`;
  if (action === "retarget-hot-coin") return `Retarget the next paper proof cycle to ${toSymbol ?? "the hot candidate"} before adding fresh size.`;
  if (action === "protect-position") return `Protect ${fromSymbol ?? "the held paper book"} first; fresh rotation waits for the next ${reviewAfterSeconds}s review.`;
  if (action === "harvest-profit") return `Harvest paper profit from ${fromSymbol ?? "the held book"} before redeploying.`;
  if (action === "stand-down") return blockers[0] ?? "Stand down until rotation evidence improves.";
  return `Hold current posture and re-check rotation evidence in ${reviewAfterSeconds}s.`;
}

function buildAutonomousOpportunityRankExecution({
  market,
  cycle,
  ranker,
  sourceQuality,
  recentTrades = [],
}: {
  market: MemecoinMarket[];
  cycle: number;
  ranker: AutonomousOpportunityRanker;
  sourceQuality?: AutonomousSourceQualityOracle;
  recentTrades?: AutonomousTrade[];
}): AutonomousOpportunityRankExecution {
  const selected = ranker.items.find((item) => item.action === "paper-attack" || item.action === "paper-probe")
    ?? ranker.items.find((item) => item.action === "refresh-proof" || item.action === "protect-capital" || item.action === "block")
    ?? ranker.items[0]
    ?? null;
  const token = selected
    ? market.find((entry) => entry.id === selected.token_id || entry.symbol === selected.symbol)
    : null;
  const sourceQualityBlocker = selected
    ? autonomousSourceQualityBuyBlocker(sourceQuality, selected.symbol)
    : null;
  const sourceSizedPaperSizeUsd = selected
    ? autonomousSourceQualityAdjustedSizeUsd(sourceQuality, selected.symbol, selected.max_paper_size_usd)
    : 0;
  const sourceQualitySizingBlocker = selected && (selected.action === "paper-attack" || selected.action === "paper-probe")
    ? autonomousSourceQualitySizingBlockerForSize(sourceQuality, selected.symbol, selected.max_paper_size_usd)
    : null;
  const canBuildTrade = Boolean(
    selected &&
      token &&
      (selected.action === "paper-attack" || selected.action === "paper-probe") &&
      sourceSizedPaperSizeUsd >= 10 &&
      selected.blockers.length === 0 &&
      !sourceQualityBlocker &&
      !sourceQualitySizingBlocker,
  );
  const tradeId = selected ? `paper-opportunity-rank-${cycle}-${selected.symbol.toLowerCase()}` : "";
  const ledgerTrade = tradeId ? latestAutonomousTradeById(recentTrades, tradeId) : null;
  const paperTrade: AutonomousTrade | null = ledgerTrade ?? (canBuildTrade && selected && token
    ? {
        id: tradeId,
        side: "buy",
        symbol: selected.symbol,
        size_usd: sourceSizedPaperSizeUsd,
        price_usd: token.price_usd,
        status: "paper-filled",
        reason: autonomousSourceQualityAdjustedReason(
          sourceQuality,
          selected.symbol,
          sourceSizedPaperSizeUsd,
          selected.max_paper_size_usd,
          `Opportunity rank ${selected.action.replace("paper-", "")}: ${selected.decision}`,
        ),
        created_at: shiftedTime(cycle, 96),
      }
    : null);
  const blockers = [...new Set([
    ...(selected?.blockers ?? []),
    selected && !token ? `No market price is available for ${selected.symbol}.` : null,
    selected && (selected.action === "refresh-proof" || selected.action === "protect-capital" || selected.action === "block" || selected.action === "watch")
      ? selected.decision
      : null,
    selected && selected.max_paper_size_usd < 10 && (selected.action === "paper-attack" || selected.action === "paper-probe")
      ? `${selected.symbol} ranked size is below the local paper-ledger minimum.`
      : null,
    sourceQualityBlocker,
    sourceQualitySizingBlocker,
    ranker.status === "protect" ? ranker.next_action : null,
  ].filter((item): item is string => Boolean(item)))].slice(0, 6);
  const ledgerApplied = Boolean(ledgerTrade);
  const paperTradeReady = Boolean(paperTrade && !ledgerApplied && blockers.length === 0);
  const status: AutonomousOpportunityRankExecution["status"] = ledgerApplied
    ? "applied"
    : paperTradeReady
      ? "queued"
      : selected && (blockers.length > 0 || selected.action === "refresh-proof" || selected.action === "protect-capital" || selected.action === "block")
        ? "blocked"
        : "idle";
  const paperSize = Math.round(paperTrade?.size_usd ?? sourceSizedPaperSizeUsd);

  return {
    mode: "opportunity-rank-paper-execution",
    status,
    selected_symbol: selected?.symbol ?? null,
    selected_action: selected?.action ?? null,
    selected_side: paperTrade ? "buy" : "hold",
    paper_trade_ready: paperTradeReady,
    ledger_applied: ledgerApplied,
    paper_trade: paperTrade,
    execution_boundary: "paper-ledger-only",
    paper_size_usd: paperSize,
    expected_edge_usd: selected?.expected_edge_usd ?? 0,
    opportunity_score: selected?.opportunity_score ?? 0,
    review_after_seconds: selected?.review_after_seconds ?? ranker.fastest_review_seconds,
    summary: autonomousOpportunityRankExecutionSummary(status, selected, paperTrade, blockers),
    next_action: autonomousOpportunityRankExecutionNextAction(status, selected, paperTrade, blockers),
    blockers,
    controls: [
      "Turns the top attack/probe opportunity rank into one bounded local paper-ledger buy candidate.",
      "Requires a market price, minimum size, no rank blockers, and the same downstream paper-ledger guardrails before applying.",
      "Fresh opportunity buys are vetoed when source quality marks the candidate paid-hype, refresh-first, blocked, or missing current proof.",
      "Refresh, protect, block, and watch rank outcomes cannot create fresh paper buys.",
      "Cannot sign, submit, custody funds, broadcast swaps, or guarantee profit.",
    ],
  };
}

function autonomousOpportunityRankExecutionSummary(
  status: AutonomousOpportunityRankExecution["status"],
  selected: AutonomousOpportunityRankItem | null,
  trade: AutonomousTrade | null,
  blockers: string[],
) {
  if (status === "applied" && trade) return `Opportunity-ranked paper buy for ${trade.symbol} is already recorded in the local ledger.`;
  if (status === "queued" && trade) return `${trade.symbol} is ranked strongly enough for a ${formatCompactValue(trade.size_usd)} local paper buy.`;
  if (status === "blocked") return blockers[0] ?? `${selected?.symbol ?? "Opportunity rank"} cannot create a paper fill yet.`;
  if (selected) return selected.decision;
  return "Opportunity rank execution is idle until a ranked attack or probe candidate appears.";
}

function autonomousOpportunityRankExecutionNextAction(
  status: AutonomousOpportunityRankExecution["status"],
  selected: AutonomousOpportunityRankItem | null,
  trade: AutonomousTrade | null,
  blockers: string[],
) {
  if (status === "applied" && trade) return `Monitor ${trade.symbol}; the ranked paper buy is already in the ledger.`;
  if (status === "queued" && trade) return `Let the ledger apply ${trade.symbol} only after trigger, readiness, lane-capital, regime, wallet, route, execution, safety, and timing gates clear.`;
  if (status === "blocked") return blockers[0] ?? selected?.decision ?? "Resolve the rank blocker before paper execution.";
  if (selected) return selected.decision;
  return "Keep ranking candidates until one clears attack or probe execution.";
}

function buildLiveScannerReadiness({
  discoveryTape,
  dexStreamFreshness,
  promotionAudit,
  discoveryEdge,
  launchSniper,
  ingestionPlan,
  feedIntegrity,
  signalNoise,
  trendVelocity,
  routeQuoteSampler,
}: {
  discoveryTape: DiscoveryTape;
  dexStreamFreshness?: DexStreamFreshness;
  promotionAudit: PromotionOrderAudit;
  discoveryEdge: DiscoveryEdgeSupervisor;
  launchSniper: LaunchSniper;
  ingestionPlan: MarketIngestionPlan;
  feedIntegrity: MarketFeedIntegrity;
  signalNoise: SignalNoiseScanner;
  trendVelocity: TrendVelocityScanner;
  routeQuoteSampler: RouteQuoteSampler;
}): LiveScannerReadiness {
  const streamFreshness = dexStreamFreshness ?? fallbackDexStreamFreshness(discoveryTape, discoveryEdge, ingestionPlan);
  const signalByToken = new Map(signalNoise.items.map((item) => [item.token_id, item]));
  const velocityByToken = new Map(trendVelocity.items.map((item) => [item.token_id, item]));
  const launchByToken = new Map(launchSniper.items.map((item) => [item.token_id, item]));
  const edgeByToken = new Map(discoveryEdge.items.map((item) => [item.token_id, item]));
  const promotionByToken = new Map(promotionAudit.items.map((item) => [item.token_id, item]));
  const routeBySymbol = new Map(routeQuoteSampler.items.map((item) => [item.symbol, item]));
  const tokenIds = [
    ...discoveryTape.top_candidates.map((item) => item.token_id),
    ...signalNoise.items.map((item) => item.token_id),
    ...launchSniper.items.map((item) => item.token_id),
  ];
  const uniqueTokenIds = [...new Set(tokenIds)].slice(0, 10);
  const candidateByToken = new Map(discoveryTape.top_candidates.map((item) => [item.token_id, item]));

  const items = uniqueTokenIds
    .map((tokenId): LiveScannerReadinessItem | null => {
      const discovery = candidateByToken.get(tokenId);
      const signal = signalByToken.get(tokenId);
      const velocity = velocityByToken.get(tokenId);
      const launch = launchByToken.get(tokenId);
      const edge = edgeByToken.get(tokenId);
      const promotion = promotionByToken.get(tokenId);
      const symbol = discovery?.symbol ?? signal?.symbol ?? launch?.symbol ?? edge?.symbol ?? tokenId;
      const route = routeBySymbol.get(symbol) ?? null;
      const sourceConfirmation = edge?.source_confirmation_score ?? clamp((discovery?.sources.length ?? 0) * 18, 0, 100);
      const freshness = discovery?.freshness_score ?? velocity?.freshness_score ?? 0;
      const signalRatio = signal?.signal_to_noise_ratio ?? velocity?.signal_to_noise_ratio ?? 0;
      const routeScore = route?.route_confidence_score ?? signal?.route_readiness_score ?? 0;
      const launchScore = launch?.launch_score ?? edge?.edge_score ?? discovery?.scout_score ?? 0;
      const paidHypeScore = promotion?.hype_risk_score ?? discovery?.promotion_intensity ?? 0;
      const feedPenalty = feedIntegrity.status === "healthy" || feedIntegrity.status === "sample" ? 0 : feedIntegrity.status === "degraded" ? 10 : 22;
      const budgetPenalty = ingestionPlan.provider_budget_status === "throttled" ? 12 : ingestionPlan.provider_budget_status === "paused" ? 16 : 0;
      const streamPressure = streamFreshness.status === "hot"
        ? 6
        : streamFreshness.status === "ready"
          ? 3
          : streamFreshness.status === "backfill" || streamFreshness.status === "watch"
            ? -5
            : streamFreshness.status === "blocked"
              ? -14
              : 0;
      const scannerScore = clamp(Math.round(
        sourceConfirmation * 0.18 +
          freshness * 0.13 +
          Math.min(100, signalRatio * 44) * 0.18 +
          routeScore * 0.17 +
          launchScore * 0.22 +
          (100 - paidHypeScore) * 0.12 -
          feedPenalty -
          budgetPenalty +
          streamPressure,
      ), 0, 100);
      const blockers = liveScannerReadinessBlockers({
        discoveryTape,
        dexStreamFreshness: streamFreshness,
        ingestionPlan,
        feedIntegrity,
        signal,
        launch,
        route,
        sourceConfirmation,
        freshness,
        paidHypeScore,
        routeScore,
        scannerScore,
      });
      const action = liveScannerReadinessAction({
        discoveryTape,
        scannerScore,
        blockers,
        signal,
        velocity,
        launch,
        route,
        ingestionPlan,
      });
      const status: LiveScannerReadinessItem["status"] = blockers.length > 0
        ? blockers.some((blocker) => /fresh|fallback|source|provider|feed|route/i.test(blocker)) ? "stale" : "blocked"
        : action === "attack" || action === "probe"
          ? "ready"
          : "watch";
      const maxPaperSize = liveScannerReadinessSize({
        action,
        launch,
        signal,
        route,
        scannerScore,
      });

      return {
        token_id: tokenId,
        symbol,
        action,
        status,
        scanner_score: scannerScore,
        source_confirmation_score: sourceConfirmation,
        freshness_score: freshness,
        signal_to_noise_ratio: Math.round(signalRatio * 100) / 100,
        route_score: routeScore,
        launch_score: launchScore,
        paid_hype_score: paidHypeScore,
        max_paper_size_usd: maxPaperSize,
        review_after_seconds: Math.max(5, Math.min(signal?.review_after_seconds ?? velocity?.chase_window_seconds ?? launch?.review_after_seconds ?? 45, 90)),
        next_action: liveScannerReadinessNextAction(action, symbol, maxPaperSize, blockers),
        evidence: liveScannerReadinessEvidence({ discovery, dexStreamFreshness: streamFreshness, signal, velocity, launch, edge, route, promotion }),
        blockers,
      };
    })
    .filter((item): item is LiveScannerReadinessItem => Boolean(item))
    .sort((a, b) => liveScannerReadinessActionRank(b.action) - liveScannerReadinessActionRank(a.action) || b.scanner_score - a.scanner_score)
    .slice(0, 8);

  const attackCount = items.filter((item) => item.action === "attack" && item.status === "ready").length;
  const probeCount = items.filter((item) => item.action === "probe" && item.status === "ready").length;
  const refreshCount = items.filter((item) => item.action === "refresh" || item.status === "stale").length;
  const blockedCount = items.filter((item) => item.action === "blocked" || item.status === "blocked").length;
  const sourceMode = discoveryTape.status;
  const leader = items.find((item) => item.status === "ready") ?? items[0] ?? null;
  const status: LiveScannerReadiness["status"] = sourceMode === "sample"
    ? "sample"
    : attackCount > 0
      ? "attack-ready"
      : probeCount > 0
        ? "probe-ready"
        : refreshCount > 0 || sourceMode === "fallback" || ingestionPlan.status === "repair"
          ? "refresh-first"
          : blockedCount > 0
            ? "blocked"
            : "idle";

  return {
    mode: "live-scanner-readiness",
    status,
    source_mode: sourceMode,
    summary: liveScannerReadinessSummary(status, attackCount, probeCount, refreshCount, blockedCount, discoveryTape),
    next_action: liveScannerReadinessDeskAction(status, leader, ingestionPlan),
    leader_symbol: leader?.symbol ?? null,
    attack_count: attackCount,
    probe_count: probeCount,
    refresh_count: refreshCount,
    blocked_count: blockedCount,
    source_coverage_pct: discoveryEdge.source_coverage_pct,
    mapped_coverage_pct: discoveryEdge.mapped_coverage_pct,
    provider_budget_status: ingestionPlan.provider_budget_status,
    fastest_review_seconds: items.length ? Math.min(...items.map((item) => item.review_after_seconds)) : ingestionPlan.next_provider_refresh_seconds,
    recommended_max_paper_size_usd: Math.max(0, ...items.filter((item) => item.status === "ready").map((item) => item.max_paper_size_usd)),
    controls: [
      "Uses DEX Screener latest profiles, boosts, community-takeover WebSocket freshness, ads, paid-order checks, token-pair mapping, GeckoTerminal-style candle readiness, and Jupiter route confidence as read-only scanner evidence.",
      "Promotes only fresh, source-confirmed, route-aware, low-noise candidates into local paper attack/probe posture.",
      "Cannot sign, submit, settle, custody funds, bypass provider limits, or prove live profitability.",
    ],
    items,
  };
}

function liveScannerReadinessBlockers({
  discoveryTape,
  dexStreamFreshness,
  ingestionPlan,
  feedIntegrity,
  signal,
  launch,
  route,
  sourceConfirmation,
  freshness,
  paidHypeScore,
  routeScore,
  scannerScore,
}: {
  discoveryTape: DiscoveryTape;
  dexStreamFreshness: DexStreamFreshness;
  ingestionPlan: MarketIngestionPlan;
  feedIntegrity: MarketFeedIntegrity;
  signal: SignalNoiseItem | undefined;
  launch: LaunchSniperItem | undefined;
  route: RouteQuoteSamplerItem | null;
  sourceConfirmation: number;
  freshness: number;
  paidHypeScore: number;
  routeScore: number;
  scannerScore: number;
}) {
  const blockers: string[] = [];
  if (discoveryTape.status === "fallback") blockers.push("Live discovery fell back; refresh DEX Screener sources before attack.");
  if (feedIntegrity.status === "stale" || feedIntegrity.status === "fallback") blockers.push(feedIntegrity.summary);
  if (ingestionPlan.status === "blocked") blockers.push(ingestionPlan.summary);
  if (ingestionPlan.provider_budget_status === "throttled") blockers.push("Provider budget is throttled; wait before spending more scanner calls.");
  if (discoveryTape.status === "live" && dexStreamFreshness.status === "blocked") blockers.push(dexStreamFreshness.summary);
  if (discoveryTape.status === "live" && (dexStreamFreshness.status === "backfill" || dexStreamFreshness.status === "watch") && freshness < 55) blockers.push(dexStreamFreshness.next_action);
  if (discoveryTape.status === "live" && sourceConfirmation < 34) blockers.push("Source confirmation is too thin for autonomous live intake.");
  if (discoveryTape.status === "live" && freshness < 28) blockers.push("Discovery candidate is not fresh enough for a memecoin chase.");
  if (paidHypeScore >= 74) blockers.push("Paid-hype score is above the autonomous intake ceiling.");
  if (route && route.action === "block") blockers.push(route.reason);
  if (discoveryTape.status === "live" && routeScore < 34) blockers.push("Route confidence is too low for attack sizing.");
  if (signal?.action === "reject") blockers.push(signal.reason);
  if (launch?.verdict === "avoid") blockers.push(launch.next_action);
  if (scannerScore < 32) blockers.push("Composite scanner score is below the minimum paper-intake floor.");
  return [...new Set(blockers)].slice(0, 5);
}

function liveScannerReadinessAction({
  discoveryTape,
  scannerScore,
  blockers,
  signal,
  velocity,
  launch,
  route,
  ingestionPlan,
}: {
  discoveryTape: DiscoveryTape;
  scannerScore: number;
  blockers: string[];
  signal: SignalNoiseItem | undefined;
  velocity: TrendVelocityItem | undefined;
  launch: LaunchSniperItem | undefined;
  route: RouteQuoteSamplerItem | null;
  ingestionPlan: MarketIngestionPlan;
}): LiveScannerReadinessAction {
  if (blockers.length > 0) return blockers.some((blocker) => /fresh|fallback|source|provider|feed|route/i.test(blocker)) ? "refresh" : "blocked";
  if (ingestionPlan.status === "repair" || ingestionPlan.provider_budget_status === "hot") return "refresh";
  if (discoveryTape.status === "sample") {
    if (launch?.verdict === "snipe" || signal?.action === "attack" || velocity?.action === "chase") return "probe";
    return "watch";
  }
  if (scannerScore >= 72 && signal?.action === "attack" && (launch?.verdict === "snipe" || velocity?.action === "chase") && (!route || route.action === "confirm" || route.action === "probe")) return "attack";
  if (scannerScore >= 56 && (signal?.action === "probe" || launch?.verdict === "probe" || velocity?.action === "probe")) return "probe";
  if (signal?.action === "protect" || launch?.verdict === "exit") return "protect";
  return "watch";
}

function liveScannerReadinessSize({
  action,
  launch,
  signal,
  route,
  scannerScore,
}: {
  action: LiveScannerReadinessAction;
  launch: LaunchSniperItem | undefined;
  signal: SignalNoiseItem | undefined;
  route: RouteQuoteSamplerItem | null;
  scannerScore: number;
}) {
  if (action !== "attack" && action !== "probe") return 0;
  const base = action === "attack" ? 650 : 225;
  const launchCap = launch?.suggested_entry_usd ?? 750;
  const routeCap = route?.recommended_size_usd && route.recommended_size_usd > 0 ? route.recommended_size_usd : 900;
  const signalMultiplier = signal?.recommended_size_multiplier ?? 0.7;
  const scoreBoost = Math.max(0, scannerScore - 50) * (action === "attack" ? 9 : 4);
  return Math.round(Math.max(50, Math.min(launchCap, routeCap, (base + scoreBoost) * signalMultiplier)));
}

function liveScannerReadinessNextAction(action: LiveScannerReadinessAction, symbol: string, sizeUsd: number, blockers: string[]) {
  if (action === "attack") return `Queue ${symbol} for local paper attack sizing up to ${formatCompactValue(sizeUsd)}.`;
  if (action === "probe") return `Probe ${symbol} with bounded paper size up to ${formatCompactValue(sizeUsd)} after the next scanner tick.`;
  if (action === "refresh") return blockers[0] ?? `Refresh scanner evidence for ${symbol} before sizing.`;
  if (action === "protect") return `Route ${symbol} through protection/exit lanes instead of fresh intake.`;
  if (action === "blocked") return blockers[0] ?? `Block ${symbol} from autonomous intake.`;
  return `Watch ${symbol}; scanner does not have enough edge to spend paper budget.`;
}

function liveScannerReadinessEvidence({
  discovery,
  dexStreamFreshness,
  signal,
  velocity,
  launch,
  edge,
  route,
  promotion,
}: {
  discovery: DiscoveryCandidate | undefined;
  dexStreamFreshness: DexStreamFreshness;
  signal: SignalNoiseItem | undefined;
  velocity: TrendVelocityItem | undefined;
  launch: LaunchSniperItem | undefined;
  edge: DiscoveryEdgeItem | undefined;
  route: RouteQuoteSamplerItem | null;
  promotion: PromotionOrderAuditItem | undefined;
}) {
  return [
    discovery ? `${discovery.sources.map(sourceLabelForModel).join(", ")} sources` : null,
    `${dexStreamFreshness.status} DEX stream freshness`,
    edge ? `${edge.source_confirmation_score}/100 source confirmation` : null,
    signal ? `${Math.round(signal.signal_to_noise_ratio * 100) / 100}x signal/noise` : null,
    velocity ? `${velocity.action} velocity ${velocity.trend_score}/100` : null,
    launch ? `${launch.verdict} launch ${launch.launch_score}/100` : null,
    route ? `${route.action} route ${route.route_confidence_score}/100` : null,
    promotion ? `${promotion.verdict} hype ${promotion.hype_risk_score}/100` : null,
  ].filter((item): item is string => Boolean(item)).slice(0, 6);
}

function liveScannerReadinessActionRank(action: LiveScannerReadinessAction) {
  if (action === "attack") return 6;
  if (action === "probe") return 5;
  if (action === "protect") return 4;
  if (action === "refresh") return 3;
  if (action === "watch") return 2;
  return 1;
}

function liveScannerReadinessSummary(
  status: LiveScannerReadiness["status"],
  attackCount: number,
  probeCount: number,
  refreshCount: number,
  blockedCount: number,
  discoveryTape: DiscoveryTape,
) {
  if (status === "attack-ready") return `${attackCount} live scanner candidate${attackCount === 1 ? "" : "s"} clear source, signal/noise, hype, and route gates for local paper attack.`;
  if (status === "probe-ready") return `${probeCount} scanner candidate${probeCount === 1 ? "" : "s"} can be probed, but none clear full attack pressure.`;
  if (status === "refresh-first") return `${refreshCount} scanner lane${refreshCount === 1 ? "" : "s"} need fresher DEX, pair, paid-order, candle, or route evidence before spending paper budget.`;
  if (status === "blocked") return `${blockedCount} scanner candidate${blockedCount === 1 ? "" : "s"} blocked by hype, source, route, or risk noise.`;
  if (status === "sample") return `Sample scanner is replaying ${discoveryTape.pairs_mapped} mapped candidate${discoveryTape.pairs_mapped === 1 ? "" : "s"}; live attack readiness requires live DEX evidence.`;
  return "No scanner candidate has enough current edge to advance.";
}

function liveScannerReadinessDeskAction(
  status: LiveScannerReadiness["status"],
  leader: LiveScannerReadinessItem | null,
  ingestionPlan: MarketIngestionPlan,
) {
  if (!leader) return ingestionPlan.next_action;
  if (status === "attack-ready" || status === "probe-ready") return leader.next_action;
  if (status === "refresh-first") return ingestionPlan.next_action;
  if (status === "sample") return "Use sample scanner for rehearsal only; switch to Live DEX before treating any intake candidate as current.";
  if (status === "blocked") return leader.blockers[0] ?? "Keep scanner blocked until source, route, or hype gates clear.";
  return "Keep observing until scanner edge improves.";
}

function buildAutonomousAlphaQuality({
  market,
  marketSource,
  discoveryTape,
  dexStreamFreshness,
  liveScannerReadiness,
  promotionAudit,
  signalNoise,
  trendVelocity,
  routeQuoteSampler,
  walletTelemetry,
}: {
  market: MemecoinMarket[];
  marketSource: Web3TradingState["market_source"];
  discoveryTape: DiscoveryTape;
  dexStreamFreshness: DexStreamFreshness;
  liveScannerReadiness: LiveScannerReadiness;
  promotionAudit: PromotionOrderAudit;
  signalNoise: SignalNoiseScanner;
  trendVelocity: TrendVelocityScanner;
  routeQuoteSampler: RouteQuoteSampler;
  walletTelemetry: AutonomousWalletTelemetry;
}): AutonomousAlphaQuality {
  const scannerByToken = new Map(liveScannerReadiness.items.map((item) => [item.token_id, item]));
  const promotionByToken = new Map(promotionAudit.items.map((item) => [item.token_id, item]));
  const signalByToken = new Map(signalNoise.items.map((item) => [item.token_id, item]));
  const velocityByToken = new Map(trendVelocity.items.map((item) => [item.token_id, item]));
  const discoveryByToken = new Map(discoveryTape.top_candidates.map((item) => [item.token_id, item]));
  const routeBySymbol = new Map(routeQuoteSampler.items.map((item) => [item.symbol, item]));
  const cashPressurePenalty = walletTelemetry.cash_usd < 100 ? 28 : walletTelemetry.cash_pct < 8 ? 18 : 0;
  const exposurePenalty = walletTelemetry.exposure_pct > 82 ? 24 : walletTelemetry.exposure_pct > 66 ? 14 : 0;
  const drawdownPenalty = walletTelemetry.max_drawdown_pct >= 5 ? 22 : walletTelemetry.max_drawdown_pct >= 3 ? 12 : 0;
  const walletFitScore = clamp(Math.round(100 - cashPressurePenalty - exposurePenalty - drawdownPenalty), 0, 100);

  const items = market
    .slice(0, 12)
    .map((token): AutonomousAlphaQualityItem => {
      const scanner = scannerByToken.get(token.id);
      const promotion = promotionByToken.get(token.id);
      const signal = signalByToken.get(token.id);
      const velocity = velocityByToken.get(token.id);
      const discovery = discoveryByToken.get(token.id);
      const route = routeBySymbol.get(token.symbol);
      const buyPressurePct = token.buys_5m + token.sells_5m > 0
        ? Math.round((token.buys_5m / Math.max(1, token.buys_5m + token.sells_5m)) * 100)
        : 0;
      const sellPressurePct = 100 - buyPressurePct;
      const sourceConfirmationScore = scanner?.source_confirmation_score ?? (discovery?.sources.length ?? 0) * 18;
      const freshnessScore = discovery?.freshness_score ?? scanner?.freshness_score ?? 0;
      const organicScore = clamp(Math.round(
        sourceConfirmationScore * 0.48 +
          freshnessScore * 0.28 +
          (promotion?.verdict === "organic" ? 18 : promotion?.verdict === "boosted" ? 8 : promotion?.verdict === "unverified" ? 2 : -10) +
          (dexStreamFreshness.websocket_ready ? 8 : 0),
      ), 0, 100);
      const momentumScore = clamp(Math.round(
        Math.max(0, token.price_change_5m_pct) * 1.4 +
          Math.max(0, token.price_change_1h_pct) * 0.55 +
          Math.min(42, token.volume_5m_usd / Math.max(1, token.liquidity_usd) * 160) +
          buyPressurePct * 0.22 +
          (velocity?.trend_score ?? 0) * 0.28,
      ), 0, 100);
      const liquidityScore = clamp(Math.round(
        Math.min(52, token.liquidity_usd / 18_000) +
          Math.min(28, token.volume_1h_usd / 70_000) +
          Math.min(20, token.age_minutes / 24),
      ), 0, 100);
      const routeScore = route?.route_confidence_score ?? scanner?.route_score ?? 0;
      const noiseScore = clamp(Math.round(
        (promotion?.hype_risk_score ?? scanner?.paid_hype_score ?? 0) * 0.42 +
          token.risk_flags.length * 11 +
          Math.max(0, sellPressurePct - 42) * 0.58 +
          (token.liquidity_usd < 150_000 ? 20 : 0) +
          (token.age_minutes < 20 ? 12 : 0),
      ), 0, 100);
      const alphaQualityScore = clamp(Math.round(
        organicScore * 0.22 +
          momentumScore * 0.24 +
          liquidityScore * 0.16 +
          routeScore * 0.16 +
          walletFitScore * 0.14 +
          (100 - noiseScore) * 0.08,
      ), 0, 100);
      const blockers = autonomousAlphaQualityBlockers({
        marketSource,
        discoveryTape,
        token,
        scanner,
        route,
        routeScore,
        organicScore,
        liquidityScore,
        noiseScore,
        walletFitScore,
      });
      const action = autonomousAlphaQualityAction({
        marketSource,
        scanner,
        signal,
        velocity,
        alphaQualityScore,
        momentumScore,
        noiseScore,
        blockers,
      });
      const status = autonomousAlphaQualityStatus(action);
      const tradableNow = action === "paper-attack" || action === "paper-probe";
      const rawPaperSize = scanner?.max_paper_size_usd ?? route?.recommended_size_usd ?? 0;
      const sizeMultiplier = action === "paper-attack" ? 1 : action === "paper-probe" ? 0.52 : 0;
      const maxPaperSizeUsd = Math.round(Math.max(0, Math.min(
        rawPaperSize * sizeMultiplier,
        walletTelemetry.cash_usd * 0.18,
        walletTelemetry.equity_usd * 0.035,
      )));

      return {
        token_id: token.id,
        symbol: token.symbol,
        action,
        status,
        alpha_quality_score: alphaQualityScore,
        organic_score: organicScore,
        momentum_score: momentumScore,
        liquidity_score: liquidityScore,
        route_score: routeScore,
        wallet_fit_score: walletFitScore,
        noise_score: noiseScore,
        tradable_now: tradableNow,
        max_paper_size_usd: maxPaperSizeUsd,
        review_after_seconds: Math.max(5, Math.min(scanner?.review_after_seconds ?? velocity?.chase_window_seconds ?? 45, 90)),
        decision: autonomousAlphaQualityDecision(action, token.symbol, maxPaperSizeUsd, alphaQualityScore, blockers),
        evidence: [
          `${organicScore}/100 organic confirmation`,
          `${momentumScore}/100 momentum`,
          `${liquidityScore}/100 liquidity`,
          `${routeScore}/100 route`,
          `${walletFitScore}/100 wallet fit`,
          `${noiseScore}/100 noise`,
        ],
        blockers,
      };
    })
    .sort((a, b) =>
      autonomousAlphaQualityActionRank(b.action) - autonomousAlphaQualityActionRank(a.action) ||
      b.alpha_quality_score - a.alpha_quality_score,
    )
    .slice(0, 8);

  const attackCount = items.filter((item) => item.action === "paper-attack").length;
  const probeCount = items.filter((item) => item.action === "paper-probe").length;
  const refreshCount = items.filter((item) => item.action === "refresh-first").length;
  const blockedCount = items.filter((item) => item.action === "blocked").length;
  const leader = items.find((item) => item.tradable_now) ?? items[0] ?? null;
  const status: AutonomousAlphaQuality["status"] = marketSource.status === "sample"
    ? "sample"
    : attackCount > 0
      ? "attack"
      : probeCount > 0
        ? "probe"
        : refreshCount > 0
          ? "refresh"
          : blockedCount > 0
            ? "blocked"
            : "watch";

  return {
    mode: "autonomous-alpha-quality",
    status,
    summary: autonomousAlphaQualitySummary(status, attackCount, probeCount, refreshCount, blockedCount, leader),
    next_action: leader?.decision ?? "Keep scanning until organic momentum, route proof, and wallet fit align.",
    leader_symbol: leader?.symbol ?? null,
    attack_count: attackCount,
    probe_count: probeCount,
    refresh_count: refreshCount,
    blocked_count: blockedCount,
    average_quality_score: Math.round(average(items.map((item) => item.alpha_quality_score))),
    average_noise_score: Math.round(average(items.map((item) => item.noise_score))),
    fastest_review_seconds: items.length ? Math.min(...items.map((item) => item.review_after_seconds)) : liveScannerReadiness.fastest_review_seconds,
    recommended_max_paper_size_usd: Math.max(0, ...items.filter((item) => item.tradable_now).map((item) => item.max_paper_size_usd)),
    controls: [
      "Fuses DEX Screener profile/boost/ad/paid-order evidence, pair liquidity, transaction imbalance, route confidence, and wallet heat into one alpha-quality verdict.",
      "Paid hype, sell pressure, thin liquidity, stale live sources, and route gaps reduce or block fresh local paper sizing.",
      "This is a paper/dry-run decision surface only; it cannot prove demand, guarantee profit, sign, submit, custody funds, or move wallet capital.",
    ],
    items,
  };
}

function autonomousAlphaQualityBlockers({
  marketSource,
  discoveryTape,
  token,
  scanner,
  route,
  routeScore,
  organicScore,
  liquidityScore,
  noiseScore,
  walletFitScore,
}: {
  marketSource: Web3TradingState["market_source"];
  discoveryTape: DiscoveryTape;
  token: MemecoinMarket;
  scanner: LiveScannerReadinessItem | undefined;
  route: RouteQuoteSamplerItem | undefined;
  routeScore: number;
  organicScore: number;
  liquidityScore: number;
  noiseScore: number;
  walletFitScore: number;
}) {
  const blockers: string[] = [];
  if (marketSource.status === "fallback" || discoveryTape.status === "fallback") blockers.push("Live discovery is in fallback; refresh market evidence before attack sizing.");
  if (marketSource.status === "live" && organicScore < 38) blockers.push("Organic source confirmation is too thin for autonomous entry.");
  if (marketSource.status === "live" && routeScore < 34) blockers.push("Route confidence is too low for a fresh entry.");
  if (route?.action === "block") blockers.push(route.reason);
  if (liquidityScore < 34 || token.liquidity_usd < 120_000) blockers.push("Liquidity is too thin for trusted churn sizing.");
  if (noiseScore >= 72) blockers.push("Paid hype, sell pressure, or risk noise is above the alpha-quality ceiling.");
  if (walletFitScore < 52) blockers.push("Wallet heat/cash fit is too weak for a fresh paper entry.");
  if (scanner?.action === "blocked" || scanner?.status === "blocked") blockers.push(scanner.blockers[0] ?? "Scanner blocked this candidate.");
  return [...new Set(blockers)].slice(0, 5);
}

function autonomousAlphaQualityAction({
  marketSource,
  scanner,
  signal,
  velocity,
  alphaQualityScore,
  momentumScore,
  noiseScore,
  blockers,
}: {
  marketSource: Web3TradingState["market_source"];
  scanner: LiveScannerReadinessItem | undefined;
  signal: SignalNoiseItem | undefined;
  velocity: TrendVelocityItem | undefined;
  alphaQualityScore: number;
  momentumScore: number;
  noiseScore: number;
  blockers: string[];
}): AutonomousAlphaQualityAction {
  if (blockers.length > 0) return blockers.some((blocker) => /fallback|refresh|source|route/i.test(blocker)) ? "refresh-first" : "blocked";
  if (signal?.action === "protect" || scanner?.action === "protect") return "protect";
  if (marketSource.status === "sample") {
    if ((scanner?.action === "attack" || scanner?.action === "probe" || velocity?.action === "chase") && alphaQualityScore >= 52) return "paper-probe";
    return "watch";
  }
  if (alphaQualityScore >= 74 && momentumScore >= 64 && noiseScore < 58 && (scanner?.action === "attack" || signal?.action === "attack")) return "paper-attack";
  if (alphaQualityScore >= 58 && momentumScore >= 48 && noiseScore < 68 && (scanner?.action === "probe" || scanner?.action === "attack" || velocity?.action === "probe" || velocity?.action === "chase")) return "paper-probe";
  if (scanner?.action === "refresh") return "refresh-first";
  return "watch";
}

function autonomousAlphaQualityStatus(action: AutonomousAlphaQualityAction): AutonomousAlphaQualityItem["status"] {
  if (action === "paper-attack") return "attack";
  if (action === "paper-probe") return "probe";
  if (action === "refresh-first") return "refresh";
  if (action === "protect") return "protect";
  if (action === "blocked") return "blocked";
  return "watch";
}

function autonomousAlphaQualityDecision(
  action: AutonomousAlphaQualityAction,
  symbol: string,
  sizeUsd: number,
  qualityScore: number,
  blockers: string[],
) {
  if (action === "paper-attack") return `Attack ${symbol} in paper mode up to ${formatCompactValue(sizeUsd)}; alpha quality is ${qualityScore}/100.`;
  if (action === "paper-probe") return `Probe ${symbol} with capped local paper size up to ${formatCompactValue(sizeUsd)}; keep the next review tight.`;
  if (action === "refresh-first") return blockers[0] ?? `Refresh ${symbol} source, route, or paid-order evidence before sizing.`;
  if (action === "protect") return `Route ${symbol} through protection lanes before any fresh entry.`;
  if (action === "blocked") return blockers[0] ?? `Block ${symbol}; alpha quality does not clear noise controls.`;
  return `Watch ${symbol}; alpha quality is ${qualityScore}/100 and not worth spending paper budget yet.`;
}

function autonomousAlphaQualityActionRank(action: AutonomousAlphaQualityAction) {
  if (action === "paper-attack") return 6;
  if (action === "paper-probe") return 5;
  if (action === "protect") return 4;
  if (action === "refresh-first") return 3;
  if (action === "watch") return 2;
  return 1;
}

function autonomousAlphaQualitySummary(
  status: AutonomousAlphaQuality["status"],
  attackCount: number,
  probeCount: number,
  refreshCount: number,
  blockedCount: number,
  leader: AutonomousAlphaQualityItem | null,
) {
  if (status === "sample") return `${leader?.symbol ?? "Sample tape"} is scored through alpha-quality rehearsal; live attack still requires current DEX evidence.`;
  if (status === "attack") return `${attackCount} candidate${attackCount === 1 ? "" : "s"} clear organic, route, liquidity, wallet, and noise gates for paper attack.`;
  if (status === "probe") return `${probeCount} candidate${probeCount === 1 ? "" : "s"} clear enough alpha quality for capped paper probes.`;
  if (status === "refresh") return `${refreshCount} candidate${refreshCount === 1 ? "" : "s"} need fresher source or route evidence before spending paper budget.`;
  if (status === "blocked") return `${blockedCount} candidate${blockedCount === 1 ? "" : "s"} are blocked by hype, liquidity, route, wallet, or risk noise.`;
  return "No candidate has enough alpha quality to justify fresh paper exposure.";
}

function buildAutonomousTrapRadar({
  market,
  alphaQuality,
  tradeability,
  tokenSafetyClearance,
  promotionAudit,
  holderFlow,
  rugFirewall,
  routeQuoteSampler,
  marketPulse,
  walletTelemetry,
}: {
  market: MemecoinMarket[];
  alphaQuality: AutonomousAlphaQuality;
  tradeability: AutonomousTradeabilitySimulator;
  tokenSafetyClearance: AutonomousTokenSafetyClearance;
  promotionAudit: PromotionOrderAudit;
  holderFlow: HolderFlowSentinel;
  rugFirewall: RugPullFirewall;
  routeQuoteSampler: RouteQuoteSampler;
  marketPulse: AutonomousMarketPulse;
  walletTelemetry: AutonomousWalletTelemetry;
}): AutonomousTrapRadar {
  const alphaByToken = new Map(alphaQuality.items.map((item) => [item.token_id, item]));
  const tradeabilityByToken = new Map(tradeability.items.map((item) => [item.token_id, item]));
  const safetyByToken = new Map(tokenSafetyClearance.items.map((item) => [item.token_id, item]));
  const promotionByToken = new Map(promotionAudit.items.map((item) => [item.token_id, item]));
  const holderByToken = new Map(holderFlow.items.map((item) => [item.token_id, item]));
  const firewallByToken = new Map(rugFirewall.items.map((item) => [item.token_id, item]));
  const routeBySymbol = new Map(routeQuoteSampler.items.map((item) => [item.symbol ?? "", item]));
  const pulseByToken = new Map(marketPulse.items.map((item) => [item.token_id, item]));
  const walletHeatScore = clamp(Math.round(
    walletTelemetry.exposure_pct * 0.55 +
      walletTelemetry.max_drawdown_pct * 8 +
      Math.max(0, 12 - walletTelemetry.cash_pct) * 2.4,
  ), 0, 100);

  const items = market.slice(0, 12).map((token): AutonomousTrapRadarItem => {
    const alpha = alphaByToken.get(token.id);
    const fill = tradeabilityByToken.get(token.id);
    const safety = safetyByToken.get(token.id);
    const promotion = promotionByToken.get(token.id);
    const holder = holderByToken.get(token.id);
    const firewall = firewallByToken.get(token.id);
    const route = routeBySymbol.get(token.symbol);
    const pulse = pulseByToken.get(token.id);
    const buys = token.buys_5m;
    const sells = token.sells_5m;
    const sellPressureScore = clamp(Math.round(
      sells + buys > 0
        ? (sells / Math.max(1, sells + buys)) * 100
        : Math.max(0, -(token.price_change_5m_pct)) * 6,
    ), 0, 100);
    const paidHypeScore = clamp(Math.round(
      promotion?.hype_risk_score ??
        alpha?.noise_score ??
        token.paid_orders * 20 + token.boosts * 0.12,
    ), 0, 100);
    const liquidityStressScore = clamp(Math.round(
      Math.max(0, 100 - (safety?.liquidity_score ?? alpha?.liquidity_score ?? 45)) * 0.72 +
        (token.liquidity_usd < 120_000 ? 24 : token.liquidity_usd < 250_000 ? 12 : 0) +
        Math.min(22, token.volume_5m_usd / Math.max(1, token.liquidity_usd) * 120),
    ), 0, 100);
    const holderRiskScore = clamp(Math.round(average([
      holder?.insider_risk_score ?? 42,
      holder?.holder_concentration_score ?? 38,
      holder?.whale_exit_pressure_score ?? 36,
      holder?.creator_wallet_risk_score ?? 34,
      firewall?.holder_concentration_risk_score ?? 38,
    ])), 0, 100);
    const routeGapScore = clamp(Math.round(
      100 - (route?.route_confidence_score ?? fill?.route_score ?? safety?.route_score ?? 40) +
        (route?.action === "block" ? 18 : route?.action === "requote" ? 10 : 0),
    ), 0, 100);
    const organicScore = clamp(Math.round(alpha?.organic_score ?? Math.max(0, 100 - paidHypeScore)), 0, 100);
    const rugRiskScore = clamp(Math.round(firewall?.composite_risk_score ?? safety?.risk_score ?? token.risk_flags.length * 18), 0, 100);
    const freshPumpScore = clamp(Math.round(
      Math.max(0, token.price_change_5m_pct) * 1.3 +
        Math.max(0, token.price_change_1h_pct) * 0.35 +
        (pulse?.flow_score ?? 0) * 0.2,
    ), 0, 100);
    const trapScore = clamp(Math.round(
      paidHypeScore * 0.18 +
        liquidityStressScore * 0.17 +
        holderRiskScore * 0.17 +
        sellPressureScore * 0.15 +
        routeGapScore * 0.12 +
        rugRiskScore * 0.12 +
        walletHeatScore * 0.09,
    ), 0, 100);
    const chaseScore = clamp(Math.round(
      (alpha?.alpha_quality_score ?? 0) * 0.28 +
        (fill?.tradeability_score ?? 0) * 0.22 +
        (safety?.safety_score ?? 0) * 0.18 +
        organicScore * 0.14 +
        freshPumpScore * 0.12 +
        Math.max(0, 100 - walletHeatScore) * 0.06 -
        Math.max(0, trapScore - 48) * 0.42,
    ), 0, 100);
    const verdict = autonomousTrapRadarVerdict({
      trapScore,
      chaseScore,
      routeGapScore,
      safety,
      holder,
      alpha,
      fill,
    });
    const maxChaseUsd = verdict === "chase" || verdict === "probe"
      ? Math.round(Math.max(0, Math.min(
        alpha?.max_paper_size_usd ?? Number.POSITIVE_INFINITY,
        fill?.recommended_size_usd ?? Number.POSITIVE_INFINITY,
        safety?.max_buy_usd ?? Number.POSITIVE_INFINITY,
        walletTelemetry.cash_usd * (verdict === "chase" ? 0.12 : 0.045),
        token.liquidity_usd * (verdict === "chase" ? 0.0022 : 0.0008),
      )))
      : 0;
    const blockers = autonomousTrapRadarBlockers({
      verdict,
      trapScore,
      paidHypeScore,
      liquidityStressScore,
      holderRiskScore,
      sellPressureScore,
      routeGapScore,
      walletHeatScore,
      safety,
      alpha,
      route,
    });

    return {
      token_id: token.id,
      symbol: token.symbol,
      verdict,
      trap_score: trapScore,
      chase_score: chaseScore,
      organic_score: organicScore,
      paid_hype_score: paidHypeScore,
      liquidity_stress_score: liquidityStressScore,
      holder_risk_score: holderRiskScore,
      sell_pressure_score: sellPressureScore,
      route_gap_score: routeGapScore,
      wallet_heat_score: walletHeatScore,
      max_chase_usd: maxChaseUsd,
      review_after_seconds: verdict === "exit-only" ? 4 : verdict === "trap" ? 8 : verdict === "refresh" ? 12 : verdict === "chase" ? 10 : 18,
      reason: autonomousTrapRadarReason(token.symbol, verdict, trapScore, chaseScore, maxChaseUsd, blockers),
      evidence: [
        `Trap ${trapScore}/100`,
        `Chase ${chaseScore}/100`,
        `Paid hype ${paidHypeScore}/100`,
        `Liquidity stress ${liquidityStressScore}/100`,
        `Holder risk ${holderRiskScore}/100`,
        `Sell pressure ${sellPressureScore}/100`,
      ],
      blockers,
    };
  }).sort((a, b) =>
    autonomousTrapRadarVerdictRank(b.verdict) - autonomousTrapRadarVerdictRank(a.verdict) ||
    b.chase_score - a.chase_score ||
    b.trap_score - a.trap_score,
  );

  const chaseCount = items.filter((item) => item.verdict === "chase").length;
  const probeCount = items.filter((item) => item.verdict === "probe").length;
  const trapCount = items.filter((item) => item.verdict === "trap").length;
  const exitOnlyCount = items.filter((item) => item.verdict === "exit-only").length;
  const refreshCount = items.filter((item) => item.verdict === "refresh").length;
  const leader = items.find((item) => item.verdict === "chase" || item.verdict === "probe") ?? items[0] ?? null;
  const status: AutonomousTrapRadar["status"] = items.length === 0
    ? "idle"
    : exitOnlyCount > 0
      ? "exit-only"
      : chaseCount > 0
        ? "chase"
        : probeCount > 0
          ? "probe"
          : refreshCount > 0
            ? "refresh"
            : trapCount > 0
              ? "trap"
              : "watch";

  return {
    mode: "autonomous-trap-radar",
    status,
    summary: autonomousTrapRadarSummary(status, leader, chaseCount, probeCount, trapCount, exitOnlyCount),
    next_action: leader?.reason ?? "Keep scanning until trend quality beats trap risk.",
    leader_symbol: leader?.symbol ?? null,
    trap_count: trapCount,
    chase_count: chaseCount,
    probe_count: probeCount,
    exit_only_count: exitOnlyCount,
    max_trap_score: Math.max(0, ...items.map((item) => item.trap_score)),
    average_trap_score: Math.round(average(items.map((item) => item.trap_score))),
    max_chase_usd: Math.max(0, ...items.map((item) => item.max_chase_usd)),
    fastest_review_seconds: items.length > 0 ? Math.min(...items.map((item) => item.review_after_seconds)) : 30,
    controls: [
      "Separates Moonshot-style momentum from exit-liquidity traps before fresh paper buys.",
      "Penalizes paid hype, thin liquidity, holder/creator risk, sell pressure, stale routes, rug flags, and hot-wallet exposure.",
      "Chase and probe are paper-only permissions; trap and exit-only verdicts preserve protective sells and suppress fresh exposure.",
    ],
    items: items.slice(0, 8),
  };
}

function autonomousTrapRadarVerdict({
  trapScore,
  chaseScore,
  routeGapScore,
  safety,
  holder,
  alpha,
  fill,
}: {
  trapScore: number;
  chaseScore: number;
  routeGapScore: number;
  safety: AutonomousTokenSafetyClearanceItem | undefined;
  holder: HolderFlowItem | undefined;
  alpha: AutonomousAlphaQualityItem | undefined;
  fill: AutonomousTradeabilityItem | undefined;
}): AutonomousTrapRadarVerdict {
  if (safety?.clearance === "exit-only" || holder?.action === "exit") return "exit-only";
  if (trapScore >= 74 || safety?.clearance === "blocked" || holder?.action === "block") return "trap";
  if (routeGapScore >= 68 || alpha?.action === "refresh-first" || fill?.action === "requote") return "refresh";
  if (chaseScore >= 72 && trapScore <= 52 && safety?.clearance === "cleared") return "chase";
  if (chaseScore >= 54 && trapScore <= 66) return "probe";
  if (trapScore >= 62) return "trap";
  return "watch";
}

function autonomousTrapRadarBlockers({
  verdict,
  trapScore,
  paidHypeScore,
  liquidityStressScore,
  holderRiskScore,
  sellPressureScore,
  routeGapScore,
  walletHeatScore,
  safety,
  alpha,
  route,
}: {
  verdict: AutonomousTrapRadarVerdict;
  trapScore: number;
  paidHypeScore: number;
  liquidityStressScore: number;
  holderRiskScore: number;
  sellPressureScore: number;
  routeGapScore: number;
  walletHeatScore: number;
  safety: AutonomousTokenSafetyClearanceItem | undefined;
  alpha: AutonomousAlphaQualityItem | undefined;
  route: RouteQuoteSamplerItem | undefined;
}) {
  const blockers = [
    trapScore >= 68 ? `Trap risk is ${trapScore}/100; do not chase without fresh proof.` : null,
    paidHypeScore >= 70 ? "Paid hype or boosted attention is above the trap ceiling." : null,
    liquidityStressScore >= 66 ? "Liquidity stress is too high for fast churn sizing." : null,
    holderRiskScore >= 68 ? "Holder, creator, or whale-flow risk is elevated." : null,
    sellPressureScore >= 62 ? "Sell pressure is ahead of buyer control." : null,
    routeGapScore >= 66 ? route?.reason ?? "Route confidence is stale, missing, or blocked." : null,
    walletHeatScore >= 70 ? "Wallet heat is high; fresh exposure must wait behind protection." : null,
    safety?.clearance === "blocked" || safety?.clearance === "exit-only" ? safety.reason : null,
    alpha?.action === "blocked" ? alpha.decision : null,
    verdict === "watch" ? "Chase score is not strong enough to spend paper budget yet." : null,
  ].filter((item): item is string => Boolean(item));
  return [...new Set(blockers)].slice(0, 5);
}

function autonomousTrapRadarReason(
  symbol: string,
  verdict: AutonomousTrapRadarVerdict,
  trapScore: number,
  chaseScore: number,
  maxChaseUsd: number,
  blockers: string[],
) {
  if (verdict === "chase") return `Chase ${symbol} only in paper mode up to ${formatCompactValue(maxChaseUsd)}; chase ${chaseScore}/100 beats trap ${trapScore}/100.`;
  if (verdict === "probe") return `Probe ${symbol} with tiny paper size up to ${formatCompactValue(maxChaseUsd)} and require the next tape to confirm.`;
  if (verdict === "refresh") return blockers[0] ?? `Refresh ${symbol} route, source, or safety proof before a fresh paper entry.`;
  if (verdict === "exit-only") return `Treat ${symbol} as exit-only; protective paper sells can run but fresh buys are suppressed.`;
  if (verdict === "trap") return blockers[0] ?? `Block ${symbol}; trap score is ${trapScore}/100.`;
  return `Watch ${symbol}; chase score ${chaseScore}/100 does not beat trap risk ${trapScore}/100.`;
}

function autonomousTrapRadarSummary(
  status: AutonomousTrapRadar["status"],
  leader: AutonomousTrapRadarItem | null,
  chaseCount: number,
  probeCount: number,
  trapCount: number,
  exitOnlyCount: number,
) {
  if (status === "chase") return `${chaseCount} candidate${chaseCount === 1 ? "" : "s"} beat the trap filter; ${leader?.symbol ?? "leader"} is paper-chase eligible.`;
  if (status === "probe") return `${probeCount} candidate${probeCount === 1 ? "" : "s"} can only be probed; trap risk is still visible.`;
  if (status === "refresh") return `${leader?.symbol ?? "The leader"} needs fresher source, route, or safety proof before chase sizing.`;
  if (status === "exit-only") return `${exitOnlyCount} candidate${exitOnlyCount === 1 ? "" : "s"} are exit-only; preserve protection lanes first.`;
  if (status === "trap") return `${trapCount} candidate${trapCount === 1 ? "" : "s"} look like exit-liquidity traps; fresh paper buys are blocked.`;
  if (status === "idle") return "Trap radar is waiting for market candidates.";
  return "Trap radar is watching; no coin beats the trap filter strongly enough to chase.";
}

function autonomousTrapRadarVerdictRank(verdict: AutonomousTrapRadarVerdict) {
  if (verdict === "chase") return 6;
  if (verdict === "probe") return 5;
  if (verdict === "refresh") return 4;
  if (verdict === "exit-only") return 3;
  if (verdict === "trap") return 2;
  return 1;
}

function buildAutonomousTradeabilitySimulator({
  marketSource,
  alphaQuality,
  routeQuoteSampler,
  liquidityDepth,
  executionCost,
  paperExecutionQuality,
  churnEfficiency,
}: {
  marketSource: Web3TradingState["market_source"];
  alphaQuality: AutonomousAlphaQuality;
  routeQuoteSampler: RouteQuoteSampler;
  liquidityDepth: LiquidityDepthController;
  executionCost: ExecutionCostMonitor;
  paperExecutionQuality: PaperExecutionQuality;
  churnEfficiency: ChurnEfficiencyAuditor;
}): AutonomousTradeabilitySimulator {
  const routeBySymbol = new Map(routeQuoteSampler.items.map((item) => [item.symbol ?? "", item]));
  const depthBySymbol = new Map(liquidityDepth.items.map((item) => [item.symbol ?? "", item]));
  const costBySymbol = new Map(executionCost.items.map((item) => [item.symbol ?? "", item]));
  const churnBySymbol = new Map(churnEfficiency.items.map((item) => [item.symbol, item]));
  const baselineFillQuality = paperExecutionQuality.status === "excellent"
    ? 92
    : paperExecutionQuality.status === "acceptable"
      ? 78
      : paperExecutionQuality.status === "degraded"
        ? 54
        : paperExecutionQuality.status === "poor"
          ? 28
          : 72;

  const items = alphaQuality.items
    .slice(0, 8)
    .map((alpha): AutonomousTradeabilityItem => {
      const route = routeBySymbol.get(alpha.symbol);
      const depth = depthBySymbol.get(alpha.symbol);
      const cost = costBySymbol.get(alpha.symbol);
      const churn = churnBySymbol.get(alpha.symbol);
      const routeScore = route?.route_confidence_score ?? alpha.route_score;
      const depthScore = depth?.depth_score ?? alpha.liquidity_score;
      const routeCostBps = cost?.total_cost_bps ?? (route?.slippage_bps ?? 0) + Math.max(0, route?.modeled_impact_bps ?? 0);
      const modeledSlippageBps = Math.round(
        Math.max(0, route?.modeled_impact_bps ?? 0) +
          Math.max(0, route?.impact_drift_bps ?? 0) * 0.45 +
          Math.max(0, depth?.spread_bps ?? 0) * 0.35 +
          Math.max(0, depth?.expected_impact_bps ?? 0) * 0.35,
      );
      const churnScore = churnEfficiencyScore(churn, churnEfficiency.entry_permission);
      const fillQualityScore = clamp(Math.round(
        baselineFillQuality * 0.52 +
          routeScore * 0.18 +
          depthScore * 0.16 +
          (100 - Math.min(100, modeledSlippageBps / 2.8)) * 0.14,
      ), 0, 100);
      const tradeabilityScore = clamp(Math.round(
        alpha.alpha_quality_score * 0.34 +
          routeScore * 0.2 +
          depthScore * 0.16 +
          fillQualityScore * 0.16 +
          churnScore * 0.1 +
          (100 - Math.min(100, routeCostBps / 2.6)) * 0.04,
      ), 0, 100);
      const blockers = autonomousTradeabilityBlockers({
        marketSource,
        alpha,
        route,
        depth,
        cost,
        churn,
        routeScore,
        depthScore,
        fillQualityScore,
        tradeabilityScore,
        routeCostBps,
        modeledSlippageBps,
        churnEfficiency,
      });
      const action = autonomousTradeabilityAction({
        alpha,
        route,
        depth,
        churn,
        blockers,
        tradeabilityScore,
        modeledSlippageBps,
        routeCostBps,
      });
      const status = autonomousTradeabilityStatus(action);
      const simulatedFillRatePct = clamp(Math.round(
        fillQualityScore * 0.58 +
          routeScore * 0.18 +
          depthScore * 0.14 +
          Math.max(0, 100 - modeledSlippageBps / 3) * 0.1,
      ), 0, 100);
      const sizeHaircut = action === "paper-fill" ? 1 : action === "paper-probe" ? 0.62 : action === "resize" ? 0.38 : 0;
      const recommendedSizeUsd = Math.round(Math.max(0, Math.min(alpha.max_paper_size_usd, depth?.recommended_size_usd ?? alpha.max_paper_size_usd) * sizeHaircut));
      const expectedShortfallUsd = roundMetric(recommendedSizeUsd * (routeCostBps + modeledSlippageBps) / 10_000);

      return {
        token_id: alpha.token_id,
        symbol: alpha.symbol,
        action,
        status,
        tradeability_score: tradeabilityScore,
        alpha_quality_score: alpha.alpha_quality_score,
        route_score: routeScore,
        depth_score: depthScore,
        fill_quality_score: fillQualityScore,
        churn_score: churnScore,
        route_cost_bps: routeCostBps,
        modeled_slippage_bps: modeledSlippageBps,
        simulated_fill_rate_pct: simulatedFillRatePct,
        expected_shortfall_usd: expectedShortfallUsd,
        recommended_size_usd: recommendedSizeUsd,
        review_after_seconds: Math.max(5, Math.min(alpha.review_after_seconds, route?.review_after_seconds ?? depth?.review_after_seconds ?? 45)),
        decision: autonomousTradeabilityDecision(action, alpha.symbol, recommendedSizeUsd, tradeabilityScore, expectedShortfallUsd, blockers),
        evidence: [
          `${alpha.alpha_quality_score}/100 alpha quality`,
          `${routeScore}/100 route confidence`,
          `${depthScore}/100 depth`,
          `${fillQualityScore}/100 fill quality`,
          `${routeCostBps}bps route cost`,
          `${modeledSlippageBps}bps modeled slippage`,
        ],
        blockers,
      };
    })
    .sort((a, b) => autonomousTradeabilityActionRank(b.action) - autonomousTradeabilityActionRank(a.action) || b.tradeability_score - a.tradeability_score);

  const fillableCount = items.filter((item) => item.action === "paper-fill").length;
  const probeCount = items.filter((item) => item.action === "paper-probe").length;
  const resizeCount = items.filter((item) => item.action === "resize").length;
  const requoteCount = items.filter((item) => item.action === "requote").length;
  const blockedCount = items.filter((item) => item.action === "blocked").length;
  const leader = items.find((item) => item.action === "paper-fill" || item.action === "paper-probe") ?? items[0] ?? null;
  const status: AutonomousTradeabilitySimulator["status"] = marketSource.status === "sample"
    ? "sample"
    : fillableCount > 0
      ? "fillable"
      : probeCount > 0
        ? "probe"
        : resizeCount > 0
          ? "resize"
          : requoteCount > 0
            ? "requote"
            : blockedCount > 0
              ? "blocked"
              : "watch";

  return {
    mode: "autonomous-tradeability-simulator",
    status,
    summary: autonomousTradeabilitySummary(status, fillableCount, probeCount, resizeCount, requoteCount, blockedCount, leader),
    next_action: leader?.decision ?? "Keep watching until alpha quality and execution quality agree.",
    leader_symbol: leader?.symbol ?? null,
    fillable_count: fillableCount,
    probe_count: probeCount,
    resize_count: resizeCount,
    requote_count: requoteCount,
    blocked_count: blockedCount,
    average_tradeability_score: Math.round(average(items.map((item) => item.tradeability_score))),
    average_slippage_bps: Math.round(average(items.map((item) => item.modeled_slippage_bps))),
    expected_shortfall_usd: roundMetric(items.reduce((sum, item) => sum + item.expected_shortfall_usd, 0)),
    recommended_max_paper_size_usd: Math.max(0, ...items.filter((item) => item.action === "paper-fill" || item.action === "paper-probe" || item.action === "resize").map((item) => item.recommended_size_usd)),
    controls: [
      "Simulates whether alpha-quality candidates can survive route confidence, liquidity depth, route cost, slippage, fill quality, and churn pressure before local paper sizing.",
      "Fillable and probe verdicts remain local paper/dry-run only; real swaps still require signer, custody, route, preflight, and live-execution gates.",
      "Uses public quote/depth/fill-quality evidence as a risk haircut and never guarantees a live fill or future profit.",
    ],
    items,
  };
}

function buildAutonomousTradeabilityExecution({
  market,
  cycle,
  simulator,
  sourceQuality,
  recentTrades = [],
}: {
  market: MemecoinMarket[];
  cycle: number;
  simulator: AutonomousTradeabilitySimulator;
  sourceQuality?: AutonomousSourceQualityOracle;
  recentTrades?: AutonomousTrade[];
}): AutonomousTradeabilityExecution {
  const selected = simulator.items.find((item) => item.action === "paper-fill" || item.action === "paper-probe")
    ?? simulator.items.find((item) => item.action === "resize" || item.action === "requote")
    ?? simulator.items[0]
    ?? null;
  const token = selected
    ? market.find((entry) => entry.id === selected.token_id || entry.symbol === selected.symbol)
    : null;
  const sourceQualityBlocker = selected
    ? autonomousSourceQualityBuyBlocker(sourceQuality, selected.symbol)
    : null;
  const sourceSizedPaperSizeUsd = selected
    ? autonomousSourceQualityAdjustedSizeUsd(sourceQuality, selected.symbol, selected.recommended_size_usd)
    : 0;
  const sourceQualitySizingBlocker = selected && (selected.action === "paper-fill" || selected.action === "paper-probe")
    ? autonomousSourceQualitySizingBlockerForSize(sourceQuality, selected.symbol, selected.recommended_size_usd)
    : null;
  const canBuildTrade = Boolean(
    selected &&
      token &&
      (selected.action === "paper-fill" || selected.action === "paper-probe") &&
      sourceSizedPaperSizeUsd >= 10 &&
      selected.blockers.length === 0 &&
      !sourceQualityBlocker &&
      !sourceQualitySizingBlocker,
  );
  const tradeId = selected ? `paper-tradeability-${cycle}-${selected.symbol.toLowerCase()}` : "";
  const ledgerTrade = tradeId ? latestAutonomousTradeById(recentTrades, tradeId) : null;
  const paperTrade: AutonomousTrade | null = ledgerTrade ?? (canBuildTrade && selected && token
    ? {
        id: tradeId,
        side: "buy",
        symbol: selected.symbol,
        size_usd: sourceSizedPaperSizeUsd,
        price_usd: token.price_usd,
        status: "paper-filled",
        reason: autonomousSourceQualityAdjustedReason(
          sourceQuality,
          selected.symbol,
          sourceSizedPaperSizeUsd,
          selected.recommended_size_usd,
          `Tradeability paper ${selected.action.replace("paper-", "")}: ${selected.decision}`,
        ),
        created_at: shiftedTime(cycle, 88),
      }
    : null);
  const blockers = [...new Set([
    ...(selected?.blockers ?? []),
    selected && !token ? `No market price is available for ${selected.symbol}.` : null,
    selected && (selected.action === "resize" || selected.action === "requote" || selected.action === "blocked" || selected.action === "watch" || selected.action === "protect")
      ? selected.decision
      : null,
    selected && selected.recommended_size_usd < 10 && (selected.action === "paper-fill" || selected.action === "paper-probe")
      ? `${selected.symbol} size is below the local paper-ledger minimum.`
      : null,
    sourceQualitySizingBlocker,
    selected && selected.modeled_slippage_bps >= 260
      ? `${selected.symbol} modeled slippage is above the fill ceiling.`
      : null,
    sourceQualityBlocker,
  ].filter((item): item is string => Boolean(item)))].slice(0, 6);
  const ledgerApplied = Boolean(ledgerTrade);
  const paperTradeReady = Boolean(paperTrade && !ledgerApplied && blockers.length === 0);
  const status: AutonomousTradeabilityExecution["status"] = ledgerApplied
    ? "applied"
    : paperTradeReady
      ? "queued"
      : selected && (blockers.length > 0 || selected.action === "resize" || selected.action === "requote" || selected.action === "blocked")
        ? "blocked"
        : "idle";
  const paperSize = Math.round(paperTrade?.size_usd ?? sourceSizedPaperSizeUsd);

  return {
    mode: "tradeability-paper-execution",
    status,
    selected_symbol: selected?.symbol ?? null,
    selected_action: selected?.action ?? null,
    selected_side: paperTrade ? "buy" : "hold",
    paper_trade_ready: paperTradeReady,
    ledger_applied: ledgerApplied,
    paper_trade: paperTrade,
    execution_boundary: "paper-ledger-only",
    paper_size_usd: paperSize,
    projected_cash_delta_usd: paperTrade ? -paperSize : 0,
    projected_exposure_delta_usd: paperTrade ? paperSize : 0,
    tradeability_score: selected?.tradeability_score ?? 0,
    modeled_slippage_bps: selected?.modeled_slippage_bps ?? 0,
    simulated_fill_rate_pct: selected?.simulated_fill_rate_pct ?? 0,
    expected_shortfall_usd: selected?.expected_shortfall_usd ?? 0,
    review_after_seconds: selected?.review_after_seconds ?? 30,
    summary: autonomousTradeabilityExecutionSummary(status, selected, paperTrade, blockers),
    next_action: autonomousTradeabilityExecutionNextAction(status, selected, paperTrade, blockers),
    blockers,
    controls: [
      "Turns the top fillable/probe verdict into one bounded local paper-ledger buy candidate.",
      "Requires route confidence, depth, modeled slippage, fill quality, churn, price, and minimum-size checks before queueing.",
      "Fresh fillability buys are vetoed when source quality marks the candidate paid-hype, refresh-first, blocked, or missing current proof.",
      "Cannot sign, submit, route, custody funds, broadcast swaps, or guarantee profit.",
    ],
  };
}

function autonomousTradeabilityExecutionSummary(
  status: AutonomousTradeabilityExecution["status"],
  selected: AutonomousTradeabilityItem | null,
  trade: AutonomousTrade | null,
  blockers: string[],
) {
  if (status === "applied" && trade) return `Tradeability paper buy for ${trade.symbol} is already recorded in the local ledger.`;
  if (status === "queued" && trade) return `${trade.symbol} is fillable enough for a ${formatCompactValue(trade.size_usd)} local paper buy.`;
  if (status === "blocked") return blockers[0] ?? `${selected?.symbol ?? "Tradeability"} needs a safer route before paper execution.`;
  if (selected) return selected.decision;
  return "Tradeability execution is idle until a fillable alpha candidate appears.";
}

function autonomousTradeabilityExecutionNextAction(
  status: AutonomousTradeabilityExecution["status"],
  selected: AutonomousTradeabilityItem | null,
  trade: AutonomousTrade | null,
  blockers: string[],
) {
  if (status === "applied" && trade) return `Monitor ${trade.symbol}; the fillability-owned paper buy is already in the ledger.`;
  if (status === "queued" && trade) return `Let the action queue compete ${trade.symbol} against pressure, trend, protection, and wallet lanes.`;
  if (status === "blocked") return blockers[0] ?? selected?.decision ?? "Requote or resize before paper fill.";
  if (selected) return selected.decision;
  return "Keep scanning until fillability clears route, depth, slippage, and size checks.";
}

function autonomousTradeabilityBlockers({
  marketSource,
  alpha,
  route,
  depth,
  cost,
  churn,
  routeScore,
  depthScore,
  fillQualityScore,
  tradeabilityScore,
  routeCostBps,
  modeledSlippageBps,
  churnEfficiency,
}: {
  marketSource: Web3TradingState["market_source"];
  alpha: AutonomousAlphaQualityItem;
  route: RouteQuoteSamplerItem | undefined;
  depth: LiquidityDepthItem | undefined;
  cost: ExecutionCostItem | undefined;
  churn: ChurnEfficiencyItem | undefined;
  routeScore: number;
  depthScore: number;
  fillQualityScore: number;
  tradeabilityScore: number;
  routeCostBps: number;
  modeledSlippageBps: number;
  churnEfficiency: ChurnEfficiencyAuditor;
}) {
  const blockers: string[] = [...alpha.blockers];
  if (marketSource.status === "fallback") blockers.push("Market source is in fallback; require fresh route/depth evidence before fill simulation.");
  if (!route || route.action === "block" || route.quote_status === "no-route") blockers.push(route?.reason ?? "No route quote is available for this candidate.");
  if (route?.action === "requote") blockers.push("Route quote needs refresh before trusting the fill.");
  if (depth?.action === "block" || depthScore < 34) blockers.push(depth?.reason ?? "Liquidity depth is too weak for a trusted fill.");
  if (cost?.status === "block" || routeCostBps >= 180) blockers.push(cost?.summary ?? "Route and priority-fee drag are too high.");
  if (modeledSlippageBps >= 260) blockers.push("Modeled slippage is above the autonomous fill ceiling.");
  if (fillQualityScore < 42) blockers.push("Paper fill-quality simulator is too weak for trusted attribution.");
  if (churn?.action === "stop" || churnEfficiency.entry_permission === "blocked") blockers.push(churn?.reason ?? churnEfficiency.summary);
  if (tradeabilityScore < 34) blockers.push("Composite tradeability score is below the minimum fill floor.");
  return [...new Set(blockers)].slice(0, 6);
}

function churnEfficiencyScore(
  churn: ChurnEfficiencyItem | undefined,
  permission: ChurnEfficiencyAuditor["entry_permission"],
) {
  if (churn?.action === "accelerate") return 88;
  if (churn?.action === "selective") return 64;
  if (churn?.action === "cooldown") return 38;
  if (churn?.action === "stop") return 12;
  if (permission === "open") return 82;
  if (permission === "selective") return 62;
  if (permission === "cooldown") return 38;
  return 18;
}

function autonomousTradeabilityAction({
  alpha,
  route,
  depth,
  churn,
  blockers,
  tradeabilityScore,
  modeledSlippageBps,
  routeCostBps,
}: {
  alpha: AutonomousAlphaQualityItem;
  route: RouteQuoteSamplerItem | undefined;
  depth: LiquidityDepthItem | undefined;
  churn: ChurnEfficiencyItem | undefined;
  blockers: string[];
  tradeabilityScore: number;
  modeledSlippageBps: number;
  routeCostBps: number;
}): AutonomousTradeabilityAction {
  if (alpha.action === "protect") return "protect";
  if (blockers.length > 0) {
    if (blockers.some((blocker) => /quote|route|refresh|fallback/i.test(blocker))) return "requote";
    if (blockers.some((blocker) => /liquidity|slippage|drag|depth|size/i.test(blocker))) return "resize";
    return "blocked";
  }
  if (alpha.action !== "paper-attack" && alpha.action !== "paper-probe") return "watch";
  if (route?.action === "probe" || depth?.action === "resize" || churn?.action === "selective") return "paper-probe";
  if (tradeabilityScore >= 74 && modeledSlippageBps < 130 && routeCostBps < 95 && alpha.action === "paper-attack") return "paper-fill";
  if (tradeabilityScore >= 56 && modeledSlippageBps < 210 && routeCostBps < 145) return "paper-probe";
  return "resize";
}

function autonomousTradeabilityStatus(action: AutonomousTradeabilityAction): AutonomousTradeabilityItem["status"] {
  if (action === "paper-fill") return "fillable";
  if (action === "paper-probe") return "probe";
  if (action === "resize") return "resize";
  if (action === "requote") return "requote";
  if (action === "protect") return "protect";
  if (action === "blocked") return "blocked";
  return "watch";
}

function autonomousTradeabilityDecision(
  action: AutonomousTradeabilityAction,
  symbol: string,
  sizeUsd: number,
  score: number,
  shortfallUsd: number,
  blockers: string[],
) {
  if (action === "paper-fill") return `Paper-fill ${symbol} up to ${formatCompactValue(sizeUsd)}; tradeability is ${score}/100 with ${formatCompactValue(shortfallUsd)} modeled shortfall.`;
  if (action === "paper-probe") return `Probe ${symbol} up to ${formatCompactValue(sizeUsd)} and re-score after the next quote/fill tick.`;
  if (action === "resize") return blockers[0] ?? `Resize ${symbol}; route or depth friction is too high for the current paper size.`;
  if (action === "requote") return blockers[0] ?? `Requote ${symbol} before trusting the fill simulation.`;
  if (action === "protect") return `Route ${symbol} through protective lanes before any fresh fill.`;
  if (action === "blocked") return blockers[0] ?? `Block ${symbol}; tradeability does not clear execution risk.`;
  return `Watch ${symbol}; alpha is not yet executable enough to spend paper budget.`;
}

function autonomousTradeabilityActionRank(action: AutonomousTradeabilityAction) {
  if (action === "paper-fill") return 7;
  if (action === "paper-probe") return 6;
  if (action === "resize") return 5;
  if (action === "protect") return 4;
  if (action === "requote") return 3;
  if (action === "watch") return 2;
  return 1;
}

function autonomousTradeabilitySummary(
  status: AutonomousTradeabilitySimulator["status"],
  fillableCount: number,
  probeCount: number,
  resizeCount: number,
  requoteCount: number,
  blockedCount: number,
  leader: AutonomousTradeabilityItem | null,
) {
  if (status === "sample") return `${leader?.symbol ?? "Sample tape"} is execution-simulated in paper mode; live fills still require fresh quotes and signed execution gates.`;
  if (status === "fillable") return `${fillableCount} alpha candidate${fillableCount === 1 ? "" : "s"} clear route, depth, slippage, fill-quality, and churn gates for local paper fill.`;
  if (status === "probe") return `${probeCount} candidate${probeCount === 1 ? "" : "s"} can be probed with capped paper sizing after execution haircuts.`;
  if (status === "resize") return `${resizeCount} candidate${resizeCount === 1 ? "" : "s"} need smaller or sliced paper size before fill simulation is trusted.`;
  if (status === "requote") return `${requoteCount} candidate${requoteCount === 1 ? "" : "s"} need fresh route evidence before paper fill simulation.`;
  if (status === "blocked") return `${blockedCount} candidate${blockedCount === 1 ? "" : "s"} are blocked by execution friction.`;
  return "No alpha candidate is executable enough to spend paper budget yet.";
}

function buildLaunchSniper({
  market,
  signals,
  discoveryTape,
  trendCatalyst,
  priceAction,
  tokenVetting,
  rugFirewall,
  portfolio,
}: {
  market: MemecoinMarket[];
  signals: TradingSignal[];
  discoveryTape: DiscoveryTape;
  trendCatalyst: TrendCatalystIntelligence;
  priceAction: PriceActionMonitor;
  tokenVetting: TokenVettingReport;
  rugFirewall: RugPullFirewall;
  portfolio: TradingPortfolio;
}): LaunchSniper {
  const discoveryByToken = new Map(discoveryTape.top_candidates.map((item) => [item.token_id, item]));
  const signalByToken = new Map(signals.map((item) => [item.token_id, item]));
  const catalystByToken = new Map(trendCatalyst.items.map((item) => [item.token_id, item]));
  const priceActionByToken = new Map(priceAction.items.map((item) => [item.token_id, item]));
  const vettingByToken = new Map(tokenVetting.items.map((item) => [item.token_id, item]));
  const firewallByToken = new Map(rugFirewall.items.map((item) => [item.token_id, item]));
  const heldTokenIds = new Set(portfolio.open_positions.map((position) => position.token_id));
  const items = market
    .slice(0, 12)
    .map((token) => launchSniperItem({
      token,
      discovery: discoveryByToken.get(token.id),
      signal: signalByToken.get(token.id),
      catalyst: catalystByToken.get(token.id),
      priceAction: priceActionByToken.get(token.id),
      vetting: vettingByToken.get(token.id),
      firewall: firewallByToken.get(token.id),
      held: heldTokenIds.has(token.id),
      feedStatus: discoveryTape.status,
    }))
    .sort((a, b) => launchVerdictRank(b.verdict) - launchVerdictRank(a.verdict) || b.launch_score - a.launch_score)
    .slice(0, 8);
  const chaseCount = items.filter((item) => item.verdict === "snipe").length;
  const probeCount = items.filter((item) => item.verdict === "probe").length;
  const watchCount = items.filter((item) => item.verdict === "watch").length;
  const avoidCount = items.filter((item) => item.verdict === "avoid").length;
  const exitCount = items.filter((item) => item.verdict === "exit").length;
  const averageLaunchScore = Math.round(average(items.map((item) => item.launch_score)));
  const status: LaunchSniper["status"] = items.length === 0
    ? "quiet"
    : chaseCount > 0
        ? "hot"
        : probeCount > 0 || watchCount > 0
          ? "selective"
          : avoidCount > 0 || exitCount > 0
            ? "blocked"
            : "quiet";

  return {
    mode: "launch-sniper",
    status,
    scan_interval_seconds: 10,
    summary: launchSniperSummary(status, chaseCount, probeCount, avoidCount, exitCount),
    chase_count: chaseCount,
    probe_count: probeCount,
    watch_count: watchCount,
    avoid_count: avoidCount,
    exit_count: exitCount,
    average_launch_score: averageLaunchScore,
    items,
  };
}

function launchSniperItem({
  token,
  discovery,
  signal,
  catalyst,
  priceAction,
  vetting,
  firewall,
  held,
  feedStatus,
}: {
  token: MemecoinMarket;
  discovery: DiscoveryCandidate | undefined;
  signal: TradingSignal | undefined;
  catalyst: TrendCatalystItem | undefined;
  priceAction: PriceActionItem | undefined;
  vetting: TokenVettingItem | undefined;
  firewall: RugFirewallItem | undefined;
  held: boolean;
  feedStatus: DiscoveryTape["status"];
}): LaunchSniperItem {
  const buyShare = token.buys_5m / Math.max(1, token.buys_5m + token.sells_5m);
  const volumeToLiquidity = token.volume_1h_usd / Math.max(1, token.liquidity_usd);
  const sources = discovery?.sources ?? discoverySourcesForMarket(token);
  const velocityScore = clamp(Math.round(
    Math.max(0, token.price_change_5m_pct) * 2.4 +
      Math.max(0, token.price_change_1h_pct) * 0.72 +
      Math.max(0, token.price_change_6h_pct) * 0.16 +
      (priceAction?.velocity_score ?? 35) * 0.26,
  ), 0, 100);
  const flowScore = clamp(Math.round(
    buyShare * 84 +
      (priceAction?.flow_score ?? 38) * 0.32 +
      Math.min(18, token.buys_5m / 12) -
      Math.min(28, token.sells_5m / 18),
  ), 0, 100);
  const liquidityScore = clamp(Math.round(
    Math.log10(Math.max(token.liquidity_usd, 1)) * 12 +
      Math.min(18, token.liquidity_usd / 80_000) -
      Math.max(0, volumeToLiquidity - 4) * 8 -
      (token.liquidity_usd < 75_000 ? 32 : token.liquidity_usd < 180_000 ? 14 : 0),
  ), 0, 100);
  const freshnessScore = clamp(
    token.age_minutes <= 20 ? 96 : token.age_minutes <= 90 ? 84 : token.age_minutes <= 240 ? 68 : token.age_minutes <= 720 ? 46 : 28,
    0,
    100,
  );
  const sourceScore = clamp(
    sources.length * 8 +
      (sources.includes("dex-latest-profiles") ? 8 : 0) +
      (sources.includes("dex-community-takeovers") ? 10 : 0) +
      (sources.includes("dex-latest-ads") ? -10 : 0),
    0,
    30,
  );
  const trapRisk = clamp(Math.round(
    (firewall?.composite_risk_score ?? 32) * 0.42 +
      (vetting?.risk_score ?? 28) * 0.32 +
      token.risk_flags.length * 7 +
      token.paid_orders * 4 +
      (catalyst?.promotion_risk_score ?? 24) * 0.18 +
      (token.liquidity_usd < 100_000 ? 18 : 0) +
      (feedStatus === "fallback" ? 18 : 0),
  ), 0, 100);
  const launchScore = clamp(Math.round(
    velocityScore * 0.26 +
      flowScore * 0.24 +
      liquidityScore * 0.19 +
      freshnessScore * 0.13 +
      (discovery?.scout_score ?? signal?.score ?? 40) * 0.12 +
      sourceScore -
      trapRisk * 0.31,
  ), 0, 100);
  const blockers = launchSniperBlockers(token, vetting, firewall, catalyst, feedStatus, held, liquidityScore, flowScore, trapRisk);
  const verdict = launchSniperVerdict({ launchScore, flowScore, liquidityScore, trapRisk, blockers, held, signal, priceAction, firewall, vetting });
  const suggestedEntry = launchSniperEntryUsd(verdict, launchScore, vetting, firewall, liquidityScore, held);
  const priority: ExecutionIntentPriority = verdict === "snipe" || verdict === "exit"
    ? "now"
    : verdict === "probe"
      ? "next"
      : "later";

  return {
    token_id: token.id,
    symbol: token.symbol,
    chain: token.chain,
    verdict,
    priority,
    launch_score: launchScore,
    velocity_score: velocityScore,
    flow_score: flowScore,
    liquidity_score: liquidityScore,
    trap_risk_score: trapRisk,
    age_minutes: token.age_minutes,
    graduation_signal: launchGraduationSignal(token),
    suggested_entry_usd: suggestedEntry,
    stop_loss_pct: verdict === "snipe" ? -9 : verdict === "probe" ? -7 : -5,
    take_profit_pct: verdict === "snipe" ? 24 : verdict === "probe" ? 16 : 10,
    max_hold_minutes: verdict === "snipe" ? 45 : verdict === "probe" ? 25 : 15,
    review_after_seconds: launchReviewSeconds(verdict, launchScore, trapRisk),
    next_action: launchSniperNextAction(verdict, token.symbol, suggestedEntry),
    sources,
    reasons: launchSniperReasons(token, velocityScore, flowScore, liquidityScore, trapRisk, sources),
    blockers,
  };
}

function launchSniperBlockers(
  token: MemecoinMarket,
  vetting: TokenVettingItem | undefined,
  firewall: RugFirewallItem | undefined,
  catalyst: TrendCatalystItem | undefined,
  feedStatus: DiscoveryTape["status"],
  held: boolean,
  liquidityScore: number,
  flowScore: number,
  trapRisk: number,
) {
  const blockers: string[] = [];
  if (feedStatus === "fallback") blockers.push("Live discovery fell back; do not snipe stale launch data.");
  if (held) blockers.push("Already held; manage through position watch instead of adding launch size.");
  if (vetting?.status === "blocked") blockers.push(vetting.issues[0] ?? vetting.summary);
  if (firewall?.action === "quarantine" || firewall?.action === "exit") blockers.push(firewall.blockers[0] ?? firewall.summary);
  if (token.risk_flags.includes("thin-liquidity") || liquidityScore < 32) blockers.push("Liquidity is too thin for autonomous launch entry.");
  if (token.risk_flags.includes("new-pair") && token.age_minutes < 30 && token.liquidity_usd < 100_000) blockers.push("Fresh pair has not earned enough liquidity support.");
  if (token.risk_flags.includes("paid-promotion-heavy") || (catalyst?.promotion_risk_score ?? 0) >= 75) blockers.push("Promotion risk is too high for a blind chase.");
  if (flowScore < 38) blockers.push("Buy flow is not strong enough for a launch snipe.");
  if (trapRisk >= 72) blockers.push("Composite trap risk is above the launch ceiling.");
  return [...new Set(blockers)].slice(0, 5);
}

function launchSniperVerdict({
  launchScore,
  flowScore,
  liquidityScore,
  trapRisk,
  blockers,
  held,
  signal,
  priceAction,
  firewall,
  vetting,
}: {
  launchScore: number;
  flowScore: number;
  liquidityScore: number;
  trapRisk: number;
  blockers: string[];
  held: boolean;
  signal: TradingSignal | undefined;
  priceAction: PriceActionItem | undefined;
  firewall: RugFirewallItem | undefined;
  vetting: TokenVettingItem | undefined;
}): LaunchSniperVerdict {
  if (held && (priceAction?.decision === "eject" || signal?.action === "sell" || firewall?.action === "exit")) return "exit";
  if (blockers.length > 0 || vetting?.status === "blocked" || firewall?.action === "quarantine") return "avoid";
  if (trapRisk >= 62 || liquidityScore < 40) return "avoid";
  if (launchScore >= 72 && flowScore >= 62 && signal?.action === "buy") return "snipe";
  if (launchScore >= 58 && flowScore >= 52) return "probe";
  return "watch";
}

function launchSniperEntryUsd(
  verdict: LaunchSniperVerdict,
  launchScore: number,
  vetting: TokenVettingItem | undefined,
  firewall: RugFirewallItem | undefined,
  liquidityScore: number,
  held: boolean,
) {
  if (held || verdict === "watch" || verdict === "avoid" || verdict === "exit") return 0;
  const base = verdict === "snipe" ? 650 : 275;
  const scoreBoost = Math.max(0, launchScore - 55) * (verdict === "snipe" ? 12 : 6);
  const liquidityBoost = Math.max(0, liquidityScore - 50) * 4;
  const cap = Math.min(vetting?.max_position_usd ?? 850, firewall?.max_entry_usd ?? 850, 1_000);
  return Math.max(100, Math.round(Math.min(cap, base + scoreBoost + liquidityBoost)));
}

function launchGraduationSignal(token: MemecoinMarket): LaunchSniperItem["graduation_signal"] {
  if (token.age_minutes < 120 && token.dex.toLowerCase().includes("pump")) return "fresh-pair";
  if (token.age_minutes < 360 && token.liquidity_usd >= 250_000 && token.volume_1h_usd >= 250_000) return "graduated";
  if (token.age_minutes >= 720) return "established";
  return "unknown";
}

function launchReviewSeconds(verdict: LaunchSniperVerdict, launchScore: number, trapRisk: number) {
  if (verdict === "snipe") return trapRisk >= 45 ? 10 : 15;
  if (verdict === "probe") return launchScore >= 65 ? 20 : 30;
  if (verdict === "exit" || verdict === "avoid") return 10;
  return 45;
}

function launchSniperNextAction(verdict: LaunchSniperVerdict, symbol: string, suggestedEntry: number) {
  if (verdict === "snipe") return `Queue a ${formatCompactValue(suggestedEntry)} paper snipe and review in 10-15 seconds.`;
  if (verdict === "probe") return `Probe ${symbol} only if the next tape confirms buy pressure.`;
  if (verdict === "exit") return `Do not add ${symbol}; route held exposure to exit watch.`;
  if (verdict === "avoid") return `Avoid ${symbol} until blockers clear.`;
  return `Watch ${symbol}; no autonomous launch entry yet.`;
}

function launchSniperReasons(
  token: MemecoinMarket,
  velocityScore: number,
  flowScore: number,
  liquidityScore: number,
  trapRisk: number,
  sources: DiscoverySourceId[],
) {
  const buyShare = Math.round((token.buys_5m / Math.max(1, token.buys_5m + token.sells_5m)) * 100);
  return [
    `${formatPct(token.price_change_5m_pct)} 5m / ${formatPct(token.price_change_1h_pct)} 1h velocity`,
    `${buyShare}% 5m buy flow`,
    `${formatCompactValue(token.volume_1h_usd)} 1h volume vs ${formatCompactValue(token.liquidity_usd)} liquidity`,
    `${velocityScore}/${flowScore}/${liquidityScore} velocity-flow-liquidity`,
    `${trapRisk}/100 trap risk`,
    sources.map(sourceLabelForModel).join(", "),
  ].filter(Boolean).slice(0, 6);
}

function launchSniperSummary(status: LaunchSniper["status"], chaseCount: number, probeCount: number, avoidCount: number, exitCount: number) {
  if (status === "hot") return `${chaseCount} launch${chaseCount === 1 ? "" : "es"} qualify for immediate paper snipe sizing; ${probeCount} remain probe-only.`;
  if (status === "selective") return `${probeCount + chaseCount} launch candidate${probeCount + chaseCount === 1 ? "" : "s"} can be tested, but none deserve full chase size.`;
  if (status === "blocked") return `${avoidCount + exitCount} launch candidate${avoidCount + exitCount === 1 ? "" : "s"} are blocked or exit-first before sizing.`;
  return "No fresh launch has enough velocity, flow, liquidity, and safety to chase right now.";
}

function buildLaunchGraduationSupervisor({
  market,
  discoveryTape,
  launchSniper,
  discoveryEdge,
  marketStream,
  trendCatalyst,
  rugFirewall,
  tokenVetting,
  portfolio,
}: {
  market: MemecoinMarket[];
  discoveryTape: DiscoveryTape;
  launchSniper: LaunchSniper;
  discoveryEdge: DiscoveryEdgeSupervisor;
  marketStream: MarketStreamSupervisor;
  trendCatalyst: TrendCatalystIntelligence;
  rugFirewall: RugPullFirewall;
  tokenVetting: TokenVettingReport;
  portfolio: TradingPortfolio;
}): LaunchGraduationSupervisor {
  const launchByToken = new Map(launchSniper.items.map((item) => [item.token_id, item]));
  const edgeByToken = new Map(discoveryEdge.items.map((item) => [item.token_id, item]));
  const candidateByToken = new Map(discoveryTape.top_candidates.map((item) => [item.token_id, item]));
  const catalystByToken = new Map(trendCatalyst.items.map((item) => [item.token_id, item]));
  const firewallByToken = new Map(rugFirewall.items.map((item) => [item.token_id, item]));
  const vettingByToken = new Map(tokenVetting.items.map((item) => [item.token_id, item]));
  const positionByToken = new Map(portfolio.open_positions.map((position) => [position.token_id, position]));
  const candidateTokenIds = new Set<string>([
    ...launchSniper.items.map((item) => item.token_id),
    ...discoveryEdge.items.map((item) => item.token_id),
    ...discoveryTape.top_candidates.map((item) => item.token_id),
    ...market.slice(0, 10).map((item) => item.id),
  ]);
  const items = market
    .filter((token) => candidateTokenIds.has(token.id))
    .map((token) => launchGraduationItem({
      token,
      launch: launchByToken.get(token.id),
      edge: edgeByToken.get(token.id),
      discovery: candidateByToken.get(token.id),
      catalyst: catalystByToken.get(token.id),
      firewall: firewallByToken.get(token.id),
      vetting: vettingByToken.get(token.id),
      position: positionByToken.get(token.id),
      feedStatus: discoveryTape.status,
      marketStream,
    }))
    .sort((a, b) => launchGraduationActionRank(b.action) - launchGraduationActionRank(a.action) || b.graduation_score - a.graduation_score)
    .slice(0, 8);
  const graduatingCount = items.filter((item) => item.phase === "graduating").length;
  const graduatedCount = items.filter((item) => item.phase === "graduated" || item.phase === "post-graduation").length;
  const actionableCount = items.filter((item) => item.action === "graduate" || item.action === "snipe" || item.action === "probe" || item.action === "trim").length;
  const avoidCount = items.filter((item) => item.action === "avoid").length;
  const averageGraduationScore = Math.round(average(items.map((item) => item.graduation_score)));
  const status: LaunchGraduationSupervisor["status"] = items.length === 0
    ? "quiet"
    : graduatingCount > 0 && actionableCount > 0
      ? "graduating"
      : items.some((item) => item.action === "graduate" || item.action === "snipe")
        ? "hunt"
        : graduatedCount > 0 && actionableCount > 0
          ? "post-graduation"
          : avoidCount > 0 && actionableCount === 0
            ? "cooldown"
            : "quiet";

  return {
    mode: "launch-graduation-supervisor",
    status,
    summary: launchGraduationSummary(status, graduatingCount, graduatedCount, actionableCount, avoidCount),
    scan_interval_seconds: launchGraduationScanSeconds(status, items),
    graduating_count: graduatingCount,
    graduated_count: graduatedCount,
    actionable_count: actionableCount,
    avoid_count: avoidCount,
    average_graduation_score: averageGraduationScore,
    next_action: launchGraduationNextAction(status, items),
    items,
  };
}

function launchGraduationItem({
  token,
  launch,
  edge,
  discovery,
  catalyst,
  firewall,
  vetting,
  position,
  feedStatus,
  marketStream,
}: {
  token: MemecoinMarket;
  launch: LaunchSniperItem | undefined;
  edge: DiscoveryEdgeItem | undefined;
  discovery: DiscoveryCandidate | undefined;
  catalyst: TrendCatalystItem | undefined;
  firewall: RugFirewallItem | undefined;
  vetting: TokenVettingItem | undefined;
  position: TradingPosition | undefined;
  feedStatus: DiscoveryTape["status"];
  marketStream: MarketStreamSupervisor;
}): LaunchGraduationItem {
  const buyShare = token.buys_5m / Math.max(1, token.buys_5m + token.sells_5m);
  const volumeToLiquidity = token.volume_1h_usd / Math.max(1, token.liquidity_usd);
  const curveProgress = launchCurveProgressPct(token, launch);
  const phase = launchGraduationPhase(token, launch, curveProgress);
  const sourceScore = clamp(Math.round(
    (discovery?.sources.length ?? 0) * 14 +
      (edge?.source_confirmation_score ?? 0) * 0.46 +
      (discovery?.freshness_score ?? 0) * 0.18,
  ), 0, 100);
  const liquidityHandoffScore = clamp(Math.round(
    Math.log10(Math.max(token.liquidity_usd, 1)) * 12 +
      Math.min(24, volumeToLiquidity * 9) +
      (isAmmGraduationDex(token.dex) ? 22 : 0) +
      (marketStream.status === "streaming" || marketStream.status === "sample" ? 8 : marketStream.status === "backfill" ? 2 : -10) -
      (token.liquidity_usd < 80_000 ? 24 : token.liquidity_usd < 160_000 ? 10 : 0),
  ), 0, 100);
  const postGraduationMomentumScore = clamp(Math.round(
    Math.max(0, token.price_change_5m_pct) * 2 +
      Math.max(0, token.price_change_1h_pct) * 0.82 +
      Math.max(0, token.price_change_6h_pct) * 0.18 +
      buyShare * 38 +
      Math.min(18, token.volume_5m_usd / Math.max(1, token.liquidity_usd) * 18) -
      Math.max(0, token.sells_5m - token.buys_5m) * 0.08,
  ), 0, 100);
  const trapRisk = clamp(Math.round(
    (launch?.trap_risk_score ?? 34) * 0.34 +
      (firewall?.composite_risk_score ?? 32) * 0.28 +
      (vetting?.risk_score ?? 30) * 0.22 +
      (catalyst?.promotion_risk_score ?? 24) * 0.12 +
      token.risk_flags.length * 5 +
      (feedStatus === "fallback" ? 14 : 0) +
      (marketStream.status === "reconnect" ? 10 : 0),
  ), 0, 100);
  const migrationReadinessScore = clamp(Math.round(
    curveProgress * 0.46 +
      sourceScore * 0.18 +
      liquidityHandoffScore * 0.18 +
      buyShare * 26 +
      (phase === "graduating" ? 10 : phase === "graduated" || phase === "post-graduation" ? 6 : 0) -
      trapRisk * 0.18,
  ), 0, 100);
  const graduationScore = clamp(Math.round(
    migrationReadinessScore * 0.34 +
      liquidityHandoffScore * 0.24 +
      postGraduationMomentumScore * 0.24 +
      (edge?.edge_score ?? launch?.launch_score ?? 42) * 0.18 -
      trapRisk * 0.28,
  ), 0, 100);
  const blockers = launchGraduationBlockers({
    token,
    launch,
    edge,
    vetting,
    firewall,
    feedStatus,
    marketStream,
    phase,
    trapRisk,
    liquidityHandoffScore,
    sourceScore,
  });
  const action = launchGraduationAction({
    phase,
    launch,
    position,
    graduationScore,
    migrationReadinessScore,
    liquidityHandoffScore,
    postGraduationMomentumScore,
    trapRisk,
    blockers,
  });
  const suggestedEntry = launchGraduationEntryUsd(action, launch, vetting, firewall, token, graduationScore, liquidityHandoffScore);
  const suggestedTrimPct = action === "trim" ? (trapRisk >= 64 ? 50 : 35) : 0;
  const priority: ExecutionIntentPriority = action === "graduate" || action === "snipe" || action === "trim"
    ? "now"
    : action === "probe"
      ? "next"
      : "later";

  return {
    token_id: token.id,
    symbol: token.symbol,
    chain: token.chain,
    phase,
    action,
    priority,
    graduation_score: graduationScore,
    migration_readiness_score: migrationReadinessScore,
    curve_progress_pct: curveProgress,
    liquidity_handoff_score: liquidityHandoffScore,
    post_graduation_momentum_score: postGraduationMomentumScore,
    trap_risk_score: trapRisk,
    suggested_entry_usd: suggestedEntry,
    suggested_trim_pct: suggestedTrimPct,
    review_after_seconds: launchGraduationReviewSeconds(action, phase, trapRisk),
    reason: launchGraduationReason(action, token.symbol, phase, graduationScore, migrationReadinessScore, curveProgress),
    triggers: launchGraduationTriggers(token, phase, curveProgress, migrationReadinessScore, liquidityHandoffScore, postGraduationMomentumScore, sourceScore),
    blockers,
  };
}

function launchCurveProgressPct(token: MemecoinMarket, launch: LaunchSniperItem | undefined) {
  const dex = token.dex.toLowerCase();
  if (isAmmGraduationDex(token.dex) && token.age_minutes < 720 && token.liquidity_usd >= 150_000) return 100;
  const threshold = dex.includes("pump")
    ? 69_000
    : dex.includes("moonshot")
      ? 345_000
      : dex.includes("meteora")
        ? 220_000
        : 180_000;
  const progress = Math.round((token.market_cap_usd / Math.max(1, threshold)) * 100);
  const freshnessFloor = token.age_minutes < 20 ? 12 : token.age_minutes < 90 ? 24 : 38;
  const launchBoost = launch?.graduation_signal === "graduated" ? 100 : launch?.graduation_signal === "fresh-pair" ? 8 : 0;
  return clamp(Math.max(freshnessFloor, progress, launchBoost), 5, 100);
}

function launchGraduationPhase(token: MemecoinMarket, launch: LaunchSniperItem | undefined, curveProgress: number): LaunchGraduationPhase {
  if (token.age_minutes >= 1_440) return "stale";
  if (launch?.graduation_signal === "graduated") return token.age_minutes <= 360 ? "graduated" : "post-graduation";
  if (isAmmGraduationDex(token.dex) && curveProgress >= 100) return token.age_minutes <= 360 ? "graduated" : "post-graduation";
  if (curveProgress >= 76 || (token.liquidity_usd >= 220_000 && token.volume_1h_usd >= 180_000 && token.age_minutes < 360)) return "graduating";
  if (isLaunchpadDex(token.dex) || launch?.graduation_signal === "fresh-pair") return curveProgress <= 18 ? "pre-curve" : "bonding-curve";
  if (token.age_minutes <= 360) return "bonding-curve";
  return token.age_minutes <= 720 ? "post-graduation" : "stale";
}

function isLaunchpadDex(dex: string) {
  const lower = dex.toLowerCase();
  return lower.includes("pump") || lower.includes("moonshot") || lower.includes("meteora") || lower.includes("launch");
}

function isAmmGraduationDex(dex: string) {
  const lower = dex.toLowerCase();
  return lower.includes("pumpswap") || lower.includes("raydium") || lower.includes("damm") || lower.includes("orca");
}

function launchGraduationBlockers({
  token,
  launch,
  edge,
  vetting,
  firewall,
  feedStatus,
  marketStream,
  phase,
  trapRisk,
  liquidityHandoffScore,
  sourceScore,
}: {
  token: MemecoinMarket;
  launch: LaunchSniperItem | undefined;
  edge: DiscoveryEdgeItem | undefined;
  vetting: TokenVettingItem | undefined;
  firewall: RugFirewallItem | undefined;
  feedStatus: DiscoveryTape["status"];
  marketStream: MarketStreamSupervisor;
  phase: LaunchGraduationPhase;
  trapRisk: number;
  liquidityHandoffScore: number;
  sourceScore: number;
}) {
  const blockers: string[] = [];
  if (feedStatus === "fallback") blockers.push("Discovery is fallback-only; graduation timing cannot be trusted.");
  if (marketStream.status === "reconnect") blockers.push("Market stream is reconnecting; wait for pair backfill before migration timing.");
  if (vetting?.status === "blocked") blockers.push(vetting.issues[0] ?? vetting.summary);
  if (firewall?.action === "quarantine" || firewall?.action === "exit") blockers.push(firewall.blockers[0] ?? firewall.summary);
  if (phase === "stale") blockers.push("Launch is outside the useful graduation window.");
  if (trapRisk >= 72) blockers.push("Trap risk is above the graduation ceiling.");
  if (liquidityHandoffScore < 34) blockers.push("Liquidity handoff is too thin for autonomous migration entry.");
  if (edge?.blockers[0]) blockers.push(edge.blockers[0]);
  if (sourceScore < 18 && token.age_minutes < 360) blockers.push("Not enough independent discovery sources confirm the launch.");
  if (launch?.blockers[0]) blockers.push(launch.blockers[0]);
  return [...new Set(blockers)].slice(0, 5);
}

function launchGraduationAction({
  phase,
  launch,
  position,
  graduationScore,
  migrationReadinessScore,
  liquidityHandoffScore,
  postGraduationMomentumScore,
  trapRisk,
  blockers,
}: {
  phase: LaunchGraduationPhase;
  launch: LaunchSniperItem | undefined;
  position: TradingPosition | undefined;
  graduationScore: number;
  migrationReadinessScore: number;
  liquidityHandoffScore: number;
  postGraduationMomentumScore: number;
  trapRisk: number;
  blockers: string[];
}): LaunchGraduationAction {
  if (blockers.length > 0) return position && (postGraduationMomentumScore < 42 || trapRisk >= 64) ? "trim" : "avoid";
  if (position && (phase === "graduated" || phase === "post-graduation") && (trapRisk >= 58 || postGraduationMomentumScore < 38)) return "trim";
  if (phase === "graduating" && graduationScore >= 62 && migrationReadinessScore >= 64 && liquidityHandoffScore >= 50) return "graduate";
  if ((phase === "bonding-curve" || phase === "pre-curve") && launch?.verdict === "snipe" && graduationScore >= 60) return "snipe";
  if ((phase === "bonding-curve" || phase === "pre-curve") && launch?.verdict === "probe" && graduationScore >= 48) return "probe";
  if ((phase === "graduated" || phase === "post-graduation") && graduationScore >= 64 && postGraduationMomentumScore >= 58) return launch?.verdict === "snipe" ? "snipe" : "probe";
  return "wait";
}

function launchGraduationEntryUsd(
  action: LaunchGraduationAction,
  launch: LaunchSniperItem | undefined,
  vetting: TokenVettingItem | undefined,
  firewall: RugFirewallItem | undefined,
  token: MemecoinMarket,
  graduationScore: number,
  liquidityHandoffScore: number,
) {
  if (action === "wait" || action === "avoid" || action === "trim") return 0;
  const base = action === "graduate" ? 575 : action === "snipe" ? 475 : 225;
  const scoreBoost = Math.max(0, graduationScore - 52) * (action === "probe" ? 4 : 8);
  const handoffBoost = Math.max(0, liquidityHandoffScore - 50) * 3;
  const liquidityCap = Math.max(100, Math.floor(token.liquidity_usd * 0.004));
  const cap = Math.min(vetting?.max_position_usd ?? 900, firewall?.max_entry_usd ?? 900, launch?.suggested_entry_usd ?? 900, liquidityCap, 1_000);
  return Math.max(100, Math.round(Math.min(cap, base + scoreBoost + handoffBoost)));
}

function launchGraduationReviewSeconds(action: LaunchGraduationAction, phase: LaunchGraduationPhase, trapRisk: number) {
  if (action === "graduate") return trapRisk >= 48 ? 5 : 7;
  if (action === "snipe") return 8;
  if (action === "probe") return 12;
  if (action === "trim" || action === "avoid") return 10;
  if (phase === "graduating") return 12;
  return 25;
}

function launchGraduationReason(
  action: LaunchGraduationAction,
  symbol: string,
  phase: LaunchGraduationPhase,
  graduationScore: number,
  migrationReadinessScore: number,
  curveProgress: number,
) {
  if (action === "graduate") return `${symbol} is in the graduation window: ${curveProgress}% curve progress and ${migrationReadinessScore}/100 migration readiness.`;
  if (action === "snipe") return `${symbol} has enough ${phase.replace("-", " ")} velocity for an immediate paper snipe.`;
  if (action === "probe") return `${symbol} can be probed while the handoff tape confirms momentum.`;
  if (action === "trim") return `${symbol} is already held; protect capital through a graduation-window trim.`;
  if (action === "avoid") return `${symbol} is blocked until migration, liquidity, or safety improves.`;
  return `${symbol} stays on watch with ${graduationScore}/100 graduation score.`;
}

function launchGraduationTriggers(
  token: MemecoinMarket,
  phase: LaunchGraduationPhase,
  curveProgress: number,
  migrationReadinessScore: number,
  liquidityHandoffScore: number,
  postGraduationMomentumScore: number,
  sourceScore: number,
) {
  return [
    `${phase.replace("-", " ")} phase`,
    `${curveProgress}% inferred curve progress`,
    `${migrationReadinessScore}/100 migration readiness`,
    `${liquidityHandoffScore}/100 liquidity handoff`,
    `${postGraduationMomentumScore}/100 post-grad momentum`,
    `${sourceScore}/100 source confirmation`,
    `${formatCompactValue(token.volume_1h_usd)} 1h volume`,
  ].slice(0, 7);
}

function launchGraduationSummary(
  status: LaunchGraduationSupervisor["status"],
  graduatingCount: number,
  graduatedCount: number,
  actionableCount: number,
  avoidCount: number,
) {
  if (status === "graduating") return `${graduatingCount} launch${graduatingCount === 1 ? "" : "es"} are near migration; ${actionableCount} graduation action${actionableCount === 1 ? "" : "s"} are queued.`;
  if (status === "hunt") return `${actionableCount} launch graduation setup${actionableCount === 1 ? "" : "s"} can be attacked with paper sizing.`;
  if (status === "post-graduation") return `${graduatedCount} migrated launch${graduatedCount === 1 ? "" : "es"} still have post-graduation tape worth supervising.`;
  if (status === "cooldown") return `${avoidCount} launch graduation candidate${avoidCount === 1 ? "" : "s"} are blocked by stream, liquidity, or safety gates.`;
  return "No launch is close enough to the migration or post-graduation window to trade.";
}

function launchGraduationNextAction(status: LaunchGraduationSupervisor["status"], items: LaunchGraduationItem[]) {
  const first = items.find((item) => item.action === "graduate" || item.action === "snipe" || item.action === "probe" || item.action === "trim");
  if (first) return `${first.action === "graduate" ? "Prepare migration entry" : first.action === "trim" ? "Protect held exposure" : "Queue paper entry"} for ${first.symbol}; review again in ${first.review_after_seconds}s.`;
  if (status === "cooldown") return items[0]?.blockers[0] ?? "Wait for migration blockers to clear before sizing.";
  return "Keep monitoring launchpad progress, AMM handoff, and post-migration momentum.";
}

function launchGraduationScanSeconds(status: LaunchGraduationSupervisor["status"], items: LaunchGraduationItem[]) {
  if (status === "graduating") return 5;
  if (status === "hunt") return 8;
  if (status === "post-graduation") return 10;
  if (status === "cooldown") return 15;
  return items.length > 0 ? 20 : 30;
}

function launchGraduationActionRank(action: LaunchGraduationAction) {
  if (action === "graduate") return 6;
  if (action === "snipe") return 5;
  if (action === "probe") return 4;
  if (action === "trim") return 3;
  if (action === "wait") return 2;
  return 1;
}

function launchVerdictRank(verdict: LaunchSniperVerdict) {
  if (verdict === "snipe") return 5;
  if (verdict === "probe") return 4;
  if (verdict === "exit") return 3;
  if (verdict === "watch") return 2;
  return 1;
}

function buildAutonomousLaunchTiming({
  market,
  launchSniper,
  launchGraduation,
  discoveryTape,
}: {
  market: MemecoinMarket[];
  launchSniper: LaunchSniper;
  launchGraduation: LaunchGraduationSupervisor;
  discoveryTape: DiscoveryTape;
}): AutonomousLaunchTiming {
  const launchByToken = new Map(launchSniper.items.map((item) => [item.token_id, item]));
  const graduationByToken = new Map(launchGraduation.items.map((item) => [item.token_id, item]));
  const discoveryByToken = new Map(discoveryTape.top_candidates.map((item) => [item.token_id, item]));
  const items = market
    .slice(0, 12)
    .map((token) => autonomousLaunchTimingItem({
      token,
      launch: launchByToken.get(token.id),
      graduation: graduationByToken.get(token.id),
      discovery: discoveryByToken.get(token.id),
      discoveryStatus: discoveryTape.status,
    }))
    .sort((a, b) => autonomousLaunchTimingActionRank(b.action) - autonomousLaunchTimingActionRank(a.action) || b.timing_score - a.timing_score)
    .slice(0, 8);
  const leader = items[0] ?? null;
  const earlyCount = items.filter((item) => item.action === "snipe-now").length;
  const probeCount = items.filter((item) => item.action === "probe").length;
  const confirmCount = items.filter((item) => item.action === "confirm").length;
  const lateCount = items.filter((item) => item.action === "late-chase").length;
  const fadedCount = items.filter((item) => item.action === "fade").length;
  const blockedCount = items.filter((item) => item.action === "stand-down").length;
  const status: AutonomousLaunchTiming["status"] = !leader
    ? "idle"
    : earlyCount > 0
      ? "snipe"
      : probeCount > 0
        ? "probe"
        : confirmCount > 0
          ? "confirm"
          : lateCount > 0
            ? "late-chase"
            : fadedCount > 0
              ? "fade"
              : blockedCount > 0
                ? "blocked"
                : "idle";

  return {
    mode: "autonomous-launch-timing",
    status,
    selected_symbol: leader?.symbol ?? null,
    selected_action: leader?.action ?? "stand-down",
    selected_phase: leader?.phase ?? null,
    timing_score: leader?.timing_score ?? 0,
    early_count: earlyCount,
    probe_count: probeCount,
    confirm_count: confirmCount,
    late_count: lateCount,
    faded_count: fadedCount,
    blocked_count: blockedCount,
    recommended_entry_usd: leader?.recommended_entry_usd ?? 0,
    max_next_fills: earlyCount > 0 ? 2 : probeCount > 0 || lateCount > 0 ? 1 : 0,
    should_wait_confirmation: status === "confirm" || leader?.action === "confirm",
    should_block_late_chase: items.some((item) => item.action === "fade" && (item.crowding_score >= 70 || item.paid_hype_score >= 70)),
    fastest_review_seconds: items.length ? Math.min(...items.map((item) => item.review_after_seconds)) : 30,
    summary: autonomousLaunchTimingSummary(status, leader, earlyCount, probeCount, confirmCount, lateCount, fadedCount, blockedCount),
    next_action: autonomousLaunchTimingNextAction(status, leader),
    controls: [
      "Ranks launch sniper and graduation candidates into one Moonshot-style entry timing call: snipe, probe, confirm, late-chase, fade, or stand down.",
      "Crowding, paid hype, liquidity, trap risk, source freshness, launch age, and migration phase can suppress fresh paper entries before the queue spends budget.",
      "This governor can recommend local paper entries and block bad chases; it cannot guarantee profit, sign live swaps, custody funds, or override live execution gates.",
    ],
    items,
  };
}

function autonomousLaunchTimingItem({
  token,
  launch,
  graduation,
  discovery,
  discoveryStatus,
}: {
  token: MemecoinMarket;
  launch: LaunchSniperItem | undefined;
  graduation: LaunchGraduationItem | undefined;
  discovery: DiscoveryCandidate | undefined;
  discoveryStatus: DiscoveryTape["status"];
}): AutonomousLaunchTimingItem {
  const buyShare = token.buys_5m / Math.max(1, token.buys_5m + token.sells_5m);
  const volumeToLiquidity = token.volume_1h_usd / Math.max(1, token.liquidity_usd);
  const sourceSet = new Set(discovery?.sources ?? launch?.sources ?? discoverySourcesForMarket(token));
  const freshnessScore = clamp(token.age_minutes <= 20 ? 98 : token.age_minutes <= 90 ? 88 : token.age_minutes <= 240 ? 70 : token.age_minutes <= 720 ? 42 : 18, 0, 100);
  const paidHypeScore = clamp(Math.round(
    token.boosts * 6 +
      token.paid_orders * 10 +
      (sourceSet.has("dex-latest-ads") ? 26 : 0) +
      (token.risk_flags.includes("paid-promotion-heavy") ? 24 : 0) +
      (token.risk_flags.includes("boost-heavy") ? 12 : 0),
  ), 0, 100);
  const crowdingScore = clamp(Math.round(
    Math.max(0, token.age_minutes - 75) / 8 +
      Math.max(0, token.price_change_1h_pct) * 0.34 +
      Math.max(0, token.price_change_6h_pct) * 0.09 +
      volumeToLiquidity * 12 +
      paidHypeScore * 0.26 +
      Math.max(0, token.sells_5m - token.buys_5m) * 1.4,
  ), 0, 100);
  const liquidityScore = clamp(Math.round(launch?.liquidity_score ?? graduation?.liquidity_handoff_score ?? (
    Math.log10(Math.max(token.liquidity_usd, 1)) * 12 -
    (token.liquidity_usd < 100_000 ? 24 : token.liquidity_usd < 250_000 ? 10 : 0)
  )), 0, 100);
  const velocityScore = clamp(Math.round(
    (launch?.velocity_score ?? 0) * 0.58 +
      (graduation?.post_graduation_momentum_score ?? 0) * 0.18 +
      Math.max(0, token.price_change_5m_pct) * 1.2 +
      Math.max(0, token.price_change_1h_pct) * 0.28 +
      buyShare * 18,
  ), 0, 100);
  const trapRiskScore = clamp(Math.round(Math.max(
    launch?.trap_risk_score ?? 0,
    graduation?.trap_risk_score ?? 0,
    token.risk_flags.length * 8 + paidHypeScore * 0.22 + (token.liquidity_usd < 100_000 ? 20 : 0),
  )), 0, 100);
  const earlyEdgeScore = clamp(Math.round(
    (launch?.launch_score ?? 35) * 0.38 +
      (graduation?.graduation_score ?? 35) * 0.16 +
      freshnessScore * 0.22 +
      velocityScore * 0.2 +
      sourceSet.size * 4 -
      crowdingScore * 0.22 -
      paidHypeScore * 0.28 -
      trapRiskScore * 0.3,
  ), 0, 100);
  const phase = autonomousLaunchTimingPhase(token, launch, graduation, crowdingScore, trapRiskScore);
  const blockers = autonomousLaunchTimingBlockers({
    token,
    launch,
    graduation,
    discoveryStatus,
    liquidityScore,
    paidHypeScore,
    crowdingScore,
    trapRiskScore,
    earlyEdgeScore,
  });
  const action = autonomousLaunchTimingAction({
    token,
    launch,
    graduation,
    phase,
    blockers,
    earlyEdgeScore,
    crowdingScore,
    paidHypeScore,
    velocityScore,
    liquidityScore,
    trapRiskScore,
  });
  const timingScore = clamp(Math.round(
    earlyEdgeScore * 0.44 +
      velocityScore * 0.22 +
      liquidityScore * 0.15 +
      freshnessScore * 0.13 -
      crowdingScore * 0.2 -
      paidHypeScore * 0.18 -
      trapRiskScore * 0.2,
  ), 0, 100);
  const recommendedEntry = autonomousLaunchTimingEntryUsd(action, launch, graduation, timingScore, liquidityScore);

  return {
    token_id: token.id,
    symbol: token.symbol,
    chain: token.chain,
    phase,
    action,
    status: action === "stand-down" ? "blocked" : action === "confirm" || action === "fade" ? "watch" : "ready",
    timing_score: timingScore,
    early_edge_score: earlyEdgeScore,
    crowding_score: crowdingScore,
    paid_hype_score: paidHypeScore,
    liquidity_score: liquidityScore,
    velocity_score: velocityScore,
    trap_risk_score: trapRiskScore,
    age_minutes: token.age_minutes,
    recommended_entry_usd: recommendedEntry,
    max_chase_seconds: autonomousLaunchTimingMaxChaseSeconds(action, token.age_minutes, crowdingScore),
    review_after_seconds: autonomousLaunchTimingReviewSeconds(action, phase, timingScore),
    reason: autonomousLaunchTimingReason(token.symbol, action, phase, timingScore, earlyEdgeScore, crowdingScore),
    blockers,
  };
}

function autonomousLaunchTimingPhase(
  token: MemecoinMarket,
  launch: LaunchSniperItem | undefined,
  graduation: LaunchGraduationItem | undefined,
  crowdingScore: number,
  trapRiskScore: number,
): AutonomousLaunchTimingPhase {
  if (trapRiskScore >= 72 || launch?.verdict === "avoid" || graduation?.action === "avoid") return "blocked";
  if (graduation?.phase === "graduating" || graduation?.phase === "graduated") return "migration-window";
  if (token.age_minutes <= 90 || launch?.graduation_signal === "fresh-pair") return "fresh-launch";
  if (token.age_minutes <= 240) return crowdingScore >= 68 ? "crowded-pump" : "early-momentum";
  if (crowdingScore >= 68) return "crowded-pump";
  return "late-cycle";
}

function autonomousLaunchTimingBlockers({
  token,
  launch,
  graduation,
  discoveryStatus,
  liquidityScore,
  paidHypeScore,
  crowdingScore,
  trapRiskScore,
  earlyEdgeScore,
}: {
  token: MemecoinMarket;
  launch: LaunchSniperItem | undefined;
  graduation: LaunchGraduationItem | undefined;
  discoveryStatus: DiscoveryTape["status"];
  liquidityScore: number;
  paidHypeScore: number;
  crowdingScore: number;
  trapRiskScore: number;
  earlyEdgeScore: number;
}) {
  const blockers: string[] = [];
  if (discoveryStatus === "fallback") blockers.push("Live discovery is in fallback; require fresh source proof before launch timing.");
  if (launch?.verdict === "exit") blockers.push("Held launch is exit-first, not a fresh entry.");
  if (launch?.verdict === "avoid") blockers.push(launch.blockers[0] ?? "Launch sniper blocks the entry.");
  if (graduation?.action === "avoid") blockers.push(graduation.blockers[0] ?? "Graduation supervisor blocks the entry.");
  if (token.risk_flags.includes("liquidity-pulled") || token.risk_flags.includes("sell-wall")) blockers.push("Local tape flags liquidity or sell-wall risk.");
  if (liquidityScore < 30) blockers.push("Liquidity support is too thin for autonomous entry timing.");
  if (trapRiskScore >= 72) blockers.push("Trap risk is above the launch timing ceiling.");
  if (paidHypeScore >= 82 && earlyEdgeScore < 64) blockers.push("Paid hype outruns organic early edge.");
  if (crowdingScore >= 86) blockers.push("The pump is too crowded to chase safely.");
  return [...new Set(blockers)].slice(0, 5);
}

function autonomousLaunchTimingAction({
  token,
  launch,
  graduation,
  phase,
  blockers,
  earlyEdgeScore,
  crowdingScore,
  paidHypeScore,
  velocityScore,
  liquidityScore,
  trapRiskScore,
}: {
  token: MemecoinMarket;
  launch: LaunchSniperItem | undefined;
  graduation: LaunchGraduationItem | undefined;
  phase: AutonomousLaunchTimingPhase;
  blockers: string[];
  earlyEdgeScore: number;
  crowdingScore: number;
  paidHypeScore: number;
  velocityScore: number;
  liquidityScore: number;
  trapRiskScore: number;
}): AutonomousLaunchTimingAction {
  if (blockers.some((blocker) => /fallback|exit-first|blocks|liquidity|trap|sell-wall/i.test(blocker))) return "stand-down";
  if (blockers.length > 0) return "fade";
  if ((launch?.verdict === "snipe" || graduation?.action === "snipe" || graduation?.action === "graduate") && earlyEdgeScore >= 64 && crowdingScore < 66 && paidHypeScore < 72) return "snipe-now";
  if (launch?.verdict === "probe" || (earlyEdgeScore >= 56 && liquidityScore >= 42 && trapRiskScore < 62 && crowdingScore < 74)) return "probe";
  if (token.age_minutes <= 240 && velocityScore >= 50 && earlyEdgeScore >= 44 && paidHypeScore < 75) return "confirm";
  if (phase === "late-cycle" && velocityScore >= 66 && crowdingScore < 64 && paidHypeScore < 62 && trapRiskScore < 58) return "late-chase";
  if (crowdingScore >= 68 || paidHypeScore >= 68) return "fade";
  return "confirm";
}

function autonomousLaunchTimingEntryUsd(
  action: AutonomousLaunchTimingAction,
  launch: LaunchSniperItem | undefined,
  graduation: LaunchGraduationItem | undefined,
  timingScore: number,
  liquidityScore: number,
) {
  if (action === "stand-down" || action === "fade" || action === "confirm") return 0;
  const suggested = Math.max(launch?.suggested_entry_usd ?? 0, graduation?.suggested_entry_usd ?? 0);
  const base = action === "snipe-now" ? 550 : action === "late-chase" ? 260 : 220;
  const scoreBoost = Math.max(0, timingScore - 50) * (action === "snipe-now" ? 9 : 4);
  const liquidityBoost = Math.max(0, liquidityScore - 50) * 3;
  return Math.round(Math.min(Math.max(suggested, base + scoreBoost + liquidityBoost), action === "snipe-now" ? 950 : 450));
}

function autonomousLaunchTimingMaxChaseSeconds(action: AutonomousLaunchTimingAction, ageMinutes: number, crowdingScore: number) {
  if (action === "snipe-now") return ageMinutes <= 30 ? 18 : 30;
  if (action === "probe") return crowdingScore >= 60 ? 20 : 35;
  if (action === "late-chase") return 15;
  return 0;
}

function autonomousLaunchTimingReviewSeconds(
  action: AutonomousLaunchTimingAction,
  phase: AutonomousLaunchTimingPhase,
  timingScore: number,
) {
  if (action === "snipe-now") return timingScore >= 78 ? 8 : 12;
  if (action === "probe") return phase === "migration-window" ? 10 : 18;
  if (action === "late-chase") return 10;
  if (action === "fade" || action === "stand-down") return 24;
  return 20;
}

function autonomousLaunchTimingReason(
  symbol: string,
  action: AutonomousLaunchTimingAction,
  phase: AutonomousLaunchTimingPhase,
  timingScore: number,
  earlyEdgeScore: number,
  crowdingScore: number,
) {
  if (action === "snipe-now") return `${symbol} is still in the ${phase.replace("-", " ")} window with ${earlyEdgeScore}/100 early edge.`;
  if (action === "probe") return `${symbol} has enough timing edge for capped paper probing, but not full chase size.`;
  if (action === "late-chase") return `${symbol} is later in cycle; only a fast, small paper chase is allowed.`;
  if (action === "fade") return `${symbol} timing is crowded or hype-heavy; fade until the tape resets.`;
  if (action === "stand-down") return `${symbol} is blocked by timing risk before fresh paper entry.`;
  return `${symbol} needs one more confirmation tick; timing score is ${timingScore}/100 and crowding is ${crowdingScore}/100.`;
}

function autonomousLaunchTimingSummary(
  status: AutonomousLaunchTiming["status"],
  leader: AutonomousLaunchTimingItem | null,
  earlyCount: number,
  probeCount: number,
  confirmCount: number,
  lateCount: number,
  fadedCount: number,
  blockedCount: number,
) {
  if (status === "snipe") return `${earlyCount} fresh launch${earlyCount === 1 ? "" : "es"} can be paper-sniped before the crowding window closes.`;
  if (status === "probe") return `${probeCount} launch candidate${probeCount === 1 ? "" : "s"} deserve capped paper probes, not full chase size.`;
  if (status === "confirm") return `${confirmCount} launch candidate${confirmCount === 1 ? "" : "s"} need one more confirmation tick before entry.`;
  if (status === "late-chase") return `${lateCount} late-cycle candidate${lateCount === 1 ? "" : "s"} can only be chased with small, fast paper sizing.`;
  if (status === "fade") return `${fadedCount} candidate${fadedCount === 1 ? "" : "s"} look crowded or hype-heavy; fresh entries should wait.`;
  if (status === "blocked") return `${blockedCount} candidate${blockedCount === 1 ? "" : "s"} are blocked by source, liquidity, trap, or exit-first timing risk.`;
  return leader ? leader.reason : "No launch has enough timing edge for autonomous entry.";
}

function autonomousLaunchTimingNextAction(status: AutonomousLaunchTiming["status"], leader: AutonomousLaunchTimingItem | null) {
  if (!leader) return "Keep scanning launch, graduation, and discovery feeds before opening fresh paper exposure.";
  if (status === "snipe") return `Queue a ${formatCompactValue(leader.recommended_entry_usd)} paper snipe for ${leader.symbol}; review in ${leader.review_after_seconds}s.`;
  if (status === "probe") return `Probe ${leader.symbol} with capped paper size and require buyer-flow confirmation on the next tick.`;
  if (status === "late-chase") return `Allow only a small, fast paper chase for ${leader.symbol}; max chase window ${leader.max_chase_seconds}s.`;
  if (status === "fade") return `Fade ${leader.symbol}; crowding or hype risk is too high for a fresh paper buy.`;
  if (status === "blocked") return leader.blockers[0] ?? `Stand down on ${leader.symbol} until timing risk clears.`;
  return `Wait for one more confirmation tick before sizing ${leader.symbol}.`;
}

function autonomousLaunchTimingActionRank(action: AutonomousLaunchTimingAction) {
  if (action === "snipe-now") return 6;
  if (action === "probe") return 5;
  if (action === "late-chase") return 4;
  if (action === "confirm") return 3;
  if (action === "fade") return 2;
  return 1;
}

function buildTrendCatalystIntelligence(
  market: MemecoinMarket[],
  discoveryTape: DiscoveryTape,
): TrendCatalystIntelligence {
  const discoveryByToken = new Map(discoveryTape.top_candidates.map((candidate) => [candidate.token_id, candidate]));
  const items = market
    .slice(0, 10)
    .map((token) => trendCatalystItem(token, discoveryByToken.get(token.id), discoveryTape.status))
    .sort((a, b) => b.attention_score - a.attention_score || b.confidence - a.confidence)
    .slice(0, 8);
  const organicCount = items.filter((item) => item.catalyst_type === "organic-breakout" || item.action === "press").length;
  const paidHypeCount = items.filter((item) =>
    item.catalyst_type === "paid-boost" ||
    item.catalyst_type === "mixed-hype" ||
    item.catalyst_type === "thin-hype" ||
    item.promotion_risk_score >= 60
  ).length;
  const blockedCount = items.filter((item) => item.action === "block").length;
  const averageAttention = Math.round(average(items.map((item) => item.attention_score)));
  const averageOrganic = Math.round(average(items.map((item) => item.organic_score)));
  const status: TrendCatalystIntelligence["status"] = items.length === 0
    ? "quiet"
    : blockedCount > organicCount && paidHypeCount > 0
      ? "promotion-risk"
      : organicCount > 0 && averageOrganic >= 62
        ? "hot"
        : paidHypeCount > organicCount
          ? "promotion-risk"
          : averageAttention >= 45
            ? "selective"
            : "quiet";

  return {
    status,
    source: "local-catalyst-model",
    summary: trendCatalystSummary(status, items, organicCount, paidHypeCount, blockedCount),
    organic_count: organicCount,
    paid_hype_count: paidHypeCount,
    blocked_count: blockedCount,
    average_attention_score: averageAttention,
    average_organic_score: averageOrganic,
    items,
  };
}

function trendCatalystItem(
  token: MemecoinMarket,
  discovery: DiscoveryCandidate | undefined,
  discoveryStatus: DiscoveryTape["status"],
): TrendCatalystItem {
  const buyShare = token.buys_5m / Math.max(1, token.buys_5m + token.sells_5m);
  const volumeToLiquidity = token.volume_1h_usd / Math.max(1, token.liquidity_usd);
  const sourceSet = new Set(discovery?.sources ?? discoverySourcesForMarket(token));
  const promotionRisk = clamp(Math.round(
    token.boosts * 6 +
      token.paid_orders * 8 +
      (sourceSet.has("dex-latest-ads") ? 24 : 0) +
      (token.risk_flags.includes("paid-promotion-heavy") ? 24 : 0) +
      (token.risk_flags.includes("boost-heavy") ? 14 : 0),
  ), 0, 100);
  const buyFlowScore = clamp(Math.round(buyShare * 100 + Math.max(0, token.price_change_5m_pct) * 1.2 - Math.max(0, -token.price_change_5m_pct) * 2), 0, 100);
  const liquiditySupport = clamp(Math.round(
    Math.log10(Math.max(token.liquidity_usd, 1)) * 12 -
      Math.max(0, volumeToLiquidity - 3.5) * 8 -
      (token.liquidity_usd < 100_000 ? 24 : token.liquidity_usd < 250_000 ? 10 : 0),
  ), 0, 100);
  const attentionScore = clamp(Math.round(
    (discovery?.scout_score ?? 40) * 0.28 +
      token.price_change_5m_pct * 0.8 +
      token.price_change_1h_pct * 0.35 +
      volumeToLiquidity * 16 +
      token.boosts * 2.8 +
      token.paid_orders * 2.1 +
      (sourceSet.has("dex-community-takeovers") ? 12 : 0) +
      (sourceSet.has("dex-latest-profiles") ? 5 : 0),
  ), 0, 100);
  const organicScore = clamp(Math.round(
    buyFlowScore * 0.36 +
      liquiditySupport * 0.28 +
      Math.max(0, token.price_change_5m_pct) * 1.4 +
      Math.max(0, token.price_change_1h_pct) * 0.42 +
      (sourceSet.has("dex-community-takeovers") ? 8 : 0) -
      promotionRisk * 0.38 -
      token.risk_flags.length * 5,
  ), 0, 100);
  const catalystType = trendCatalystType(token, sourceSet, organicScore, promotionRisk, liquiditySupport);
  const blockers = trendCatalystBlockers(token, promotionRisk, liquiditySupport, buyFlowScore, discoveryStatus);
  const action = trendCatalystAction(catalystType, organicScore, attentionScore, promotionRisk, blockers);
  const confidence = clamp(Math.round(
    Math.max(attentionScore, organicScore) * 0.58 +
      Math.abs(attentionScore - promotionRisk) * 0.18 +
      (sourceSet.size * 4) +
      (blockers.length > 0 ? 10 : 0),
  ), 0, 100);

  return {
    token_id: token.id,
    symbol: token.symbol,
    chain: token.chain,
    catalyst_type: catalystType,
    action,
    confidence,
    attention_score: attentionScore,
    organic_score: organicScore,
    promotion_risk_score: promotionRisk,
    buy_flow_score: buyFlowScore,
    liquidity_support_score: liquiditySupport,
    review_after_seconds: trendReviewSeconds(action, catalystType, attentionScore, promotionRisk),
    reason: trendCatalystReason(token.symbol, action, catalystType, organicScore, promotionRisk),
    evidence: trendCatalystEvidence(token, sourceSet, buyShare, volumeToLiquidity, discovery),
    blockers,
  };
}

function trendCatalystType(
  token: MemecoinMarket,
  sources: Set<DiscoverySourceId>,
  organicScore: number,
  promotionRisk: number,
  liquiditySupport: number,
): TrendCatalystType {
  if (liquiditySupport < 28 && promotionRisk >= 45) return "thin-hype";
  if (organicScore >= 68 && promotionRisk < 55) return "organic-breakout";
  if (sources.has("dex-community-takeovers") && promotionRisk < 70) return "community-takeover";
  if (sources.has("dex-community-takeovers") && organicScore >= 40 && liquiditySupport >= 45) return "community-takeover";
  if (sources.has("dex-latest-profiles") && token.age_minutes < 240 && promotionRisk < 60) return "fresh-profile";
  if (promotionRisk >= 70 && organicScore >= 30 && liquiditySupport >= 55) return "mixed-hype";
  if (promotionRisk >= 70 && organicScore >= 45) return "mixed-hype";
  if (promotionRisk >= 45) return "paid-boost";
  return "fresh-profile";
}

function trendCatalystBlockers(
  token: MemecoinMarket,
  promotionRisk: number,
  liquiditySupport: number,
  buyFlowScore: number,
  discoveryStatus: DiscoveryTape["status"],
) {
  const blockers: string[] = [];
  if (discoveryStatus === "fallback") blockers.push("Live discovery is unavailable, so catalyst timing cannot be trusted.");
  if (token.risk_flags.includes("liquidity-pulled") || token.risk_flags.includes("sell-wall")) blockers.push("Local tape flags liquidity or sell-wall risk.");
  if (token.risk_flags.includes("thin-liquidity") || liquiditySupport < 24) blockers.push("Liquidity support is too thin for autonomous entry.");
  if (promotionRisk >= 78 && buyFlowScore < 62) blockers.push("Paid promotion is not confirmed by enough buyer flow.");
  if (token.age_minutes < 30 && token.liquidity_usd < 250_000) blockers.push("Fresh pair needs more age and liquidity before autonomous sizing.");
  return [...new Set(blockers)];
}

function trendCatalystAction(
  catalystType: TrendCatalystType,
  organicScore: number,
  attentionScore: number,
  promotionRisk: number,
  blockers: string[],
): TrendCatalystAction {
  if (blockers.length > 0) return "block";
  if (catalystType === "organic-breakout" && organicScore >= 68 && attentionScore >= 58) return "press";
  if (catalystType === "community-takeover" && organicScore >= 56) return "scout";
  if (catalystType === "mixed-hype" && organicScore >= 30 && attentionScore >= 55) return "scout";
  if (catalystType === "fresh-profile" && organicScore >= 48) return "scout";
  if (promotionRisk >= 70 || catalystType === "thin-hype") return "fade";
  return attentionScore >= 45 ? "scout" : "fade";
}

function trendReviewSeconds(
  action: TrendCatalystAction,
  catalystType: TrendCatalystType,
  attentionScore: number,
  promotionRisk: number,
) {
  if (action === "press") return attentionScore >= 78 ? 8 : 12;
  if (action === "scout") return catalystType === "community-takeover" ? 15 : 20;
  if (action === "block") return 45;
  return promotionRisk >= 70 ? 30 : 24;
}

function trendCatalystReason(
  symbol: string,
  action: TrendCatalystAction,
  catalystType: TrendCatalystType,
  organicScore: number,
  promotionRisk: number,
) {
  if (action === "press") return `${symbol} has organic catalyst confirmation with ${organicScore}/100 organic score.`;
  if (action === "scout") return `${symbol} is a ${catalystType.replace("-", " ")} worth watching before size increases.`;
  if (action === "block") return `${symbol} catalyst is blocked until liquidity, age, or sell-flow risk clears.`;
  return `${symbol} looks promotion-heavy: ${promotionRisk}/100 hype risk outruns organic confirmation.`;
}

function trendCatalystEvidence(
  token: MemecoinMarket,
  sources: Set<DiscoverySourceId>,
  buyShare: number,
  volumeToLiquidity: number,
  discovery: DiscoveryCandidate | undefined,
) {
  return [
    `${Math.round(buyShare * 100)}% 5m buy flow`,
    `${volumeToLiquidity.toFixed(2)}x 1h volume/liquidity`,
    `${token.boosts} boosts, ${token.paid_orders} paid orders`,
    discovery ? `scout ${discovery.scout_score}/100` : "local market-only catalyst",
    [...sources].map(sourceLabelForModel).join(" + "),
  ].filter(Boolean);
}

function sourceLabelForModel(source: DiscoverySourceId) {
  if (source === "dex-top-boosts") return "top boosts";
  if (source === "dex-latest-boosts") return "fresh boosts";
  if (source === "dex-latest-profiles") return "profile";
  if (source === "dex-community-takeovers") return "community takeover";
  if (source === "dex-latest-ads") return "ad";
  return "sample";
}

function trendCatalystSummary(
  status: TrendCatalystIntelligence["status"],
  items: TrendCatalystItem[],
  organicCount: number,
  paidHypeCount: number,
  blockedCount: number,
) {
  if (status === "quiet") return "No catalyst has enough attention quality for autonomous sizing yet.";
  if (status === "promotion-risk") return `${paidHypeCount} catalyst${paidHypeCount === 1 ? "" : "s"} look promotion-heavy; fade or block until organic flow confirms.`;
  if (status === "hot") return `${organicCount} organic catalyst${organicCount === 1 ? "" : "s"} can feed the paper entry loop with tight review cadence.`;
  return `${items.length} catalyst${items.length === 1 ? "" : "s"} are active, but the desk should scout selectively before pressing.`;
}

function liveRiskFlags(
  pair: DexScreenerPair,
  candidate: DexDiscoveryItem | undefined,
  ageMinutes: number,
  liquidity: number,
) {
  const flags: string[] = [];
  const buys = numberOrZero(pair.txns?.m5?.buys);
  const sells = numberOrZero(pair.txns?.m5?.sells);
  if (ageMinutes < 60) flags.push("new-pair");
  if (liquidity < 100_000) flags.push("thin-liquidity");
  if (numberOrZero(pair.priceChange?.m5) < -10 || sells > buys * 2) flags.push("sell-pressure");
  if (numberOrZero(candidate?.amount) >= 10 || numberOrZero(candidate?.totalAmount) >= 10) flags.push("boost-heavy");
  if (
    numberOrZero(candidate?.adImpressions) > 0 ||
    numberOrZero(candidate?.paidAdOrderCount) > 0 ||
    candidate?.sources.includes("dex-latest-ads")
  ) flags.push("paid-promotion-heavy");
  if (candidate?.sources.includes("dex-community-takeovers")) flags.push("community-takeover");
  if (candidate?.sources.includes("dex-latest-profiles") && ageMinutes < 240) flags.push("profile-fresh");
  return flags;
}

function buildAutonomousSourceQualityOracle({
  discoveryTape,
  promotionAudit,
  trendCatalyst,
  liveScannerReadiness,
  dataFreshnessGate,
}: {
  discoveryTape: DiscoveryTape;
  promotionAudit: PromotionOrderAudit;
  trendCatalyst: TrendCatalystIntelligence;
  liveScannerReadiness: LiveScannerReadiness;
  dataFreshnessGate: AutonomousDataFreshnessGate;
}): AutonomousSourceQualityOracle {
  const catalystByToken = new Map(trendCatalyst.items.map((item) => [item.token_id, item]));
  const promotionByToken = new Map(promotionAudit.items.map((item) => [item.token_id, item]));
  const scannerByToken = new Map(liveScannerReadiness.items.map((item) => [item.token_id, item]));
  const dataGatePenalty = dataFreshnessGate.status === "blocked"
    ? 22
    : dataFreshnessGate.status === "refresh" || dataFreshnessGate.status === "backfill"
      ? 12
      : dataFreshnessGate.status === "sample"
        ? 4
        : 0;
  const items = discoveryTape.top_candidates
    .map((candidate): AutonomousSourceQualityItem => {
      const promotion = promotionByToken.get(candidate.token_id);
      const catalyst = catalystByToken.get(candidate.token_id);
      const scanner = scannerByToken.get(candidate.token_id);
      const organicConfirmationScore = clamp(Math.round(
        (catalyst?.organic_score ?? Math.max(0, candidate.scout_score - candidate.promotion_intensity * 0.45)) * 0.36 +
          (scanner?.source_confirmation_score ?? candidate.sources.length * 18) * 0.26 +
          candidate.freshness_score * 0.18 +
          (promotion?.verdict === "organic" ? 16 : promotion?.verdict === "boosted" ? 8 : promotion?.verdict === "paid-hype" ? -12 : 0) +
          (candidate.sources.includes("dex-community-takeovers") ? 8 : 0),
      ), 0, 100);
      const marketActivityScore = clamp(Math.round(
        (catalyst?.attention_score ?? candidate.scout_score) * 0.42 +
          Math.min(36, candidate.volume_1h_usd / Math.max(1, candidate.liquidity_usd) * 18) +
          Math.min(22, Math.log10(Math.max(candidate.liquidity_usd, 1)) * 2.2),
      ), 0, 100);
      const promotionNoiseScore = clamp(Math.round(
        Math.max(candidate.promotion_intensity, promotion?.hype_risk_score ?? 0) +
          candidate.paid_ad_order_count * 10 +
          (candidate.sources.includes("dex-latest-ads") ? 16 : 0) +
          (candidate.risk_flags.includes("paid-promotion-heavy") ? 14 : 0),
      ), 0, 100);
      const trustScore = clamp(Math.round(
        organicConfirmationScore * 0.42 +
          marketActivityScore * 0.24 +
          (scanner?.route_score ?? 0) * 0.12 +
          (candidate.paid_order_checked ? 10 : -10) +
          (100 - promotionNoiseScore) * 0.22 -
          dataGatePenalty,
      ), 0, 100);
      const blockers = autonomousSourceQualityBlockers({
        discoveryTape,
        candidate,
        promotionNoiseScore,
        organicConfirmationScore,
        trustScore,
        dataFreshnessGate,
        scanner,
      });
      const action = autonomousSourceQualityAction({
        discoveryTape,
        dataFreshnessGate,
        trustScore,
        organicConfirmationScore,
        marketActivityScore,
        promotionNoiseScore,
        blockers,
      });
      const status = autonomousSourceQualityStatus(action, promotionNoiseScore, organicConfirmationScore, candidate, promotion);

      return {
        token_id: candidate.token_id,
        symbol: candidate.symbol,
        action,
        status,
        source_quality_score: trustScore,
        organic_confirmation_score: organicConfirmationScore,
        market_activity_score: marketActivityScore,
        promotion_noise_score: promotionNoiseScore,
        trust_score: trustScore,
        source_count: candidate.sources.length,
        paid_order_checked: candidate.paid_order_checked,
        paid_order_count: candidate.paid_order_count,
        review_after_seconds: Math.max(5, Math.min(scanner?.review_after_seconds ?? catalyst?.review_after_seconds ?? 45, 90)),
        max_paper_size_multiplier: autonomousSourceQualitySizeMultiplier(action, trustScore, promotionNoiseScore),
        reason: autonomousSourceQualityReason(action, candidate.symbol, trustScore, organicConfirmationScore, promotionNoiseScore, blockers),
        evidence: [
          `${candidate.sources.map(sourceLabelForModel).join(" + ")} sources`,
          `${organicConfirmationScore}/100 organic confirmation`,
          `${marketActivityScore}/100 market activity`,
          `${promotionNoiseScore}/100 paid/boost noise`,
          candidate.paid_order_checked ? `${candidate.paid_order_count} paid orders checked` : "paid orders unchecked",
          `${dataFreshnessGate.status} data gate`,
        ],
        blockers,
      };
    })
    .sort((a, b) =>
      autonomousSourceQualityActionRank(b.action) - autonomousSourceQualityActionRank(a.action) ||
      b.source_quality_score - a.source_quality_score,
    )
    .slice(0, 8);
  const leader = items.find((item) => item.action === "attack" || item.action === "probe") ?? items[0] ?? null;
  const organicCount = items.filter((item) => item.status === "organic").length;
  const boostedConfirmedCount = items.filter((item) => item.status === "boosted-confirmed").length;
  const paidHypeCount = items.filter((item) => item.status === "paid-hype").length;
  const refreshCount = items.filter((item) => item.action === "refresh-proof").length;
  const blockedCount = items.filter((item) => item.action === "block").length;
  const status: AutonomousSourceQualityOracle["status"] = discoveryTape.status === "sample"
    ? "sample"
    : items.length === 0
      ? "idle"
      : paidHypeCount > organicCount + boostedConfirmedCount && !items.some((item) => item.action === "attack" || item.action === "probe")
        ? "paid-hype"
        : blockedCount > 0 && blockedCount >= items.length
          ? "blocked"
          : refreshCount > 0 && !items.some((item) => item.action === "attack" || item.action === "probe")
            ? "refresh-first"
            : organicCount > 0 && leader?.status === "organic"
              ? "organic"
              : boostedConfirmedCount > 0
                ? "boosted-confirmed"
                : paidHypeCount > 0
                  ? "paid-hype"
                  : "idle";
  const canChase = Boolean(leader && (leader.action === "attack" || leader.action === "probe"));

  return {
    mode: "autonomous-source-quality-oracle",
    status,
    leader_symbol: leader?.symbol ?? null,
    leader_action: leader?.action ?? null,
    quality_score: leader?.source_quality_score ?? 0,
    organic_count: organicCount,
    boosted_confirmed_count: boostedConfirmedCount,
    paid_hype_count: paidHypeCount,
    refresh_count: refreshCount,
    blocked_count: blockedCount,
    can_chase: canChase,
    needs_refresh: status === "refresh-first" || items.some((item) => item.action === "refresh-proof"),
    size_multiplier: leader ? leader.max_paper_size_multiplier : 0,
    fastest_review_seconds: items.length ? Math.min(...items.map((item) => item.review_after_seconds)) : dataFreshnessGate.max_staleness_seconds,
    summary: autonomousSourceQualitySummary(status, leader, organicCount, boostedConfirmedCount, paidHypeCount, refreshCount, blockedCount),
    next_action: leader?.reason ?? "Keep scanning until source quality is clear enough for a local paper decision.",
    controls: [
      "Separates organic momentum from boosted or paid-ad attention before the high-frequency paper loop can chase.",
      "Uses DEX Screener profile, boost, ad, paid-order, pair activity, freshness, and route-readiness evidence.",
      "Paper sizing can be reduced or blocked by paid-hype noise, unchecked orders, stale evidence, thin source coverage, or route refresh requirements.",
    ],
    items,
  };
}

function autonomousSourceQualityBlockers({
  discoveryTape,
  candidate,
  promotionNoiseScore,
  organicConfirmationScore,
  trustScore,
  dataFreshnessGate,
  scanner,
}: {
  discoveryTape: DiscoveryTape;
  candidate: DiscoveryCandidate;
  promotionNoiseScore: number;
  organicConfirmationScore: number;
  trustScore: number;
  dataFreshnessGate: AutonomousDataFreshnessGate;
  scanner: LiveScannerReadinessItem | undefined;
}) {
  const blockers: string[] = [];
  if (discoveryTape.status === "fallback") blockers.push("Live discovery is in fallback, so source quality cannot clear.");
  if (!candidate.paid_order_checked && discoveryTape.status === "live") blockers.push("Paid-order audit is not checked for this candidate.");
  if (promotionNoiseScore >= 78 && organicConfirmationScore < 64) blockers.push("Paid boost or ad noise outruns organic buyer confirmation.");
  if (candidate.sources.length < 2 && discoveryTape.status === "live") blockers.push("Source coverage is too thin for autonomous chase sizing.");
  if (dataFreshnessGate.action === "refresh-stream" || dataFreshnessGate.action === "refresh-quote" || dataFreshnessGate.action === "fetch-candles") {
    blockers.push(dataFreshnessGate.next_action);
  }
  if (scanner?.status === "blocked" || scanner?.action === "blocked") blockers.push(scanner.blockers[0] ?? "Scanner blocks this candidate.");
  if (trustScore < 34) blockers.push("Source-quality score is below the paper-chase floor.");
  return [...new Set(blockers)].slice(0, 5);
}

function autonomousSourceQualityAction({
  discoveryTape,
  dataFreshnessGate,
  trustScore,
  organicConfirmationScore,
  marketActivityScore,
  promotionNoiseScore,
  blockers,
}: {
  discoveryTape: DiscoveryTape;
  dataFreshnessGate: AutonomousDataFreshnessGate;
  trustScore: number;
  organicConfirmationScore: number;
  marketActivityScore: number;
  promotionNoiseScore: number;
  blockers: string[];
}): AutonomousSourceQualityAction {
  if (blockers.some((blocker) => /fallback|refresh|quote|candle|stream|unchecked/i.test(blocker))) return "refresh-proof";
  if (blockers.length > 0 || dataFreshnessGate.status === "blocked") return "block";
  if (discoveryTape.status === "sample") return trustScore >= 48 ? "probe" : "watch";
  if (trustScore >= 74 && organicConfirmationScore >= 66 && marketActivityScore >= 56 && promotionNoiseScore < 58) return "attack";
  if (trustScore >= 56 && organicConfirmationScore >= 46 && promotionNoiseScore < 72) return "probe";
  if (promotionNoiseScore >= 70 && organicConfirmationScore < 58) return "fade";
  return trustScore >= 42 ? "watch" : "block";
}

function autonomousSourceQualityStatus(
  action: AutonomousSourceQualityAction,
  promotionNoiseScore: number,
  organicConfirmationScore: number,
  candidate: DiscoveryCandidate,
  promotion: PromotionOrderAuditItem | undefined,
): AutonomousSourceQualityItem["status"] {
  if (promotionNoiseScore >= 72 && organicConfirmationScore < 64) return "paid-hype";
  if (promotion?.verdict === "boosted" && organicConfirmationScore >= 52) return "boosted-confirmed";
  if (candidate.sources.includes("dex-top-boosts") && organicConfirmationScore >= 58 && promotionNoiseScore < 72) return "boosted-confirmed";
  if (organicConfirmationScore >= 64 && promotionNoiseScore < 58) return "organic";
  if (action === "refresh-proof") return "refresh-first";
  if (action === "block") return "blocked";
  if (action === "fade") return "paid-hype";
  return "watch";
}

function autonomousSourceQualitySizeMultiplier(action: AutonomousSourceQualityAction, trustScore: number, promotionNoiseScore: number) {
  if (action === "attack") return Math.max(0.7, Math.min(1.2, Math.round((0.72 + (trustScore - 70) / 100 - Math.max(0, promotionNoiseScore - 50) / 180) * 100) / 100));
  if (action === "probe") return Math.max(0.25, Math.min(0.65, Math.round((0.42 + (trustScore - 50) / 180 - Math.max(0, promotionNoiseScore - 58) / 220) * 100) / 100));
  return 0;
}

function autonomousSourceQualityActionRank(action: AutonomousSourceQualityAction) {
  if (action === "attack") return 6;
  if (action === "probe") return 5;
  if (action === "refresh-proof") return 4;
  if (action === "watch") return 3;
  if (action === "fade") return 2;
  return 1;
}

function autonomousSourceQualityReason(
  action: AutonomousSourceQualityAction,
  symbol: string,
  trustScore: number,
  organicConfirmationScore: number,
  promotionNoiseScore: number,
  blockers: string[],
) {
  if (action === "attack") return `${symbol} clears source quality for local paper attack with ${trustScore}/100 trust and ${organicConfirmationScore}/100 organic confirmation.`;
  if (action === "probe") return `${symbol} can be probed with reduced local paper size while source quality is ${trustScore}/100.`;
  if (action === "refresh-proof") return blockers[0] ?? `Refresh paid-order, route, candle, or DEX-stream proof before sizing ${symbol}.`;
  if (action === "fade") return `${symbol} is promotion-heavy; ${promotionNoiseScore}/100 paid or boost noise outruns clean flow.`;
  if (action === "block") return blockers[0] ?? `Block ${symbol}; source quality is too weak for paper churn.`;
  return `Watch ${symbol}; source quality is ${trustScore}/100 and not yet worth paper budget.`;
}

function autonomousSourceQualitySummary(
  status: AutonomousSourceQualityOracle["status"],
  leader: AutonomousSourceQualityItem | null,
  organicCount: number,
  boostedConfirmedCount: number,
  paidHypeCount: number,
  refreshCount: number,
  blockedCount: number,
) {
  if (status === "organic") return `${organicCount} candidate${organicCount === 1 ? "" : "s"} show organic source quality; ${leader?.symbol ?? "the leader"} can feed the paper chase stack.`;
  if (status === "boosted-confirmed") return `${boostedConfirmedCount} boosted candidate${boostedConfirmedCount === 1 ? "" : "s"} have enough organic confirmation for reduced paper sizing.`;
  if (status === "paid-hype") return `${paidHypeCount} candidate${paidHypeCount === 1 ? "" : "s"} look promotion-heavy; fade until buyer flow and paid-order proof improve.`;
  if (status === "refresh-first") return `${refreshCount} candidate${refreshCount === 1 ? "" : "s"} need fresher source, paid-order, candle, or route proof before paper sizing.`;
  if (status === "blocked") return `${blockedCount} candidate${blockedCount === 1 ? "" : "s"} are blocked by source quality.`;
  if (status === "sample") return "Sample source quality is rehearsed locally; live chase decisions require current DEX evidence.";
  return "Source quality oracle is idle until discovery, paid-order, and scanner evidence exist.";
}

function autonomousSourceQualityItemForSymbol(
  sourceQuality: AutonomousSourceQualityOracle | undefined,
  symbol: string | null | undefined,
) {
  if (!sourceQuality || !symbol) return null;
  return sourceQuality.items.find((item) => item.symbol === symbol) ?? null;
}

function autonomousSourceQualityBuyBlocker(
  sourceQuality: AutonomousSourceQualityOracle | undefined,
  symbol: string | null | undefined,
) {
  if (!sourceQuality || !symbol) return null;
  const item = autonomousSourceQualityItemForSymbol(sourceQuality, symbol);
  if (!item) {
    if (sourceQuality.status === "sample" || sourceQuality.status === "idle") return null;
    return `Source-quality oracle has no current proof for ${symbol}.`;
  }
  if (item.action === "attack" || item.action === "probe") return null;
  if (item.status === "paid-hype" || item.action === "fade") {
    return item.reason || `${item.symbol} is paid-hype; fresh buys stay blocked until organic flow confirms.`;
  }
  if (item.status === "refresh-first" || item.action === "refresh-proof") {
    return item.reason || `${item.symbol} needs source-quality proof refresh before a fresh buy.`;
  }
  if (item.status === "blocked" || item.action === "block") {
    return item.reason || `${item.symbol} is blocked by source quality.`;
  }
  if (item.max_paper_size_multiplier <= 0 && sourceQuality.status !== "sample") {
    return item.reason || `${item.symbol} source quality does not allow fresh paper sizing.`;
  }
  return null;
}

function autonomousSourceQualityTradeBlocker(
  sourceQuality: AutonomousSourceQualityOracle | undefined,
  trade: AutonomousTrade | null | undefined,
) {
  if (!trade || trade.side !== "buy") return null;
  return autonomousSourceQualityBuyBlocker(sourceQuality, trade.symbol);
}

function autonomousSourceQualityAllowsTrade(
  sourceQuality: AutonomousSourceQualityOracle | undefined,
  trade: AutonomousTrade | null | undefined,
) {
  return !autonomousSourceQualityTradeBlocker(sourceQuality, trade);
}

function autonomousSourceQualityRuntimeSizeMultiplier(
  sourceQuality: AutonomousSourceQualityOracle | undefined,
  symbol: string | null | undefined,
) {
  if (!sourceQuality || !symbol) return 1;
  const item = autonomousSourceQualityItemForSymbol(sourceQuality, symbol);
  if (!item) return sourceQuality.status === "sample" || sourceQuality.status === "idle" ? 1 : 0;
  if (item.action !== "attack" && item.action !== "probe") return 0;
  return roundMetric(clamp(Math.min(1, item.max_paper_size_multiplier), 0, 1));
}

function autonomousSourceQualityAdjustedSizeUsd(
  sourceQuality: AutonomousSourceQualityOracle | undefined,
  symbol: string | null | undefined,
  requestedSizeUsd: number,
) {
  const size = Math.round(Math.max(0, requestedSizeUsd));
  if (size <= 0) return 0;
  if (autonomousSourceQualityBuyBlocker(sourceQuality, symbol)) return 0;
  const multiplier = autonomousSourceQualityRuntimeSizeMultiplier(sourceQuality, symbol);
  if (multiplier >= 0.995) return size;
  const adjusted = Math.round(size * multiplier);
  return adjusted >= 10 ? adjusted : 0;
}

function autonomousSourceQualityAdjustedReason(
  sourceQuality: AutonomousSourceQualityOracle | undefined,
  symbol: string | null | undefined,
  adjustedSizeUsd: number,
  requestedSizeUsd: number,
  reason: string,
) {
  const requested = Math.round(Math.max(0, requestedSizeUsd));
  if (!symbol || adjustedSizeUsd <= 0 || requested <= 0 || adjustedSizeUsd >= requested) return reason;
  const item = autonomousSourceQualityItemForSymbol(sourceQuality, symbol);
  const pct = Math.round((adjustedSizeUsd / requested) * 100);
  return `${reason} Source-quality sizing caps ${symbol} at ${pct}%${item ? ` (${item.status})` : ""}.`;
}

function autonomousSourceQualityAdjustedTrade(
  sourceQuality: AutonomousSourceQualityOracle | undefined,
  trade: AutonomousTrade | null | undefined,
): AutonomousTrade | null {
  if (!trade) return null;
  if (trade.side !== "buy") return trade;
  if (autonomousSourceQualityTradeBlocker(sourceQuality, trade)) return null;
  const adjustedSizeUsd = autonomousSourceQualityAdjustedSizeUsd(sourceQuality, trade.symbol, trade.size_usd);
  if (adjustedSizeUsd <= 0) return null;
  if (adjustedSizeUsd >= Math.round(trade.size_usd)) return trade;
  return {
    ...trade,
    size_usd: adjustedSizeUsd,
    reason: autonomousSourceQualityAdjustedReason(sourceQuality, trade.symbol, adjustedSizeUsd, trade.size_usd, trade.reason),
  };
}

function autonomousSourceQualitySizingBlockerForSize(
  sourceQuality: AutonomousSourceQualityOracle | undefined,
  symbol: string | null | undefined,
  requestedSizeUsd: number,
) {
  const size = Math.round(Math.max(0, requestedSizeUsd));
  if (!symbol || size < 10) return null;
  if (autonomousSourceQualityBuyBlocker(sourceQuality, symbol)) return null;
  if (autonomousSourceQualityAdjustedSizeUsd(sourceQuality, symbol, size) >= 10) return null;
  const multiplier = autonomousSourceQualityRuntimeSizeMultiplier(sourceQuality, symbol);
  return `Source-quality sizing caps ${symbol} to ${Math.round(multiplier * 100)}%, below the local paper-ledger minimum.`;
}

function autonomousSourceQualitySizingBlocker(
  sourceQuality: AutonomousSourceQualityOracle | undefined,
  trade: AutonomousTrade | null | undefined,
) {
  if (!trade || trade.side !== "buy") return null;
  return autonomousSourceQualitySizingBlockerForSize(sourceQuality, trade.symbol, trade.size_usd);
}

function toTradingChain(value: string | undefined): MemecoinMarket["chain"] | null {
  if (value === "solana") return "solana";
  if (value === "base") return "base";
  if (value === "ethereum" || value === "ether") return "ethereum";
  return null;
}

function isSupportedChain(value: string | undefined) {
  return value === "solana" || value === "base" || value === "ethereum" || value === "ether";
}

function numberOrZero(value: unknown): number {
  const number = typeof value === "string" ? Number(value) : typeof value === "number" ? value : 0;
  return Number.isFinite(number) ? number : 0;
}

function numberOrNull(value: unknown): number | null {
  const number = typeof value === "string" ? Number(value) : typeof value === "number" ? value : NaN;
  return Number.isFinite(number) ? number : null;
}

function positiveNumber(value: unknown, fallback: number) {
  const number = typeof value === "number" ? value : typeof value === "string" ? Number(value) : NaN;
  return Number.isFinite(number) && number > 0 ? number : fallback;
}

function positiveInteger(value: unknown, fallback: number) {
  return Math.round(positiveNumber(value, fallback));
}

type PayloadInspection =
  | { valid: true; hash: string; bytes: number }
  | { valid: false; hash: null; bytes: null };

type SignerSimulationResult = {
  signature: string | null;
  session_label: string | null;
  network: SignerSimulationNetwork | null;
};

function inspectUnsignedTransactionPayload(value: string): PayloadInspection {
  const trimmed = value.trim();
  if (!trimmed || trimmed.length % 4 !== 0 || !/^[A-Za-z0-9+/]+={0,2}$/.test(trimmed)) {
    return { valid: false, hash: null, bytes: null };
  }
  const bytes = Buffer.from(trimmed, "base64");
  const normalized = bytes.toString("base64").replace(/=+$/, "");
  if (bytes.length === 0 || normalized !== trimmed.replace(/=+$/, "")) {
    return { valid: false, hash: null, bytes: null };
  }
  return {
    valid: true,
    hash: createHash("sha256").update(bytes).digest("hex"),
    bytes: bytes.length,
  };
}

function buildSignerSimulation(
  config: ExecutionConfig,
  plan: ExecutionPlan | null,
  nonce: string,
  blockers: string[],
): SignerSimulationResult {
  if (
    blockers.length > 0 ||
    !config.signer_simulation_enabled ||
    !plan?.dry_run.transaction_ready ||
    !plan.dry_run.payload_hash
  ) {
    return { signature: null, session_label: null, network: null };
  }

  const digest = createHash("sha256")
    .update([
      "mastermold-web3-signer-simulation",
      config.signer_network,
      config.signer_session_label,
      nonce,
      plan.id,
      plan.dry_run.request_id ?? "no-request",
      plan.dry_run.payload_hash,
    ].join(":"))
    .digest("hex");

  return {
    signature: `sim_sig_${digest.slice(0, 40)}`,
    session_label: config.signer_session_label,
    network: config.signer_network,
  };
}

function normalizeWallet(value: string | null | undefined) {
  if (typeof value !== "string") return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
}

function normalizeSignerLabel(value: unknown) {
  if (typeof value !== "string") return "dry-run-session";
  const trimmed = value.trim().replace(/\s+/g, "-").slice(0, 40);
  return trimmed.length > 0 ? trimmed : "dry-run-session";
}

function isLikelySolanaPublicKey(value: string) {
  return /^[1-9A-HJ-NP-Za-km-z]{32,44}$/.test(value);
}

function formatPct(value: number) {
  return `${value >= 0 ? "+" : ""}${value.toFixed(1)}%`;
}

function formatPriceValue(value: number) {
  if (value < 0.01) return `$${value.toFixed(7)}`;
  if (value < 1) return `$${value.toFixed(4)}`;
  return `$${value.toFixed(2)}`;
}

function formatCompactValue(value: number) {
  const sign = value < 0 ? "-" : "";
  const absolute = Math.abs(value);
  if (absolute >= 1_000_000) return `${sign}$${(absolute / 1_000_000).toFixed(1)}M`;
  if (absolute >= 1_000) return `${sign}$${Math.round(absolute / 1_000)}K`;
  return `${sign}$${Math.round(absolute)}`;
}

function formatSignedCompactValue(value: number) {
  return `${value >= 0 ? "+" : ""}${formatCompactValue(value)}`;
}

function trailingStopPrice(peakPrice: number, stopLossPct: number) {
  const trailPct = Math.min(18, Math.max(6, Math.abs(stopLossPct)));
  return peakPrice * (1 - trailPct / 100);
}

function clamp(value: number, min: number, max: number) {
  return Math.max(min, Math.min(max, value));
}
